async function refreshAutoKolWallets() {
  try {
    const scans = await Promise.all(["hot", "fresh", "top", "consistent"].map((mode) => buildKolScan("autopilot", mode, "").catch(() => null)));
    const kols = uniqueKolSummaries(scans.flatMap((scan) => (scan && Array.isArray(scan.kols)) ? scan.kols : []));
    let added = 0, tracked = 0;
    for (const k of kols) {
      const w = String(k.wallet || "").trim();
      if (!w) continue;
      const win = Number(k.winRatePct);
      const trades = Number(k.trades || k.callsTracked || 0);
      rememberTrackedKolWallet(w, { name: k.name || shortMint(w), winRate: win, roi: Number(k.roiPct) || null, trades: trades || null, source: k.source || "kol_api" });
      tracked += 1;
      if (!Number.isFinite(win) || win < KOL_COPY_MIN_WINRATE) continue;   // must clear the win-rate bar
      if (trades && trades < KOL_COPY_MIN_TRADES) continue;                // and have a real sample
      if (!autoKolWallets.has(w)) added += 1;
      autoKolWallets.set(w, { name: k.name || shortMint(w), winRate: win, roi: Number(k.roiPct) || null, trades: trades || null, at: Date.now() });
    }
    // Keep the roster bounded to the strongest win-rates.
    if (autoKolWallets.size > 500) {
      const top = [...autoKolWallets.entries()].sort((a, b) => (b[1].winRate || 0) - (a[1].winRate || 0)).slice(0, 500);
      autoKolWallets.clear();
      for (const [w, r] of top) autoKolWallets.set(w, r);
    }
    if (added || tracked) { void saveAutoKolWallets(); void saveKolLearning(); }
    console.log(`[auto-kol] tracking ${trackedKolWallets.size} KOLs from API scans; proven roster ${autoKolWallets.size} (+${added}; win>=${KOL_COPY_MIN_WINRATE}%, trades>=${KOL_COPY_MIN_TRADES})`);
  } catch (e) { console.warn(`[auto-kol] ${e && e.message}`); }
}

// ── COPY-TRADE ENGINE FEED ─────────────────────────────────────────────────────────────────
// The autopilot's smart-money path used to depend on per-trade data from the PumpPortal trade
// stream, which delivers nothing for us (subscribeTokenTrade returns 0). That starved copy-trade:
// smartMoneyScore() saw no buyers, smartMoneyFeed() returned []. The WORKING signal we already
// pay for is the Solana Tracker KOL tracker — buildKolScan("autopilot","hot") surfaces the tokens
// proven KOLs are HOLDING / just BOUGHT right now, each tagged with the KOL's win-rate. We turn
// that into engine-ready candidate rows (free DexScreener MC/liquidity enrichment so the gates +
// sizing work), cache it, and refresh on a bounded interval. This is the real "copy any good KOL
// with a win rate" edge — no Helius, no credit burn beyond the tracker we already use.
let kolCopyFeedCache = { rows: [], at: 0 };
let kolCopyFeedRefreshing = false;
const KOL_COPY_FEED_TTL_MS = 90_000;                 // staleness window (background poller cadence)
const KOL_COPY_FEED_MIN_WINRATE = 50;                // proven copy KOLs with a real win-rate; others are observed/probed small
const KOL_COPY_FEED_FRESH_MS = Math.max(5 * 60 * 1000, Number(process.env.KOL_COPY_FEED_FRESH_MS) || 20 * 60 * 1000); // recent touch = "now"
const KOL_COPY_FEED_MAX = 24;                         // bounded candidate list
const KOL_COPY_PROBE_MAX = 8;                          // thin-sample KOLs get a small learning lane, not full sizing

// ===== WINNER-FOLLOW LIVE COPY FEED (Solana Tracker Premium) =============================
// The direct copy edge: poll our OWN proven-winner wallets' (+ KOLs') live trades, detect a
// FRESH buy into a sellable coin, and surface that coin as a self-entry candidate. This is what
// turns the 92 seeded winners from a static roster into a live "they're buying NOW → copy them"
// signal — the path that was dark (zero 🐳 detections) because the observatory only ever saw the
// early-buyers of fresh pump.fun dust, never what the leaderboard winners actually trade.
// GENTLE TRICKLE (the crash-loop lesson): a few wallets per cycle, sequential with a small gap.
// ST budget guard: BATCH/(INTERVAL) sets req/min. Defaults poll the top 30 wallets
// at 3/minute, so the full rotation is ~10m and stays inside the fresh-buy window.
// All env-tunable to dial harder if wanted.
let winnerFollowCache = { rows: [], at: 0 };           // engine-shaped copy candidate rows
let winnerFollowPolling = false;
let winnerFollowCursor = 0;                            // rotation pointer through the wallet pool
let winnerFollowPolledTotal = 0;
const winnerBuys = new Map();                          // mint -> { clusters:Set, addrs:Set, lastAt, kol, mc } (rolling, pruned to FRESH window)
const WINNER_FOLLOW_BATCH = Math.max(1, Number(process.env.WINNER_FOLLOW_BATCH) || 3);              // wallets polled per cycle
const WINNER_FOLLOW_INTERVAL_MS = Math.max(20_000, Number(process.env.WINNER_FOLLOW_INTERVAL_MS) || 60_000);
const WINNER_FOLLOW_POOL = Math.max(5, Number(process.env.WINNER_FOLLOW_POOL) || 30);               // top-N winners on rotation
const WINNER_FOLLOW_FRESH_MS = Math.max(5 * 60 * 1000, Number(process.env.WINNER_FOLLOW_FRESH_MS) || 25 * 60 * 1000); // a buy this recent = "now"
const WINNER_FOLLOW_MAX = 16;                          // bounded candidate list

async function refreshKolCopyFeed() {
  if (!CONFIG.solanaTrackerApiKey) return;            // tracker is the source; nothing to do without it
  if (kolCopyFeedRefreshing) return;
  kolCopyFeedRefreshing = true;
  try {
    // Read every KOL surface our API exposes. Every row is recorded for learning; only the rows with
    // enough learned/API edge become copy candidates, and thin-sample KOLs go through a small probe lane.
    const scans = await Promise.all(["hot", "fresh", "top", "consistent"].map((mode) => buildKolScan("autopilot", mode, "").catch(() => null)));
    const rows = uniqueKolSignals(scans.flatMap((scan) => (scan && Array.isArray(scan.rows)) ? scan.rows : [])).sort(compareKolSignals);
    for (const k of uniqueKolSummaries(scans.flatMap((scan) => (scan && Array.isArray(scan.kols)) ? scan.kols : []))) {
      const w = String(k.wallet || "").trim();
      if (w) rememberTrackedKolWallet(w, { name: k.name || shortMint(w), winRate: k.winRatePct, roi: k.roiPct, trades: k.trades || k.callsTracked, source: k.source || "kol_api" });
    }
    const now = Date.now();
    // Group by mint so multiple KOLs in the same coin = confluence (we size + ride those harder).
    const byMint = new Map();
    for (const r of rows) {
      const mint = r && r.tokenMint;
      if (!mint || mint === SOL_MINT) continue;
      const win = Number(r.winRatePct);
      const w = String(r.kolWallet || "").trim();
      recordKolSignal(r); // learn every KOL pattern, even when it is not copied
      // FRESH gate: only "buying now" — skip stale holdings (when we know the time).
      const last = r.lastTradeAt ? Number(r.lastTradeAt) : 0;
      if (last && (now - last) > KOL_COPY_FEED_FRESH_MS) continue;
      let g = byMint.get(mint);
      if (!g) { g = { mint, sym: r.symbol, kols: new Set(), bestWin: 0, bestScore: 0, kolName: r.kolName, lastTradeAt: last, rows: [] }; byMint.set(mint, g); }
      if (w) { g.kols.add(w); rememberTrackedKolWallet(w, { name: r.kolName || r.twitter || shortMint(w), winRate: win, roi: r.kolRoiPct ?? r.roiPct, trades: r.callsTracked, source: r.source || r.sourceLabel || "kol_signal" }); }
      g.rows.push(r);
      const rw = Number(win); if (Number.isFinite(rw) && rw > g.bestWin) g.bestWin = rw;
      const rs = Number(r.score); if (Number.isFinite(rs) && rs > g.bestScore) { g.bestScore = rs; g.kolName = r.kolName || g.kolName; g.sym = r.symbol || g.sym; }
      if (last > g.lastTradeAt) g.lastTradeAt = last;
    }
    const mints = [...byMint.keys()].slice(0, 40);
    if (!mints.length) { kolCopyFeedCache = { rows: [], at: now }; return; }
    // FREE enrichment: DexScreener batch gives live MC + liquidity (no Helius / RPC). The engine
    // also re-verifies liquidity via getPairLite for liquid modes, so this is a fast first read.
    const pairs = await fetchDexScreenerTokenPairsBatch(mints).catch(() => []);
    const out = [];
    for (const mint of mints) {
      const g = byMint.get(mint);
      const best = bestDexPairForToken(mint, (pairs || []).filter((p) => pairMatchesToken(p, mint)));
      const mc = Number(best?.marketCap || best?.fdv) || 0;
      if (mc <= 0) continue;                          // openPosition needs a real entry MC
      const liq = Number(best?.liquidity?.usd) || 0;
      const kolCount = g.kols.size || 1;
      const profiles = [...g.kols].map((w) => kolLearningProfile(w, g.bestWin));
      const learnedGood = profiles.some((p) => p.learnedGood);
      const learnedBad = profiles.length > 0 && profiles.every((p) => p.learnedBad);
      const apiGood = profiles.some((p) => p.apiGood) || (Number.isFinite(Number(g.bestWin)) && Number(g.bestWin) >= KOL_COPY_FEED_MIN_WINRATE);
      const confluence = kolCount >= 2 || Number(g.rows?.[0]?.kolCount || 0) >= 2;
      const rowScore = Math.max(Number(g.bestScore) || 0, ...((g.rows || []).map((r) => Number(r.bestPickScore || r.score || 0) || 0)));
      const hasMarket = mc >= 2_000 && liq >= 1_000;
      // API win-rate is useful for discovery, but it is not enough to size like an edge.
      // Normal copy sizing needs our own learned-good record, or API-good KOL confluence
      // on a high-score current signal. Lone API-good rows stay in the small probe lane.
      const provenCopy = !learnedBad && (learnedGood || (apiGood && confluence && rowScore >= 72));
      const probeCopy = !provenCopy && !learnedBad && hasMarket && (rowScore >= 68 || apiGood);
      if (!provenCopy && !probeCopy) continue;
      // EXIT-BEFORE-DUMP, conviction-scaled: more KOLs / higher win-rate → ride a touch longer before
      // banking. exitMult feeds the engine's smart-money exit (sell into strength, ahead of the crowd).
      const learnedExit = profiles.map((p) => {
        const s = kolStatsForWallet(p.wallet);
        return s && s.exitN >= 2 ? s.exitSum / s.exitN : null;
      }).filter((x) => x != null);
      const exitMult = learnedExit.length
        ? Math.min(...learnedExit)
        : 1 + Math.min(2.2, (probeCopy ? 0.18 : 0.35) + (kolCount - 1) * 0.18 + Math.max(0, (g.bestWin || 0) - 50) / 120);
      out.push({
        tokenMint: mint,
        symbol: g.sym || shortMint(mint),
        marketCap: mc,
        liquidityUsd: liq,
        pairAgeSeconds: best?.pairCreatedAt ? Math.max(0, Math.round((now - Number(best.pairCreatedAt)) / 1000)) : null,
        volume5m: Number(best?.volume?.m5 || 0),
        buys5m: Number(best?.txns?.m5?.buys || 0),
        sells5m: Number(best?.txns?.m5?.sells || 0),
        sniperCount: 0,
        _smartMoney: { kol: provenCopy, kolProbe: probeCopy, winners: kolCount, exitMult, kolName: g.kolName || shortMint(mint), winRatePct: g.bestWin || null, learnedSignals: profiles.reduce((a, p) => a + p.signals, 0), source: probeCopy ? "kol_probe" : "kol_position" }
      });
    }
    // Strongest first: more KOLs, then higher win-rate, then fresher.
    out.sort((a, b) => (Number(b._smartMoney.kol) - Number(a._smartMoney.kol))
      || (b._smartMoney.winners - a._smartMoney.winners)
      || ((b._smartMoney.winRatePct || 0) - (a._smartMoney.winRatePct || 0)));
    const proven = out.filter((r) => r._smartMoney.kol).slice(0, KOL_COPY_FEED_MAX - KOL_COPY_PROBE_MAX);
    const probes = out.filter((r) => r._smartMoney.kolProbe).slice(0, KOL_COPY_PROBE_MAX);
    kolCopyFeedCache = { rows: [...proven, ...probes].slice(0, KOL_COPY_FEED_MAX), at: now };
    if (out.length) console.log(`[kol-copy] ${proven.length} proven + ${probes.length} probe KOL candidate(s) live from ${trackedKolWallets.size} tracked KOLs (top: ${out[0].symbol} · ${out[0]._smartMoney.winners} KOL)`);
    void saveKolLearning();
  } catch (e) { console.warn(`[kol-copy] ${e && e.message}`); }
  finally { kolCopyFeedRefreshing = false; }
}

// Prioritised wallet pool for the winner-follow poller: our OWN-proven winners first (we watched
// them win), then big-PnL seeded winners, then proven auto-KOLs / listed KOLs. Capped to the top
// WINNER_FOLLOW_POOL so the ST budget rotates over the BEST wallets, not every tracked address.
function winnerFollowPool() {
  const scored = [];
  for (const [w, r] of walletObs.entries()) {
    if (!isWinnerWallet(r)) continue;
    // BACKTEST-VALIDATED loser: copy-replay proved that copying this wallet LOSES money over a real
    // sample. Drop it from the live poll entirely — no point spending ST calls watching a proven leak.
    if (isBacktestedCopyLoser(r)) continue;
    let q = 0;
    if (isOrganicWinnerWallet(r) || isLinkedWinnerWallet(r)) q += 1000;     // OUR-proven outrank borrowed stats
    if (r.seeded) q += Math.min(400, Number(r.seedPnl) || 0) + (Number(r.seedWin) || 0); // leaderboard: PnL + win%
    // EARLY-ALPHA: repeat profitable early-entry is real skill — rank the 13-runner snipers near the
    // top, the lucky-twice ones below.
    if (r.earlyAlpha) q += 150 + Math.min(250, ((Number(r.earlyRunners) || 0) - 1) * 50) + Math.min(100, (Number(r.earlyRoi) || 0) / 2);
    // BACKTESTED COPY-EDGE dominates everything else once we have it: a proven 2.7x printer must sit at
    // the very top of the poll, a 1.0x neutral mid, regardless of its grab pedigree. This is the whole
    // point of the tune — watch the wallets that actually make US money, ranked by how much.
    if (r.btMult != null && (r.btSims || 0) >= 3) q += 1500 + (Number(r.btMult) - 1) * 1200;
    scored.push({ wallet: w, isKol: isKolWallet(w), q, tier: copyTierForWalletRecord(r), edge: Number.isFinite(Number(r.btMult)) ? Number(r.btMult) : null });
  }
  for (const w of autoKolWallets.keys()) {
    if (walletObs.has(w)) continue;
    scored.push({ wallet: w, isKol: true, q: 500 + (Number(autoKolWallets.get(w)?.winRate) || 0) });
  }
  for (const w of KOL_WALLETS) {
    if (walletObs.has(w) || autoKolWallets.has(w)) continue;
    scored.push({ wallet: w, isKol: true, q: 600 });
  }
  scored.sort((a, b) => b.q - a.q);
  return scored.slice(0, WINNER_FOLLOW_POOL);
}

// THE LIVE COPY EDGE. Rotate a few proven wallets per cycle, read their recent ST trades, and bank
// any FRESH SOL→token buy into a rolling per-mint tally. A coin 2+ deduped winners (or a KOL) bought
// recently becomes a PROVEN copy candidate — surfaced to the engine via smartMoneyFeed, entered
// instantly (it skips the red-tape comps veto). Cluster-deduped so a wallet-farm can't fake confluence.
async function pollWinnerTrades() {
  if (!CONFIG.solanaTrackerApiKey || winnerFollowPolling) return;
  winnerFollowPolling = true;
  try {
    const pool = winnerFollowPool();
    if (!pool.length) return;
    if (winnerFollowCursor >= pool.length) winnerFollowCursor = 0;
    const batch = pool.slice(winnerFollowCursor, winnerFollowCursor + WINNER_FOLLOW_BATCH);
    winnerFollowCursor += WINNER_FOLLOW_BATCH;
    const now = Date.now();
    for (const { wallet, isKol } of batch) {
      let trades = [];
      try {
        const d = await solanaTrackerJson(`/wallet/${encodeURIComponent(wallet)}/trades?limit=8`, { cacheTtlMs: 20_000, timeoutMs: 8_000 });
        trades = (d && d.trades) || [];
      } catch { continue; }
      for (const t of trades) {
        // BUY = SOL in, token out → the non-SOL `to` side is the bought mint (verified ST shape).
        const tk = (t && t.to && t.to.address && t.to.address !== SOL_MINT) ? t.to : null;
        if (!tk || !tk.address) continue;
        if (!(t.from && t.from.address === SOL_MINT)) continue;
        const raw = Number(t.time) || 0; const tms = raw > 1e12 ? raw : raw * 1000;
        if (!tms || (now - tms) > WINNER_FOLLOW_FRESH_MS) continue;
        let g = winnerBuys.get(tk.address);
        if (!g) { g = { clusters: new Set(), addrs: new Set(), lastAt: 0, kol: false, mc: 0 }; winnerBuys.set(tk.address, g); }
        g.clusters.add(clusterIdFor(wallet));
        g.addrs.add(wallet);
        if (isKol || isKolWallet(wallet)) g.kol = true;
        if (tms > g.lastAt) g.lastAt = tms;
        const mc = Number(tk.marketCap) || 0; if (mc > 0) g.mc = mc;
      }
      await new Promise((res) => setTimeout(res, 150));   // gentle pacing — never burst the instance
    }
    winnerFollowPolledTotal += batch.length;
    for (const [mint, g] of winnerBuys) { if ((now - g.lastAt) > WINNER_FOLLOW_FRESH_MS) winnerBuys.delete(mint); }
    const cands = [...winnerBuys.entries()]
      .sort((a, b) => (Number(b[1].kol) - Number(a[1].kol)) || (b[1].clusters.size - a[1].clusters.size) || (b[1].lastAt - a[1].lastAt))
      .slice(0, 30);
    if (!cands.length) { winnerFollowCache = { rows: [], at: now }; return; }
    // FREE enrichment: DexScreener batch → live MC + liquidity (no Helius / RPC). Engine re-verifies
    // sellable liquidity for liquid modes, so this is a fast first read.
    const pairs = await fetchDexScreenerTokenPairsBatch(cands.map(([mint]) => mint)).catch(() => []);
    const rows = [];
    for (const [mint, g] of cands) {
      const best = bestDexPairForToken(mint, (pairs || []).filter((p) => pairMatchesToken(p, mint)));
      const mc = Number(best?.marketCap || best?.fdv) || g.mc || 0;
      const liq = Number(best?.liquidity?.usd) || 0;
      if (!(mc >= 2_000 && liq >= 1_000)) continue;        // real, sellable market only (no phantoms)
      const winners = g.clusters.size;                      // cluster-deduped count
      // exitMult from the actual winners' learned style (sell into strength ahead of the dump); else
      // a conviction-scaled default that rides a touch longer with more confluence.
      const exits = [...g.addrs].map((w) => walletExitMult(walletObs.get(w))).filter((x) => Number.isFinite(x) && x > 1);
      const exitMult = exits.length ? Math.min(...exits) : 1 + Math.min(2.0, 0.25 + (winners - 1) * 0.2);
      // === COMPOSITE APE-SCORE: think better, ape the BEST opportunity, not just any signal. ===
      // 1) EDGE — the backtest-validated copy-multiple of the wallets actually in this coin (null=untested).
      const btVals = [...g.addrs].map((w) => { const r = walletObs.get(w); return (r && r.btMult != null && (r.btSims || 0) >= 3) ? Number(r.btMult) : null; }).filter((x) => x != null);
      const edge = btVals.length ? Math.round((btVals.reduce((a, b) => a + b, 0) / btVals.length) * 1000) / 1000 : null;
      const validatedPrinter = btVals.some((x) => x >= 1.2);
      const copyTier = btVals.some((x) => x >= 1.5) ? "A" : validatedPrinter ? "B" : g.kol || winners >= 2 ? "C" : "probe";
      const proven = g.kol || winners >= 2 || validatedPrinter;
      // 2) VELOCITY — buy-led m5 flow = "moving fastest right now" (neutral 0.5 when the sample is thin).
      const b5 = Number(best?.txns?.m5?.buys || 0), s5 = Number(best?.txns?.m5?.sells || 0);
      const buyFlow = (b5 + s5) >= 8 ? b5 / (b5 + s5) : 0.5;
      // 3) FRESHNESS — fresher buy = more upside left before the crowd. 4) CONFLUENCE — more elite wallets.
      const freshF = Math.max(0.3, 1 - ((now - g.lastAt) / 60000) / 25);
      const edgeF = edge != null ? Math.max(0.25, Math.min(2.2, edge)) : 1.0;     // validated multiple (neutral if untested)
      const apeScore = Math.round(edgeF * (1 + 0.25 * (winners - 1)) * (0.6 + 0.8 * buyFlow) * freshF * 100) / 100;
      rows.push({
        tokenMint: mint,
        symbol: best?.baseToken?.symbol || shortMint(mint),
        marketCap: mc,
        liquidityUsd: liq,
        pairAgeSeconds: best?.pairCreatedAt ? Math.max(0, Math.round((now - Number(best.pairCreatedAt)) / 1000)) : null,
        volume5m: Number(best?.volume?.m5 || 0),
        buys5m: b5,
        sells5m: s5,
        sniperCount: 0,
        _smartMoney: { kol: proven, kolProbe: !proven, winners, exitMult, learnedExit: exits.length > 0, edge, apeScore, buyFlow: Math.round(buyFlow * 100) / 100, kolName: "proven-winner", winRatePct: null, source: "winner_follow", copyTier, copyLadder: "s10_t40_f70" }
      });
    }
    // Rank by composite ape-score (validated edge × confluence × velocity × freshness) — best opportunity first.
    rows.sort((a, b) => (b._smartMoney.apeScore || 0) - (a._smartMoney.apeScore || 0));
    winnerFollowCache = { rows: rows.slice(0, WINNER_FOLLOW_MAX), at: now };
    if (rows.length) {
      const top = rows[0]; const tw = top._smartMoney.winners;
      console.log(`[winner-follow] ${rows.length} coin(s) our winners are buying (top ${top.symbol} · ${tw} winner${tw > 1 ? "s" : ""}${(top._smartMoney.kol || tw >= 2) ? " PROVEN" : ""}) — pool ${pool.length}, ${WINNER_FOLLOW_BATCH}/cycle`);
    }
  } catch (e) { console.warn(`[winner-follow] ${e && e.message}`); }
  finally { winnerFollowPolling = false; }
}
// Persist the market-wide tape so the bot isn't "blind" (marketTape() => null) for the
// first ~30 min after a redeploy. On load we keep only entries inside the 30-min window;
// stale ones are dropped (marketTape's own cutoff would ignore them anyway).
async function loadMarketTape() {
  try {
    const j = await readJson(MARKET_TAPE_FILE).catch(() => null);
    if (j && Array.isArray(j.recent)) {
      const cutoff = Date.now() - 30 * 60 * 1000;
      for (const e of j.recent) {
        if (e && Number(e.at) >= cutoff) marketRecent.push({ ranMult: Number(e.ranMult) || 1, rugged: Boolean(e.rugged), at: Number(e.at) });
      }
      if (marketRecent.length > 600) marketRecent.splice(0, marketRecent.length - 600);
    }
  } catch {}
}
async function saveMarketTape() {
  try { await writeJsonFile(MARKET_TAPE_FILE, { recent: marketRecent.slice(-600), savedAt: Date.now() }); } catch {}
}
async function loadKolLearning() {
  try {
    const j = await readJson(KOL_LEARNING_FILE).catch(() => null);
    if (j && j.tracked) for (const [w, r] of Object.entries(j.tracked)) trackedKolWallets.set(w, r);
    if (j && j.stats) for (const [w, r] of Object.entries(j.stats)) kolSignalStats.set(w, r);
    if (j && j.signals) {
      const cutoff = Date.now() - 2 * 60 * 60 * 1000;
      for (const [m, r] of Object.entries(j.signals)) {
        if (r && Number(r.at || 0) >= cutoff) kolSignalMints.set(m, r);
      }
    }
  } catch {}
}
async function saveKolLearning() {
  try {
    await writeJsonFile(KOL_LEARNING_FILE, {
      tracked: Object.fromEntries(trackedKolWallets),
      stats: Object.fromEntries(kolSignalStats),
      signals: Object.fromEntries(kolSignalMints),
      savedAt: Date.now()
    });
  } catch {}
}
async function sampleKolSignalOutcomes() {
  try {
    const now = Date.now();
    const active = [...kolSignalMints.entries()]
      .filter(([, r]) => now - Number(r.at || 0) < 2 * 60 * 60 * 1000)
      .sort((a, b) => Number(a[1].seen || 0) - Number(b[1].seen || 0))
      .slice(0, 30);
    if (!active.length) return;
    const pairs = await fetchDexScreenerTokenPairsBatch(active.map(([m]) => m)).catch(() => []);
    for (const [mint, rec] of active) {
      const best = bestDexPairForToken(mint, pairs);
      const mc = Number(best?.marketCap || best?.fdv) || 0;
      if (mc > 0) {
        if (!(rec.firstMc > 0)) rec.firstMc = mc;
        rec.maxMc = Math.max(Number(rec.maxMc) || 0, mc);
        rec.lastMc = mc;
        rec.seen = now;
        kolSignalMints.set(mint, rec);
      }
      const age = now - Number(rec.at || now);
      const ranMult = rec.firstMc > 0 ? Math.max(1, (Number(rec.maxMc) || rec.firstMc) / rec.firstMc) : 1;
      const rugged = rec.firstMc > 0 && ((Number(rec.maxMc) || rec.firstMc) >= rec.firstMc * 1.2 && (Number(rec.lastMc) || rec.firstMc) <= (Number(rec.maxMc) || rec.firstMc) * 0.35);
      const earlyRunner = ranMult >= 2 && age >= 5 * 60 * 1000;
      const done = earlyRunner || rugged || age >= 45 * 60 * 1000;
      if (done) recordKolOutcome(mint, ranMult, rugged);
    }
    for (const [mint, rec] of [...kolSignalMints.entries()]) {
      if (now - Number(rec.at || 0) >= 2 * 60 * 60 * 1000) kolSignalMints.delete(mint);
    }
    void saveKolLearning();
  } catch (e) { console.warn(`[kol-learn] ${e && e.message}`); }
}
function sampleDevObservatory() {
  try {
    const rows = pumpPortalStream.getCreationCandidates({ maxAgeMs: 30 * 60 * 1000, limit: 250 });
    const now = Date.now();
    const seen = new Set();
    for (const row of rows) {
      const mint = row.tokenMint; if (!mint) continue;
      const mc = Number(row.profile?.marketCap) || 0; if (mc <= 0) continue;
      const dev = String(row.profile?.devWallet || "").trim();
      seen.add(mint);
      const c = obsCoins.get(mint) || { dev, firstMc: mc, maxMc: mc, lastMc: mc, at: now, seen: now, buyers: [] };
      if (!c.dev && dev) c.dev = dev;
      c.maxMc = Math.max(c.maxMc, mc);
      c.lastMc = mc;
      c.seen = now;
      // One trade scan captures TWO things: the coin's early BUYER wallets (to score
      // them), and the gain-multiple at which any known WINNER wallet SELLS (to learn
      // each winner's exit style, so we can bank just BEFORE them next time).
      if (!c.buyers) c.buyers = [];
      // Merge the LIVE-captured early buyers (recordEarlyBuyer, via the stream's onTrade) — these
      // survive even after the coin's trade-sub is evicted, which is what the getTrades scan below
      // can't (it's empty once unsubscribed). This is the fix that makes walletObs actually fill.
      const eb = earlyBuyers.get(mint);
      if (eb) { for (const w of eb) { if (c.buyers.length < 15 && !c.buyers.includes(w)) c.buyers.push(w); } }
      try {
        for (const t of (pumpPortalStream.getTrades(mint, { limit: 40 }) || [])) {
          if (!t || !t.trader) continue;
          const w = String(t.trader);
          if (t.side === "buy") {
            if (c.buyers.length < 15 && !c.buyers.includes(w)) c.buyers.push(w);
          } else if (t.side === "sell" && c.firstMc > 0) {
            recordWalletExit(mint, w);
          }
        }
      } catch {}
      obsCoins.set(mint, c);
    }
    // Finalize coins that aged out of the buffer or got old enough to judge.
    for (const [mint, c] of obsCoins) {
      const old = now - c.at > 25 * 60 * 1000;
      const gone = !seen.has(mint) && now - c.seen > 90 * 1000;
      // EARLY-RUNNER CREDIT: the moment a watched coin confirms a 2x (and is >2min old, so it's a
      // real move not a single-tick blip), score its early buyers as winners NOW instead of waiting
      // ~25-30min to finalize. This builds the "wallets that get into coins early that run" roster
      // in MINUTES — the copy-trade roster the bot trades on — and judges each coin exactly once
      // (it's deleted right after). Non-runners still wait the full window to confirm they faded.
      const ranEarly = c.firstMc > 0 && c.maxMc >= c.firstMc * 2 && (now - c.at) > 120_000;
      if (old || gone || ranEarly) {
        const ranMult = c.firstMc > 0 ? c.maxMc / c.firstMc : 1;
        const rugged = (c.maxMc >= c.firstMc * 1.2 && c.lastMc <= c.maxMc * 0.3) || (c.firstMc > 0 && c.lastMc <= c.firstMc * 0.4);
        devObsBump(c.dev, ranMult, rugged);
        for (const w of (c.buyers || [])) walletObsBump(w, ranMult, rugged); // score early buyers
        linkRelatedBuyerWallets(c.buyers || [], ranMult, rugged); // detect fresh wallets tied to tracked/KOL wallets
        recordKolOutcome(mint, ranMult, rugged); // score any KOL API signal that pointed at this mint
        marketRecent.push({ ranMult, rugged, at: now }); // feed the market-wide tape
        if (marketRecent.length > 600) marketRecent.splice(0, marketRecent.length - 600);
        earlyBuyers.delete(mint); // done with this coin's live buyer buffer
        obsCoins.delete(mint);
      }
    }
    if (obsCoins.size > 5000) {
      for (const [m] of [...obsCoins.entries()].sort((a, b) => a[1].seen - b[1].seen).slice(0, 800)) obsCoins.delete(m);
    }
    void saveDevObservatory();
    void saveWalletObservatory();
    void saveMarketTape();
    void saveKolLearning();
  } catch (e) { console.warn(`[dev-obs] ${e && e.message}`); }
}
// SWAP-API EARLY-BUYER CAPTURE — the resurrection of the smart-money flywheel.
// The PumpPortal trade stream is DEAD for us (streamTrades:0, buyWsTrades:0), so the observatory
// captured NO buyers for the 100s of coins the brain watches → walletObs sat at 0 → copy-trade never
// activated. But swap-api.pump.fun DOES deliver per-trade buyer wallets server-side (verified 200;
// the group buy bot runs on it). So poll it for the FRESHEST watched coins and feed recordEarlyBuyer.
// No PumpPortal, no Helius, no API key — free, and it fills walletObs over the next hours of runtime.
const obsSwapSeenTx = new Map(); // mint -> Set(tx) — dedup so a buyer isn't re-counted each poll
let _obsSwapPolling = false;
async function pollObsTradesSwapApi() {
  if (_obsSwapPolling) return;
  _obsSwapPolling = true;
  try {
    // Freshest watched coins first — their early-buyer window is still open and they're what the
    // engine is actually evaluating. Bounded so we never flood the API.
    const coins = [...obsCoins.entries()].sort((a, b) => (b[1].seen || 0) - (a[1].seen || 0)).slice(0, 60).map(([m]) => m);
    for (let i = 0; i < coins.length; i += 8) {           // small concurrency, in chunks
      await Promise.all(coins.slice(i, i + 8).map(async (mint) => {
        let j = null;
        try { j = await fetch(`https://swap-api.pump.fun/v2/coins/${mint}/trades?limit=40`, { headers: { accept: "application/json" } }).then((r) => r.ok ? r.json() : null); } catch {}
        const trades = (j && Array.isArray(j.trades)) ? j.trades : [];
        if (!trades.length) return;
        let seen = obsSwapSeenTx.get(mint); if (!seen) { seen = new Set(); obsSwapSeenTx.set(mint, seen); }
        for (const t of trades) {
          const sig = String(t.tx || t.slotIndexId || ""); if (!sig || seen.has(sig)) continue; seen.add(sig);
          const side = String(t.type || "").toLowerCase();
          const trader = String(t.userAddress || ""); if (!trader) continue;
          if (side === "buy") recordEarlyBuyer(mint, { side: "buy", trader });
          else if (side === "sell") recordWalletExit(mint, trader);
        }
        if (seen.size > 200) { const a = [...seen]; obsSwapSeenTx.set(mint, new Set(a.slice(a.length - 150))); }
      }));
    }
    if (obsSwapSeenTx.size > 1500) { for (const m of [...obsSwapSeenTx.keys()]) if (!obsCoins.has(m)) obsSwapSeenTx.delete(m); }
  } catch {} finally { _obsSwapPolling = false; }
}
function startDevObservatory() {
  void loadDevObservatory().then(() => mergeDeployerGrabFile());   // fold in the offline deployer warehouse (once per grab) AFTER organic devObs loads
  void loadWalletObservatory().then(() => mergeBrainGrabFile());   // fold in the committed offline mass-grab (once per grab)
  void loadMarketTape();
  void loadKolLearning();
  void loadCoinBanners();
  // INSTANT LAUNCH SNIPER: keep the active-ticker set warm so onCreation can fire a watched snipe the
  // instant a matching coin streams in (create/cancel also refresh it). FREE — always on, sniper needs it.
  void refreshSnipeWatchTickers();
  setInterval(() => { void refreshSnipeWatchTickers(); }, 15_000);
  // EVERYTHING BELOW feeds the autopilot brain and burns Solana-Tracker credits + RPC. Gated OFF while
  // the autopilot is stopped (the user's call — it never won enough to justify the spend). Flip
  // AUTOPILOT_ENABLED=true on Render to resume the flywheel.
  if (!CONFIG.autopilotEnabled) {
    console.log("Autopilot brain feeders idle (AUTOPILOT_ENABLED=false) — winner-follow / copy-feed / seed-trickle / observatory pollers OFF to save ST credits + RPC.");
    return;
  }
  setInterval(sampleDevObservatory, 45_000);
  setInterval(() => { void sampleKolSignalOutcomes(); }, 60_000);
  setInterval(() => { void pollObsTradesSwapApi(); }, 18_000); // resurrect the buyer flywheel via the working swap-api source
  setInterval(() => { void pollWalletFunders(); }, 60_000);    // FUNDING GRAPH: resolve winner funders + clusters (free RPC, cached forever)
  setInterval(() => { void pollSeedTrickle(); }, 30_000);
  void loadAutoKolWallets().then(() => { void refreshAutoKolWallets(); });
  setInterval(() => { void refreshAutoKolWallets(); }, 10 * 60 * 1000);
  void refreshKolCopyFeed();
  setInterval(() => { void refreshKolCopyFeed(); }, KOL_COPY_FEED_TTL_MS);
  setTimeout(() => { void pollWinnerTrades(); setInterval(() => { void pollWinnerTrades(); }, WINNER_FOLLOW_INTERVAL_MS); }, 45_000);
}
// Combined dev reputation = our own trades + the market-wide observatory.
function combinedDevRep(dev) {
  if (!dev) return null;
  const mine = autopilotDevRep.get(dev);
  const obs = devObs.get(dev);
  if (!mine && !obs) return null;
  const trades = (mine?.trades || 0) + (obs?.coins || 0);
  const runners = (mine?.runners || 0) + (obs?.ran || 0);
  const rugs = (mine?.rugs || 0) + (obs?.rugged || 0);
  // avgPeak in %: our peakSum is already %, observatory peakSum is multiples.
  const minePct = mine?.peakSum || 0;
  const obsPct = obs ? (obs.peakSum * 100 - obs.coins * 100) : 0;
  const avgPeak = trades > 0 ? Math.round((minePct + obsPct) / trades) : 0;
  return { trades, runners, rugs, avgPeak, peakSum: minePct + obsPct, pnl: mine?.pnl || 0 };
}

// TRENDING feed cache for the autopilot liquid hunt — the boosted/trending tokens (dexscreener
// boosts/profiles) are coins of ANY age that are "starting to move" (a 6-month-old coin can boost
// and run). Enriched with full market data in ONE batch call, refreshed at most every ~30s so the
// hot scan path never hammers the API. The engine's liquidScore + safety gates still vet every row.
let autopilotTrendingCache = { at: 0, rows: [] };
async function autopilotTrendingRows() {
  if (Date.now() - autopilotTrendingCache.at < 30_000) return autopilotTrendingCache.rows;
  let rows = [];
  try {
    const cands = await fetchSniperCandidates({ ttlMs: 15_000 }).catch(() => []);
    const mints = [...new Set((cands || []).map((c) => c && c.tokenMint).filter(Boolean))].slice(0, 30);
    if (mints.length) {
      const pairs = await fetchDexScreenerTokenPairsBatch(mints).catch(() => []);
      const seen = new Set();
      for (const mint of mints) {
        const p = bestDexPairForToken(mint, pairs);
        if (!p) continue;
        const tm = (p.baseToken && p.baseToken.address) || mint;
        if (seen.has(tm)) continue;
        seen.add(tm);
        const created = Number(p.pairCreatedAt) || 0;
        rows.push({
          tokenMint: tm,
          symbol: (p.baseToken && p.baseToken.symbol) || "",
          pairAgeSeconds: created ? Math.max(0, Math.round((Date.now() - created) / 1000)) : undefined,
          marketCap: Number(p.marketCap || p.fdv) || 0,
          liquidityUsd: Number(p.liquidity && p.liquidity.usd) || 0,
          volume5m: Number(p.volume && p.volume.m5) || 0,
          volumeH1: Number(p.volume && p.volume.h1) || 0,
          buys5m: Number(p.txns && p.txns.m5 && p.txns.m5.buys) || 0,
          sells5m: Number(p.txns && p.txns.m5 && p.txns.m5.sells) || 0,
          buysH1: Number(p.txns && p.txns.h1 && p.txns.h1.buys) || 0,
          sellsH1: Number(p.txns && p.txns.h1 && p.txns.h1.sells) || 0,
          m5: Number.isFinite(Number(p.priceChange && p.priceChange.m5)) ? Number(p.priceChange.m5) : undefined,
          h1: Number.isFinite(Number(p.priceChange && p.priceChange.h1)) ? Number(p.priceChange.h1) : undefined,
          sniperCount: 0,
          bestPickScore: 0,
          _trending: true
        });
      }
    }
  } catch {}
  autopilotTrendingCache = { at: Date.now(), rows };
  return rows;
}

// ===== LIVE PRICE for the autopilot's coins via the WORKING swap-api =========================
// The autopilot apes FRESH pump coins, but getPairLite/getInstantMc read the PumpPortal trade tick
// (DEAD for us, streamTrades:0) and DexScreener (no pair for a pre-DEX bonding-curve coin) — so a
// freshly-aped coin had NO live price. That single gap caused ALL THREE reported bugs: the % froze
// then jumped on stale reads (inaccurate %), TP/stop couldn't fire (so it rode losers down → "still
// losing"), and the resulting feed-lost sell + re-entry cooldown re-bought the same coin ("aped a
// pair it already aped"). swap-api.pump.fun delivers real per-trade prices server-side (the buy bot
// runs on it). MC = median recent trade price × 1B pump supply = a real, SELLABLE mark.
const swapApiPriceCache = new Map(); // mint -> { mc, liq, px, at }
const heldReqAt = new Map();         // mint -> last time the engine asked for this coin's price (= it still holds it)
async function swapApiPriceFor(mint) {
  try {
    const j = await fetch(`https://swap-api.pump.fun/v2/coins/${mint}/trades?limit=8`, { headers: { accept: "application/json" } }).then((r) => r.ok ? r.json() : null);
    const trades = (j && Array.isArray(j.trades)) ? j.trades : [];
    const pxs = trades.map((t) => Number(t.priceUsd) || 0).filter((x) => x > 0).sort((a, b) => a - b);
    if (!pxs.length) return null;
    const px = pxs[Math.floor(pxs.length / 2)];   // MEDIAN — one thin-curve phantom tick can't fool the mark
    const rec = { mc: px * 1e9, liq: 0, px, at: Date.now() };
    swapApiPriceCache.set(mint, rec);
    return rec;
  } catch { return null; }
}
let _heldPxPolling = false;
async function pollHeldPricesSwapApi() {
  if (_heldPxPolling) return; _heldPxPolling = true;
  try {
    const now = Date.now();
    // Poll only coins the engine asked about in the last 90s (= it's still holding them). When a
    // position sells, the engine stops calling getPairLite for it → it ages out → we stop polling.
    const active = [...heldReqAt.entries()].filter(([, t]) => now - t < 90_000).map(([m]) => m).slice(0, 30);
    for (let i = 0; i < active.length; i += 8) await Promise.all(active.slice(i, i + 8).map(swapApiPriceFor));
    for (const [m, t] of [...heldReqAt.entries()]) if (now - t > 120_000) { heldReqAt.delete(m); swapApiPriceCache.delete(m); } // GC sold/dead
  } catch {} finally { _heldPxPolling = false; }
}
setInterval(() => { void pollHeldPricesSwapApi(); }, 3000); // keep held coins hot so per-tick exit checks are fast cache hits

// ---------------------------------------------------------------------------
// NOTABLE-X CLOUT for the launch sniper (the user's top-priority "X link from a big name" signal).
// FREE, no X API: resolve a fresh launch's attached X handle from pump metadata, then score the
// account's clout via the fxtwitter mirror (real follower count) + our own tracked-KOL/caller name
// roster. Cached per mint (a coin's X never changes) + per handle (clout is stable). Trickle-polled
// ONLY while a SNIPE mode is active — crash-loop-safe (≤3 mints/cycle, spaced). The engine reads the
// attached row.xClout (0 none / 1 known-sizable / 2 big-name) in snipeSignalScore.
const SNIPE_X_CLOUT = new Map();   // mint -> { clout, handle, at }
const SNIPE_X_HANDLE = new Map();  // handle(lower) -> { clout, at }
const SNIPE_X_SEEN = new Set();    // mints already attempted this run (don't re-hammer)
let lastFreshMints = [];           // the mints the fresh feed last returned (the sniper's candidate pool)

function extractXHandle(url) {
  const m = String(url || "").match(/(?:twitter|x)\.com\/(?:#!\/)?@?([A-Za-z0-9_]{1,15})(?:[/?#]|$)/i);
  if (!m) return null;
  const h = m[1].toLowerCase();
  if (["i", "intent", "home", "search", "share", "hashtag", "explore", "messages", "notifications", "communities", "compose", "status", "about"].includes(h)) return null;
  return m[1];
}

// Is this handle one of our tracked KOLs / known callers by name? (free, curated roster check).
function isNotableHandle(handle) {
  const h = String(handle || "").toLowerCase().replace(/^@/, "");
  if (!h) return false;
  for (const rec of trackedKolWallets.values()) {
    const n = String((rec && rec.name) || "").toLowerCase().replace(/^@/, "");
    if (n && n === h) return true;
  }
  return false;
}

async function assessXClout(handle) {
  const key = String(handle || "").toLowerCase();
  if (!key) return 0;
  const cached = SNIPE_X_HANDLE.get(key);
  if (cached && Date.now() - cached.at < 6 * 60 * 60 * 1000) return cached.clout;
  let clout = 0;
  if (isNotableHandle(handle)) clout = 2;
  else {
    try {
      const j = await fetchJson(`https://api.fxtwitter.com/${encodeURIComponent(handle)}`, { timeoutMs: 7000, headers: { "User-Agent": "SlimeWireBot/1.0" } }).catch(() => null);
      const u = (j && (j.user || j.data || j)) || {};
      const followers = Number(u.followers || u.followers_count || 0) || 0;
      const verified = Boolean(u.verified || u.is_blue_verified);
      if (followers >= 100000 || (verified && followers >= 25000)) clout = 2;
      else if (followers >= 10000) clout = 1;
      else clout = 0;
    } catch { clout = 0; }
  }
  SNIPE_X_HANDLE.set(key, { clout, at: Date.now() });
  return clout;
}

async function resolveTokenXClout(mint) {
  if (!mint) return 0;
  const cached = SNIPE_X_CLOUT.get(mint);
  if (cached) return cached.clout;
  let handle = null;
  try {
    const j = await fetchJson(`https://frontend-api-v3.pump.fun/coins/${mint}`, { timeoutMs: 7000, headers: { "User-Agent": "Mozilla/5.0", accept: "application/json" } }).catch(() => null);
    handle = extractXHandle((j && (j.twitter || j.twitter_url)) || "");
  } catch {}
  const clout = handle ? await assessXClout(handle) : 0;
  SNIPE_X_CLOUT.set(mint, { clout, handle, at: Date.now() });
  if (clout >= 1) console.log(`[autopilot:info] ⭐ notable X (clout ${clout}) @${handle} on ${String(mint).slice(0, 6)}…`);
  return clout;
}

let _snipeXPolling = false;
async function pollSnipeXClout() {
  if (_snipeXPolling) return;
  let mode = null;
  try { mode = autopilotEngine.status()?.mode || null; } catch {}
  if (!mode || !/^snipe/i.test(mode)) return;          // only spend calls when actually sniping
  _snipeXPolling = true;
  try {
    let done = 0;
    for (const m of (lastFreshMints || [])) {
      if (done >= 3) break;                              // gentle: ≤3 mints/cycle
      if (!m || SNIPE_X_SEEN.has(m)) continue;
      SNIPE_X_SEEN.add(m);
      try { await resolveTokenXClout(m); } catch {}
      done += 1;
      await new Promise((r) => setTimeout(r, 200));      // spacing (crash-loop-safe)
    }
    if (SNIPE_X_SEEN.size > 4000) SNIPE_X_SEEN.clear();
  } finally { _snipeXPolling = false; }
}
setInterval(() => { void pollSnipeXClout(); }, 15_000);

// ===== SOCIAL-VELOCITY ("trending on X hard") — the cheapest real-time virality signal ===========
// The X-clout above only asks "is the coin's OWN attached account notable?" This asks the bigger
// question the user wants: "is this CA/ticker suddenly getting posted by LOTS of real accounts right
// now?" — mention velocity + unique authors + follower-weighted reach + notable-account detection.
// CHEAPEST FAST PATH (no overpay): twitterapi.io advanced-search, pay-as-you-go (~$0.15/1k tweets, no
// monthly minimum, ~500ms). We do bot-filtering + notable detection ourselves with the FREE fxtwitter
// roster we already have — NO paid scoring service, NO official X API. DORMANT until TWITTERAPI_KEY is
// set: every function below no-ops and costs $0 without it, so it can't affect the live bot until you
// opt in. Set TWITTERAPI_KEY on Render to switch it on. The heat (0/1/2) folds into row.xClout so it
// flows straight into snipeSignalScore's X signal + confluenceMult — works for snipes AND bigger pairs.
const TWITTERAPI_KEY = process.env.TWITTERAPI_KEY || process.env.TWITTERAPI_IO_KEY || "";
const SOCIAL_HEAT = new Map();     // mint -> { heat, authors, topFollowers, at }
const SOCIAL_HEAT_SEEN = new Set();
const lastFreshSyms = new Map();   // mint -> symbol (so the poller can search the ticker)

// COST GUARD ("don't overpay"): hard daily cap on twitterapi.io searches (~$0.003 each). A fresh
// day resets it; once hit, social-heat lookups no-op until tomorrow. Default 300/day (≈ $0.90/day,
// ≈ $27/mo worst case); tune via SOCIAL_HEAT_DAILY_CAP. Only counts ACTUAL fetches (cache hits free).
let _socialDay = "", _socialCalls = 0;
function socialBudgetOk() {
  const day = new Date().toISOString().slice(0, 10);
  if (day !== _socialDay) { _socialDay = day; _socialCalls = 0; }
  const cap = Math.max(50, Number(process.env.SOCIAL_HEAT_DAILY_CAP) || 300);
  if (_socialCalls >= cap) return false;
  _socialCalls += 1;
  return true;
}

// Pure: turn a filtered mention set into a 0/1/2 heat score. Velocity = UNIQUE authors (dedup bots),
// weighted by reach (top follower count) and whether a notable account is on it. Exported-shape logic
// kept tiny + inspectable. >=8 distinct real authors OR a big/notable account = "trending hard" (2).
function scoreSocialHeat({ authors, topFollowers, notable }) {
  if (notable || authors >= 8 || topFollowers >= 100000) return 2;
  if (authors >= 4 || topFollowers >= 25000) return 1;
  return 0;
}

async function fetchTwitterMentions(query) {
  if (!TWITTERAPI_KEY) return null;
  try {
    const url = `https://api.twitterapi.io/twitter/tweet/advanced_search?queryType=Latest&query=${encodeURIComponent(query)}`;
    const j = await fetchJson(url, { timeoutMs: 8000, headers: { "X-API-Key": TWITTERAPI_KEY } }).catch(() => null);
    const tweets = j && (j.tweets || j.data || j.results || (j.tweet ? [j.tweet] : null));
    return Array.isArray(tweets) ? tweets : [];
  } catch { return null; }
}

async function assessSocialHeat(mint, symbol) {
  if (!TWITTERAPI_KEY) return 0;
  const sym = String(symbol || "").replace(/^\$/, "").trim();
  if (sym.length < 2 || sym.length > 12 || !/^[A-Za-z0-9_]+$/.test(sym)) return 0;  // skip empty/too-generic tickers
  const cached = SOCIAL_HEAT.get(mint);
  if (cached && Date.now() - cached.at < 8 * 60 * 1000) return cached.heat;
  if (!socialBudgetOk()) return 0;                                 // daily cost cap reached → no-op until tomorrow
  const tweets = await fetchTwitterMentions(`$${sym}`);
  if (!Array.isArray(tweets)) return 0;
  const authors = new Set();
  let topF = 0, notable = false;
  for (const t of tweets) {
    const a = (t && (t.author || t.user)) || {};
    const followers = Number(a.followers ?? a.followersCount ?? a.followers_count ?? 0) || 0;
    const handle = String(a.userName || a.screen_name || a.username || "").toLowerCase();
    if (followers < 150) continue;                                   // bot/spam filter: drop near-zero accounts
    if (handle) authors.add(handle);
    if (followers > topF) topF = followers;
    if (followers >= 50000 || isNotableHandle(handle)) notable = true;
  }
  const heat = scoreSocialHeat({ authors: authors.size, topFollowers: topF, notable });
  SOCIAL_HEAT.set(mint, { heat, authors: authors.size, topFollowers: topF, at: Date.now() });
  if (heat >= 1) console.log(`[autopilot:info] 🔥 social heat ${heat} on $${sym} (${authors.size} real authors, top ${topF} followers)`);
  return heat;
}

let _socialPolling = false;
async function pollSocialHeat() {
  if (!TWITTERAPI_KEY || _socialPolling) return;                     // dormant + zero-cost without the key
  _socialPolling = true;
  try {
    let done = 0;
    for (const m of (lastFreshMints || [])) {
      if (done >= 3) break;                                          // gentle: ≤3 lookups/cycle (cost + crash-safe)
      if (!m || SOCIAL_HEAT_SEEN.has(m)) continue;
      const sym = lastFreshSyms.get(m);
      if (!sym) continue;
      SOCIAL_HEAT_SEEN.add(m);
      try { await assessSocialHeat(m, sym); } catch {}
      done += 1;
      await new Promise((r) => setTimeout(r, 250));
    }
    if (SOCIAL_HEAT_SEEN.size > 4000) SOCIAL_HEAT_SEEN.clear();
  } finally { _socialPolling = false; }
}
setInterval(() => { void pollSocialHeat(); }, 20_000);

// ===== POP RADAR — real-time IGNITION detector (the "get in before the pop" entry engine) =========
// Detects a coin POPPING right now from its LIVE trade flow: net SOL inflow ACCELERATING vs its own
// recent baseline + buy-led (sellers drying) + a BURST of distinct buyers (+ smart-money bonus). Fed by
// the free per-trade sources we already run 24/7 — the PumpPortal onTrade stream (real-time) + a focused
// swap-api fast-poll on the freshest candidates. Surfaces igniting coins as a pre-vetted, top-priority
// "pop" feed the 'pop' mode trades (MC-AGNOSTIC — flow leads, MC lags). The score is the pure
// popIgnitionScore() in the engine; here we compute the live flow metrics + the momentum-fade signal.
const popTrades = new Map();      // mint -> [{ at, side, sol, trader }]  (rolling, last ~45s)
const popSeenTx = new Map();      // mint -> Set(tx)  (swap-api dedup)
const popCandidates = new Map();  // mint -> { at, score, mc, symbol, inflowNow, spike?, liq?, m5? }
const POP_SPIKE_FIRE = 44;        // jumpScore at/above which a live-feed coin counts as "spiking NOW" (vol surge + m5 breakout + buy-led)
const popPeakInflow = new Map();  // mint -> peak recent buy-inflow (drives the momentum-fade exit)
const popHeldMints = new Map();   // mint -> at  (open pop positions kept watched so fade can fire)
let _popHb = 0;                   // radar heartbeat counter
let _popSrcTick = 0;              // throttle the live-feed source refresh
let _popSrcBusy = false;          // a live-feed refresh is in flight (non-blocking)
let popLiveMints = [];            // route-filtered MC-spread movers from the live feed (cached ~15s)
let popLiveRows = [];             // SPIKE RADAR: the FULL live-feed rows (m5/vol5m/buys5m/liq/mc) — scored by jumpScore so we catch coins VISIBLY ripping on DexScreener (price+volume spike), not just on-curve SOL inflow
const popUnroutable = new Set();  // mints we've confirmed are Token-2022 / un-routable (skip — "rugs that won't show on routes")
const _popRouteChecked = new Set();  // mints whose route/safety we've already checked (don't re-check every poll)
function popIngestTrade(mint, trade) {
  if (!mint || !trade) return;
  const sol = Number(trade.solAmount ?? trade.amountSol ?? trade.sol) || 0;
  const side = String(trade.side || trade.type || "").toLowerCase() === "sell" ? "sell" : "buy";
  const at = Number(trade.at) || Date.now();
  let arr = popTrades.get(mint); if (!arr) { arr = []; popTrades.set(mint, arr); }
  arr.push({ at, side, sol, trader: String(trade.trader || trade.userAddress || "") });
  const cut = Date.now() - 45_000;
  while (arr.length && arr[0].at < cut) arr.shift();
  if (arr.length > 240) arr.splice(0, arr.length - 240);
}
function popMetrics(mint, nowMs) {
  const arr = popTrades.get(mint); if (!arr || arr.length < 4) return null;
  const W = 8_000;                                        // 8s "now" window vs the prior 24s baseline
  const now0 = nowMs - W, baseStart = nowMs - 4 * W;
  let buyNow = 0, sellNow = 0, buySolNow = 0, buySolBase = 0; const buyers = new Set();
  for (const t of arr) {
    if (t.at >= now0) { if (t.side === "buy") { buyNow++; buySolNow += t.sol; if (t.trader) buyers.add(t.trader); } else sellNow++; }
    else if (t.at >= baseStart) { if (t.side === "buy") buySolBase += t.sol; }
  }
  let smart = false;
  for (const w of buyers) { if (isKolWallet(w) || isWinnerWallet(walletObs.get(w))) { smart = true; break; } }
  return { accel: buySolNow / Math.max(buySolBase / 3, 0.05), inflowNow: buySolNow, buyShare: (buyNow + sellNow) > 0 ? buyNow / (buyNow + sellNow) : 0, uniqBuyers: buyers.size, smart };
}
// True once the inflow that drove OUR ENTRY has DECELERATED (the engine's momentum-fade exit calls
// this). CRITICAL: fade against the peak SINCE WE ENTERED, not the coin's LIFETIME peak. A coin we
// buy mid-run (whose all-time inflow spike was minutes ago) would otherwise read as "already faded"
// on the very first tick and we'd instant-sell every entry (live bug: Bb4j peaked 57 SOL/8s 20min
// before we bought at ~4 → 4 < 57*0.35 → instant pop-fade). An 8s min-hold also gives a genuinely
// fresh pop room to develop; the -10% stop still guards a real crash during that window.
const POP_FADE_MIN_HOLD_MS = 8_000;
function popFadingNow(mint) {
  const h = popHeldMints.get(mint);
  if (h && Date.now() - h.at < POP_FADE_MIN_HOLD_MS) return false;   // just entered — let it breathe
  const peak = (h && h.peak) || popPeakInflow.get(mint) || 0;        // peak SINCE ENTRY (fallback: lifetime)
  if (peak < 0.3) return false;                          // never really popped -> nothing to fade
  const m = popMetrics(mint, Date.now());
  if (!m) return true;                                   // no live trades at all = the burst is dead
  return m.inflowNow < peak * 0.35;                      // collapsed to <35% of the post-entry peak = pop is over
}
// Coerce a webLivePairs row's m5/h1 (stored as an OBJECT {priceChange} OR a number) to a plain number
// %, which is what liquidScore/jumpScore expect. Undefined when unparseable (the scorers skip it).
function liveRowPct(v) {
  if (v && Number.isFinite(Number(v.priceChange))) return Number(v.priceChange);
  return Number.isFinite(Number(v)) ? Number(v) : undefined;
}
// Carry the ENRICHED feed signals the autopilot needs (rug hard-gate + situational "what can run
// now" read) instead of dropping them in the feed adapters — the root cause of the bot "buying blind"
// on a thin score band. riskFlags carries freezeAuthorityActive/mintAuthorityActive/token2022
// (derived by pairRiskFlags); rugRisk/manipulationScore/devInfoSummary/category/bonding power the
// expert read. See fresh-feed-contract + autopilot rebuild.
function autopilotEnrichedFields(r = {}) {
  return {
    riskFlags: Array.isArray(r.riskFlags) ? r.riskFlags : [],
    safetyNote: r.safetyNote || "",
    slimeScopeCategory: r.slimeScopeCategory || r.category || "",
    rugRisk: r.rugRisk,
    manipulationScore: r.manipulationScore,
    devInfoSummary: r.devInfoSummary || null,
    bondingProgressPct: Number(r.bondingProgressPct) || 0,
    graduated: Boolean(r.graduated || r.isGraduated),
    isPump: Boolean(r.isPump),
    smartMoney: r.smartMoney,
    freezeAuthority: r.freezeAuthority || "",
    mintAuthority: r.mintAuthority || "",
    tokenProgram: r.tokenProgram || ""
  };
}

// CHEAP rug hard-gate (free — reads already-computed signals): drop coins with KNOWN danger before
// the autopilot ever scores them. Fresh-ape semantics — only genuine danger blocks; unknown/"check"
// (a brand-new coin not yet enriched) is NOT treated as danger (the engine + pre-buy SlimeShield
// check vet further). This is the host-side complement to the engine's pre-buy securityGate.
function autopilotRowHasHardDanger(r = {}) {
  // FEED-LEVEL hard gate = ONLY unambiguous rug/scam vectors. It must stay LOOSE: live diagnostics
  // showed the old version nuking 48/50 fresh coins (out=2) → the blend/steady engine "found nothing
  // to buy." TWO over-rejections removed (2026-06-20): (1) token2022 — a pump Token-2022 on a trusted
  // pool IS buyable (see the pop route-filter fix bd226f5; ~44% of pump launches are Token-2022), so
  // it's not hard danger; (2) the rugRisk>=85 / manipulationScore>=85 HEURISTICS — they score brand-
  // new fresh dust as "risky" en masse. The REAL per-coin safety is the PRE-BUY securityGate (full
  // SlimeShield, re-checks every candidate right before the buy) + the entry gauntlet, so the feed
  // gate only needs to drop the clear scams here. Keep active freeze/mint authority + honeypot/
  // blacklist/mayhem/hardblock (genuine, unfakeable rug vectors).
  const flags = (Array.isArray(r.riskFlags) ? r.riskFlags : []).map((f) => String(f).toLowerCase());
  // NOTE (2026-06-21): freezeAuthorityActive / mintAuthorityActive are DROPPED from this feed gate.
  // They were a SYSTEMATIC FALSE POSITIVE on Token-2022 pump coins — verified on-chain that 50/50
  // flagged fresh coins had freezeAuthority=null, yet the derived flag stamped them, collapsing the
  // candidate pool to out=1 of 50 ("feed quiet, bought nothing"). The flag comes from a provider
  // jsonParsed mis-read upstream; the AUTHORITATIVE freeze/mint check now runs at BUY time in
  // assertTokenBuyBaseSafety, which decodes the authority from the RAW mint bytes (provider-independent,
  // correct for SPL + Token-2022). So a real freeze/mint authority is still BLOCKED before any SOL is
  // spent — this gate just stops pre-rejecting safe coins on a broken flag. Keep the genuine,
  // unfakeable scam vectors below.
  if (flags.some((f) => /honeypot|mayhem|hardblock|blacklist/.test(f))) return true;
  const rug = Number(r.rugRisk); if (Number.isFinite(rug) && rug >= 97) return true;            // only the most extreme AVOID-grade
  return false;
}

// ===== LIVE-ACTIVITY ENRICHMENT — the FIX for "Pop Radar best jump 0" / "only losing, no spikes".
// The mover pool is built from DexScreener /search, whose rows almost NEVER carry the 5-minute
// micro-window (volume5m, txns.m5, priceChange.m5) the spike detector (jumpScore) and entry scorer
// need — verified live: only ~5/50 rows had any 5m data, so ~90% scored 0 and the bot traded blind,
// aping stale near-mega-caps that instantly rug-scratched. DexScreener's BATCH token endpoint
// (/tokens/v1/solana/{addrs}, 30/call) DOES return the populated 5m/h1 window (verified: the same
// coins that showed v5=0 there came back m5 +10%, real vol+txns here). So before scoring, overlay
// REAL current activity onto the in-band candidates: now jumpScore can SEE a coin ripping NOW, and
// liquidScore/entry decisions run on live turnover/flow instead of zeros. Cached 12s per mint so the
// 4s pop poll + every-hunt liquid feed reuse one fetch (cheap: ~2 batch calls / 20s, well under the
// free-tier budget). Mutates rows in place (and returns them).
const _dexActCache = new Map();   // mint -> { at, v5, vH1, b5, s5, bH1, sH1, m5, h1, mc, liq }
function applyDexActivity(r, act) {
  // Only overlay when the batch endpoint actually HAS activity — never zero out a row that already
  // carried real data (the 5/50 that did). DexScreener pc.* are plain percent numbers (what jumpScore
  // reads via Number(row.m5)); vol/txns are the m5/h1 windows liquidScore/jumpScore turnover needs.
  if (act.v5 > 0) r.volume5m = act.v5;
  if (act.b5 + act.s5 > 0) { r.buys5m = act.b5; r.sells5m = act.s5; }
  if (act.vH1 > 0) r.volumeH1 = act.vH1;
  if (act.bH1 + act.sH1 > 0) { r.buysH1 = act.bH1; r.sellsH1 = act.sH1; }
  if (Number.isFinite(act.m5)) r.m5 = act.m5;
  if (Number.isFinite(act.h1)) r.h1 = act.h1;
  if (act.mc > 0 && !(Number(r.marketCap) > 0)) r.marketCap = act.mc;
  if (act.liq > 0 && !(Number(r.liquidityUsd) > 0)) r.liquidityUsd = act.liq;
  return r;
}
async function enrichRowsWithDexActivity(rows, { limit = 60, mcMin = 6000, mcMax = 400000 } = {}) {
  if (!Array.isArray(rows) || !rows.length) return rows;
  const now = Date.now();
  const need = [];
  for (const r of rows) {
    if (!r || !r.tokenMint) continue;
    const mc = Number(r.marketCap) || 0;
    // Tradeable pop band OR unknown MC (fresh climbers often have MC but no activity). Skip mega-caps.
    if (!(mc === 0 || (mc >= mcMin && mc <= mcMax))) continue;
    const cached = _dexActCache.get(r.tokenMint);
    if (cached && now - cached.at < 12_000) { applyDexActivity(r, cached); continue; }   // reuse fresh
    const hasAct = (Number(r.volume5m) || 0) > 0 || (Number(r.buys5m) || 0) + (Number(r.sells5m) || 0) > 0;
    if (!hasAct || mc === 0) need.push(r.tokenMint);   // only fetch the BLIND ones
  }
  const mints = [...new Set(need)].slice(0, limit);
  if (!mints.length) return rows;
  const batches = [];
  for (let i = 0; i < mints.length; i += 30) batches.push(mints.slice(i, i + 30));
  const results = await Promise.all(batches.map((b) => fetchDexScreenerTokenPairsBatch(b).catch(() => [])));
  const pairs = results.flat();
  const byMint = new Map();
  for (const m of mints) {
    const p = bestDexPairForToken(m, pairs);
    if (!p) continue;
    const vol = p.volume || {}, tx = p.txns || {}, pc = p.priceChange || {};
    const m5tx = tx.m5 || {}, h1tx = tx.h1 || {};
    const act = {
      at: now,
      v5: Number(vol.m5) || 0, vH1: Number(vol.h1) || 0,
      b5: Number(m5tx.buys) || 0, s5: Number(m5tx.sells) || 0,
      bH1: Number(h1tx.buys) || 0, sH1: Number(h1tx.sells) || 0,
      m5: Number.isFinite(Number(pc.m5)) ? Number(pc.m5) : undefined,
      h1: Number.isFinite(Number(pc.h1)) ? Number(pc.h1) : undefined,
      mc: Number(p.marketCap || p.fdv) || 0,
      liq: Number(p.liquidity && p.liquidity.usd) || 0
    };
    _dexActCache.set(m, act);
    byMint.set(m, act);
  }
  for (const r of rows) { const act = byMint.get(r.tokenMint); if (act) applyDexActivity(r, act); }
  if (_dexActCache.size > 800) { for (const [k, v] of _dexActCache) { if (now - v.at > 60_000) _dexActCache.delete(k); } }
  return rows;
}

// The broad NORMALIZED liquid-movers pool — the scalp feed scores it. Rows carry m5/h1 as NUMBERS
// (raw webLivePairs stores m5 as an object {priceChange}) + real liquidityUsd, which is exactly what
// liquidScore/jumpScore need. ~120 coins across fresh→24h buckets + trending. The in-band rows are
// then DexScreener-activity enriched so entry scoring runs on REAL live turnover/flow, not zeros.
async function buildLiquidMovers() {
  const BUCKETS = ["live", "under1h", "under3h", "under1d"];
  const SORTS = ["liquidity", "volume", "momentum"];
  const jobs = [];
  for (const b of BUCKETS) for (const s of SORTS) jobs.push(webLivePairs("autopilot", b, { sort: s, feed: "ap" }).catch(() => null));
  let feeds = [];
  try { feeds = await Promise.all(jobs); } catch {}
  try { const trending = await autopilotTrendingRows(); if (trending && trending.length) feeds.push({ rows: trending }); } catch {}
  const seen = new Set();
  const out = [];
  for (const feed of feeds) {
    for (const r of (Array.isArray(feed?.rows) ? feed.rows : [])) {
      if (!r || !r.tokenMint || seen.has(r.tokenMint)) continue;
      const lq = Number(r.liquidityUsd) || 0;
      if (lq > 0 && lq < 1500) continue;           // drop KNOWN-thin only; keep unknown-liq (engine vets)
      if (autopilotRowHasHardDanger(r)) continue;  // rug hard-gate: drop KNOWN-dangerous before scoring
      seen.add(r.tokenMint);
      out.push({
        tokenMint: r.tokenMint, symbol: r.symbol, pairAgeSeconds: r.pairAgeSeconds,
        marketCap: r.marketCap, liquidityUsd: r.liquidityUsd, volume5m: r.volume5m, volumeH1: r.volumeH1,
        buys5m: r.buys5m, sells5m: r.sells5m, buysH1: r.buysH1, sellsH1: r.sellsH1,
        m5: liveRowPct(r.m5), h1: liveRowPct(r.h1),
        sniperCount: r.sniperCount || r.snipers || 0,
        bestPickScore: r.bestPickScore || r.bestPick || 0,
        ...autopilotEnrichedFields(r)
      });
    }
  }
  out.sort((a, b) => (Number(b.liquidityUsd) || 0) - (Number(a.liquidityUsd) || 0));
  const top = out.slice(0, 120);
  // Overlay REAL live 5m/h1 activity onto the BLIND in-band rows so liquidScore/jumpScore/entry
  // decisions run on actual turnover/flow — the feed's /search rows mostly carry zeros for the
  // micro-window, which made the bot ape near-blind mega-caps that instantly rug-scratched.
  try { await enrichRowsWithDexActivity(top, { limit: 50 }); } catch {}
  return top;
}
let _popPolling = false;
async function pollPopRadar() {
  if (_popPolling) return; _popPolling = true;
  try {
    const now = Date.now();
    for (const [m, h] of popHeldMints) { if (now - ((h && h.at) || 0) > 8 * 60_000) popHeldMints.delete(m); }
    // WATCHLIST = a SPREAD of routable movers, not just fresh dust:
    //  • the live feed (DexScreener pairs) volume+momentum sorts → real routable coins across the WHOLE
    //    MC range (5k→40k+). A coin with a real Pump/Raydium/etc. pool shows here; a pool-less rug does
    //    NOT — exactly "use routes that rugs won't show on / do like our live feed". Refreshed ~15s.
    //  • the freshest pump.fun launches from the 24/7 creation stream (the early sub-5k pops).
    //  • open pop positions (so the momentum-fade can keep scoring them).
    _popSrcTick = (_popSrcTick + 1) % 5;
    if ((_popSrcTick === 0 || !popLiveMints.length) && !_popSrcBusy) {
      // FIRE-AND-FORGET — never block the poll cycle on the live-feed fetch (a hang there would freeze
      // the radar by leaving _popPolling stuck). popLiveMints just updates whenever the fetch resolves.
      _popSrcBusy = true;
      void (async () => {
        try {
          // LEAN focused fetch for the spike scan — ONLY the 4 keys where a CURRENT spike shows (recent
          // buckets × momentum/volume sorts). NOT the heavy 12-key buildLiquidMovers: that runs always
          // (radar is on 24/7) and was competing with the Pairs page for the shared live-feed cache,
          // starving it (pairs flicker / stale categories / dev-info timeouts). Rows are NORMALIZED so
          // jumpScore reads m5/h1 as NUMBERS (raw webLivePairs stores m5 as an object {priceChange}).
          // INCLUDE deeper, LIQUID buckets — not just live/under1h. jumpScore requires >=$4k liquidity
          // to score above 0 (it won't chase a coin it can't exit), and fresh live/under1h coins are
          // mostly sub-$4k thin curves → "best jump 0" for every mover. The under6h/graduated buckets
          // carry the exitable DexScreener-pool movers a real spike scan needs. Still lean (6 keys, not
          // the 12-key buildLiquidMovers) so it doesn't starve the Pairs page.
          const combos = [["live", "momentum"], ["under1h", "volume"], ["under6h", "volume"], ["under6h", "momentum"], ["graduated", "volume"], ["graduated", "momentum"]];
          const results = await Promise.all(combos.map(([b, s]) => webLivePairs("autopilot", b, { sort: s, feed: "ap" }).catch(() => null)));
          const seen = new Set(); const rows = [];
          for (const f of results) for (const r of (Array.isArray(f && f.rows) ? f.rows : [])) {
            if (!(r && r.tokenMint) || seen.has(r.tokenMint)) continue;
            if (autopilotRowHasHardDanger(r)) continue;  // rug hard-gate
            seen.add(r.tokenMint);
            rows.push({
              tokenMint: r.tokenMint, symbol: r.symbol, marketCap: r.marketCap, liquidityUsd: r.liquidityUsd,
              volume5m: r.volume5m, buys5m: r.buys5m, sells5m: r.sells5m,
              m5: liveRowPct(r.m5), h1: liveRowPct(r.h1),
              ...autopilotEnrichedFields(r)
            });
          }
          // Overlay REAL live 5m/h1 activity onto the in-band candidates — the spike radar's whole
          // job is jumpScore (vol surge + m5 breakout + buy-led), but the /search feed rows almost
          // never carry the 5m window, so it saw "best jump 0" forever. Now it can SEE spikes NOW.
          const enriched = rows.slice(0, 140);
          try { await enrichRowsWithDexActivity(enriched, { limit: 50, mcMax: 300000 }); } catch {}
          if (enriched.length) { popLiveRows = enriched; popLiveMints = enriched.map((r) => r.tokenMint).slice(0, 40); }
        } catch {} finally { _popSrcBusy = false; }
      })();
    }
    // Pop is now SPIKE-SOURCED (exitable-only). The on-curve INFLOW radar is RETIRED: its candidates
    // were all gated out by the liquidity requirement, and its 24-coin swap-api poll + per-coin Alchemy
    // ROUTE-CHECKS (getMintSafetyInfo) were starving the Pairs page — the live-feed safety filter hits
    // the SAME Alchemy "get mint safety info" budget, so fresh builds timed out. We now only swap-api
    // poll the OPEN pop positions, so the engine's momentum-fade keeps inflow data for them. Everything
    // we ENTER comes from the FREE DexScreener spike scan below — no RPC, no 24-coin poll.
    const held = [...popHeldMints.keys()].filter((m) => !popUnroutable.has(m)).slice(0, 8);
    if (held.length) {
      await Promise.all(held.map(async (mint) => {
        let j = null;
        try { j = await fetch(`https://swap-api.pump.fun/v2/coins/${mint}/trades?limit=40`, { headers: { accept: "application/json" }, signal: AbortSignal.timeout(5000) }).then((r) => r.ok ? r.json() : null); } catch {}
        const trades = (j && Array.isArray(j.trades)) ? j.trades : [];
        if (trades.length) {
          let seen = popSeenTx.get(mint); if (!seen) { seen = new Set(); popSeenTx.set(mint, seen); }
          for (const t of trades) {
            const sig = String(t.tx || t.slotIndexId || ""); if (!sig || seen.has(sig)) continue; seen.add(sig);
            popIngestTrade(mint, { at: now, side: t.type, solAmount: t.amountSol ?? t.quoteAmount, trader: t.userAddress });
          }
          if (seen.size > 200) { const a = [...seen]; popSeenTx.set(mint, new Set(a.slice(a.length - 150))); }
        }
        const _m = popMetrics(mint, now);     // keep the held position's peak-inflow fresh for the engine fade
        if (_m) { const _h = popHeldMints.get(mint); if (_h && _m.inflowNow > _h.peak) _h.peak = _m.inflowNow; if (_m.inflowNow > (popPeakInflow.get(mint) || 0)) popPeakInflow.set(mint, _m.inflowNow); }
      }));
    }
    // ===== SPIKE RADAR — the fix for "it misses the coins VISIBLY ripping on DexScreener". Score the
    // WHOLE broad live feed (the ~140 rows we ALREADY fetched) by jumpScore: a real VOLUME SURGE +
    // PRICE BREAKOUT (m5) + buy-led flow = a coin popping NOW. This is the price/MC-spike signal the
    // 8s-inflow radar was blind to, and it costs ZERO extra API calls (pure compute on data in hand).
    // Live-feed coins inherently have a real pool (jumpScore needs ≥$4k liq), so they're exitable —
    // no per-coin RPC route-check needed (the buy-failure blacklist catches any rare un-routable one).
    let _spikeBest = 0, _spikeCount = 0;
    for (const r of popLiveRows) {
      const mint = r && r.tokenMint; if (!mint || popUnroutable.has(mint)) continue;
      const mc = Number(r.marketCap) || 0;
      if (mc < 8000 || mc > 250000) continue;            // catchable spread (jumpScore needs mc≥8k; cap mega-caps)
      const js = jumpScore(r);
      if (js > _spikeBest) _spikeBest = js;
      const m5 = Number(r.m5) || 0;                      // 5-min price change %
      if (js < POP_SPIKE_FIRE || m5 < 3) continue;       // must be ripping NOW (jumpScore) AND price actually UP (MC increasing)
      _spikeCount++;
      const prev = popCandidates.get(mint);
      const sym = r.symbol || (r.baseToken && r.baseToken.symbol) || (prev && prev.symbol) || shortMint(mint);
      popCandidates.set(mint, { at: now, score: Math.max(js, (prev && prev.score) || 0), mc, symbol: sym, inflowNow: (prev && prev.inflowNow) || 0, liq: Number(r.liquidityUsd) || 0, m5: Number(r.m5) || 0, spike: true });
      if (!prev || !prev.spike) console.log(`[autopilot:info] ⚡ POP spike ${sym} — m5 +${(Number(r.m5) || 0).toFixed(0)}% · vol/liq ${((Number(r.volume5m) || 0) / Math.max(1, Number(r.liquidityUsd) || 0)).toFixed(1)}x · $${Math.round(mc)} MC · score ${Math.round(js)}`);
    }
    // RADAR HEARTBEAT (~30s) — makes a quiet pop feed diagnosable: how many live movers we scanned and
    // how many are actually SPIKING (jumpScore ≥ fire) right now, vs the market just being quiet.
    _popHb = (_popHb + 1) % 10;
    if (_popHb === 0) {
      console.log(`[autopilot:info] 📡 Pop Radar: ${popLiveRows.length} live movers scanned, ${_spikeCount} spiking now (best jump ${Math.round(_spikeBest)} @${POP_SPIKE_FIRE}) · ${held.length} held`);
    }
    for (const [m, r] of popCandidates) { if (now - r.at > 20_000) popCandidates.delete(m); }   // a pop is brief
    if (popTrades.size > 80) { for (const [m, arr] of popTrades) { if (!arr.length || now - arr[arr.length - 1].at > 60_000) { popTrades.delete(m); popSeenTx.delete(m); popPeakInflow.delete(m); } } }
  } catch {} finally { _popPolling = false; }
}
// Start the radar AFTER boot settles (45s) — never pile a 20-coin swap-api poll + live-feed fetch onto
// the boot storm on the single instance (the crash-loop lesson: no bursty background jobs at boot).
setTimeout(() => { setInterval(() => { void pollPopRadar(); }, 4_000); }, 45_000);
// ===== DISPLAY-FEED WARMER — keep the USER-FACING Pairs tabs ALWAYS hot + fresh so every category
// shows pairs the instant a user opens it (fresh launches "by the second", High Volume, Biggest
// Gainers, etc.), never cold/empty. This is SEPARATE from the autopilot (which uses the "ap:" cache
// pool), so the two never cluster — but the display caches stay warm on their own cadence. The worker
// warmer only covered best/newest; the metric tabs (volume/momentum/liquidity/buys) went cold, which
// is why those categories were empty. Light: stale-while-revalidate serves cache instantly + refreshes
// in the background, and per-coin RPC safety is off so each build is ~3s. userId "warmer" → the SHARED
// display cache keys (live:newest, live:volume, …) the Pairs page reads (NOT the "ap:" autopilot pool).
const DISPLAY_WARM_SORTS = ["newest", "best", "volume", "momentum", "liquidity", "buys"];
function warmDisplayFeeds() {
  for (const sort of DISPLAY_WARM_SORTS) { void webLivePairs("warmer", "live", { sort }).catch(() => {}); }
}
setTimeout(() => { warmDisplayFeeds(); setInterval(warmDisplayFeeds, 7_000); }, 20_000);   // start ~20s after boot, refresh every 7s (cache stale window is longer, so it never goes cold)
// The pre-vetted POP FEED the 'pop' mode trades — igniting coins, MC enriched (free pump frontend-api).
async function popFeedRows() {
  const now = Date.now();
  const POP_MC_CEIL = 250_000;   // match aggParams pop mcCeil — catch the visible movers, not mature mega-caps
  const live = [...popCandidates.entries()].filter(([, r]) => now - r.at < 18_000).sort((a, b) => b[1].score - a[1].score).slice(0, 6);
  // The radar DETECTS a spike off the fully-enriched popLiveRows (real volume5m/m5/flow), but the feed
  // row used to hand apex/pop a STRIPPED shell (volume5m:0, no row-level m5) — so the scorer re-read it
  // BLIND (liquidScore ~17, jumpScore 0) and the confirmed winner lost to fresh dust every tick, and
  // apexType mis-routed it to the fresh ladder (round-trip) instead of pop→bank-fast. Carry the real
  // enriched activity through so the scorer sees what the radar saw.
  const liveByMint = new Map((Array.isArray(popLiveRows) ? popLiveRows : []).map((x) => [x.tokenMint, x]));
  const rows = [];
  for (const [mint, r] of live) {
    if (popUnroutable.has(mint)) continue;   // route filter — set in the background poll, no RPC in this hot path
    // EXITABLE-ONLY (user's call): require VERIFIED DexScreener liquidity (≥$4k) so every entry can
    // actually be SOLD. This drops the on-curve INFLOW candidates (sub-8k bonding dust with no verified
    // pool — CHFARA ran +190% but was unsellable: "Pool account not found / No Jupiter route") and keeps
    // the jumpScore SPIKE coins, which are exitable by construction (jumpScore needs ≥$4k liq).
    if ((Number(r.liq) || 0) < 4000) continue;
    // ENTRY-FRESHNESS (on-curve INFLOW source only): skip a coin already PAST its pop (inflow collapsed
    // below the fade threshold). A SPIKE candidate (DexScreener m5/volume) is freshness-gated inside
    // jumpScore itself (rejects negative m5 + already-blown-off >140% tops), so don't double-filter it.
    if (!r.spike) {
      const pk = popPeakInflow.get(mint) || 0;
      if (pk >= 0.3 && (Number(r.inflowNow) || 0) < pk * 0.35) continue;
    }
    if (!r.mc) {
      try { const j = await fetchJson(`https://frontend-api-v3.pump.fun/coins/${mint}`, { timeoutMs: 5000, headers: { "User-Agent": "Mozilla/5.0", accept: "application/json" } }).catch(() => null); r.mc = Number(j && (j.usd_market_cap || j.market_cap)) || 0; } catch {}
    }
    if (r.mc && r.mc > POP_MC_CEIL) continue;   // mega-cap already extended — never surface it
    const lr = liveByMint.get(mint) || {};
    rows.push({
      tokenMint: mint, symbol: r.symbol,
      marketCap: r.mc || Number(lr.marketCap) || 4000,
      liquidityUsd: Number(r.liq) || Number(lr.liquidityUsd) || 0,
      pairAgeSeconds: Number(lr.pairAgeSeconds) || 1,
      volume5m: Number(lr.volume5m) || 0, volumeH1: Number(lr.volumeH1) || 0,
      buys5m: Number(lr.buys5m) || 0, sells5m: Number(lr.sells5m) || 0,
      buysH1: Number(lr.buysH1) || 0, sellsH1: Number(lr.sellsH1) || 0,
      m5: Number(lr.m5 ?? r.m5) || 0, h1: Number(lr.h1) || 0,
      source: "pop", _pop: { score: r.score, inflowNow: r.inflowNow, spike: Boolean(r.spike), m5: Number(r.m5) || 0 }
    });
    if (rows.length >= 4) break;
  }
  return rows;
}

// ---------------------------------------------------------------------------
// INSIDER-LAUNCH MACHINE — bet the OPERATOR, not the coin. The instant a KNOWN/linked wallet (a
// tracked KOL, a proven winner, or a funding-cluster sibling of one) DEPLOYS a coin, get in early
// and ride the launch pump (the operator's followers/bundle pile in) — then bail before the rug via
// the dev-dump tripwire. The coin doesn't have to last; we just have to be EARLY and OUT AHEAD.
const insiderLaunches = new Map();   // mint -> { creator, symbol, tier, why, at, mc, mcAt, dumped }
const insiderDevSold = new Set();    // mints whose creator has SOLD -> the engine's dev-dump tripwire fires
const insiderRotationLink = new Map(); // ROTATED creator -> { operator, at } — a NEW wallet funded by a known operator (rotation-catcher)
// PRECURSOR EXITS (Brain 5): COPY/smart-money positions the engine asked us to rug-watch. Same shape
// as insiderLaunches ({creator, at, symbol, dumped}) so checkInsiderRug + the poller + the WSS watcher
// treat them identically — we bail on the operator/cluster DISTRIBUTION precursor instead of racing
// the whale's sell. Bounded + TTL'd; deduped against insiderLaunches.
const copyRugWatch = new Map();      // mint -> { creator, at, symbol, dumped }
function noteCopyRugWatch(mint, creator, symbol) {
  mint = String(mint || "").trim(); creator = String(creator || "").trim();
  if (!mint || !creator) return;
  if (insiderLaunches.has(mint) || copyRugWatch.has(mint)) return;   // already watched
  copyRugWatch.set(mint, { creator, at: Date.now(), symbol: symbol || mint.slice(0, 6), dumped: false });
  if (copyRugWatch.size > 300) {                                     // prune dumped/stale
    const now = Date.now();
    for (const [m, r] of copyRugWatch) { if (r.dumped || now - r.at > 30 * 60_000) copyRugWatch.delete(m); }
  }
}

// Tier a creator wallet by how proven/linked it is (null = not a known operator -> skip).
// OPERATOR RUG-BLACKLIST — the fix for the serial-rugger bleed (one wallet launching coin after coin,
// each rugging in ~1min, and the insider machine re-buying every one off its STALE pump history). The
// instant an operator's launch rugs on us (rug-flow tripwire arms), stop treating that wallet as an
// insider target — adaptive: "bet the operator, but the moment they turn rugger, walk away." A single
// rug blacklists the wallet for 6h; repeat ruggers stay out longer. This is what breaks the loop.
const creatorRugs = new Map();   // creator -> { count, at }
function noteCreatorRug(creator) {
  const w = String(creator || "").trim(); if (!w) return;
  const e = creatorRugs.get(w) || { count: 0, at: 0 };
  e.count += 1; e.at = Date.now(); creatorRugs.set(w, e);
  if (creatorRugs.size > 2000) { const k0 = creatorRugs.keys().next().value; creatorRugs.delete(k0); }
}
function isRecentRugger(creator) {
  const e = creatorRugs.get(String(creator || "").trim());
  if (!e || !e.count) return false;
  const ttl = (e.count >= 2 ? 24 : 6) * 60 * 60_000;   // 1 rug -> 6h cooldown, repeat rugger -> 24h
  return Date.now() - e.at < ttl;
}

function insiderLaunchTier(creator) {
  const w = String(creator || "").trim();
  if (!w) return null;
  if (isRecentRugger(w)) return null;                  // walked away — this operator just rugged us
  if (isKolWallet(w)) return { tier: 3, why: "kol" };
  if (insiderRotationLink.has(w)) return { tier: 2, why: "rotation" };   // a known operator's freshly-funded alt
  const rec = walletObs.get(w);
  const ct = copyTierForWalletRecord(rec);
  if (ct === "A" || ct === "B") return { tier: 3, why: "winner" };
  if (ct === "C" || ct === "probe") return { tier: 2, why: "linked" };
  // ANY KNOWN WALLET WHOSE LAUNCHES REACH A DECENT MC (the user's "any wallet known to get to a
  // decent point even before a rug"). We exit before the rug (rug-flow tripwire), so a pump-then-rug
  // dev is a valid target as long as their launches reach a sellable peak. Sourced from our own dev
  // observatory: rep.runners = past launches that ran; rep.avgPeak = their launches' average peak %.
  const rep = (typeof combinedDevRep === "function") ? combinedDevRep(w) : null;
  if (rep && (rep.runners >= 1 || (rep.trades >= 3 && rep.avgPeak >= 60))) {
    return { tier: rep.runners >= 2 ? 3 : 2, why: "dev-pumps", avgPeak: rep.avgPeak || 0 };
  }
  if (ct === "blocked") return null;                       // a copy-loser with NO launch pedigree -> skip
  const cid = clusterIdFor(w);                             // funding-cluster sibling of a known operator?
  if (cid && cid !== w) {
    if (isKolWallet(cid) || isWinnerWallet(walletObs.get(cid))) return { tier: 2, why: "cluster" };
    const crep = (typeof combinedDevRep === "function") ? combinedDevRep(cid) : null;
    if (crep && crep.runners >= 1) return { tier: 2, why: "cluster-dev" };   // sibling is a proven pump-dev
  }
  return null;
}

function recordInsiderLaunch(entry) {
  try {
    const creator = String(entry?.event?.traderPublicKey || "").trim();
    const mint = String(entry?.mint || "").trim();
    if (!creator || !mint || insiderLaunches.has(mint)) return;
    const t = insiderLaunchTier(creator);
    if (!t) return;
    const symbol = String(entry?.event?.symbol || "???");
    insiderLaunches.set(mint, { creator, symbol, tier: t.tier, why: t.why, at: Date.now(), mc: 0, mcAt: 0, dumped: false });
    console.log(`[autopilot:info] 🧬 INSIDER LAUNCH $${symbol} — ${t.why} ${creator.slice(0, 4)}..${creator.slice(-4)} (tier ${t.tier})`);
    if (insiderLaunches.size > 400) { const oldest = insiderLaunches.keys().next().value; insiderLaunches.delete(oldest); }
  } catch {}
}

// Surface FRESH insider launches (last ~6 min — we want EARLY) as TOP-priority copy rows for the
// engine. Enriched with live MC from the free pump frontend-api (cached 20s). Dropped once dumped.
async function insiderFeedRows() {
  const now = Date.now();
  const fresh = [...insiderLaunches.entries()]
    .filter(([mint, r]) => !r.dumped && !insiderDevSold.has(mint) && !isRecentRugger(r.creator) && now - r.at < 6 * 60_000)
    .sort((a, b) => b[1].tier - a[1].tier || b[1].at - a[1].at)
    .slice(0, 6);
  const rows = [];
  for (const [mint, r] of fresh) {
    if (!r.mc || now - (r.mcAt || 0) > 20_000) {
      try {
        const j = await fetchJson(`https://frontend-api-v3.pump.fun/coins/${mint}`, { timeoutMs: 6000, headers: { "User-Agent": "Mozilla/5.0", accept: "application/json" } }).catch(() => null);
        r.mc = Number(j && (j.usd_market_cap || j.market_cap)) || 0; r.mcAt = now;
      } catch {}
    }
    if (!(r.mc > 0)) continue;
    // GET IN LOW — the whole edge is entering early with room to the operator's typical peak (in by
    // ~4k -> 12k = a 3x). Past ~$8k the early-entry edge is mostly gone, so don't chase it up there.
    if (r.mc > 8000) continue;
    rows.push({
      tokenMint: mint,
      symbol: r.symbol,
      marketCap: r.mc,
      liquidityUsd: 0, // pump curve: unknown-liq is KEPT by the engine's known-thin-only gate
      source: "insider",
      _smartMoney: { insider: true, kol: r.tier >= 3, winners: r.tier, exitMult: 1.6, devWallet: r.creator, why: r.why, source: "insider_launch" }
    });
  }
  return rows;
}

function hasFreshInsiderLaunch() {
  const now = Date.now();
  for (const r of insiderLaunches.values()) if (!r.dumped && now - r.at < 6 * 60_000) return true;
  return false;
}

// RUG-FLOW WATCHER (the SMART tripwire). Naive "creator sold -> exit" gets HEAD-FAKED: operators who
// know they're copy-traded flip the CREATOR wallet instantly to shake followers, then PUMP with ALTS.
// So we read the whole operator FLOW from swap-api (per-wallet bought/sold in SOL) and only bail when a
// MAIN PUMPER — a linked/cluster alt or a top accumulator that actually drove the price — EXITS its
// position. The creator's early bait-flip is IGNORED while alts are still accumulating. (The engine's
// liquidity-pull + tight stop still cover a genuine instant-rug inside that window.) Trickle/crash-safe.
// One mint's rug-flow check (reads the operator flow from swap-api, arms the tripwire on a real
// dump). Extracted so BOTH the 6s poller AND the real-time Chainstack WSS watcher run the IDENTICAL
// confirmed logic — the WSS path only changes LATENCY (fires it sooner), never the decision, so it
// adds zero new false-positive surface. Returns true if it armed the tripwire.
async function checkInsiderRug(mint, r) {
  if (!r || r.dumped || insiderDevSold.has(mint)) return false;
  const now = Date.now();
  try {
    const j = await fetch(`https://swap-api.pump.fun/v2/coins/${mint}/trades?limit=100`, { headers: { accept: "application/json" } }).then((x) => x.ok ? x.json() : null).catch(() => null);
    const trades = Array.isArray(j) ? j : (j && j.trades) || [];
    if (!trades.length) return false;
    // Per-wallet bought/sold SOL on this coin = the operator flow.
    const flow = new Map();
    for (const t of trades) {
      const a = String(t.userAddress || t.user || "").trim(); if (!a) continue;
      const sol = Number(t.amountSol || t.quoteAmount || 0) || 0;
      const side = String(t.type || t.side || "").toLowerCase();
      const e = flow.get(a) || { bought: 0, sold: 0 };
      if (side === "buy") e.bought += sol; else if (side === "sell") e.sold += sol;
      flow.set(a, e);
    }
    const creator = r.creator;
    const creatorCluster = clusterIdFor(creator);
    // The PUMPERS that drove it: the biggest real accumulators (>= 0.3 SOL bought).
    const pumpers = [...flow.entries()].filter(([, e]) => e.bought >= 0.3).sort((x, y) => y[1].bought - x[1].bought).slice(0, 5);
    let rug = false, why = "";
    for (const [a, e] of pumpers) {
      if (a === creator && now - r.at < 30_000) continue;                 // creator bait-flip window: ignore
      const linked = a !== creator && clusterIdFor(a) === creatorCluster && creatorCluster !== a;
      const dumpFrac = e.sold / Math.max(e.bought, 0.0001);
      const bar = linked ? 0.4 : 0.55;                                    // linked alt dumping = lower bar (user: it matters more)
      if (dumpFrac >= bar && e.sold >= 0.2) { rug = true; why = `${linked ? "linked alt" : "main pumper"} ${a.slice(0, 4)}.. exited ${Math.round(dumpFrac * 100)}% of its bag`; break; }
    }
    // Genuine creator ABANDON (NOT the head-fake): creator sold real size, NO alts still pumping, past the window.
    const cre = flow.get(creator) || { bought: 0, sold: 0 };
    const altsPumping = pumpers.some(([a, e]) => a !== creator && (e.bought - e.sold) > 0.2);
    if (!rug && cre.sold >= 0.3 && !altsPumping && now - r.at >= 30_000) { rug = true; why = "creator abandoned, no alt support"; }
    if (rug) { insiderDevSold.add(mint); r.dumped = true; noteCreatorRug(r.creator); console.log(`[autopilot:info] 🚨 RUG-FLOW ${r.symbol}: ${why} — tripwire armed; blacklisting operator ${String(r.creator).slice(0, 4)}.. from new buys`); return true; }
  } catch {}
  return false;
}

let _insiderRugPolling = false;
async function pollInsiderRugWatch() {
  if (_insiderRugPolling) return;
  _insiderRugPolling = true;
  try {
    const now = Date.now();
    const watch = [...insiderLaunches.entries(), ...copyRugWatch.entries()].filter(([m, r]) => !r.dumped && !insiderDevSold.has(m) && now - r.at < 25 * 60_000).slice(0, 8);
    for (const [mint, r] of watch) {
      await checkInsiderRug(mint, r);
      await new Promise((res) => setTimeout(res, 150));
    }
    if (insiderDevSold.size > 2000) insiderDevSold.clear();
  } finally { _insiderRugPolling = false; }
}
setInterval(() => { void pollInsiderRugWatch(); }, 6000);

// ===== REAL-TIME RUG-WATCH via Chainstack WebSocket (sub-second dev-dump detection) =============
// Polling the operator flow every 6s means we can be up to 6s late catching a creator/linked-pumper
// sell — on a rug, that's the whole exit. This subscribes (Solana native logsSubscribe) to each
// active insider creator's wallet on the Chainstack WSS endpoint; the instant that wallet transacts,
// we run the SAME checkInsiderRug confirm immediately instead of waiting for the next poll. DORMANT +
// $0 until CHAINSTACK_WSS (or SOLANA_WSS) env is set — no endpoint, no connection, no behavior change.
// Additive: it can only ARM the existing tripwire sooner, never alter exit logic. The 6s poller stays
// as the backstop. Set CHAINSTACK_WSS to the wss:// node URL (keep the token secret — Render env only).
const CHAINSTACK_WSS = process.env.CHAINSTACK_WSS || process.env.SOLANA_WSS || "";
let _rugWs = null;
const _rugWsReqWallet = new Map();   // jsonrpc request id -> wallet (to map the sub id back)
const _rugWsSubWallet = new Map();   // subscription id -> wallet
const _rugWsSubscribed = new Set();  // wallets we've already subscribed this connection
let _rugWsReqId = 1;

function rugWatchWallets() {
  const now = Date.now();
  const set = new Set();
  for (const [, r] of [...insiderLaunches.entries(), ...copyRugWatch.entries()]) {
    if (!r || r.dumped || now - r.at > 25 * 60_000) continue;
    if (r.creator) set.add(String(r.creator));
  }
  return [...set].slice(0, 40);                       // cap subscriptions (one stream, many subs)
}
function rugMintsForWallet(wallet) {
  const now = Date.now(), out = [];
  for (const [mint, r] of [...insiderLaunches.entries(), ...copyRugWatch.entries()]) {
    if (r && !r.dumped && String(r.creator) === wallet && now - r.at < 25 * 60_000) out.push([mint, r]);
  }
  return out;
}
function resyncRugWatchSubs() {
  if (!_rugWs || _rugWs.readyState !== WebSocket.OPEN) return;
  for (const w of rugWatchWallets()) {
    if (_rugWsSubscribed.has(w)) continue;
    _rugWsSubscribed.add(w);
    const id = _rugWsReqId++;
    _rugWsReqWallet.set(id, w);
    try { _rugWs.send(JSON.stringify({ jsonrpc: "2.0", id, method: "logsSubscribe", params: [{ mentions: [w] }, { commitment: "processed" }] })); } catch {}
  }
}
function startRugWatchWs() {
  if (!CHAINSTACK_WSS) return;                        // dormant without the endpoint
  try {
    _rugWs = new WebSocket(CHAINSTACK_WSS);
    _rugWs.on("open", () => {
      _rugWsSubscribed.clear(); _rugWsSubWallet.clear(); _rugWsReqWallet.clear();
      console.log("[autopilot:info] ⚡ Chainstack WSS rug-watch connected");
      resyncRugWatchSubs();
    });
    _rugWs.on("message", (buf) => {
      let m = null; try { m = JSON.parse(buf.toString()); } catch { return; }
      if (m.id != null && _rugWsReqWallet.has(m.id) && m.result != null) {     // subscribe ack: map subId -> wallet
        _rugWsSubWallet.set(m.result, _rugWsReqWallet.get(m.id)); _rugWsReqWallet.delete(m.id); return;
      }
      if (m.method === "logsNotification") {
        const subId = m.params && m.params.subscription;
        const wallet = _rugWsSubWallet.get(subId);
        if (!wallet) return;
        for (const [mint, r] of rugMintsForWallet(wallet)) { void checkInsiderRug(mint, r); }   // SAME confirm, fired NOW
      }
    });
    _rugWs.on("close", () => { _rugWs = null; setTimeout(startRugWatchWs, 5000); });
    _rugWs.on("error", () => { try { _rugWs && _rugWs.close(); } catch {} });
  } catch { setTimeout(startRugWatchWs, 10000); }
}
if (CHAINSTACK_WSS) {
  startRugWatchWs();
  setInterval(() => { resyncRugWatchSubs(); }, 30_000);   // pick up newly-launched insider creators
}

function devSoldForMint(mint) { return insiderDevSold.has(String(mint || "").trim()); }

// ---------------------------------------------------------------------------
// WALLET-INTELLIGENCE EXPANSION — "always have the best options + be in tune with the wallets
// operators rotate to." Three BOUNDED, crash-safe trickles (the one-instance no-burst rule):
//   (1) ROTATION-CATCHER  — a NEW wallet funded by a known operator IS their rotation; link it so its
//       launches are caught as insider, now and forever (no operator escapes by switching wallets).
//   (2) FIRST-BUYER ROSTER — scale the "caught a runner early + profited" roster toward tens of
//       thousands from Solana Tracker Premium — the wallets worth copying + watching for launches.
//   (3) FRESHNESS — bound + evict stale non-winners so the roster stays current as wallets rotate.
const recentLaunchers = new Map();    // creator -> { mint, symbol, at } — every recent creation
const launcherFunderSeen = new Set(); // creators we've funder-resolved (don't redo)
function recordRecentLauncher(entry) {
  try {
    const creator = String(entry?.event?.traderPublicKey || "").trim();
    const mint = String(entry?.mint || "").trim();
    if (!creator || !mint) return;
    recentLaunchers.set(creator, { mint, symbol: String(entry?.event?.symbol || "???"), at: Date.now() });
    if (recentLaunchers.size > 500) { const k = recentLaunchers.keys().next().value; recentLaunchers.delete(k); }
  } catch {}
}

// (1) ROTATION-CATCHER. Resolve the funder of recent UNKNOWN launchers; a launcher funded by a known
// operator is their rotation -> link it (and flag its current launch). Trickle: 3 / 30s (free RPC).
let _launcherFunderPolling = false;
async function pollLauncherFunders() {
  if (_launcherFunderPolling || !funderBudgetOk()) return;
  _launcherFunderPolling = true;
  try {
    const now = Date.now();
    // COST GUARD: a funder lookup is expensive (Alchemy getSignatures+getParsedTransaction), and 99%
    // of launchers are random noise that never trace to a known operator — so DON'T resolve every
    // launcher (that was the free-tier burn). Only spend a lookup on a launcher whose coin ALREADY
    // drew SMART MONEY (a known winner/KOL bought it early — a cheap in-memory check); skip the rest
    // WITHOUT marking them seen so they're re-checked cheaply until traction appears or they age out.
    const cands = [...recentLaunchers.entries()]
      .filter(([w, r]) => !launcherFunderSeen.has(w) && now - r.at < 30 * 60_000 && insiderLaunchTier(w) === null)
      .filter(([, r]) => { const sm = smartMoneyScore(r.mint); return sm && (sm.kol || (sm.winners || 0) >= 1); })
      .sort((a, b) => b[1].at - a[1].at)
      .slice(0, 2);
    for (const [creator, r] of cands) {
      if (!funderBudgetOk()) break;          // hard daily Alchemy cap
      launcherFunderSeen.add(creator);
      funderUsedToday += 1;
      let funder = null;
      try { funder = await lookupWalletFunder(creator); } catch {}
      if (funder && insiderLaunchTier(funder) !== null) {
        insiderRotationLink.set(creator, { operator: funder, at: now });
        if (insiderRotationLink.size > 3000) { const k = insiderRotationLink.keys().next().value; insiderRotationLink.delete(k); }
        console.log(`[autopilot:info] 🔗 ROTATION: ${creator.slice(0, 4)}.. funded by known operator ${funder.slice(0, 4)}.. — linked, watching its launches`);
        if (now - r.at < 6 * 60_000 && !insiderLaunches.has(r.mint)) {
          insiderLaunches.set(r.mint, { creator, symbol: r.symbol, tier: 2, why: "rotation", at: r.at, mc: 0, mcAt: 0, dumped: false });
        }
      }
      await new Promise((res) => setTimeout(res, 250));
    }
    if (launcherFunderSeen.size > 6000) launcherFunderSeen.clear();
  } finally { _launcherFunderPolling = false; }
}
setInterval(() => { void pollLauncherFunders(); }, 60_000);

// (2) FIRST-BUYER ROSTER SCALE. Scan first-buyers of recent RUNNER tokens (trending/volume); a wallet
// that profitably first-bought >= 2 INDEPENDENT runners is an early-alpha winner. Quota-aware trickle
// (env FIRST_BUYER_GRAB_MS, default 120s; trending/volume cached 2min) -> ~90k ST req/mo headroom.
const fbAccum = new Map();             // wallet -> { runners:Set<mint>, pnl }
const fbSeenTokens = new Set();        // runner tokens already scanned
let _fbPolling = false;
async function pollFirstBuyerGrab() {
  if (_fbPolling || !CONFIG.solanaTrackerApiKey) return;
  _fbPolling = true;
  try {
    let mints = [];
    try {
      const src = await Promise.all([
        solanaTrackerJson(`/tokens/trending`, { cacheTtlMs: 120_000, timeoutMs: 8000 }).catch(() => null),
        solanaTrackerJson(`/tokens/volume`, { cacheTtlMs: 120_000, timeoutMs: 8000 }).catch(() => null)
      ]);
      for (const arr of src) for (const t of (Array.isArray(arr) ? arr : [])) {
        const m = t && (t.token?.mint || t.mint); if (m) mints.push(String(m));
      }
    } catch {}
    mints = [...new Set(mints)].filter((m) => !fbSeenTokens.has(m)).slice(0, 2); // 2 fresh runners / cycle
    let added = 0;
    for (const mint of mints) {
      fbSeenTokens.add(mint);
      let buyers = [];
      try { const d = await solanaTrackerJson(`/first-buyers/${mint}?limit=60`, { cacheTtlMs: 0, timeoutMs: 9000 }); buyers = Array.isArray(d) ? d : (d && d.buyers) || []; } catch {}
      for (const b of buyers) {
        const w = b && b.wallet; if (!w) continue;
        const total = Number(b.total) || 0;        // realized+unrealized profit on this token
        if (total <= 0) continue;                   // only PROFITABLE early entries
        const g = fbAccum.get(w) || { runners: new Set(), pnl: 0 };
        g.runners.add(mint); g.pnl += total; fbAccum.set(w, g);
        if (g.runners.size >= 2 && g.pnl > 0) {     // early-alpha: caught >=2 independent runners early + green
          const rec = walletObs.get(w) || {};
          if (!rec.earlyAlpha) added += 1;
          rec.earlyAlpha = true; rec.earlyRunners = g.runners.size; rec.earlyPnl = Math.round(g.pnl); rec.seenAt = Date.now();
          walletObs.set(w, rec);
        }
      }
      await new Promise((res) => setTimeout(res, 250));
    }
    if (added) console.log(`[autopilot:info] 🧠 first-buyer roster +${added} early-alpha wallets (tracked ${fbAccum.size})`);
    if (fbSeenTokens.size > 4000) fbSeenTokens.clear();
  } finally { _fbPolling = false; }
}
setInterval(() => { void pollFirstBuyerGrab(); }, Math.max(60_000, Number(process.env.FIRST_BUYER_GRAB_MS) || 120_000));

// (3) FRESHNESS. Keep every winner/KOL; evict only STALE (>7d inactive) low-value non-winners when the
// roster exceeds a generous cap, so it can grow into the tens of thousands without unbounded bloat.
function pruneStaleWallets() {
  try {
    const CAP = 40000;
    if (walletObs.size <= CAP) return;
    const now = Date.now();
    let evicted = 0;
    for (const [w, r] of walletObs) {
      if (walletObs.size <= CAP) break;
      if (isWinnerWallet(r) || isTrackedKolWallet(w)) continue;
      const seen = Number(r && (r.seenAt || r.lastAt)) || 0;
      if (now - seen > 7 * 24 * 60 * 60_000) { walletObs.delete(w); evicted += 1; }
    }
    if (evicted) console.log(`[autopilot:info] 🧹 freshness: evicted ${evicted} stale non-winner wallets (roster now ${walletObs.size})`);
  } catch {}
}
setInterval(() => { void pruneStaleWallets(); }, 6 * 60 * 60_000);

const autopilotEngine = createAutopilotEngine({
  exitMs: 1000,
  huntMs: 5000,
  // Learning flywheel hooks:
  getDevWallet: (mint) => {
    try {
      const ce = pumpPortalStream.getCreationEntry(mint);
      return (ce && ce.event && ce.event.traderPublicKey) ? String(ce.event.traderPublicKey) : null;
    } catch { return null; }
  },
  devReputation: (dev) => combinedDevRep(dev),
  smartMoney: (mint) => smartMoneyScore(mint),
  clusterRisk: (mint) => autopilotClusterRisk(mint),
  // PRE-BUY rug hard-gate (fresh-ape semantics): the same on-chain SlimeShield danger check the Ogre
  // AI pick surface runs — active mint/freeze authority, Token-2022, honeypot-style signals. Only
  // genuine DANGER blocks (not a soft AVOID), so thin-but-clean fresh launches still trade. The hunt
  // loop never had this; it's the authoritative confirmation right before SOL moves.
  securityGate: async (row) => {
    try {
      const mint = String((row && row.tokenMint) || "").trim();
      if (!mint) return null;
      const shield = await webSlimeShield(mint).catch(() => null);
      if (shield && slimeShieldHasHardDanger(shield)) {
        return { danger: true, reason: `SlimeShield ${shield.verdict || "danger"} — mint/freeze authority or honeypot signal` };
      }
    } catch {}
    return null;
  },
  smartMoneyReady: () => smartMoneyReady(),
  smartMoneyFeed: async () => smartMoneyFeed(),
  // INSIDER-LAUNCH dev-dump tripwire: the engine exits 100% the instant a launch's creator sells.
  devSold: (mint) => devSoldForMint(mint),
  noteRugWatch: (mint, creator, symbol) => noteCopyRugWatch(mint, creator, symbol),
  getReadiness: () => autopilotReadiness(),   // SELF-ARM: trade only once the brain has learned enough edge

  callerIntel: (mint) => telegramCallerIntelForMint(mint),
  getMarketTape: () => marketTape(),
  entryHistory: async (row) => {
    const mint = String(row?.tokenMint || "").trim();
    if (!mint) return null;
    return webReplayBeforeBuy(mint).catch(() => null);
  },
  symbolLoserCount: (symbol) => autopilotSymbolLoserCount(symbol),
  recordTrade: (rec) => { void recordAutopilotTrade(rec); },
  log: (level, msg) => { console.log(`[autopilot:${level}] ${msg}`); pushAutopilotEvent(level, msg); },
  isPaused: async () => Boolean((await readState().catch(() => ({}))).paused),
  persist: async (snap) => {
    try {
      await writeJsonFile(AUTOPILOT_STATE_FILE, snap || {});
    } catch {}
  },
  getFreshFeed: async () => {
    const feed = await webLivePairs("autopilot", "live", { sort: "fresh", force: true, feed: "ap" });
    let rows = Array.isArray(feed?.rows) ? feed.rows : [];
    const __freshN = rows.length; let __moversN = 0, __u1hN = 0;   // diag
    // GRIND targets SURVIVED/climbed coins ($5-80k, aged past the first seconds). The
    // fresh/newest view is almost all brand-new sub-$5k launches, so grind starves on it
    // (50 fresh, 0 passed). Data-driven sorts (volume/momentum) pull the broader LAST-HOUR
    // window — exactly the coins grind wants — so for grind we merge those in (deduped).
    // Cheap: the extra views are served from the shared live-pairs cache (no force).
    let mode = null;
    try { mode = autopilotEngine.status()?.mode || null; } catch {}
    // STARVATION FALLBACK (2026-06-20): the `live` creation bucket's FRESH sort returns 0 whenever
    // no BRAND-new launch landed in the last few seconds (creation stream momentarily quiet) — even
    // though plenty of <1h fresh coins exist (verified live: live/fresh=0 while under1h/newest=26,
    // live/volume=25). Without broadening, the engine logged "feed quiet (0 fresh pairs)" for 20+
    // min straight and bought NOTHING despite a live market. So whenever the fresh view is THIN,
    // merge the broader last-hour window (under1h newest + live volume/momentum), deduped, behind
    // the fresh rows (fresh-first order preserved when fresh exists). The engine's own age/MC/score/
    // rug gates still decide — this only refills the CANDIDATE POOL so it never starves on a quiet
    // creation tick. GRIND always broadens (survived-coin target); the fresh path broadens only when
    // thin so it stays fresh-first when the seconds-old feed is healthy.
    if (mode === "grind" || rows.length < 6) {
      try {
        // TWO sources, because the `ap` feed pool only ever built the `live` bucket (the autopilot
        // only requested `live`), so requesting under1h/volume from it WITHOUT force returns 0 (cold
        // cache). So: (1) buildLiquidMovers() — the SHARED, already-warm normalized movers pool the
        // pop radar/scalp keep hot (fresh→24h, real m5/h1/liquidity), FREE to reuse; and (2) a
        // FORCE-built under1h/newest in the ap pool — the reliably-populated fresh window (verified
        // live: 26 coins while live/fresh=0). Merged + deduped behind the fresh rows. The engine's
        // own age (<20min)/MC/score/rug/security gates still decide every entry.
        const [movers, u1h] = await Promise.all([
          buildLiquidMovers().catch(() => []),
          webLivePairs("autopilot", "under1h", { sort: "newest", force: true, feed: "ap" })
            .then((f) => (Array.isArray(f?.rows) ? f.rows : [])).catch(() => [])
        ]);
        __moversN = Array.isArray(movers) ? movers.length : 0; __u1hN = Array.isArray(u1h) ? u1h.length : 0;   // diag
        const seen = new Set(rows.map((r) => r.tokenMint));
        for (const r of [...(Array.isArray(movers) ? movers : []), ...u1h]) {
          if (r && r.tokenMint && !seen.has(r.tokenMint)) { seen.add(r.tokenMint); rows.push(r); }
        }
      } catch (e) { try { console.warn(`[ap-fresh-dbg] broaden error: ${e && e.message}`); } catch {} }
    }
    const out = rows.filter((r) => !autopilotRowHasHardDanger(r)).map((r) => ({   // rug hard-gate
      tokenMint: r.tokenMint,
      symbol: r.symbol,
      pairAgeSeconds: r.pairAgeSeconds,
      marketCap: r.marketCap,
      liquidityUsd: r.liquidityUsd,
      volume5m: r.volume5m,
      volumeH1: r.volumeH1,
      buys5m: r.buys5m,
      sells5m: r.sells5m,
      buysH1: r.buysH1,
      sellsH1: r.sellsH1,
      m5: liveRowPct(r.m5),
      h1: liveRowPct(r.h1),
      sniperCount: r.sniperCount || r.snipers || 0,
      bestPickScore: r.bestPickScore || r.bestPick || 0,
      ...autopilotEnrichedFields(r)
    }));
    // SNIPER: remember this candidate pool (the X-clout trickle resolves these) and attach any
    // already-resolved notable-X clout so snipeSignalScore can fire the X signal.
    lastFreshMints = out.map((row) => row.tokenMint).filter(Boolean);
    lastFreshSyms.clear();
    for (const row of out) { if (row.tokenMint && row.symbol) lastFreshSyms.set(row.tokenMint, row.symbol); }
    for (const row of out) {
      const c = SNIPE_X_CLOUT.get(row.tokenMint);
      if (c && c.clout >= 1) { row.xClout = c.clout; row.xNotable = true; }
      // SOCIAL VELOCITY: a coin trending on X (lots of real accounts posting it) counts as X-clout
      // even if its own attached handle isn't notable — folds into the same X signal the brain reads.
      const sh = SOCIAL_HEAT.get(row.tokenMint);
      if (sh && sh.heat >= 1) { row.xClout = Math.max(Number(row.xClout) || 0, sh.heat); row.xNotable = true; row.socialHeat = sh.heat; }
      // GRADUATION / CURVE-VELOCITY (free, in-memory PumpPortal stream): bonding fill % from the
      // virtual-SOL reserve + SOL/min flowing into the curve over the recent trade window. The
      // engine's graduationScore reads these (no-op when absent — DexScreener-only rows are fine).
      try {
        const ce = pumpPortalStream.getCreationEntry(row.tokenMint);
        const vSol = (ce && ce.lastTrade) ? Number(ce.lastTrade.vSolInBondingCurve) || 0 : 0;
        // pump.fun curve: virtual SOL starts ~30 at launch and graduates ~115 (≈85 real SOL in).
        if (vSol > 0) row.bondingPct = Math.max(0, Math.min(1, (vSol - 30) / 85));
        const trades = pumpPortalStream.getTrades(row.tokenMint, { limit: 80 }) || [];
        if (trades.length >= 4) {
          let buySol = 0, minAt = Infinity, maxAt = 0;
          for (const t of trades) {
            if (!t) continue;
            const at = Number(t.at) || 0;
            if (at > 0) { if (at < minAt) minAt = at; if (at > maxAt) maxAt = at; }
            if (t.side === "buy") buySol += Number(t.solAmount) || 0;
          }
          const mins = (maxAt - minAt) / 60000;
          if (mins >= 0.1 && buySol > 0) row.curveVelSol = buySol / mins;
        }
      } catch {}
    }
    try {
      const __n = Date.now();
      if (__n - (globalThis.__apFreshDbgAt || 0) > 20_000) {
        globalThis.__apFreshDbgAt = __n;
        console.warn(`[ap-fresh-dbg] mode=${mode} fresh=${__freshN} movers=${__moversN} u1h=${__u1hN} merged=${rows.length} out=${out.length}`);
      }
    } catch {}
    return out;
  },
  // SCALP feed: LIQUID movers across the FULL range — from fresh small caps to mid-cap runners
  // (the 30k→150k / 50k→200k quick-win movers the user wants). It pulls the data-driven
  // liquidity/volume/momentum sorts across MULTIPLE AGE buckets (fresh 0-60m + 1-2h + 3-6h), not
  // just the fresh window — that's why earlier it "only found small pairs": the fresh bucket misses
  // the minutes-to-hours-old climbers. Deduped, KNOWN-thin (<$1.5k) dropped, unknown-liq KEPT
  // (the engine's liquidScore + volume gate + fast exits vet them). The engine's wide MC band
  // (4k..12M) + liquidScore then pick whatever has quick-win momentum, low or high cap.
  // SCALP feed = the shared normalized liquid-movers pool (also scored by the pop spike radar).
  getLiquidFeed: async () => buildLiquidMovers(),
  // POP mode feed: real-time IGNITION candidates from PopRadar (pre-vetted, MC-agnostic).
  getPopFeed: async () => popFeedRows(),
  // APEX STAGE 2 — deep-vet ONLY the top finalists (≤6) the cheap scan surfaced: Solana Tracker
  // holder/insider/sniper/bundler/dev-hold/LP-burn + our deployer-warehouse dev reputation. ST is
  // cached 90s so repeated finalists are nearly free. Returns a {mint: deep} map for apexDeepEdge.
  enrichFinalists: async (mints) => {
    const out = {};
    const list = [...new Set((Array.isArray(mints) ? mints : []).filter(Boolean))].slice(0, 6);
    await Promise.all(list.map(async (mint) => {
      try {
        const st = await fetchSolanaTrackerTokenReport(mint).catch(() => null);
        if (!st || !st.ok) return;
        let devRunners = 0, devRugs = 0;
        if (st.creator) {
          const rep = combinedDevRep(st.creator);
          if (rep) { devRunners = Number(rep.runners) || 0; devRugs = Number(rep.rugs) || 0; }
        }
        out[mint] = {
          top10Pct: st.topHolderPercent, snipersPct: st.snipersPercent, insidersPct: st.insidersPercent,
          bundlersPct: st.bundlersPercent, devHoldPct: st.devHoldPercent, lpBurnedPct: st.lpBurnedPercent,
          rugged: st.rugged, devRunners, devRugs
        };
      } catch { /* leave this finalist on its Stage-1 edge */ }
    }));
    return out;
  },
  // Momentum-fade exit signal: the inflow that drove the pop has decelerated.
  popFading: (mint) => popFadingNow(mint),
  popInflow: (mint) => { try { return popMetrics(mint, Date.now())?.inflowNow || 0; } catch { return 0; } },
  getPairLite: async (mint) => {
    // PRIMARY = swap-api live price (the WORKING source — PumpPortal trades are dead). The poller
    // keeps held coins hot, so this is almost always a fast in-memory cache hit; on a miss it fetches
    // inline. Median trade price × 1B supply = a real sellable mark, so the % + exits are accurate.
    heldReqAt.set(mint, Date.now()); // the engine is asking → it holds this coin → keep it hot in the poller
    const sc = swapApiPriceCache.get(mint);
    if (sc && Date.now() - sc.at < 4000 && sc.mc > 0) return { marketCap: sc.mc, liquidityUsd: sc.liq, priceUsd: sc.px };
    const fresh = await swapApiPriceFor(mint);
    if (fresh && fresh.mc > 0) return { marketCap: fresh.mc, liquidityUsd: fresh.liq, priceUsd: fresh.px };
    // Graduated / off-curve coins (swap-api has no curve trades): DexScreener, then on-chain curve.
    try {
      const pairs = await fetchDexScreenerTokenPairsFallback(mint).catch(() => []);
      const best = bestDexPairForToken(mint, pairs);
      if (best) {
        const mc = Number(best.marketCap || best.fdv) || 0;
        const out = { marketCap: mc, liquidityUsd: Number(best.liquidity?.usd) || 0, priceUsd: Number(best.priceUsd) || 0 };
        if (mc > 0) swapApiPriceCache.set(mint, { mc, liq: out.liquidityUsd, px: out.priceUsd, at: Date.now() }); // feed getInstantMc too
        return out;
      }
      const curve = await pumpCurvePairFallback(mint).catch(() => null);
      if (curve) {
        return { marketCap: Number(curve.marketCap || curve.fdv) || 0, liquidityUsd: Number(curve.liquidity?.usd) || 0, priceUsd: Number(curve.priceUsd) || 0 };
      }
    } catch {}
    return null;
  },
  // Register a freshly-aped coin for live-price polling (swap-api) + the legacy trade-tick stream.
  onOpen: (mint) => { try { heldReqAt.set(mint, Date.now()); void swapApiPriceFor(mint); pumpPortalStream.watchMint(mint); let md = null; try { md = autopilotEngine.status()?.mode; } catch {} if (md === "pop") popHeldMints.set(mint, { at: Date.now(), peak: (() => { try { return popMetrics(mint, Date.now())?.inflowNow || 0; } catch { return 0; } })() }); } catch {} },
  // Synchronous, in-memory latest market cap (USD) from the live pump tick — used
  // so status() shows truly live prices on every poll, with zero network wait.
  getInstantMc: (mint) => {
    // In-memory, synchronous live MC for the display — the swap-api cache the poller + getPairLite
    // keep fresh (PumpPortal getTrades is dead, so reading it here showed a frozen/blank number).
    try {
      const sc = swapApiPriceCache.get(mint);
      if (sc && Date.now() - sc.at < 9000 && sc.mc > 0) return sc.mc;
    } catch {}
    return null;
  },
  // Real free SOL in the dedicated wallet — the true source of truth for the
  // displayed balance and for position sizing (reconciled into the engine).
  getWalletSol: async () => {
    if (!autopilotWalletRecord) return null;
    try {
      // Return a NUMBER (lamportsToSol returns a formatted string, which fails the
      // engine's Number.isFinite check — that bug left wallet(real) null + the
      // ledger synthetic instead of tracking real SOL).
      const lamports = await getSolBalanceCached(new PublicKey(autopilotWalletRecord.publicKey), { force: true });
      const sol = Number(lamports) / AUTOPILOT_LAMPORTS_PER_SOL;
      return Number.isFinite(sol) ? sol : null;
    } catch {
      return null;
    }
  },
  // Big-runner win (>=5x): post a clean SlimeWire PnL card to the channel + groups.
  onBigWin: (d) => { try { announceWinCard(d); } catch {} },
  // Send a specific SOL amount from the autopilot wallet to the vault address.
  sweepProfit: async (destination, amountSol) => {
    if (!autopilotWalletRecord) return { ok: false, error: "no wallet" };
    try {
      const dest = new PublicKey(destination);
      const lamports = Math.floor(Number(amountSol) * AUTOPILOT_LAMPORTS_PER_SOL);
      if (!(lamports > 0)) return { ok: false, error: "amount too small" };
      const keypair = decryptWallet(autopilotWalletRecord);
      const tx = new Transaction().add(SystemProgram.transfer({
        fromPubkey: keypair.publicKey,
        toPubkey: dest,
        lamports
      }));
      const signature = await sendLegacyTransaction(tx, [keypair]);
      invalidateWalletReadCache(autopilotWalletRecord.publicKey);
      return { ok: true, sentSol: Number(amountSol), signature };
    } catch (e) {
      return { ok: false, error: e && e.message };
    }
  },
  buyToken: async (mint, lamports) => {
    if (!autopilotWalletRecord) throw new Error("autopilot wallet not resolved");
    const res = await buyTokenForPlan(autopilotWalletRecord, mint, lamports, CONFIG.autopilotSlippageBps, {
      trackTokenDelta: true,
      priority: true,
      userId: `autopilot:${autopilotWalletRecord.ownerId}`
    });
    // CONFIRM the buy actually delivered tokens before the engine opens a position.
    // tokenDeltaAmount is the REAL measured balance increase (retried ~10s); if it's
    // null/0 the tokens never landed, so report failure instead of falling back to the
    // EXPECTED outputAmount. Falling back was the phantom source: a buy that didn't
    // deliver still "opened" and rode a marked price it never owned (the "deep" case).
    let delta = null;
    try { delta = res && res.tokenDeltaAmount != null ? BigInt(res.tokenDeltaAmount) : null; } catch { delta = null; }
    if (delta == null || delta <= 0n) {
      console.warn(`[autopilot] buy ${shortMint(mint)} did not deliver tokens — skipping (no phantom position).`);
      return { ok: false, error: "buy delivered no tokens", signature: res && res.signature };
    }
    return { ok: true, tokenAmount: res.tokenDeltaAmount, signature: res.signature };
  },
  sellPercent: async (mint, pct, pos = null) => {
    if (!autopilotWalletRecord) throw new Error("autopilot wallet not resolved");
    let baseRawAmount = null;
    try {
      if (pos && pos.tokenAmount != null && BigInt(pos.tokenAmount) > 0n) baseRawAmount = String(pos.tokenAmount);
    } catch {}
    // ESCALATING-SLIPPAGE EXIT (live-money fix — the "caught the rug but couldn't sell" bug). A
    // rugging/dumping memecoin craters faster than the flat 7% slippage can fill, so the sell REJECTS
    // and the position rides to ZERO. Retry with progressively higher slippage until it actually
    // LANDS — exiting at -40% beats failing at -7% and riding to -99%. The FIRST level that fills wins,
    // so a normal TP/stop on a stable/rising coin still exits cheap (no over-slippage); only a real
    // crash escalates to the 50% emergency. Each level tries BOTH routes (pump curve first, then
    // Jupiter) inside sellTokenFromWallet. Throws only if EVERY level fails (preserves the prior
    // throw-on-failure contract so the engine keeps the position instead of booking a phantom close).
    const base = Math.max(1, Number(CONFIG.autopilotSlippageBps) || 700);
    const levels = [...new Set([base, 1500, 2500, 5000].filter((s) => s >= base))];
    let res = null, lastErr = null, usedSlip = base;
    for (const slip of levels) {
      try {
        res = await sellTokenFromWallet(autopilotWalletRecord, mint, pct, slip, {
          priceExit: true,
          priority: true,
          ...(baseRawAmount ? { baseRawAmount } : {})
        });
        if (res) { usedSlip = slip; break; }
      } catch (e) { lastErr = e; }
    }
    if (!res) {
      console.warn(`[autopilot] exit ${shortMint(mint)} FAILED at every slippage level (${levels.join("/")}bps): ${lastErr && lastErr.message}`);
      throw lastErr || new Error("exit failed at all slippage levels");
    }
    if (usedSlip > base) console.log(`[autopilot] 🔻 exit ${shortMint(mint)} filled at ${(usedSlip / 100).toFixed(0)}% slippage (escalated from ${(base / 100).toFixed(0)}%) — got out ahead of the rug`);
    // Return the REAL SOL the wallet received (gross swap out minus our platform fee),
    // so the engine books actual fills — not the marked/displayed price. Without this
    // a +480%-marked moon bag that fills at +40% logged a fake +0.48 "win" while the
    // wallet barely moved. receivedSol = the truth the ledger + learning must use.
    const gross = Number(res?.outputLamports || 0);
    const fee = Number(res?.feeLamports || 0);
    const receivedSol = gross > 0 ? Math.max(0, gross - fee) / 1_000_000_000 : null;
    return { ok: true, signature: res?.signature, receivedSol };
  }
});

async function startLiveAutopilotResume() {
  // Populate dev-reputation from the trade history so it's effective immediately.
  await loadAutopilotTrades().catch(() => {});
  await loadAutopilotEvents().catch(() => {});
  // After a redeploy/restart, re-attach to an in-flight session so open positions keep
  // being managed and hunting resumes. RETRY with backoff — on boot the wallet store /
  // RPC may not be ready for a beat, and a single failure used to SILENTLY drop a LIVE
  // session (the run just stopped after a deploy). Now it keeps trying so a restart
  // re-attaches reliably instead of leaving the user stopped.
  let snap = null;
  try { snap = await readJson(AUTOPILOT_STATE_FILE).catch(() => null); } catch {}
  if (!snap || snap.stopped) return;
  // Don't resume a timer that already fully expired with nothing open.
  if (Number(snap.endAt) && Date.now() >= Number(snap.endAt) && (!Array.isArray(snap.open) || snap.open.length === 0)) return;
  for (let attempt = 1; attempt <= 5; attempt += 1) {
    try {
      if (snap.live) await relockAutopilotWalletByPubkey(snap.walletPubkey);
      const resumed = await autopilotEngine.resume(snap);
      if (resumed) {
        console.log(`[autopilot] resumed ${snap.live ? "LIVE" : "PAPER"} session with ${snap.open?.length || 0} open position(s) (attempt ${attempt}).`);
      }
      return; // resumed, or resume() declined (stopped/expired) — nothing left to retry
    } catch (e) {
      console.warn(`[autopilot] resume attempt ${attempt}/5 failed: ${e && e.message}`);
      if (attempt < 5) await sleep(2000 * attempt); // back off 2s,4s,6s,8s — wait for the store/RPC
    }
  }
  console.warn("[autopilot] resume gave up after 5 attempts — LIVE session not re-attached; restart it from the panel.");
}

