async function callOgreAgentModel(message = "", context = {}, fallback = {}) {
  if (!ogreAgentProviderEnabled()) return null;
  const providers = new Map([
    ["groq", callOgreAgentGroq],
    ["openai", callOgreAgentOpenAi],
    ["gemini", callOgreAgentGemini],
    ["openrouter", callOgreAgentOpenRouter]
  ]);
  const order = String(process.env.OGRE_AGENT_PROVIDER_ORDER || "groq,openai,gemini,openrouter")
    .split(",")
    .map((item) => item.trim().toLowerCase())
    .filter((item, index, list) => providers.has(item) && list.indexOf(item) === index);
  const startedAt = Date.now();
  const totalBudgetMs = Math.max(1500, Math.min(4500, Number(process.env.OGRE_AGENT_TOTAL_TIMEOUT_MS || 2800) || 2800));
  for (const name of (order.length ? order : providers.keys())) {
    const remainingMs = totalBudgetMs - (Date.now() - startedAt);
    if (remainingMs < 700) break;
    const timeoutMs = Math.min(ogreAgentProviderTimeoutMs(), remainingMs);
    const result = await providers.get(name)(message, context, fallback, timeoutMs).catch(() => null);
    if (result?.reply) return result;
  }
  return null;
}

async function webOgreAgentReply(body = {}) {
  const message = String(body.message || "").trim().slice(0, 1200);
  const context = body.context && typeof body.context === "object" ? body.context : {};
  if (!message) {
    return ogreAgentFallbackReply("help", context);
  }
  const siteHelpReply = ogreAgentSiteHelpReply(message, context);
  if (siteHelpReply) return siteHelpReply;
  const kolTrendReply = await ogreAgentKolTrendReply(message, context);
  if (kolTrendReply) return kolTrendReply;
  const toolRouterReply = await ogreAgentToolRouterReply(message, context);
  if (toolRouterReply) return toolRouterReply;
  const socialReply = await ogreAgentTokenSocialReply(message, context);
  if (socialReply) return socialReply;
  const trendReply = await ogreAgentTrendReply(message, context);
  if (trendReply) return trendReply;
  const fallback = await enrichOgreAgentCoinReply(ogreAgentFallbackReply(message, context), message, context);
  if (/^trade_/.test(String(fallback.intent || ""))) return fallback;
  const modelResult = await callOgreAgentModel(message, context, fallback);
  const modelReply = typeof modelResult === "string" ? modelResult : String(modelResult?.reply || "");
  return {
    ...fallback,
    reply: modelReply || fallback.reply,
    modelPowered: Boolean(modelReply),
    modelProvider: typeof modelResult === "object" ? String(modelResult?.provider || "") : ""
  };
}
function sendWebJson(request, response, status, data) {
  response.writeHead(status, {
    "Content-Type": "application/json",
    "Cache-Control": "no-store",
    ...webCorsHeaders(request)
  });
  response.end(JSON.stringify(data));
}

function sendCachedWebJson(request, response, status, data, cacheControl = "public, max-age=15, stale-while-revalidate=60") {
  response.writeHead(status, {
    "Content-Type": "application/json",
    "Cache-Control": cacheControl,
    ...webCorsHeaders(request)
  });
  response.end(JSON.stringify(data));
}

function sendWebBinary(request, response, status, buffer, contentType, filename = "") {
  response.writeHead(status, {
    "Content-Type": contentType,
    "Cache-Control": "no-store",
    "X-Ogre-Filename": filename,
    "Content-Disposition": filename ? `attachment; filename="${filename.replace(/[^a-z0-9_.-]/gi, "_")}"` : "attachment",
    ...webCorsHeaders(request)
  });
  response.end(buffer);
}

async function handleInternalWorkerTick(request, response) {
  if (!CONFIG.workerTickEnabled) {
    sendWebJson(request, response, 503, {
      ok: false,
      error: "worker_tick_disabled"
    });
    return;
  }

  const providedSecret = workerTickSecretFromRequest(request);
  if (!constantTimeStringEquals(providedSecret, CONFIG.workerSecret)) {
    sendWebJson(request, response, 401, {
      ok: false,
      error: "unauthorized_worker_tick"
    });
    return;
  }

  const body = await readJsonRequestBody(request, 64_000);
  const result = await runInternalWorkerTick(body);
  sendWebJson(request, response, 200, {
    ok: true,
    ...result
  });
}

function handleInternalWorkerHealth(request, response) {
  sendWebJson(request, response, 200, {
    ok: true,
    serviceRole: CONFIG.serviceRole,
    runWorker: CONFIG.runWorker,
    workerTickEnabled: CONFIG.workerTickEnabled,
    workerSecretConfigured: Boolean(CONFIG.workerSecret && CONFIG.workerSecret.length >= 24),
    runTradePlans: CONFIG.workerTickRunTradePlans,
    runDcaPlans: CONFIG.workerTickRunDcaPlans,
    warmFeeds: CONFIG.workerTickWarmFeeds,
    warmDisplayCaches: CONFIG.workerTickWarmDisplayCaches,
    displayCacheUserLimit: CONFIG.workerDisplayCacheUserLimit,
    workerConcurrency: CONFIG.workerConcurrency,
    webInternalTpSlRunnersEnabled: CONFIG.webInternalTpSlRunnersEnabled,
    webCriticalTpSlSafetyRunnerEnabled: webCriticalTpSlSafetyRunnerEnabled(),
    webInternalDcaRunnerEnabled: CONFIG.webInternalDcaRunnerEnabled,
    cacheEnabled: CONFIG.cacheEnabled,
    cacheProvider: kvProviderName(),
    cacheConfigured: kvConfigured(),
    cacheStats: cacheStatsSnapshot(),
    postgresHistory: postgresStatsSnapshot(),
    postgresHydrationEnabled: Boolean(CONFIG.postgresHydrationEnabled),
    postgresHydrationMaxConcurrency: CONFIG.postgresHydrationMaxConcurrency,
    devInfoEnabled: Boolean(CONFIG.devInfoEnabled),
    devInfoStats: { ...devInfoStats },
    activeCacheLocks: activeCacheLockSnapshot(),
    rpcProviderName: CONFIG.rpcProviderName,
    rpcUrlHost: CONFIG.rpcUrlHost,
    readRpcProviderName: CONFIG.readRpcProviderName || CONFIG.rpcProviderName,
    readRpcHost: CONFIG.readRpcHost || CONFIG.rpcUrlHost,
    readRpcSplitActive: Boolean(CONFIG.readRpcUrl),
    rpcRpsLimit: CONFIG.rpcRpsLimit,
    dasRpsLimit: CONFIG.dasRpsLimit,
    rpcStats: rpcStatsSnapshot(),
    deployId: process.env.RENDER_GIT_COMMIT || process.env.RENDER_SERVICE_ID || "",
    livePairRefreshSeconds: CONFIG.livePairsRefreshSeconds,
    stopLossCheckIntervalMs: CONFIG.stopLossCheckIntervalMs,
    stopLossPriceFailureSellAfter: CONFIG.stopLossPriceFailureSellAfter,
    tpSlMonitorStepTimeoutMs: CONFIG.tpSlMonitorStepTimeoutMs
  });
}

function workerTickSecretFromRequest(request) {
  const direct = request.headers["x-worker-secret"] || request.headers["x-ogre-worker-secret"];
  if (Array.isArray(direct)) return direct[0] || "";
  if (direct) return String(direct);

  const authorization = request.headers.authorization || "";
  const match = String(authorization).match(/^Bearer\s+(.+)$/i);
  return match ? match[1].trim() : "";
}

function constantTimeStringEquals(a, b) {
  const left = Buffer.from(String(a || ""));
  const right = Buffer.from(String(b || ""));
  if (left.length !== right.length || left.length === 0) return false;
  try {
    return crypto.timingSafeEqual(left, right);
  } catch {
    return false;
  }
}

function normalizeWorkerTaskSet(value = "all") {
  return String(value || "all").trim().toLowerCase() === "wallets" ? "wallets" : "all";
}

async function runInternalWorkerTick(body = {}) {
  const taskSet = normalizeWorkerTaskSet(body.taskSet || "all");
  const includeTradeTasks = taskSet === "all";
  const startedAt = Date.now();
  await recordTpSlWorkerHeartbeat("worker_tick_started", {
    requested: {
      taskSet,
      runTradePlans: body.runTradePlans !== false,
      runWebExitGuards: body.runWebExitGuards !== false,
      runPortfolioExits: body.runPortfolioExits !== false
    }
  }).catch(() => {});
  const result = {
    ranAt: new Date(startedAt).toISOString(),
    taskSet,
    portfolioExits: { skipped: true },
    webExitGuards: { skipped: true },
    tradePlans: { skipped: true },
    dcaPlans: { skipped: true },
    feeds: { skipped: true },
    displayCaches: { skipped: true }
  };

  const tradeTaskFlags = workerTickTaskFlags(body, {
    workerTickRunTradePlans: CONFIG.workerTickRunTradePlans,
    taskSet
  });

  if (includeTradeTasks && tradeTaskFlags.webExitGuards) {
    result.webExitGuards = await runWorkerTask("webExitGuards", () => processWebExitGuards({
      forcePriceCheck: body.forceTradePlans !== false
    }));
  }

  if (includeTradeTasks && tradeTaskFlags.tradePlans) {
    result.tradePlans = await runWorkerTask("tradePlans", () => processTradePlans({
      forcePriceCheck: body.forceTradePlans !== false
    }));
  }

  if (includeTradeTasks && tradeTaskFlags.portfolioExits) {
    result.portfolioExits = await runWorkerTask("portfolioExits", () => processWebPortfolioExits({
      forcePriceCheck: body.forceTradePlans !== false
    }));
  }

  if (includeTradeTasks && CONFIG.workerTickRunDcaPlans && body.runDcaPlans !== false) {
    result.dcaPlans = await runWorkerTask("dcaPlans", () => processDcaPlans());
  }

  if (includeTradeTasks && CONFIG.workerTickWarmFeeds && body.warmLivePairs !== false) {
    result.feeds = await runWorkerTask("feeds", () => warmWorkerLivePairFeeds(body));
  }

  if (CONFIG.workerTickWarmDisplayCaches && body.warmDisplayCaches !== false) {
    result.displayCaches = await runWorkerTask("displayCaches", () => warmWorkerDisplayCaches(body));
  }

  result.durationMs = Date.now() - startedAt;
  await recordTpSlWorkerHeartbeat("worker_tick_completed", result).catch(() => {});
  return result;
}

async function runWorkerTask(name, fn) {
  const startedAt = Date.now();
  try {
    const value = await fn();
    return {
      ok: true,
      durationMs: Date.now() - startedAt,
      value: value && typeof value === "object" ? value : undefined
    };
  } catch (error) {
    console.warn(`Worker ${name} tick failed: ${error.message}`);
    return {
      ok: false,
      durationMs: Date.now() - startedAt,
      error: error.message
    };
  }
}

async function warmWorkerLivePairFeeds(body = {}) {
  const buckets = normalizeWorkerList(body.buckets, ["live", "under1h", "under3h", "under1d"])
    .map(normalizeLivePairBucket)
    .filter((value, index, list) => list.indexOf(value) === index);
  const sorts = normalizeWorkerList(body.sorts, ["best", "newest"])
    .map((sort) => String(sort || "best").trim().toLowerCase())
    .filter(Boolean);
  const force = Boolean(body.forceFeeds);
  const warmed = [];

  for (const bucket of buckets) {
    for (const sort of sorts) {
      const livePairs = await DedupeService.run(`worker-feed:${bucket}:${sort}`, 10_000, () => webLivePairs("worker", bucket, { sort, force }));
      warmed.push({
        bucket,
        sort,
        rows: Array.isArray(livePairs?.rows) ? livePairs.rows.length : 0,
        stale: Boolean(livePairs?.stale)
      });
    }
  }

  return { warmed };
}

async function activeWebUserIdsForDisplayCache(limit = CONFIG.workerDisplayCacheUserLimit) {
  if (!limit) return [];
  const store = await readWebAuthStore();
  const now = Date.now();
  const seen = new Set();
  const users = [];
  const sessionsByRecent = [...(store.sessions || [])]
    .filter((session) => session?.userId && Date.parse(session.expiresAt || "") > now)
    .sort((a, b) => Date.parse(b.createdAt || b.expiresAt || "") - Date.parse(a.createdAt || a.expiresAt || ""));
  for (const session of sessionsByRecent) {
    const userId = String(session.userId || "").trim();
    if (!userId || seen.has(userId)) continue;
    seen.add(userId);
    users.push(userId);
    if (users.length >= limit) break;
  }
  return users;
}

async function warmWorkerDisplayCaches(body = {}) {
  return LockService.withLock("worker-display-caches", 25_000, async () => {
    const limit = Math.max(0, Math.min(50, Number.parseInt(body.displayCacheUserLimit || CONFIG.workerDisplayCacheUserLimit, 10) || 0));
    const userIds = await activeWebUserIdsForDisplayCache(limit);
    const warmed = [];
    const force = body.forceDisplayCaches !== false;
    await runWithConcurrency(userIds, Math.min(2, Math.max(1, CONFIG.balanceConcurrency)), async (userId) => {
      const userResult = {
        userId: crypto.createHash("sha256").update(String(userId)).digest("hex").slice(0, 10),
        balances: null,
        positions: null,
        pnl: null
      };
      const tasks = [
        ["balances", () => cachedWebSummary("web:balances", userId, { force, background: true }, 0, async () => {
          const [balances, connectedWallet] = await Promise.all([
            webBalanceRows(userId, { force }),
            webConnectedWalletBalance(userId, { force })
          ]);
          return { balances, connectedWallet };
        })],
        ["positions", () => cachedWebSummary("web:positions", userId, { force, background: true }, 0, async () => ({
          positions: await webPositionRows(userId, { force })
        }))],
        ["pnl", () => cachedWebSummary("web:pnl", userId, { force, background: true }, 0, async () => ({
          pnl: await webPnlSummary(userId)
        }))]
      ];
      const results = await Promise.allSettled(tasks.map(([, task]) => task()));
      results.forEach((result, index) => {
        const name = tasks[index][0];
        if (result.status === "fulfilled") {
          userResult[name] = {
            ok: true,
            cacheHit: Boolean(result.value.cacheHit),
            stale: Boolean(result.value.stale),
            rows: countSummaryRows(result.value.value),
            durationMs: result.value.durationMs
          };
        } else {
          userResult[name] = {
            ok: false,
            error: safePerfEventText(result.reason?.message || "Refresh failed", 120)
          };
        }
      });
      warmed.push(userResult);
    });

    return {
      provider: kvProviderName(),
      cacheConfigured: kvConfigured(),
      users: userIds.length,
      warmed
    };
  }, () => ({
    skipped: true,
    reason: "display_cache_lock_active",
    provider: kvProviderName(),
    cacheConfigured: kvConfigured(),
    users: 0,
    warmed: []
  }));
}

function normalizeWorkerList(value, fallback) {
  if (Array.isArray(value)) return value.map(String).filter(Boolean);
  if (typeof value === "string") {
    return value.split(",").map((item) => item.trim()).filter(Boolean);
  }
  return [...fallback];
}

async function readJsonRequestBody(request, maxBytes = 0) {
  const text = await readRequestBody(request, maxBytes);
  if (!text.trim()) return {};
  try {
    return JSON.parse(text);
  } catch {
    const error = new Error("Request body must be valid JSON.");
    error.statusCode = 400;
    throw error;
  }
}

function webhookPath() {
  return `/telegram/webhook/${CONFIG.webhookSecret}`;
}

function readRequestBody(request, maxBytes = 0) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    let totalBytes = 0;
    let tooLarge = false;
    request.on("data", (chunk) => {
      totalBytes += chunk.length;
      if (maxBytes > 0 && totalBytes > maxBytes) {
        tooLarge = true;
        chunks.length = 0;
        return;
      }
      if (tooLarge) return;
      chunks.push(chunk);
    });
    request.on("end", () => {
      if (tooLarge) {
        const error = new Error("Upload is too large. Use a smaller image or compress it before launching.");
        error.statusCode = 413;
        reject(error);
        return;
      }
      resolve(Buffer.concat(chunks).toString("utf8"));
    });
    request.on("error", reject);
  });
}

function parseAllowedUserIds(value) {
  return value
    .split(",")
    .map((item) => Number.parseInt(item.trim(), 10))
    .filter((item) => Number.isInteger(item));
}

function normalizeTelegramUsername(value) {
  return String(value || "").trim().replace(/^@/, "");
}

function parseBoolean(value) {
  return ["1", "true", "yes", "on"].includes(String(value).toLowerCase());
}

function parseOptionalBoolean(value, fallback) {
  if (value === undefined || value === null || String(value).trim() === "") return Boolean(fallback);
  return parseBoolean(value);
}

function normalizeServiceRole(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["worker", "background", "job", "jobs"].includes(normalized)) return "worker";
  if (["web", "server", "app", "api"].includes(normalized)) return "web";
  return "web";
}

function safeUrlHost(value = "") {
  try {
    return new URL(String(value || "")).host.toLowerCase();
  } catch {
    return "";
  }
}

function resolveSolanaRpcConfig() {
  const candidates = [
    ["SOLANA_VALIDATOR_RPC_URL", process.env.SOLANA_VALIDATOR_RPC_URL],
    ["SLIMEWIRE_VALIDATOR_RPC_URL", process.env.SLIMEWIRE_VALIDATOR_RPC_URL],
    ["HELIUS_RPC_URL", process.env.HELIUS_RPC_URL],
    ["HELIUS_DEVELOPER_RPC_URL", process.env.HELIUS_DEVELOPER_RPC_URL],
    ["HELIUS_HTTP_URL", process.env.HELIUS_HTTP_URL],
    ["HELIUS_SOLANA_RPC_URL", process.env.HELIUS_SOLANA_RPC_URL],
    ["SOLANA_RPC_URL", process.env.SOLANA_RPC_URL]
  ];
  const match = candidates.find(([, value]) => String(value || "").trim());
  const allowPublicFallback = parseBoolean(process.env.ALLOW_PUBLIC_RPC_FALLBACK || "false");
  const envSource = match?.[0] || (allowPublicFallback ? "ALLOW_PUBLIC_RPC_FALLBACK" : "");
  const url = String(match?.[1] || (allowPublicFallback ? "https://api.mainnet-beta.solana.com" : "")).trim();
  const host = safeUrlHost(url);
  if (!url || !host) {
    throw new Error("HELIUS_RPC_URL (or another Helius RPC env var) must be set. Public Solana RPC fallback is disabled unless ALLOW_PUBLIC_RPC_FALLBACK=true.");
  }
  const isPublicSolana = host === "api.mainnet-beta.solana.com";
  if (isPublicSolana && !allowPublicFallback) {
    throw new Error("Public Solana RPC fallback is disabled. Set HELIUS_RPC_URL/HELIUS_DEVELOPER_RPC_URL to the Helius Developer RPC endpoint.");
  }
  const providerName = String(envSource || "").includes("VALIDATOR")
    ? "validator"
    : host.includes("helius")
    ? "helius"
    : isPublicSolana
      ? "public-solana"
      : "custom";
  return {
    url,
    host,
    providerName,
    envSource,
    publicFallbackAllowed: allowPublicFallback
  };
}

// OPTIONAL cheaper READ provider (Alchemy / Chainstack / any standard Solana RPC).
// When set, high-volume READ calls (balances, token accounts, signature history) are
// routed here with AUTOMATIC fallback to the primary Helius connection on any error.
// Writes (sendRawTransaction), DAS metadata, and webhooks always stay on Helius.
// Unset => reads use Helius exactly as before (zero behavior change).
function resolveReadRpcConfig() {
  const candidates = [
    ["READ_RPC_URL", process.env.READ_RPC_URL],
    ["ALCHEMY_RPC_URL", process.env.ALCHEMY_RPC_URL],
    ["CHAINSTACK_RPC_URL", process.env.CHAINSTACK_RPC_URL],
    ["SECONDARY_RPC_URL", process.env.SECONDARY_RPC_URL]
  ];
  const match = candidates.find(([, value]) => String(value || "").trim());
  if (!match) return null;
  const url = String(match[1] || "").trim();
  const host = safeUrlHost(url);
  if (!url || !host) {
    throw new Error(`${match[0]} is set but is not a valid URL.`);
  }
  const providerName = /alchemy/i.test(host)
    ? "alchemy"
    : /chainstack|p2pify/i.test(host)
    ? "chainstack"
    : host.includes("helius")
    ? "helius"
    : "custom";
  return { url, host, providerName, envSource: match[0] };
}

function normalizeMetadataProvider(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized || normalized === "auto") return "auto";
  if (normalized === "pinata") return "pinata";
  if (["pumpfun-ipfs", "pump-fun-ipfs", "pumpfun", "pump.fun", "pump-fun"].includes(normalized)) {
    return "pumpfun-ipfs";
  }
  if (["hosted", "slimewire", "slimewire-hosted", "backend", "backend-hosted"].includes(normalized)) {
    return "slimewire-hosted";
  }
  throw new Error("METADATA_PROVIDER/PUMP_LAUNCH_METADATA_PROVIDER must be auto, pinata, pumpfun-ipfs, or slimewire-hosted.");
}

function normalizeCacheProvider(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized || normalized === "auto") return "auto";
  if (["memory", "none", "off", "disabled"].includes(normalized)) return "memory";
  if (["redis", "render-redis", "keyvalue", "key-value", "kv"].includes(normalized)) return "redis";
  if (["rest", "rest-kv", "upstash", "upstash-redis"].includes(normalized)) return "rest-kv";
  throw new Error("CACHE_PROVIDER/KV_PROVIDER must be auto, memory, redis, or rest-kv.");
}

function parseTradingSpeedPreset(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (["safe", "balanced", "fast"].includes(normalized)) {
    return normalized;
  }
  throw new Error("TRADING_SPEED_PRESET must be safe, balanced, or fast.");
}

function tradingSpeedDefaults(preset) {
  const presets = {
    safe: {
      bundleConcurrency: 1,
      balanceConcurrency: 1,
      rpcDelayMs: 1500,
      rpcMinIntervalMs: 1200,
      rpc429CooldownMs: 15000,
      jupiterMinIntervalMs: 1200,
      jupiter429CooldownMs: 15000
    },
    balanced: {
      bundleConcurrency: 2,
      balanceConcurrency: 3,
      rpcDelayMs: 750,
      rpcMinIntervalMs: 450,
      rpc429CooldownMs: 10000,
      jupiterMinIntervalMs: 500,
      jupiter429CooldownMs: 10000
    },
    fast: {
      bundleConcurrency: 3,
      balanceConcurrency: 5,
      rpcDelayMs: 400,
      rpcMinIntervalMs: 200,
      rpc429CooldownMs: 7000,
      jupiterMinIntervalMs: 250,
      jupiter429CooldownMs: 7000
    }
  };
  return presets[preset] || presets.balanced;
}

function loadDotEnv() {
  const envPath = path.resolve(process.cwd(), ".env");

  try {
    const raw = fsSync.readFileSync(envPath, "utf8");
    for (const line of raw.split(/\r?\n/)) {
      const trimmed = line.trim();
      if (!trimmed || trimmed.startsWith("#") || !trimmed.includes("=")) continue;
      const index = trimmed.indexOf("=");
      const key = trimmed.slice(0, index).trim();
      const value = trimmed.slice(index + 1).trim().replace(/^["']|["']$/g, "");
      if (!process.env[key]) process.env[key] = value;
    }
  } catch {
    // .env is optional when environment variables are supplied by the host.
  }
}

async function ensureDataFiles() {
  await ensureDataDir();
  await writeJsonIfMissing(walletPath(), { wallets: [] });
  await writeJsonIfMissing(auditPath(), { entries: [] });
  await writeJsonIfMissing(statePath(), { paused: false });
  await writeJsonIfMissing(tradePlansPath(), { plans: [] });
  await writeJsonIfMissing(webExitGuardsPath(), { guards: [] });
  await writeJsonIfMissing(tpSlWorkerStatePath(), defaultTpSlWorkerState());
  await writeJsonIfMissing(dcaPlansPath(), { plans: [] });
  await writeJsonIfMissing(sniperSettingsPath(), { users: {} });
  await writeJsonIfMissing(tradeHistoryPath(), { trades: [] });
  await writeJsonIfMissing(pumpLaunchAttemptsPath(), { attempts: [] });
  await writeJsonIfMissing(webAuthPath(), { codes: [], sessions: [] });
  await writeJsonIfMissing(lockInEventsPath(), { events: [] });
  await writeJsonIfMissing(terminalFeedEventsPath(), { events: [] });
  await writeJsonIfMissing(performanceEventsPath(), { events: [] });
  await writeJsonIfMissing(cacheEventsPath(), { events: [] });
  await fs.mkdir(pumpLaunchHostedMetadataRoot(), { recursive: true });
  await ensureAppSecretFingerprint();
  await assignUnownedWalletsToSingleAdmin();
  await validateStoredWalletSecrets();
}

async function ensureDataDir() {
  try {
    await fs.mkdir(CONFIG.dataDir, { recursive: true });
    await fs.access(CONFIG.dataDir, fsSync.constants.R_OK | fsSync.constants.W_OK);
  } catch (error) {
    if (isPermissionError(error)) {
      if (CONFIG.allowEphemeralStorage) {
        const fallbackDir = path.resolve(process.cwd(), "data");
        await fs.mkdir(fallbackDir, { recursive: true });
        await fs.access(fallbackDir, fsSync.constants.R_OK | fsSync.constants.W_OK);
        console.warn(`DATA_DIR ${CONFIG.dataDir} is not writable. Falling back to ephemeral storage at ${fallbackDir}. Wallet data can reset on free Render.`);
        CONFIG.dataDir = fallbackDir;
        return;
      }

      throw new Error([
        `Cannot write DATA_DIR at ${CONFIG.dataDir}.`,
        "On Render, this usually means the persistent disk is not mounted.",
        "Fix: add a persistent disk to this Web Service with mount path /var/data, keep DATA_DIR=/var/data, and redeploy.",
        "For free Render testing, set ALLOW_EPHEMERAL_STORAGE=true and use the bot's Export Backup button after wallet changes.",
        "If you created a normal Web Service from Git instead of a Blueprint, render.yaml did not automatically attach the disk.",
        "Do not change DATA_DIR to an ephemeral path for real wallets, or wallet data can reset on redeploy."
      ].join(" "));
    }

    throw error;
  }
}

function isPermissionError(error) {
  return ["EACCES", "EPERM", "EROFS"].includes(error?.code);
}

async function writeJsonIfMissing(filePath, value) {
  try {
    const existing = await fs.readFile(filePath, "utf8");
    if (existing.trim()) return;
  } catch {
  }
  await writeJsonFile(filePath, value);
}

