async function renderLaunchCard(d = {}, mint = "", cp = null) {
  const S = PNL_CARD_STYLE;
  const inner = await launchCardInnerSvg(d, mint, cp);
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${S.width}" height="${S.height}" viewBox="0 0 ${S.width} ${S.height}">${inner}</svg>`;
  return sharp(Buffer.from(svg)).png().toBuffer();
}

// Clean trade-WIN PnL card (for big runners). Branded as a SlimeWire trade — no
// mention of any bot/autopilot. Returns a PNG buffer.
function pnlMcLabel(n) {
  const v = Number(n) || 0;
  if (v >= 1000) return "$" + (v / 1000).toFixed(v >= 10000 ? 0 : 1) + "K";
  return "$" + Math.round(v);
}
async function renderPnlWinCard(d = {}) {
  const S = PNL_CARD_STYLE;
  const e = (s) => escapeSvg(String(s == null ? "" : s));
  const sym = e(String(d.symbol || "COIN").toUpperCase()).slice(0, 18);
  const gain = "+" + Math.round(Number(d.gainPct) || 0).toLocaleString("en-US") + "%";
  const mult = (Number(d.multiple) || 0) + "x";
  const entry = pnlMcLabel(d.entryMc);
  const peak = pnlMcLabel(d.peakMc);
  const ca = d.mint ? e(shortMint(d.mint)) : "";
  const W = S.width, H = S.height, slime = S.slime, green = S.green, white = S.white, muted = S.muted, FF = S.fontFamily;
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">
    <defs>
      <radialGradient id="bgg" cx="50%" cy="38%" r="70%"><stop offset="0%" stop-color="#0c2a10"/><stop offset="100%" stop-color="${S.bg}"/></radialGradient>
      <filter id="glow"><feDropShadow dx="0" dy="0" stdDeviation="10" flood-color="${slime}" flood-opacity="0.9"/></filter>
    </defs>
    <rect width="${W}" height="${H}" fill="url(#bgg)"/>
    <rect x="14" y="14" width="${W - 28}" height="${H - 28}" rx="26" fill="none" stroke="${slime}" stroke-opacity="0.55" stroke-width="3"/>
    <text x="60" y="86" font-family="${FF}" font-size="34" font-weight="900" fill="${slime}" letter-spacing="2">SLIMEWIRE</text>
    <text x="${W - 60}" y="86" text-anchor="end" font-family="${FF}" font-size="26" font-weight="700" fill="${muted}">PROFIT</text>
    <text x="60" y="210" font-family="${FF}" font-size="78" font-weight="900" fill="${white}">$${sym}</text>
    <text x="60" y="392" font-family="${FF}" font-size="190" font-weight="900" fill="${green}" filter="url(#glow)">${gain}</text>
    <text x="62" y="470" font-family="${FF}" font-size="64" font-weight="900" fill="${slime}">${mult}</text>
    <text x="${W - 60}" y="392" text-anchor="end" font-family="${FF}" font-size="40" font-weight="800" fill="${muted}">${entry} <tspan fill="${white}">→</tspan> ${peak}</text>
    <text x="${W - 60}" y="448" text-anchor="end" font-family="${FF}" font-size="30" font-weight="600" fill="${muted}">market cap</text>
    ${ca ? `<text x="60" y="560" font-family="${FF}" font-size="30" font-weight="600" fill="${muted}">CA ${ca}</text>` : ""}
    <text x="${W - 60}" y="608" text-anchor="end" font-family="${FF}" font-size="32" font-weight="800" fill="${slime}">www.slimewire.org</text>
    <text x="60" y="608" font-family="${FF}" font-size="28" font-weight="700" fill="${white}">traded on SlimeWire 🐸</text>
  </svg>`;
  return sharp(Buffer.from(svg)).png().toBuffer();
}

// ---- NEXT-LEVEL PnL cards: 10 rotating slime styles + a loss "blood-drip" style.
// Higgs-generated slime backgrounds in src/assets/pnl-bg, with dripping slime-text
// overlays. No bot wording — reads like a hand trade flex. Held time fixed (the
// engine passes numeric ms; we compute the duration directly).
const SLIME_BG_DIR = path.join(__dirname, "assets", "pnl-bg");
const slimeBgDataUrlCache = new Map();
async function slimeBgDataUrl(name) {
  if (slimeBgDataUrlCache.has(name)) return slimeBgDataUrlCache.get(name);
  try {
    const buffer = await fs.readFile(path.join(SLIME_BG_DIR, name));
    const mime = name.endsWith(".png") ? "image/png" : "image/jpeg";
    const url = `data:${mime};base64,${buffer.toString("base64")}`;
    slimeBgDataUrlCache.set(name, url);
    return url;
  } catch { slimeBgDataUrlCache.set(name, null); return null; }
}
// Stable 1..15 style per mint (so a coin always looks the same), or an explicit override.
// 15 distinct swamp-ogre backgrounds for wins AND 15 for losses, so cards never feel
// same-y — each coin gets its own scene, win or loss.
const SLIME_BG_COUNT = 15;
function slimeStyleIndex(mint, override) {
  const ov = Number(override);
  if (Number.isFinite(ov) && ov >= 1) return (((Math.floor(ov) - 1) % SLIME_BG_COUNT) + SLIME_BG_COUNT) % SLIME_BG_COUNT + 1;
  let h = 5381; const s = String(mint || "slime");
  for (let i = 0; i < s.length; i++) h = ((h * 33) ^ s.charCodeAt(i)) >>> 0;
  return (h % SLIME_BG_COUNT) + 1;
}
// A gooey slime drip = a fat rounded neck that bulges into a big teardrop blob at
// the end (NOT a thin line). The blob is wider than the neck so it reads as molten
// slime oozing down. Width drives the whole thing.
function slimeDripGroup(cx, baseY, color, drops, w) {
  return drops.map(([dx, len]) => {
    const x = cx + dx, ww = w || 12, r = ww * 1.15 + 3;   // blob noticeably fatter than neck
    const yb = baseY + len + r - 4;
    return `<rect x="${(x - ww / 2).toFixed(1)}" y="${baseY.toFixed(1)}" width="${ww}" height="${len}" rx="${(ww / 2).toFixed(1)}" fill="${color}"/>`
      + `<ellipse cx="${x.toFixed(1)}" cy="${yb.toFixed(1)}" rx="${(r * 0.92).toFixed(1)}" ry="${r.toFixed(1)}" fill="${color}"/>`;
  }).join("");
}

async function renderSlimeCard(d = {}) {
  const win = d.loss === true ? false : (d.loss === false ? true : (Number(d.profitSol) >= 0));
  const style = slimeStyleIndex(d.mint, d.style);
  const bgUrl = await slimeBgDataUrl(win ? `slime-bg-${style}.jpg` : `slime-loss-${style}.jpg`);
  let imageDataUrl = "";
  try { imageDataUrl = await tokenImageDataUrl(d.imageUrl || ""); } catch {}
  const W = PNL_CARD_STYLE;
  const symbol = escapeSvg(sanitizeCardText(String(d.symbol || "TOKEN"), 16));
  const name = escapeSvg(sanitizeCardText(String(d.name || "SlimeWire"), 22));
  const gainPct = Number(d.gainPct);
  const multiple = d.multiple != null ? Math.round(Number(d.multiple) * 10) / 10 : (Number.isFinite(gainPct) ? Math.round((1 + gainPct / 100) * 10) / 10 : null);
  const profit = Number(d.profitSol) || 0;
  const spent = Number(d.costSol) || 0;
  const received = Number(d.receivedSol) || 0;
  const heldMs = (Number(d.closedAt) > 0 && Number(d.openedAt) > 0)
    ? Math.max(0, Number(d.closedAt) - Number(d.openedAt))
    : (Number(d.heldMs) || 0);
  const held = heldMs > 0 ? formatCompactDurationMs(heldMs) : "n/a";
  const mc = Number(d.peakMc || d.entryMc) || 0;
  const sol4 = (n) => (Math.round(Number(n) * 1e4) / 1e4).toString();
  // Per-feature card theming (gold OgreSwap, violet SlimeBot, green Autopilot default).
  // "receipt" mode shows an honest headline + lines instead of PnL math (for flows that
  // don't track round-trip P&L, e.g. a manual swap or a volume campaign).
  const CARD_THEME = { auto: { a: "#39ff14", label: "PNL CARD", f: ["#f1ffd6", "#76ff3c", "#13a30c"] }, swap: { a: "#ffd45a", label: "OGRESWAP", f: ["#fff3c4", "#ffc23a", "#c8860f"] }, volume: { a: "#c06bff", label: "SLIMEBOT", f: ["#efd9ff", "#b06bff", "#6a2bb0"] } };
  const theme = CARD_THEME[String(d.theme || "")] ? CARD_THEME[String(d.theme)] : CARD_THEME.auto;
  const themedWin = win && theme !== CARD_THEME.auto;
  const receipt = d.receipt === true || d.receipt === "true";
  const big = receipt
    ? String(d.headline || "RECEIPT")
    : (win ? `${multiple != null ? multiple : "?"}X` : `-${Math.abs(Math.round(gainPct || 0))}%`);
  const accent = win ? theme.a : W.red;
  const dripColor = win ? theme.a : "#c41212";
  const bigDrops = win ? [[-45, 30], [50, 52], [150, 36], [245, 58], [95, 22]] : [[-45, 50], [50, 76], [150, 56], [245, 92], [110, 108]];
  const artX = 66, artY = 168, artS = 360, colX = 472;
  const art = imageDataUrl
    ? `<image href="${imageDataUrl}" x="${artX}" y="${artY}" width="${artS}" height="${artS}" preserveAspectRatio="xMidYMid slice" clip-path="url(#artClip)"/>`
    : `<rect x="${artX}" y="${artY}" width="${artS}" height="${artS}" rx="30" fill="#0c1f10"/><text x="${artX + artS / 2}" y="${artY + artS / 2 + 34}" text-anchor="middle" font-size="120" font-weight="900" fill="${accent}" font-family="${W.fontFamily}">${symbol.slice(0, 3)}</text>`;
  // Frame: REAL photoreal slime (Higgs-rendered, background removed) dripping from
  // the top of every card, and pooling at the bottom — green on wins, blood-red on
  // losses. These are raster overlays, not drawn shapes, so they read as actual goo.
  const TOPH = 155, BOTH = win ? 125 : 130;
  let topBand, bottomBand;
  if (themedWin) {
    // gold/violet themed flat accent bars instead of the green slime raster
    topBand = `<rect x="0" y="0" width="${W.width}" height="12" fill="${accent}" opacity="0.9"/>`;
    bottomBand = `<rect x="0" y="${W.height - 12}" width="${W.width}" height="12" fill="${accent}" opacity="0.9"/>`;
  } else {
    const topUrl = await slimeBgDataUrl("slime-top-green.png");
    const botUrl = await slimeBgDataUrl(win ? "slime-bot-green.png" : "slime-bot-red.png");
    topBand = topUrl ? `<image href="${topUrl}" x="0" y="0" width="${W.width}" height="${TOPH}" preserveAspectRatio="none"/>` : "";
    bottomBand = botUrl ? `<image href="${botUrl}" x="0" y="${W.height - BOTH}" width="${W.width}" height="${BOTH}" preserveAspectRatio="none"/>` : "";
  }

  const svg = `
<svg xmlns="http://www.w3.org/2000/svg" width="${W.width}" height="${W.height}" viewBox="0 0 ${W.width} ${W.height}">
  <defs>
    <linearGradient id="bigFill" x1="0" y1="0" x2="0" y2="1">
      ${win
        ? `<stop offset="0%" stop-color="${theme.f[0]}"/><stop offset="45%" stop-color="${theme.f[1]}"/><stop offset="100%" stop-color="${theme.f[2]}"/>`
        : `<stop offset="0%" stop-color="#a6ff6b"/><stop offset="42%" stop-color="#ff7a3a"/><stop offset="100%" stop-color="#8a0d0d"/>`}
    </linearGradient>
    <linearGradient id="scrim" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="#000000" stop-opacity="0.20"/>
      <stop offset="38%" stop-color="#000000" stop-opacity="0.62"/>
      <stop offset="100%" stop-color="#000000" stop-opacity="0.30"/>
    </linearGradient>
    <clipPath id="artClip"><rect x="${artX}" y="${artY}" width="${artS}" height="${artS}" rx="30"/></clipPath>
    <filter id="cardShadow" x="-20%" y="-20%" width="140%" height="140%"><feDropShadow dx="0" dy="16" stdDeviation="22" flood-color="#000" flood-opacity="0.6"/></filter>
    <filter id="bigGlow" x="-12%" y="-15%" width="124%" height="150%">
      <feDropShadow dx="0" dy="0" stdDeviation="6" flood-color="${accent}" flood-opacity="0.95"/>
      <feDropShadow dx="0" dy="0" stdDeviation="22" flood-color="${accent}" flood-opacity="0.45"/>
    </filter>
    <filter id="txtGlow" x="-20%" y="-40%" width="140%" height="180%"><feDropShadow dx="0" dy="0" stdDeviation="4" flood-color="${W.slime}" flood-opacity="0.8"/></filter>
  </defs>
  ${bgUrl ? `<image href="${bgUrl}" x="0" y="0" width="${W.width}" height="${W.height}" preserveAspectRatio="xMidYMid slice"/>` : `<rect width="${W.width}" height="${W.height}" fill="${W.bg}"/>`}
  <rect width="${W.width}" height="${W.height}" fill="url(#scrim)"/>
  <rect x="20" y="20" width="${W.width - 40}" height="${W.height - 40}" rx="34" fill="none" stroke="${accent}" stroke-width="4" opacity="0.5"/>
  ${art}
  <rect x="${artX}" y="${artY}" width="${artS}" height="${artS}" rx="30" fill="none" stroke="${accent}" stroke-width="5" opacity="0.85" filter="url(#bigGlow)"/>
  <text x="${colX}" y="196" font-family="${W.fontFamily}" font-size="44" font-weight="900" fill="${W.slime}" filter="url(#txtGlow)">www.SlimeWire.org</text>
  <text x="${colX}" y="226" font-family="${W.fontFamily}" font-size="26" font-weight="800" fill="${W.muted}" letter-spacing="6">${escapeSvg(theme.label)}</text>
  <g filter="url(#bigGlow)"><text x="${colX}" y="358" font-family="${W.fontFamily}" font-size="${receipt ? 110 : 168}" font-weight="900" fill="url(#bigFill)" letter-spacing="-2">${escapeSvg(big)}</text></g>
  <text x="${colX}" y="420" font-family="${W.fontFamily}" font-size="42" font-weight="900" fill="${W.white}">${symbol} <tspan fill="${W.muted}" font-size="30">/ ${name}</tspan></text>
  ${receipt
    ? `<text x="${colX}" y="462" font-family="${W.fontFamily}" font-size="34" font-weight="900" fill="${accent}">${escapeSvg(String((d.lines && d.lines[0]) || ""))}</text>
  <text x="${colX}" y="500" font-family="${W.fontFamily}" font-size="26" font-weight="700" fill="${W.muted}">${escapeSvg(String((d.lines && d.lines[1]) || ""))}</text>
  <text x="${colX}" y="534" font-family="${W.fontFamily}" font-size="26" font-weight="700" fill="${W.muted}">${escapeSvg(String((d.lines && d.lines[2]) || ""))}</text>`
    : `<text x="${colX}" y="462" font-family="${W.fontFamily}" font-size="36" font-weight="900" fill="${accent}">${win ? "Profit +" : "Loss -"}${escapeSvg(sol4(Math.abs(profit)))} SOL</text>
  <text x="${colX}" y="500" font-family="${W.fontFamily}" font-size="26" font-weight="700" fill="${W.muted}">Spent ${escapeSvg(sol4(spent))} SOL   |   Received ${escapeSvg(sol4(received))} SOL</text>
  <text x="${colX}" y="534" font-family="${W.fontFamily}" font-size="26" font-weight="700" fill="${W.muted}">Held ${escapeSvg(held)}${mc ? `   |   ${win ? "Peak " : ""}MC ${escapeSvg(formatUsdCompact(mc))}` : ""}</text>`}
  ${topBand}${bottomBand}
</svg>`;
  return sharp(Buffer.from(svg)).png().toBuffer();
}

// Public entry: enrich autopilot win/loss data with token name/image/MC, then render.
async function renderAutopilotPnlCard(d = {}) {
  const enriched = { ...d };
  try {
    const m = await getDexTokenMetadata(d.mint).catch(() => null);
    if (m) {
      if (!enriched.name) enriched.name = m.name || "";
      if (!enriched.imageUrl) enriched.imageUrl = m.imageUrl || m.avatarUrl || "";
      if (!enriched.peakMc && !enriched.entryMc) enriched.peakMc = Number(m.marketCap || m.fdv) || 0;
    }
  } catch {}
  return renderSlimeCard(enriched);
}

// Post a big-win PnL card to the channel + opted-in groups. Looks like a normal
// SlimeWire trade flex — never references any automation.
function announceWinCard(d = {}) {
  void (async () => {
    try {
      const png = await renderAutopilotPnlCard(d).catch(() => null);
      if (!png) return;
      const sym = String(d.symbol || "").toUpperCase();
      const link = d.mint ? `https://www.slimewire.org/t?ca=${d.mint}` : "https://www.slimewire.org";
      const cap = `🟢 <b>$${escapeTelegramHtml(sym)}</b> +${Math.round(Number(d.gainPct) || 0).toLocaleString("en-US")}% (${d.multiple}x) — traded on SlimeWire\n${link}`;
      const fname = `win-${sanitizeFilenamePart(sym || d.mint || "trade")}.png`;
      tgChannel.announcePhoto("pnl-win", d.mint || sym, png, fname, cap);
      broadcastPhotoToTelegramGroups("pnl-win", d.mint || sym, png, fname, cap);
    } catch (e) {
      console.warn(`[pnl-win] ${e && e.message}`);
    }
  })();
}

// FREE animated GIF trailer (no external API): the fire card with a slow zoom +
// a diagonal "shine" sweep, authored frame-by-frame via sharp's join. Returns a
// GIF buffer, or null if anything fails (caller falls back to the static card).
async function buildLaunchTrailerGif(d = {}, mint = "", cp = null) {
  try {
    const S = PNL_CARD_STYLE;
    const inner = await launchCardInnerSvg(d, mint, cp);
    const FRAMES = 16, OUTW = 760;
    const bufs = [];
    for (let f = 0; f < FRAMES; f++) {
      const t = f / (FRAMES - 1);
      const zoom = 1 + t * 0.05;                       // slow push-in
      const vw = S.width / zoom, vh = S.height / zoom;
      const vx = (S.width - vw) / 2, vy = (S.height - vh) / 2;
      const sweepX = -400 + t * (S.width + 800);       // diagonal light sweep
      const overlay = `<g opacity="0.10"><polygon points="${sweepX},0 ${sweepX + 180},0 ${sweepX - 120},${S.height} ${sweepX - 300},${S.height}" fill="#ffffff"/></g>`;
      const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${S.width}" height="${S.height}" viewBox="${vx.toFixed(2)} ${vy.toFixed(2)} ${vw.toFixed(2)} ${vh.toFixed(2)}">${inner}${overlay}</svg>`;
      bufs.push(await sharp(Buffer.from(svg)).resize(OUTW).png().toBuffer());
    }
    return await sharp(bufs, { join: { animated: true } }).gif({ loop: 0, delay: 130 }).toBuffer();
  } catch { return null; }
}

// FREE cinematic ~15s MP4 trailer (no external API): 5 composed scenes (suspense ->
// logo reveal -> $TICKER -> LIVE ON PUMP.FUN + CA -> CTA) rendered by sharp and
// stitched with ffmpeg crossfades. Watermarked www.SlimeWire.org. Returns an MP4
// buffer or null (caller falls back to the GIF).
function trailerSceneFrame(inner) {
  const W = 1200, H = 675, slime = "#39ff14";
  const wm = `<text x="600" y="652" text-anchor="middle" font-family="Arial, Helvetica, sans-serif" font-size="22" font-weight="800" fill="${slime}" opacity="0.85">www.SlimeWire.org</text>`;
  const defs = `<defs><radialGradient id="g" cx="50%" cy="46%" r="60%"><stop offset="0%" stop-color="${slime}" stop-opacity="0.5"/><stop offset="100%" stop-color="${slime}" stop-opacity="0"/></radialGradient><clipPath id="cir"><circle cx="600" cy="300" r="190"/></clipPath><filter id="gl"><feDropShadow dx="0" dy="0" stdDeviation="6" flood-color="${slime}" flood-opacity="0.95"/></filter></defs>`;
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}"><rect width="${W}" height="${H}" fill="#040a05"/>${defs}${inner}${wm}</svg>`;
}
async function buildLaunchTrailerMp4(d = {}, mint = "", cp = null) {
  if (!ffmpegPath) return null;
  const FF = "Arial, Helvetica, sans-serif", slime = "#39ff14", white = "#f7fff7", muted = "#b8c7b8";
  const e = (s) => escapeSvg(String(s == null ? "" : s));
  const sym = e(String(d.symbol || "COIN").toUpperCase());
  const copy = cp || await launchHypeCopy(d);
  const tagline = e(sanitizeCardText(copy.tagline || "", 46));
  const caShort = mint ? e(shortMint(mint)) : "minting";
  const socialsText = e(sanitizeCardText(launchSocials(d).map((s) => s.label).join("    ") || "pump.fun", 46));
  const artUrl = await safeLaunchArtDataUrl(d.imageDataUrl) || (mint ? await safeLaunchArtDataUrl((await getDexTokenMetadata(mint).catch(() => null))?.imageUrl) : "");
  const art = artUrl
    ? `<image href="${artUrl}" x="410" y="110" width="380" height="380" preserveAspectRatio="xMidYMid slice" clip-path="url(#cir)"/><circle cx="600" cy="300" r="190" fill="none" stroke="${slime}" stroke-width="5" filter="url(#gl)"/>`
    : `<circle cx="600" cy="300" r="190" fill="#0c2410" stroke="${slime}" stroke-width="5" filter="url(#gl)"/><text x="600" y="335" text-anchor="middle" font-family="${FF}" font-size="120" font-weight="900" fill="${slime}">${sym.slice(0, 3)}</text>`;
  const scenes = [
    `<rect width="1200" height="675" fill="url(#g)" opacity="0.25"/><text x="600" y="320" text-anchor="middle" font-family="${FF}" font-size="40" font-weight="900" fill="${muted}" letter-spacing="14">INCOMING...</text>`,
    `<rect width="1200" height="675" fill="url(#g)" opacity="0.5"/>${art}<text x="600" y="560" text-anchor="middle" font-family="${FF}" font-size="34" font-weight="800" fill="${white}">a fresh slime crawls out of the swamp</text>`,
    `<rect width="1200" height="675" fill="url(#g)" opacity="0.4"/><text x="600" y="300" text-anchor="middle" font-family="${FF}" font-size="150" font-weight="900" fill="${white}">$${sym}</text><text x="600" y="380" text-anchor="middle" font-family="${FF}" font-size="40" font-weight="900" fill="${slime}" filter="url(#gl)">${tagline}</text>`,
    `<rect width="1200" height="675" fill="url(#g)" opacity="0.55"/><text x="600" y="280" text-anchor="middle" font-family="${FF}" font-size="92" font-weight="900" fill="${slime}" filter="url(#gl)">LIVE ON PUMP.FUN</text><text x="600" y="362" text-anchor="middle" font-family="monospace" font-size="34" font-weight="800" fill="${white}">CA ${caShort}</text>`,
    `<rect width="1200" height="675" fill="url(#g)" opacity="0.45"/><text x="600" y="262" text-anchor="middle" font-family="${FF}" font-size="64" font-weight="900" fill="${slime}" filter="url(#gl)">BORN ON SLIMEWIRE</text><text x="600" y="334" text-anchor="middle" font-family="${FF}" font-size="30" font-weight="800" fill="${white}">${socialsText}</text><text x="600" y="416" text-anchor="middle" font-family="${FF}" font-size="46" font-weight="900" fill="${white}">www.SlimeWire.org</text>`
  ];
  const dur = [3.2, 3.4, 3.4, 3.4, 3.8], xf = 0.6;
  let dir = null;
  try {
    dir = await fs.mkdtemp(path.join(os.tmpdir(), "swtrail-"));
    const files = [];
    for (let i = 0; i < scenes.length; i++) {
      const f = path.join(dir, `s${i}.png`);
      await fs.writeFile(f, await sharp(Buffer.from(trailerSceneFrame(scenes[i]))).png().toBuffer());
      files.push(f);
    }
    const out = path.join(dir, "out.mp4");
    const inputs = [];
    files.forEach((f, i) => { inputs.push("-loop", "1", "-t", String(dur[i]), "-i", f); });
    let fc = "";
    files.forEach((f, i) => { fc += `[${i}:v]scale=768:432,fps=25,format=yuv420p,setsar=1[v${i}];`; });
    let prev = "v0", off = 0;
    for (let i = 1; i < files.length; i++) {
      off += dur[i - 1] - xf;
      const tag = (i === files.length - 1) ? "vout" : `x${i}`;
      fc += `[${prev}][v${i}]xfade=transition=fade:duration=${xf}:offset=${off.toFixed(2)}[${tag}];`;
      prev = tag;
    }
    const args = ["-y", ...inputs, "-filter_complex", fc.replace(/;$/, ""), "-map", "[vout]", "-pix_fmt", "yuv420p", "-c:v", "libx264", "-preset", "veryfast", "-movflags", "+faststart", out];
    await new Promise((res, rej) => {
      const proc = spawn(ffmpegPath, args);
      let err = "";
      proc.stderr.on("data", (chunk) => { err += chunk; if (err.length > 4000) err = err.slice(-2000); });
      proc.on("error", rej);
      proc.on("close", (code) => code === 0 ? res() : rej(new Error(`ffmpeg ${code}: ${err.slice(-300)}`)));
    });
    return await fs.readFile(out);
  } catch (error) {
    console.warn(`[launch-trailer] mp4 failed: ${error.message}`);
    return null;
  } finally {
    if (dir) fs.rm(dir, { recursive: true, force: true }).catch(() => {});
  }
}

// Best available trailer: cinematic MP4 if ffmpeg works, else the GIF.
async function buildBestTrailer(d = {}, mint = "", cp = null) {
  const mp4 = await buildLaunchTrailerMp4(d, mint, cp);
  if (mp4 && mp4.length) return { kind: "mp4", buffer: mp4 };
  const gif = await buildLaunchTrailerGif(d, mint, cp);
  if (gif && gif.length) return { kind: "gif", buffer: gif };
  return null;
}

async function postLaunchTrailer(chatId, d = {}, mint = "") {
  try {
    const sym = String(d.symbol || "COIN").toUpperCase();
    const cp = await launchHypeCopy(d);
    const socials = launchSocials(d);
    // caption links (clickable in Telegram): pump + chart + each social + ALWAYS website
    const linkLines = [];
    if (mint) { linkLines.push(`💊 <a href="https://pump.fun/${mint}">Pump.fun</a>  ·  📈 <a href="https://www.slimewire.org/t?ca=${mint}">Chart</a>`); }
    for (const s of socials) { linkLines.push(`🔗 <a href="${s.url}">${escapeHtml(s.label)}</a>`); }
    linkLines.push(`🌐 <a href="https://www.slimewire.org">www.SlimeWire.org</a>`);
    const caption = [
      `🚀 <b>$${sym} — born on SlimeWire</b>`,
      escapeHtml(cp.tagline),
      "",
      ...cp.lines.map((l) => escapeHtml(l)),
      mint ? `\nCA: <code>${mint}</code>` : "",
      "",
      ...linkLines
    ].filter(Boolean).join("\n");
    const kbRows = [];
    if (mint) kbRows.push([{ text: "📈 Chart", url: `https://www.slimewire.org/t?ca=${mint}` }, { text: "💊 Pump.fun", url: `https://pump.fun/${mint}` }]);
    const socialBtns = socials.map((s) => ({ text: s.label.length > 16 ? s.label.slice(0, 15) + "…" : s.label, url: s.url }));
    for (let i = 0; i < socialBtns.length; i += 2) kbRows.push(socialBtns.slice(i, i + 2));
    kbRows.push([{ text: "🌐 SlimeWire.org", url: "https://www.slimewire.org" }, { text: "🐸 Swamp", url: "https://www.slimewire.org/swamp" }]);
    const kb = { inline_keyboard: kbRows };

    // Public channel/groups are posted by announceLaunchCard. Here we ONLY give the
    // launcher a private copy (DM = positive chat id) so groups don't get doubles.
    const targets = [];
    if (Number(chatId) > 0) targets.push(chatId);
    const broadcast = ogreAgentEnv("LAUNCH_BROADCAST_CHAT_ID");
    if (broadcast && !targets.map(String).includes(String(broadcast))) targets.push(broadcast);
    if (!targets.length) return;

    // 1) FIRE IMAGE FIRST — the launch card with CA + socials + website (fast, always works)
    const png = await renderLaunchCard(d, mint, cp);
    const fname = `launch-${sanitizeFilenamePart(sym)}.png`;
    for (const t of targets) { try { await sendPhoto(t, fname, png, caption, kb, "HTML"); } catch { /* per-target */ } }

    // 2) THEN THE VIDEO — free cinematic MP4 trailer by default (no API/no cost);
    //    upgrades to a real AI MP4 only if a video key (FAL_KEY) is set.
    const vCap = `🎬 <b>$${sym}</b> trailer — born on SlimeWire${mint ? `\nCA: <code>${mint}</code>` : ""}`;
    const hasVideoApi = ogreAgentEnv("FAL_KEY") || ogreAgentEnv("LAUNCH_VIDEO_API_KEY") || ogreAgentEnv("LAUNCH_VIDEO_API_URL");
    (async () => {
      if (hasVideoApi) {
        const vid = await generateLaunchVideo(d, mint, cp).catch(() => null);
        if (vid && vid.url) { for (const t of targets) { try { await sendTelegramVideo(t, { url: vid.url }, vCap, kb); } catch { /* per-target */ } } return; }
      }
      const tr = await buildBestTrailer(d, mint, cp);
      if (!tr) return;
      for (const t of targets) {
        try {
          if (tr.kind === "mp4") await sendTelegramVideo(t, { buffer: tr.buffer, filename: `${fname}.mp4` }, vCap, kb);
          else await sendTelegramAnimation(t, tr.buffer, `${fname}.gif`, vCap, kb);
        } catch { /* per-target */ }
      }
    })().catch(() => {});
  } catch { /* launch already succeeded; trailer is bonus */ }
}

async function nextPnlBorderDataUrl() {
  if (PNL_CARD_BORDER_FILES.length === 0) return null;

  for (let attempt = 0; attempt < PNL_CARD_BORDER_FILES.length; attempt += 1) {
    const index = pnlBorderRotationIndex % PNL_CARD_BORDER_FILES.length;
    pnlBorderRotationIndex = (pnlBorderRotationIndex + 1) % PNL_CARD_BORDER_FILES.length;
    const dataUrl = await pnlBorderDataUrl(PNL_CARD_BORDER_FILES[index]);
    if (dataUrl) return dataUrl;
  }

  return null;
}

async function pnlBorderDataUrl(filePath) {
  if (pnlBorderDataUrlCache.has(filePath)) {
    return pnlBorderDataUrlCache.get(filePath);
  }

  try {
    const buffer = await fs.readFile(filePath);
    const dataUrl = `data:image/png;base64,${buffer.toString("base64")}`;
    pnlBorderDataUrlCache.set(filePath, dataUrl);
    return dataUrl;
  } catch {
    pnlBorderDataUrlCache.set(filePath, null);
    return null;
  }
}

