// Shareable signal card: token stats + shield verdict as a watermarked PNG. Built the
// same way as PnL cards (SVG composited by sharp) so it needs no new dependencies.
const signalCardCache = new Map();
async function renderSignalCard(tokenMint) {
  const cached = signalCardCache.get(tokenMint);
  if (cached && Date.now() - cached.at < 60_000) return cached.png;
  const shield = await webSlimeShield(tokenMint).catch(() => null);
  const pairs = await fetchDexScreenerTokenPairsFallback(tokenMint).catch(() => []);
  const best = bestDexPairForToken(tokenMint, pairs);
  const symbol = sanitizeCardText(best?.baseToken?.symbol || shortMint(tokenMint), 14);
  const name = sanitizeCardText(best?.baseToken?.name || "", 30);
  const verdict = String(shield?.verdict || "UNRATED").toUpperCase();
  const verdictColor = { BUY: "#72ff23", CAUTION: "#ffd84d", RISK: "#ff9d4d", AVOID: "#ff6b5e" }[verdict] || "#9fb59a";
  const mcap = Number(best?.marketCap || best?.fdv) || null;
  const liq = Number(best?.liquidity?.usd) || null;
  const vol = Number(best?.volume?.h24) || null;
  const change = Number(best?.priceChange?.h1);
  const stats = [
    mcap ? `MC ${formatUsdCompact(mcap)}` : null,
    liq ? `LIQ ${formatUsdCompact(liq)}` : null,
    vol ? `VOL ${formatUsdCompact(vol)}` : null,
    Number.isFinite(change) ? `1H ${change >= 0 ? "+" : ""}${change.toFixed(1)}%` : null
  ].filter(Boolean).join("   ");
  // Same visual language as the PnL card: slime border, dark panel, token art on
  // the left, glow title - so every shared card is unmistakably SlimeWire.
  const imageDataUrl = await tokenImageDataUrl(best?.info?.imageUrl);
  const art = imageDataUrl
    ? `<image href="${imageDataUrl}" x="72" y="160" width="400" height="400" preserveAspectRatio="xMidYMid slice" clip-path="url(#sigArtClip)"/>
  <rect x="72" y="160" width="400" height="400" rx="34" fill="none" stroke="${verdictColor}" stroke-opacity="0.6" stroke-width="3"/>`
    : `<rect x="72" y="160" width="400" height="400" rx="34" fill="#123018"/><text x="272" y="395" text-anchor="middle" font-size="120" font-weight="900" fill="${verdictColor}" font-family="${PNL_CARD_STYLE.fontFamily}">${escapeSvg(symbol.slice(0, 4))}</text>`;
  const bgArt = imageDataUrl
    ? `<image href="${imageDataUrl}" x="430" y="-120" width="900" height="900" preserveAspectRatio="xMidYMid slice" opacity="0.07"/>`
    : "";
  const borderDataUrl = await nextPnlBorderDataUrl();
  const borderLayer = borderDataUrl
    ? `<image href="${borderDataUrl}" x="0" y="0" width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" preserveAspectRatio="xMidYMid slice"/>`
    : pnlSlimeBorderSvg();
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" viewBox="0 0 ${PNL_CARD_STYLE.width} ${PNL_CARD_STYLE.height}">
  <defs>
    <linearGradient id="sigBg" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%" stop-color="#061006"/>
      <stop offset="48%" stop-color="#0b2b12"/>
      <stop offset="100%" stop-color="#020702"/>
    </linearGradient>
    <radialGradient id="sigGlow" cx="68%" cy="50%" r="48%">
      <stop offset="0%" stop-color="${verdictColor}" stop-opacity="0.30"/>
      <stop offset="100%" stop-color="${verdictColor}" stop-opacity="0"/>
    </radialGradient>
    <clipPath id="sigArtClip"><rect x="72" y="160" width="400" height="400" rx="34"/></clipPath>
    <filter id="sigShadow" x="-20%" y="-20%" width="140%" height="140%">
      <feDropShadow dx="0" dy="20" stdDeviation="24" flood-color="#000000" flood-opacity="0.55"/>
    </filter>
    <filter id="slimeGlow" x="-10%" y="-20%" width="120%" height="145%">
      <feDropShadow dx="0" dy="0" stdDeviation="5" flood-color="${PNL_CARD_STYLE.slime}" flood-opacity="0.95"/>
      <feDropShadow dx="0" dy="0" stdDeviation="18" flood-color="${PNL_CARD_STYLE.slime}" flood-opacity="0.42"/>
    </filter>
  </defs>
  <rect width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" fill="url(#sigBg)"/>
  ${bgArt}
  <rect width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" fill="url(#sigGlow)"/>
  ${borderLayer}
  <rect x="42" y="86" width="1116" height="510" rx="42" fill="${PNL_CARD_STYLE.panel}" filter="url(#sigShadow)" stroke="rgba(255,255,255,0.09)"/>
  ${art}
  <text x="520" y="178" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="56" font-weight="900" fill="${PNL_CARD_STYLE.slime}" filter="url(#slimeGlow)">www.SlimeWire.org</text>
  <text x="520" y="226" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="30" font-weight="800" fill="${PNL_CARD_STYLE.muted}">SIGNAL CARD</text>
  <text x="520" y="330" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="96" font-weight="900" fill="${PNL_CARD_STYLE.white}">$${escapeSvg(symbol)}</text>
  ${name ? `<text x="520" y="376" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="30" font-weight="700" fill="${PNL_CARD_STYLE.muted}">${escapeSvg(name)}</text>` : ""}
  <rect x="516" y="404" width="${Math.min(580, 230 + verdict.length * 34)}" height="74" rx="37" fill="${verdictColor}" fill-opacity="0.16" stroke="${verdictColor}" stroke-width="3"/>
  <text x="548" y="455" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="40" font-weight="900" fill="${verdictColor}">SHIELD: ${escapeSvg(verdict)}${shield?.score != null ? ` ${shield.score}/100` : ""}</text>
  <text x="520" y="540" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="34" font-weight="800" fill="#d6ffbf">${escapeSvg(stats || "fresh pair - data filling in")}</text>
  <text x="72" y="630" font-family="Consolas, monospace" font-size="24" fill="#7d937a">${escapeSvg(tokenMint)}</text>
  <text x="1128" y="630" text-anchor="end" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="32" font-weight="900" fill="#72ff23">slimewire.org/proof</text>
</svg>`;
  const png = await sharp(Buffer.from(svg)).png().toBuffer();
  signalCardCache.set(tokenMint, { png, at: Date.now() });
  if (signalCardCache.size > 60) {
    const oldest = [...signalCardCache.entries()].sort((a, b) => a[1].at - b[1].at)[0];
    if (oldest) signalCardCache.delete(oldest[0]);
  }
  return png;
}

// Aggregate "Shield Report" card: the engine's track record over a window as a
// single shareable PNG. Built for posting on X/Telegram - receipts ARE the
// marketing. Same visual language as the signal/PnL cards.
let shieldReportCardCache = { at: 0, days: 0, png: null };

async function renderShieldReportCard(days = 7) {
  const safeDays = Math.max(1, Math.min(90, Math.round(Number(days) || 7)));
  if (shieldReportCardCache.png && shieldReportCardCache.days === safeDays && Date.now() - shieldReportCardCache.at < 10 * 60 * 1000) {
    return shieldReportCardCache.png;
  }
  const [receiptsStore, callsStore] = await Promise.all([
    readShieldReceipts().catch(() => ({ receipts: [] })),
    readAlphaCalls().catch(() => ({ calls: [] }))
  ]);
  const cutoff = Date.now() - safeDays * 24 * 60 * 60 * 1000;
  const inWindow = (item, field) => Date.parse(item?.[field] || "") >= cutoff;
  const receipts = receiptsStore.receipts.filter((item) => inWindow(item, "flaggedAt"));
  const resolved = receipts.filter((item) => item.status === "resolved");
  const rugged = resolved.filter((item) => item.outcome === "rugged");
  const warningTimes = rugged.map((item) => Number(item.confirmedAfterMinutes)).filter((minutes) => Number.isFinite(minutes) && minutes > 0);
  const avgWarning = warningTimes.length ? Math.round(warningTimes.reduce((sum, m) => sum + m, 0) / warningTimes.length) : null;
  const wins = callsStore.calls.filter((call) => call.status === "resolved" && call.outcome === "won" && inWindow(call, "resolvedAt"));
  const bestX = wins.length ? Math.max(...wins.map((call) => Number(call.peakX) || 0)) : null;
  const catchRate = resolved.length ? Math.round((rugged.length / resolved.length) * 100) : null;

  const stat = (x, value, label, color = PNL_CARD_STYLE.slime) => `
  <text x="${x}" y="392" text-anchor="middle" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="92" font-weight="900" fill="${color}" filter="url(#slimeGlow)">${escapeSvg(String(value))}</text>
  <text x="${x}" y="442" text-anchor="middle" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="26" font-weight="800" fill="${PNL_CARD_STYLE.muted}">${escapeSvg(label)}</text>`;
  const borderDataUrl = await nextPnlBorderDataUrl();
  const borderLayer = borderDataUrl
    ? `<image href="${borderDataUrl}" x="0" y="0" width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" preserveAspectRatio="xMidYMid slice"/>`
    : pnlSlimeBorderSvg();
  const rangeLabel = safeDays === 7 ? "LAST 7 DAYS" : safeDays === 30 ? "LAST 30 DAYS" : `LAST ${safeDays} DAYS`;
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" viewBox="0 0 ${PNL_CARD_STYLE.width} ${PNL_CARD_STYLE.height}">
  <defs>
    <linearGradient id="repBg" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%" stop-color="#061006"/>
      <stop offset="48%" stop-color="#0b2b12"/>
      <stop offset="100%" stop-color="#020702"/>
    </linearGradient>
    <radialGradient id="repGlow" cx="50%" cy="38%" r="55%">
      <stop offset="0%" stop-color="${PNL_CARD_STYLE.slime}" stop-opacity="0.18"/>
      <stop offset="100%" stop-color="${PNL_CARD_STYLE.slime}" stop-opacity="0"/>
    </radialGradient>
    <filter id="repShadow" x="-20%" y="-20%" width="140%" height="140%">
      <feDropShadow dx="0" dy="20" stdDeviation="24" flood-color="#000000" flood-opacity="0.55"/>
    </filter>
    <filter id="slimeGlow" x="-10%" y="-20%" width="120%" height="145%">
      <feDropShadow dx="0" dy="0" stdDeviation="5" flood-color="${PNL_CARD_STYLE.slime}" flood-opacity="0.95"/>
      <feDropShadow dx="0" dy="0" stdDeviation="18" flood-color="${PNL_CARD_STYLE.slime}" flood-opacity="0.42"/>
    </filter>
  </defs>
  <rect width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" fill="url(#repBg)"/>
  <rect width="${PNL_CARD_STYLE.width}" height="${PNL_CARD_STYLE.height}" fill="url(#repGlow)"/>
  ${borderLayer}
  <rect x="42" y="86" width="1116" height="510" rx="42" fill="${PNL_CARD_STYLE.panel}" filter="url(#repShadow)" stroke="rgba(255,255,255,0.09)"/>
  <text x="600" y="180" text-anchor="middle" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="58" font-weight="900" fill="${PNL_CARD_STYLE.slime}" filter="url(#slimeGlow)">SLIMESHIELD REPORT</text>
  <text x="600" y="224" text-anchor="middle" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="28" font-weight="800" fill="${PNL_CARD_STYLE.muted}">${escapeSvg(rangeLabel)} - TRIPLE-ENGINE RISK READS, EVERY FLAG TRACKED TO ITS OUTCOME</text>
  ${stat(238, receipts.length, "TOKENS FLAGGED")}
  ${stat(600, rugged.length, "CONFIRMED RUGS CALLED", "#ff6b5e")}
  ${stat(962, avgWarning != null ? `${avgWarning}m` : "-", "AVG WARNING BEFORE RUG")}
  ${catchRate != null ? `<text x="600" y="510" text-anchor="middle" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="30" font-weight="800" fill="#d6ffbf">${escapeSvg(`${catchRate}% of resolved flags went to zero`)}${bestX ? escapeSvg(` - best tracked call hit ${bestX}x`) : ""}</text>` : ""}
  <text x="72" y="630" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="26" font-weight="800" fill="#7d937a">SlimeShield x Rugcheck x GoPlus</text>
  <text x="1128" y="630" text-anchor="end" font-family="${PNL_CARD_STYLE.fontFamily}" font-size="32" font-weight="900" fill="#72ff23">slimewire.org/proof</text>
</svg>`;
  const png = await sharp(Buffer.from(svg)).png().toBuffer();
  shieldReportCardCache = { at: Date.now(), days: safeDays, png };
  return png;
}

// --- Call Board: structured, auto-tracked calls tied to real token data -----------
// Not a chat. Every post is a position statement (bullish/bearish/warning/question)
// stamped with the SlimeShield score and entry price at post time, then tracked to its
// outcome exactly like alpha drops. Reputation comes from results, not volume.
const CALL_BOARD_SIDES = new Set(["bullish", "bearish", "warning", "question"]);

// Per-file mutation lock: the new JSON stores (calls, receipts, groups, links, push
// subs) are read-modify-write; concurrent ticks or user posts must queue, not race.
const jsonFileLocks = new Map();
function withFileLock(filePath, fn) {
  const prev = jsonFileLocks.get(filePath) || Promise.resolve();
  const next = prev.then(fn, fn);
  jsonFileLocks.set(filePath, next.catch(() => {}));
  return next;
}

function callBoardPath() {
  return path.join(CONFIG.dataDir, "call-board.json");
}

async function readCallBoard() {
  const store = await readJson(callBoardPath());
  if (!Array.isArray(store.calls)) store.calls = [];
  return store;
}

function callerReputation(calls, handle) {
  const resolved = calls.filter((call) => call.handle === handle && call.status === "resolved" && call.side === "bullish");
  const wins = resolved.filter((call) => call.outcome === "won").length;
  // Streak: consecutive wins counting back from the most recent resolved call.
  let streak = 0;
  for (const call of [...resolved].reverse()) {
    if (call.outcome !== "won") break;
    streak += 1;
  }
  return {
    calls: calls.filter((call) => call.handle === handle).length,
    wins,
    streak,
    hitRatePct: resolved.length ? Math.round((wins / resolved.length) * 100) : null
  };
}

async function webPostBoardCall(userId, body = {}) {
  const tokenMint = parsePublicKey(String(body.tokenMint || "")).toBase58();
  const side = String(body.side || "").toLowerCase();
  if (!CALL_BOARD_SIDES.has(side)) throw new Error("Pick bullish, bearish, warning, or question.");
  const note = String(body.note || "").trim().slice(0, 140);
  const targetX = Math.max(0, Math.min(1000, Number(body.targetX) || 0)) || null;
  const profile = await webProfileForUser(userId);
  const handle = String(profile.username || "").trim() || `degen-${String(userId).slice(-4)}`;
  return withFileLock(callBoardPath(), async () => {
  const store = await readCallBoard();
  const sixHoursAgo = Date.now() - 6 * 60 * 60 * 1000;
  if (store.calls.some((call) => call.userId === String(userId) && call.mint === tokenMint && Date.parse(call.createdAt) > sixHoursAgo)) {
    throw new Error("You already posted on this token in the last 6 hours - let the call play out.");
  }
  const shield = await webSlimeShield(tokenMint).catch(() => null);
  const pairs = await fetchDexScreenerTokenPairsFallback(tokenMint).catch(() => []);
  const best = bestDexPairForToken(tokenMint, pairs);
  const call = {
    id: `call-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    mint: tokenMint,
    symbol: String(best?.baseToken?.symbol || shield?.marketContext?.symbol || shortMint(tokenMint)).slice(0, 24),
    side,
    note,
    targetX,
    handle,
    userId: String(userId),
    source: String(body.source || "site").slice(0, 12),
    shieldVerdict: shield?.verdict || "",
    shieldScore: Number(shield?.score) || null,
    priceUsd: Number(best?.priceUsd) || null,
    entryMcUsd: Number(best?.marketCap || best?.fdv) || null,
    createdAt: new Date().toISOString(),
    status: side === "bullish" && Number(best?.priceUsd) > 0 ? "watching" : "open",
    outcome: null
  };
  store.calls.push(call);
  store.calls = store.calls.slice(-1000);
  await writeJsonFile(callBoardPath(), store);
  return call;
  });
}

async function webBoardCallsForMint(tokenMint = "") {
  const store = await readCallBoard();
  const mint = String(tokenMint || "").trim();
  const scoped = mint ? store.calls.filter((call) => call.mint === mint) : store.calls;
  const rows = scoped.slice(-30).reverse().map((call) => ({
    ...call,
    userId: undefined,
    reputation: callerReputation(store.calls, call.handle)
  }));
  const handles = [...new Set(store.calls.map((call) => call.handle))];
  const topCallers = handles
    .map((handle) => ({ handle, ...callerReputation(store.calls, handle) }))
    .filter((caller) => caller.wins > 0)
    .sort((a, b) => b.wins - a.wins)
    .slice(0, 5);
  return { calls: rows, topCallers, total: scoped.length };
}

// Outcome tracking: bullish calls resolve on the same 2x / dead / flat rules as the
// engine's own alpha drops - one honest standard for humans and machine alike.
async function checkBoardCallOutcomes() {
  return withFileLock(callBoardPath(), async () => {
  const store = await readCallBoard();
  const now = Date.now();
  const due = store.calls.filter((call) => call.status === "watching" && Number(call.priceUsd) > 0).slice(0, 25);
  if (!due.length) return;
  const pairs = await fetchDexScreenerTokenPairsBatch(due.map((call) => call.mint)).catch(() => []);
  let changed = false;
  for (const call of due) {
    const best = bestDexPairForToken(call.mint, pairs.filter((pair) => pairMatchesToken(pair, call.mint)));
    const priceNow = Number(best?.priceUsd) || 0;
    const ageMs = now - Date.parse(call.createdAt);
    const multiple = priceNow > 0 ? priceNow / call.priceUsd : 0;
    if (multiple >= 2) {
      call.status = "resolved";
      call.outcome = "won";
      call.peakX = Math.round(multiple * 10) / 10;
      call.resolvedAt = new Date(now).toISOString();
      changed = true;
    } else if (ageMs > 60 * 60 * 1000 && (!priceNow || multiple < 0.4)) {
      call.status = "resolved";
      call.outcome = "lost";
      call.resolvedAt = new Date(now).toISOString();
      changed = true;
    } else if (ageMs > 48 * 60 * 60 * 1000) {
      call.status = "resolved";
      call.outcome = "flat";
      call.resolvedAt = new Date(now).toISOString();
      changed = true;
    }
  }
  if (changed) await writeJsonFile(callBoardPath(), store);
  });
}

// --- Alpha drops + winner receipts -------------------------------------------------
// Every few hours, opted-in groups (and the channel) get ONE pick - but only when a
// candidate passes the full gate (top scanner row AND SlimeShield BUY verdict). No
// qualified pick = no post; silence costs nothing, a bad call costs trust. Every drop
// records its entry price, and when a called pick 2x's, the same chats get the receipt.
const TG_ALPHA_DROP_INTERVAL_MS = Math.max(5, Math.min(24 * 60, Number.parseInt(process.env.TG_ALPHA_DROP_INTERVAL_MINUTES || "180", 10) || 180)) * 60 * 1000;
// Conviction-engine epoch: calls recorded before this were volume-era (every
// radar play tracked). Public stats count from here so the record reflects the
// selective engine - older calls stay in the store, honestly labeled.
const ALPHA_CONVICTION_EPOCH = Date.parse(process.env.TG_ALPHA_RECORD_EPOCH || "2026-06-11T20:00:00Z");
const alphaCallInRecord = (call) => Date.parse(call.calledAt || 0) >= ALPHA_CONVICTION_EPOCH;
const TG_ALPHA_DROP_PICKS = Math.max(1, Math.min(4, Number.parseInt(process.env.TG_ALPHA_DROP_PICKS || "4", 10) || 4));

function alphaCallsPath() {
  return path.join(CONFIG.dataDir, "alpha-calls.json");
}

async function readAlphaCalls() {
  const store = await readJson(alphaCallsPath());
  if (!Array.isArray(store.calls)) store.calls = [];
  return store;
}

async function firstAlphaGroupTitle(chatIds = []) {
  const first = (chatIds || [])[0];
  if (!first) return "";
  try {
    const store = await readTelegramGroups();
    return String(store.groups?.[String(first)]?.title || "").slice(0, 48);
  } catch {
    return "";
  }
}

function alphaAgeLabel(ms) {
  const minutes = Math.round(ms / 60_000);
  if (minutes < 90) return `${minutes} min ago`;
  if (minutes < 48 * 60) return `${Math.round(minutes / 60)}h ago`;
  return `${Math.round(minutes / 1440)}d ago`;
}

async function runAlphaDropTick() {
  const groupsStore = await readTelegramGroups();
  const now = Date.now();
  const dueGroups = Object.entries(groupsStore.groups || {}).filter(([, group]) =>
    group?.alerts && (!group.lastAlphaAt || now - Date.parse(group.lastAlphaAt) > TG_ALPHA_DROP_INTERVAL_MS));
  if (!dueGroups.length && !tgChannel.enabled) return;

  // Engine record footer: publishing the losses is what makes the wins believable.
  const priorCalls = await readAlphaCalls();
  const priorResolved = priorCalls.calls.filter((call) => call.status === "resolved" && alphaCallInRecord(call));
  const priorWins = priorResolved.filter((call) => call.outcome === "won").length;
  const priorLosses = priorResolved.filter((call) => call.outcome === "lost").length;
  const recordLine = priorResolved.length
    ? ` Engine record: ${priorWins}W-${priorLosses}L${priorResolved.length - priorWins - priorLosses ? `-${priorResolved.length - priorWins - priorLosses}F` : ""}.`
    : "";

  // Take the top scanner rows, attach a shield verdict to each, and drop everything
  // that is not an outright AVOID. Risky plays are shown honestly with their verdict -
  // degens want the early ones, the label keeps it honest.
  const { rows } = await telegramAlphaRows("alpha-drop");
  // Mix in low-MC moonshot rows: degens want at least a couple of genuinely early
  // plays per drop, not just the safest scanner output.
  let moonRows = [];
  try {
    const moonScan = await webSniperScan("tg:alpha-drop:moon", "moonshot");
    moonRows = (moonScan?.rows || []).filter((row) => row.tokenMint);
  } catch {
    // moonshot pool empty - the main rows still post
  }
  const seenMints = new Set();
  const blended = [];
  const maxLen = Math.max(rows.length, moonRows.length);
  // Moonshot rows lead: the bot's identity is early low-MC plays, not safe leftovers.
  for (let i = 0; i < maxLen; i++) {
    for (const row of [moonRows[i], rows[i]]) {
      if (row?.tokenMint && !seenMints.has(row.tokenMint)) {
        seenMints.add(row.tokenMint);
        blended.push(row);
      }
    }
  }
  // X potential floats up: live socials mean someone is pushing it; among equals,
  // the lower market cap wins the slot.
  const socialScore = (row) => (row.twitterUrl ? 2 : 0) + (row.telegramUrl ? 1 : 0) + (row.websiteUrl ? 1 : 0);
  const mcOf = (row) => Number(row.marketCapUsd ?? row.marketCap ?? row.fdv) || Number.MAX_SAFE_INTEGER;
  blended.sort((a, b) => (socialScore(b) - socialScore(a)) || (mcOf(a) - mcOf(b)));
  const picks = [];
  for (const row of blended.slice(0, TG_ALPHA_DROP_PICKS + 4)) {
    if (picks.length >= TG_ALPHA_DROP_PICKS) break;
    const shield = await webSlimeShield(row.tokenMint).catch(() => null);
    const verdict = String(shield?.verdict || "").toUpperCase();
    if (verdict === "AVOID") continue;
    picks.push({ row, shield, verdict: verdict || "UNRATED" });
  }
  if (!picks.length) return;

  const pairs = await fetchDexScreenerTokenPairsBatch(picks.map((pick) => pick.row.tokenMint)).catch(() => []);
  // Conviction gate: tracking every radar play buried the record under volume
  // ("140 calls, 6 wins" reads as dumb). At most ONE pick per drop goes on the
  // wall - the strongest that clears a real-but-achievable bar (not AVOID/RISK,
  // decent shield score, real liquidity). Picks are already sorted best-first,
  // so the first that clears the bar is the conviction call.
  const liqOf = (row) => Number(row.liquidityUsd ?? row.liquidity?.usd) || 0;
  const conviction = picks.find((pick) =>
    ["BUY", "CAUTION"].includes(pick.verdict)
    && (Number(pick.shield?.score) || 0) >= 50
    && liqOf(pick.row) >= 4_000)
    // Fallback: if nothing clears the strict bar but the top pick is non-AVOID
    // with a real score, still record ONE so the wall never goes silent for long.
    || picks.find((pick) => pick.verdict !== "AVOID" && (Number(pick.shield?.score) || 0) >= 45)
    || null;
  const verdictIcon = { BUY: "🟢", CAUTION: "🟡", RISK: "🟠", UNRATED: "⚪" };
  const lines = picks.map((pick, index) => {
    const { row, shield, verdict } = pick;
    const links = slimewireTokenLinks(row.tokenMint);
    const stats = [row.marketCapLabel ? `MC ${row.marketCapLabel}` : "", row.liquidityLabel ? `Liq ${row.liquidityLabel}` : "", row.pairAgeLabel || ""].filter(Boolean).map(escapeTelegramHtml).join(" | ");
    const tag = pick === conviction ? " 🎯 <b>TRACKED CALL</b>" : "";
    return [
      `${index + 1}. ${verdictIcon[verdict] || "⚪"} <a href="${links.site}"><b>$${escapeTelegramHtml(row.symbol || shortMint(row.tokenMint))}</b></a> - ${escapeTelegramHtml(verdict)}${shield?.score != null ? ` ${shield.score}/100` : ""}${stats ? ` | ${stats}` : ""}${tag}`,
      `<code>${escapeTelegramHtml(row.tokenMint)}</code>`
    ].join("\n");
  });
  const topLinks = slimewireTokenLinks(picks[0].row.tokenMint);
  const text = [
    `🐸 <b>SlimeWire plays</b> - tap a pair to open its chart:`,
    ...lines,
    `${topLinks.dmBuy ? `<a href="${topLinks.dmBuy}">quick buy top pick</a> | ` : ""}<a href="https://www.slimewire.org/proof">proof wall</a> - 🎯 tracked calls go on the record, radar plays are for speed.${escapeTelegramHtml(recordLine)}`
  ].join("\n");

  // Key by time bucket so the cadence holds even when the same top pick repeats.
  const dropKey = `drop-${Math.floor(now / TG_ALPHA_DROP_INTERVAL_MS)}`;
  const recipients = [];
  for (const [chatId] of dueGroups) {
    groupBridgeFor(chatId).announce("alpha-drop", dropKey, text);
    recipients.push(chatId);
  }
  if (recipients.length) {
    await withFileLock(telegramGroupsPath(), async () => {
      const fresh = await readTelegramGroups();
      for (const chatId of recipients) {
        if (fresh.groups[chatId]) fresh.groups[chatId].lastAlphaAt = new Date(now).toISOString();
      }
      await writeJsonFile(telegramGroupsPath(), fresh);
    });
  }
  tgChannel.announce("alpha-drop", dropKey, text);

  // Only the conviction pick is recorded - the wall reflects judgment, not volume.
  if (!conviction) return;
  await withFileLock(alphaCallsPath(), async () => {
    const calls = await readAlphaCalls(); // fresh read: never clobber outcomes written mid-tick
    let recorded = false;
    for (const pick of [conviction]) {
      const best = bestDexPairForToken(pick.row.tokenMint, pairs.filter((pair) => pairMatchesToken(pair, pick.row.tokenMint)));
      const priceUsd = Number(best?.priceUsd) || null;
      if (!priceUsd) continue;
      const recentCall = calls.calls.find((call) => call.mint === pick.row.tokenMint
        && call.status === "watching");
      if (recentCall) continue; // already tracking this mint
      calls.calls.push({
        id: "alpha-" + Date.now().toString(36) + Math.random().toString(36).slice(2, 7),
        mint: pick.row.tokenMint,
        symbol: String(pick.row.symbol || shortMint(pick.row.tokenMint)).slice(0, 24),
        chatIds: recipients,
        priceUsd,
        shieldScore: Number(pick.shield?.score) || null,
        verdict: pick.verdict,
        calledAt: new Date(now).toISOString(),
        status: "watching",
        outcome: null
      });
      recorded = true;
    }
    if (recorded) {
      calls.calls = calls.calls.slice(-300);
      await writeJsonFile(alphaCallsPath(), calls);
    }
  });
}

async function checkAlphaCallOutcomes() {
  return withFileLock(alphaCallsPath(), async () => {
  const store = await readAlphaCalls();
  const now = Date.now();
  const due = store.calls.filter((call) => call.status === "watching" && Number(call.priceUsd) > 0).slice(0, 25);
  if (!due.length) return;
  const pairs = await fetchDexScreenerTokenPairsBatch(due.map((call) => call.mint)).catch(() => []);
  let changed = false;
  for (const call of due) {
    const best = bestDexPairForToken(call.mint, pairs.filter((pair) => pairMatchesToken(pair, call.mint)));
    const priceNow = Number(best?.priceUsd) || 0;
    const ageMs = now - Date.parse(call.calledAt);
    const multiple = priceNow > 0 ? priceNow / call.priceUsd : 0;
    if (multiple >= 2) {
      call.status = "resolved";
      call.outcome = "won";
      call.peakX = Math.round(multiple * 10) / 10;
      call.resolvedAt = new Date(now).toISOString();
      changed = true;
      const links = slimewireTokenLinks(call.mint);
      const firstGroupTitle = await firstAlphaGroupTitle(call.chatIds);
      const winText = [
        `✅ <b>Called it</b>: $${escapeTelegramHtml(call.symbol)} is <b>${call.peakX}x</b> since the SlimeWire alpha drop ${alphaAgeLabel(ageMs)}.${firstGroupTitle ? ` First dropped in <b>${escapeTelegramHtml(firstGroupTitle)}</b>.` : ""}`,
        `<a href="${call.id ? `https://go.slimewire.org/call/${call.id}` : "https://www.slimewire.org/proof"}">Receipts, not promises - this receipt has its own page</a>.`,
        `<a href="${links.site}">chart</a> | <a href="${links.siteBuy}">buy on site</a>`
      ].join("\n");
      for (const chatId of call.chatIds || []) groupBridgeFor(chatId).announce("alpha-win", call.mint, winText);
      tgChannel.announce("alpha-win", call.mint, winText);
    } else if (ageMs > 60 * 60 * 1000 && (!priceNow || multiple < 0.4)) {
      call.status = "resolved";
      call.outcome = "lost";
      call.resolvedAt = new Date(now).toISOString();
      changed = true;
    } else if (ageMs > 24 * 60 * 60 * 1000) {
      call.status = "resolved";
      call.outcome = "flat";
      call.resolvedAt = new Date(now).toISOString();
      changed = true;
    }
  }
  if (changed) await writeJsonFile(alphaCallsPath(), store);
  });
}

// --- Watchlist move alerts: "your watched coin moved 42%" straight to the phone.
// Only users with push subscriptions are checked; per-user-per-mint 6h dedupe.
function watchAlertsPath() {
  return path.join(CONFIG.dataDir, "watch-alerts.json");
}

async function readWatchAlerts() {
  const store = await readJson(watchAlertsPath());
  if (!store.snapshots || typeof store.snapshots !== "object") store.snapshots = {};
  return store;
}

async function checkWatchlistMoveAlerts() {
  if (!webPushEnabled) return;
  await withFileLock(watchAlertsPath(), async () => {
    const subs = await readPushSubscriptions();
    const userIds = Object.keys(subs.subs || {}).slice(0, 50);
    if (!userIds.length) return;
    const store = await readWatchAlerts();
    const now = Date.now();
    for (const userId of userIds) {
      let rows = [];
      try {
        const profile = await webProfileForUser(userId);
        rows = (Array.isArray(profile.watchedTokens) ? profile.watchedTokens : []).slice(0, 20);
      } catch {
        continue;
      }
      const mints = rows.map((row) => row.tokenMint).filter(Boolean);
      if (!mints.length) continue;
      const pairs = await fetchDexScreenerTokenPairsBatch(mints).catch(() => []);
      const userSnap = store.snapshots[userId] || {};
      for (const row of rows) {
        const best = bestDexPairForToken(row.tokenMint, pairs.filter((pair) => pairMatchesToken(pair, row.tokenMint)));
        const priceNow = Number(best?.priceUsd) || 0;
        if (!priceNow) continue;
        const snap = userSnap[row.tokenMint] || {};
        const lastPrice = Number(snap.priceUsd) || 0;
        const lastAlertAt = Number(snap.alertAt) || 0;
        if (lastPrice > 0 && now - lastAlertAt > 6 * 60 * 60 * 1000) {
          const movePct = ((priceNow - lastPrice) / lastPrice) * 100;
          if (Math.abs(movePct) >= 40) {
            void sendWebPushToUser(userId, {
              title: `${row.symbol || shortMint(row.tokenMint)} moved ${movePct > 0 ? "+" : ""}${movePct.toFixed(0)}%`,
              body: movePct > 0 ? "Your watched coin is running. Tap to open the chart." : "Your watched coin is dumping. Tap to check it.",
              tag: `watch-${row.tokenMint}`,
              url: `/terminal/chart?token=${row.tokenMint}&source=watch-alert`
            });
            pushUserActivity(store, userId, { kind: "move", title: `${row.symbol || shortMint(row.tokenMint)} moved ${movePct > 0 ? "+" : ""}${movePct.toFixed(0)}%`, tokenMint: row.tokenMint });
            userSnap[row.tokenMint] = { priceUsd: priceNow, alertAt: now };
            continue;
          }
        }
        if (!lastPrice) userSnap[row.tokenMint] = { priceUsd: priceNow, alertAt: snap.alertAt || 0 };
      }
      store.snapshots[userId] = userSnap;
    }
    await writeJsonFile(watchAlertsPath(), store);
  });
}

// ===================== MY RADAR — personalized per-user alerts =====================
// Users set rules once ("alert me when $X hits +50% / crosses $40k MC") and SlimeWire
// watches for them, delivering via web push + Telegram with a plain-English WHY. Rules
// live on the user's profile (web-auth.json); fire-dedupe lives in the watch-alerts
// snapshot store (written every cycle anyway). Safe-by-default: no rules => nothing fires.
const RADAR_RULE_TYPES = ["tp", "sl", "mc_above", "mc_below", "dump"];
const RADAR_DEDUPE_MS = 6 * 60 * 60 * 1000;

function radarUsd(n) {
  n = Number(n) || 0;
  if (n >= 1e9) return `$${(n / 1e9).toFixed(1)}B`;
  if (n >= 1e6) return `$${(n / 1e6).toFixed(1)}M`;
  if (n >= 1e3) return `$${Math.round(n / 1e3)}K`;
  return `$${Math.round(n)}`;
}

const RADAR_TAG_RULE_TYPES = ["mc_above", "mc_below", "dump"]; // tag-scoped = basis-free conditions only
function normalizeRadarRule(input = {}) {
  const type = String(input.type || "").trim().toLowerCase();
  if (!RADAR_RULE_TYPES.includes(type)) return null;
  const value = Number(input.value) || 0;
  if (!(value > 0)) return null;
  const channels = input.channels || {};
  const base = {
    id: `r_${Date.now().toString(36)}${Math.floor(Math.random() * 1e4).toString(36)}`,
    type,
    value,
    channels: { push: channels.push !== false, telegram: Boolean(channels.telegram) },
    enabled: true,
    createdAt: new Date().toISOString()
  };
  // TAG-SCOPED (per-list) rule: applies to every watched coin carrying this tag. Basis-free only.
  const tag = String(input.tag || "").trim().replace(/[^\w \-]/g, "").slice(0, 24);
  if (tag) {
    if (!RADAR_TAG_RULE_TYPES.includes(type)) return null;
    return { ...base, scope: "tag", tag, tokenMint: "", symbol: tag, basisPrice: 0 };
  }
  // TOKEN-SCOPED rule (the default).
  const tokenMint = String(input.tokenMint || "").trim();
  if (!tokenMint) return null;
  return { ...base, scope: "token", tokenMint, symbol: String(input.symbol || "").trim().slice(0, 24), basisPrice: Number(input.basisPrice) || 0 };
}

async function radarRulesForUser(userId) {
  try {
    const profile = await webProfileForUser(userId);
    return Array.isArray(profile.radarRules) ? profile.radarRules : [];
  } catch {
    return [];
  }
}

async function updateRadarRules(userId, body = {}) {
  const action = String(body.action || "add").trim().toLowerCase();
  const store = await readWebAuthStore();
  const key = String(userId);
  const { profile: existing } = ensureWebProfileDefaults(store, userId);
  let rules = Array.isArray(existing.radarRules) ? existing.radarRules : [];
  if (action === "clear") {
    rules = [];
  } else if (action === "remove") {
    const id = String(body.id || "");
    rules = rules.filter((rule) => rule.id !== id);
  } else if (action === "toggle") {
    const id = String(body.id || "");
    rules = rules.map((rule) => (rule.id === id ? { ...rule, enabled: !rule.enabled } : rule));
  } else {
    const rule = normalizeRadarRule(body.rule || body);
    if (rule) {
      // Token-scoped TP/SL need a basis price; fetch it now if the client didn't supply one.
      // (Tag-scoped rules are basis-free.)
      if (rule.scope !== "tag" && (rule.type === "tp" || rule.type === "sl") && !(rule.basisPrice > 0)) {
        const pairs = await fetchDexScreenerTokenPairsBatch([rule.tokenMint]).catch(() => []);
        const best = bestDexPairForToken(rule.tokenMint, pairs.filter((pair) => pairMatchesToken(pair, rule.tokenMint)));
        rule.basisPrice = Number(best?.priceUsd) || 0;
      }
      rules = rules.filter((existingRule) => (rule.scope === "tag"
        ? !(existingRule.tag === rule.tag && existingRule.type === rule.type)
        : !(existingRule.tokenMint === rule.tokenMint && existingRule.type === rule.type)));
      rules.unshift(rule);
      rules = rules.slice(0, 60);
    }
  }
  const profile = { ...existing, radarRules: rules, updatedAt: new Date().toISOString() };
  store.profiles[key] = profile;
  await writeWebAuthStore(store);
  await audit("web_radar_update", { userId, action, count: rules.length });
  return { rules };
}

// Evaluate one rule against the token's fresh market read. Returns { title, why } when it
// should fire, else null. Every message names WHY it fired (the user's explicit ask).
function evaluateRadarRule(rule, best) {
  const price = Number(best?.priceUsd) || 0;
  const mc = Number(best?.marketCap) || Number(best?.fdv) || 0;
  const sym = rule.symbol || shortMint(rule.tokenMint);
  if (rule.type === "tp" && rule.basisPrice > 0 && price > 0) {
    const pct = ((price - rule.basisPrice) / rule.basisPrice) * 100;
    if (pct >= rule.value) return { title: `🎯 ${sym} hit +${Math.round(rule.value)}% take-profit`, why: `Up ${pct.toFixed(0)}% since you set the alert — tap to bank it.` };
  } else if (rule.type === "sl" && rule.basisPrice > 0 && price > 0) {
    const pct = ((price - rule.basisPrice) / rule.basisPrice) * 100;
    if (pct <= -rule.value) return { title: `🛑 ${sym} hit -${Math.round(rule.value)}% stop-loss`, why: `Down ${Math.abs(pct).toFixed(0)}% since you set the alert — tap to check it.` };
  } else if (rule.type === "mc_above" && mc > 0 && mc >= rule.value) {
    return { title: `📈 ${sym} crossed ${radarUsd(rule.value)} MC`, why: `Market cap is now ${radarUsd(mc)}.` };
  } else if (rule.type === "mc_below" && mc > 0 && mc <= rule.value) {
    return { title: `📉 ${sym} fell below ${radarUsd(rule.value)} MC`, why: `Market cap is now ${radarUsd(mc)}.` };
  } else if (rule.type === "dump") {
    const h1 = Number(best?.priceChange?.h1);
    if (Number.isFinite(h1) && h1 <= -rule.value) return { title: `🩸 ${sym} dumping ${Math.abs(h1).toFixed(0)}% (1h)`, why: `Down ${Math.abs(h1).toFixed(0)}% in the last hour — possible rug/dump. Tap to check.` };
  }
  return null;
}

async function checkRadarRules() {
  const authStore = await readWebAuthStore().catch(() => null);
  if (!authStore || !authStore.profiles) return;
  const radarUsers = Object.keys(authStore.profiles).filter((uid) => {
    const rr = authStore.profiles[uid] && authStore.profiles[uid].radarRules;
    return Array.isArray(rr) && rr.some((rule) => rule && rule.enabled);
  }).slice(0, 80);
  if (!radarUsers.length) return;
  const tgLinks = await readTelegramLinks().catch(() => ({ links: {} }));
  await withFileLock(watchAlertsPath(), async () => {
    const store = await readWatchAlerts();
    const now = Date.now();
    for (const userId of radarUsers) {
      const profile = authStore.profiles[userId];
      const rules = (profile.radarRules || []).filter((rule) => rule && rule.enabled).slice(0, 60);
      const watched = Array.isArray(profile.watchedTokens) ? profile.watchedTokens : [];
      // Expand each rule into the concrete tokens it watches. A TAG-scoped rule fans out to every
      // watched coin carrying that tag (each gets its own dedupe key); a TOKEN rule maps to itself.
      const evalRules = [];
      for (const rule of rules) {
        if (rule.scope === "tag" && rule.tag) {
          const tagLc = String(rule.tag).toLowerCase();
          for (const w of watched) {
            if (!w || !w.tokenMint || !Array.isArray(w.tags)) continue;
            if (!w.tags.some((t) => String(t).toLowerCase() === tagLc)) continue;
            evalRules.push({ ...rule, tokenMint: w.tokenMint, symbol: w.symbol || rule.tag, _fireKey: `radar:${rule.id}:${w.tokenMint}` });
          }
        } else if (rule.tokenMint) {
          evalRules.push({ ...rule, _fireKey: `radar:${rule.id}` });
        }
      }
      const mints = [...new Set(evalRules.map((rule) => rule.tokenMint).filter(Boolean))];
      if (!mints.length) continue;
      const pairs = await fetchDexScreenerTokenPairsBatch(mints).catch(() => []);
      const userSnap = store.snapshots[userId] || {};
      for (const rule of evalRules) {
        const best = bestDexPairForToken(rule.tokenMint, pairs.filter((pair) => pairMatchesToken(pair, rule.tokenMint)));
        if (!best) continue;
        const fireKey = rule._fireKey;
        if (now - (Number(userSnap[fireKey]?.alertAt) || 0) < RADAR_DEDUPE_MS) continue;
        const hit = evaluateRadarRule(rule, best);
        if (!hit) continue;
        const channels = rule.channels || { push: true };
        if (channels.push !== false && webPushEnabled) {
          void sendWebPushToUser(userId, { title: hit.title, body: hit.why, tag: `radar-${rule.id}`, url: `/t?ca=${rule.tokenMint}` }).catch(() => {});
        }
        if (channels.telegram) {
          const tgUserId = tgLinks.links?.[userId];
          if (tgUserId) {
            void sayHtml(tgUserId, [
              `📡 <b>Radar:</b> ${escapeTelegramHtml(hit.title)}`,
              escapeTelegramHtml(hit.why),
              `<a href="https://www.slimewire.org/t?ca=${rule.tokenMint}">Open on SlimeWire</a>`
            ].join("\n")).catch(() => {});
          }
        }
        pushUserActivity(store, userId, { kind: "radar", title: hit.title, body: hit.why, tokenMint: rule.tokenMint });
        userSnap[fireKey] = { alertAt: now };
      }
      store.snapshots[userId] = userSnap;
    }
    await writeJsonFile(watchAlertsPath(), store);
  });
}

// ===================== RETURN DASHBOARD — "since your last visit" =====================
// The alert timers already DETECT per-user events; we just persist them to a per-user
// activity log (in the watch-alerts store, written every cycle anyway) so the terminal can
// greet a returning user with what changed. Aggregates Radar fires + watchlist big-moves.
function pushUserActivity(store, userId, event) {
  if (!store.activity || typeof store.activity !== "object") store.activity = {};
  const list = Array.isArray(store.activity[userId]) ? store.activity[userId] : [];
  list.unshift({ at: Date.now(), ...event });
  store.activity[userId] = list.slice(0, 40);
}

async function returnSummaryForUser(userId) {
  const profile = await webProfileForUser(userId).catch(() => ({}));
  const since = Number(profile.lastReturnSeenAt) || 0;
  const store = await readWatchAlerts().catch(() => ({ activity: {} }));
  const all = Array.isArray(store.activity && store.activity[String(userId)]) ? store.activity[String(userId)] : [];
  const events = all.filter((event) => Number(event.at) > since).slice(0, 20);
  return { events, since, now: Date.now() };
}

async function markReturnSeen(userId) {
  const store = await readWebAuthStore();
  const { profile } = ensureWebProfileDefaults(store, userId);
  store.profiles[String(userId)] = { ...profile, lastReturnSeenAt: Date.now(), updatedAt: new Date().toISOString() };
  await writeWebAuthStore(store);
}

// --- Pre-launch hype pages: a creator schedules a launch and gets a shareable
// countdown page; degens tap "notify me" (TG deep link, no login needed); when the
// creator's Pump Launch completes, every subscriber gets the launch-room link.
function launchHypePath() {
  return path.join(CONFIG.dataDir, "launch-hype.json");
}

async function readLaunchHype() {
  const store = await readJson(launchHypePath());
  if (!store.pages || typeof store.pages !== "object") store.pages = {};
  return store;
}

async function subscribeHypePage(hypeId, tgUserId) {
  let page = null;
  await withFileLock(launchHypePath(), async () => {
    const store = await readLaunchHype();
    page = store.pages[hypeId] || null;
    if (!page) return;
    const subs = new Set(page.subscriberTgIds || []);
    subs.add(String(tgUserId));
    page.subscriberTgIds = [...subs].slice(0, 500);
    await writeJsonFile(launchHypePath(), store);
  });
  return page;
}

// Called when a Pump Launch completes: the creator's oldest unlaunched hype page is
// marked live and every TG subscriber gets the launch-room link.
async function fulfillLaunchHype(userId, mint, symbol) {
  let page = null;
  await withFileLock(launchHypePath(), async () => {
    const store = await readLaunchHype();
    page = Object.values(store.pages)
      .filter((item) => item.userId === String(userId) && !item.mint)
      .sort((a, b) => Date.parse(a.launchAt || 0) - Date.parse(b.launchAt || 0))[0] || null;
    if (!page) return;
    page.mint = mint;
    page.launchedAt = new Date().toISOString();
    await writeJsonFile(launchHypePath(), store);
  });
  if (!page) return;
  const ticker = escapeTelegramHtml(symbol || page.symbol || "???");
  const text = [
    `🚀 <b>$${ticker} is LIVE</b> - the launch you were waiting on just happened via <a href="https://www.slimewire.org">SlimeWire</a>.`,
    `<a href="https://www.slimewire.org/t?ca=${mint}">Chart + shield read + one-tap trade</a> | <a href="https://pump.fun/coin/${mint}">pump.fun</a>`
  ].join("\n");
  for (const tgUserId of page.subscriberTgIds || []) {
    sayHtml(tgUserId, text).catch(() => {});
  }
  // Shill the moment to every group/channel the bot is armed in: a launch that
  // had a countdown page and waiting subscribers is a story, not just a CA.
  const waiting = (page.subscriberTgIds || []).length;
  const groupText = [
    `🔥 <b>$${ticker} JUST WENT LIVE</b> - this one had its own countdown page${waiting >= 5 ? ` with <b>${waiting} degens</b> waiting on the notify list` : ""}.`,
    `Scheduled, hyped, and launched through <a href="https://www.slimewire.org">SlimeWire</a> - dev buy landed at block one.`,
    `<a href="https://www.slimewire.org/t?ca=${mint}">launch room: chart + shield read + one-tap trade</a> | <a href="https://pump.fun/coin/${mint}">pump.fun</a> | <a href="https://www.slimewire.org">launch yours with a hype page</a>`
  ].join("\n");
  broadcastToTelegramGroups("hype-launch", mint, groupText);
  tgChannel.announce("hype-launch", mint, groupText);
}

// --- Public share pages on go.slimewire.org: /call/:id, /u/:handle, /g ------------
