function ensureWebProfileDefaults(store, userId) {
  const key = String(userId);
  const existing = store.profiles[key] || {};
  let changed = false;
  const profile = { ...existing };

  if (!profile.referralCode) {
    profile.referralCode = generateWebReferralCode(store, profile.username || key);
    changed = true;
  }
  if (!Array.isArray(profile.tradePresets)) {
    profile.tradePresets = [];
    changed = true;
  }
  if (!Array.isArray(profile.bundlePresets)) {
    profile.bundlePresets = [];
    changed = true;
  }
  if (!Array.isArray(profile.hiddenWebPresetIds)) {
    profile.hiddenWebPresetIds = [];
    changed = true;
  }
  if (!Array.isArray(profile.watchedTokens)) {
    profile.watchedTokens = [];
    changed = true;
  }
  if (typeof profile.showOnTraderBoard !== "boolean") {
    profile.showOnTraderBoard = false;
    changed = true;
  }
  if (!["all", "manual"].includes(String(profile.traderBoardWalletMode || ""))) {
    profile.traderBoardWalletMode = "all";
    changed = true;
  }
  if (!Array.isArray(profile.traderBoardWalletIndexes)) {
    profile.traderBoardWalletIndexes = [];
    changed = true;
  }
  if (!Array.isArray(profile.traderBoardWalletPublicKeys)) {
    profile.traderBoardWalletPublicKeys = [];
    changed = true;
  }
  if (profile.referralPayoutWallet === undefined) {
    profile.referralPayoutWallet = "";
    changed = true;
  }
  if (!profile.referralStats || typeof profile.referralStats !== "object") {
    profile.referralStats = { totalLamports: "0", payoutCount: 0, referrals: {} };
    changed = true;
  }
  if (!profile.automationPermission || typeof profile.automationPermission !== "object") {
    profile.automationPermission = defaultWebAutomationPermission();
    changed = true;
  } else {
    const normalized = normalizeWebAutomationPermission(profile.automationPermission);
    if (JSON.stringify(normalized) !== JSON.stringify(profile.automationPermission)) {
      profile.automationPermission = normalized;
      changed = true;
    }
  }

  if (changed || !store.profiles[key]) {
    profile.updatedAt = profile.updatedAt || new Date().toISOString();
    store.profiles[key] = profile;
  }
  return { profile, changed };
}

function defaultWebAutomationPermission() {
  return {
    enabled: false,
    grantedAt: "",
    expiresAt: "",
    revokedAt: "",
    walletScope: "managed",
    maxSellPercent: 100,
    allowedActions: ["tp_sl_exit", "timer_exit"],
    connectedWalletPublicKey: ""
  };
}

function normalizeWebAutomationPermission(value = {}) {
  const enabled = Boolean(value.enabled);
  const maxSellPercent = Math.max(1, Math.min(100, Number.parseFloat(value.maxSellPercent || "100") || 100));
  const allowedActions = Array.isArray(value.allowedActions) && value.allowedActions.length
    ? uniqueStrings(value.allowedActions.map((item) => String(item || "").trim()).filter(Boolean)).slice(0, 10)
    : ["tp_sl_exit", "timer_exit"];
  return {
    enabled,
    grantedAt: value.grantedAt || "",
    expiresAt: value.expiresAt || "",
    revokedAt: enabled ? "" : (value.revokedAt || ""),
    walletScope: "managed",
    maxSellPercent,
    allowedActions,
    connectedWalletPublicKey: value.connectedWalletPublicKey || ""
  };
}

function webAutomationPermissionActive(profile = {}) {
  const permission = normalizeWebAutomationPermission(profile.automationPermission || {});
  if (!permission.enabled) return false;
  const expiresAt = Date.parse(permission.expiresAt || "");
  return Number.isFinite(expiresAt) && expiresAt > Date.now();
}

async function requireWebAutomationPermission(userId, context = "server-side TP/SL") {
  const profile = await webProfileForUser(userId);
  if (!webAutomationPermissionActive(profile)) {
    const error = new Error(`Enable TP/SL Automation permission before using ${context}. This permission only applies to managed/imported SlimeWire wallets and can be revoked from Profile or Wallets.`);
    error.statusCode = 403;
    throw error;
  }
  return normalizeWebAutomationPermission(profile.automationPermission);
}

function generateWebReferralCode(store, seed = "sw") {
  const cleanSeed = String(seed || "sw")
    .replace(/^web_/i, "")
    .replace(/[^a-z0-9_-]/gi, "")
    .replace(/[_-]{2,}/g, "-")
    .replace(/^[-_]+|[-_]+$/g, "")
    .slice(0, 10)
    .toUpperCase() || "SW";
  for (let i = 0; i < 20; i += 1) {
    const suffix = crypto.randomBytes(3).toString("hex").toUpperCase();
    const code = normalizeReferralCode(`${cleanSeed}${suffix}`);
    if (!findWebProfileByReferralCode(store, code)) return code;
  }
  return normalizeReferralCode(crypto.randomBytes(7).toString("hex").toUpperCase());
}

function normalizeReferralCode(value) {
  return String(value || "")
    .trim()
    .replace(/[^a-z0-9_-]/gi, "")
    .replace(/[_-]{2,}/g, "-")
    .replace(/^[-_]+|[-_]+$/g, "")
    .toUpperCase()
    .slice(0, 24);
}

function assertReferralCodeAvailable(store, userId, codeValue) {
  const code = normalizeReferralCode(codeValue);
  if (code.length < 3) {
    const error = new Error("Referral code must be at least 3 letters or numbers.");
    error.statusCode = 400;
    throw error;
  }
  if (!/[A-Z0-9]/.test(code)) {
    const error = new Error("Referral code needs at least one letter or number.");
    error.statusCode = 400;
    throw error;
  }
  const reserved = new Set(["API", "ADMIN", "APP", "LOGIN", "LOGOUT", "OGRE", "OGREVOLBOT", "REF", "SLIMEWIRE", "SUPPORT", "TRADE", "WALLET"]);
  if (reserved.has(code)) {
    const error = new Error("That referral code is reserved. Try a more personal tag.");
    error.statusCode = 400;
    throw error;
  }
  const owner = findWebProfileByReferralCode(store, code);
  if (owner && String(owner.userId) !== String(userId)) {
    const error = new Error("That referral code is already taken. Try another tag.");
    error.statusCode = 409;
    throw error;
  }
  return code;
}

function generateWebReferralCodeForUser(store, userId, profile = {}) {
  const seed = profile.username || profile.xHandle || profile.connectedWallet?.shortPublicKey || userId || "sw";
  let code = generateWebReferralCode(store, seed);
  for (let i = 0; i < 12; i += 1) {
    const owner = findWebProfileByReferralCode(store, code);
    if (!owner || String(owner.userId) === String(userId)) return code;
    code = generateWebReferralCode(store, `${seed}${i}`);
  }
  return generateWebReferralCode(store, userId || "sw");
}

function findWebProfileByReferralCode(store, codeValue) {
  const code = normalizeReferralCode(codeValue);
  if (!code) return null;
  const entry = Object.entries(store.profiles || {}).find(([, profile]) => normalizeReferralCode(profile.referralCode) === code);
  return entry ? { userId: entry[0], profile: entry[1] } : null;
}

function webReferralLink(code) {
  const base = CONFIG.webPortalUrl || "https://www.slimewire.org";
  const url = new URL(base);
  url.pathname = `/r/${encodeURIComponent(normalizeReferralCode(code))}`;
  url.searchParams.delete("ref");
  return url.toString();
}

async function createWebLoginCode(userId, chatId) {
  const store = await readWebAuthStore();
  const now = Date.now();
  const result = addWebLoginCodeToStore(store, userId, chatId, now);
  await writeWebAuthStore(store);
  await audit("web_login_code_created", { userId, chatId, expiresAt: result.expiresAt });

  return result;
}

function addWebLoginCodeToStore(store, userId, chatId, now = Date.now()) {
  const code = crypto.randomBytes(8).toString("hex").toUpperCase();
  const formatted = code.match(/.{1,4}/g).join("-");
  const expiresAt = new Date(now + WEB_LOGIN_CODE_TTL_MS).toISOString();

  store.codes = store.codes.filter((item) => {
    const expired = Date.parse(item.expiresAt || "") <= now;
    const sameUser = String(item.userId) === String(userId);
    return !expired && !sameUser && !item.usedAt;
  });
  store.codes.push({
    codeHash: hashWebSecret(code),
    userId: String(userId),
    chatId: String(chatId),
    createdAt: new Date(now).toISOString(),
    expiresAt
  });
  store.sessions = store.sessions.filter((item) => Date.parse(item.expiresAt || "") > now);

  return { code: formatted, expiresAt };
}

async function verifyWebLoginCode(input) {
  const normalized = normalizeWebLoginCode(input);
  if (!normalized) {
    const error = new Error("Enter the login code from Telegram.");
    error.statusCode = 400;
    throw error;
  }

  const store = await readWebAuthStore();
  const now = Date.now();
  const codeHash = hashWebSecret(normalized);
  const index = store.codes.findIndex((item) => item.codeHash === codeHash && !item.usedAt && Date.parse(item.expiresAt || "") > now);

  if (index === -1) {
    const error = new Error("Login code is expired or invalid. Open Telegram and request a new /web code.");
    error.statusCode = 401;
    throw error;
  }

  const codeRecord = store.codes[index];
  store.codes[index] = {
    ...codeRecord,
    usedAt: new Date(now).toISOString()
  };
  store.codes = store.codes.filter((item) => !item.usedAt && Date.parse(item.expiresAt || "") > now);
  const session = issueWebSessionRecord(codeRecord.userId, codeRecord.chatId || codeRecord.userId, now);
  store.sessions = [
    ...store.sessions.filter((item) => Date.parse(item.expiresAt || "") > now),
    session.record
  ];
  await writeWebAuthStore(store);
  await audit("web_login_success", { userId: codeRecord.userId, expiresAt: session.expiresAt });

  return { token: session.token, tokenHash: session.tokenHash, userId: codeRecord.userId, expiresAt: session.expiresAt };
}

async function verifyWebPasswordLogin(usernameValue, passwordValue) {
  const username = normalizeWebUsername(usernameValue);
  const password = normalizeWebPassword(passwordValue);
  const store = await readWebAuthStore();
  const entry = findWebProfileByUsername(store, username);
  const invalidError = () => {
    const error = new Error("Username or password is incorrect.");
    error.statusCode = 401;
    return error;
  };

  if (!entry?.profile?.passwordLogin) throw invalidError();
  if (!verifyWebPassword(password, entry.profile.passwordLogin)) throw invalidError();

  const now = Date.now();
  const session = issueWebSessionRecord(entry.userId, entry.userId, now);
  store.sessions = [
    ...store.sessions.filter((item) => Date.parse(item.expiresAt || "") > now),
    session.record
  ];
  entry.profile.lastPasswordLoginAt = new Date(now).toISOString();
  await writeWebAuthStore(store);
  await audit("web_password_login_success", { userId: entry.userId, username, expiresAt: session.expiresAt });
  return { token: session.token, tokenHash: session.tokenHash, userId: entry.userId, expiresAt: session.expiresAt };
}

async function createWebAccount(options = {}) {
  const body = typeof options === "string" ? { email: options } : (options || {});
  const store = await readWebAuthStore();
  const now = Date.now();
  const userId = `web_${crypto.randomBytes(12).toString("base64url")}`;
  const email = normalizeEmail(body.email);
  const rawUsername = String(body.username || "").trim();
  const rawPassword = String(body.password || "");
  const wantsPasswordLogin = Boolean(rawUsername || rawPassword);
  const username = wantsPasswordLogin ? normalizeWebUsername(rawUsername) : "";
  // Idempotent signup: if this username already exists, don't fail with "already
  // taken" - that read as a dead button to people who'd simply signed up before and
  // were re-entering the SAME credentials. Verify the password and log them straight
  // in. Only a real mismatch (someone else's username, or a typo'd password) gets the
  // friendly conflict message.
  if (username) {
    const existing = findWebProfileByUsername(store, username);
    if (existing) {
      const normalizedPassword = normalizeWebPassword(rawPassword);
      if (existing.profile?.passwordLogin && verifyWebPassword(normalizedPassword, existing.profile.passwordLogin)) {
        const loginNow = Date.now();
        const loginSession = issueWebSessionRecord(existing.userId, existing.userId, loginNow);
        store.sessions = [
          ...store.sessions.filter((item) => Date.parse(item.expiresAt || "") > loginNow),
          loginSession.record
        ];
        existing.profile.lastPasswordLoginAt = new Date(loginNow).toISOString();
        await writeWebAuthStore(store);
        await audit("web_signup_login_existing", { userId: existing.userId, username, expiresAt: loginSession.expiresAt });
        return { userId: existing.userId, token: loginSession.token, tokenHash: loginSession.tokenHash, expiresAt: loginSession.expiresAt, emailSent: false, emailError: null, loggedInExisting: true };
      }
      const error = new Error("That username is already taken. If it's yours, log in with your password instead.");
      error.statusCode = 409;
      throw error;
    }
  }
  const passwordLogin = wantsPasswordLogin ? hashWebPassword(normalizeWebPassword(rawPassword)) : null;
  const referralEntry = findWebProfileByReferralCode(store, body.referralCode || body.ref || "");
  const referralCode = generateWebReferralCode(store, username || userId);
  const session = issueWebSessionRecord(userId, userId, now);

  store.profiles[userId] = {
    email,
    username,
    usernameNormalized: username,
    passwordLogin,
    referralCode,
    referredByUserId: referralEntry && referralEntry.userId !== userId ? String(referralEntry.userId) : "",
    referredByCode: referralEntry && referralEntry.userId !== userId ? normalizeReferralCode(referralEntry.profile.referralCode) : "",
    referralPayoutWallet: "",
    showOnTraderBoard: false,
    traderBoardWalletMode: "all",
    traderBoardWalletIndexes: [],
    traderBoardWalletPublicKeys: [],
    tradePresets: [],
    bundlePresets: [],
    hiddenWebPresetIds: [],
    watchedTokens: [],
    automationPermission: defaultWebAutomationPermission(),
    xHandle: "",
    xConnectedAt: "",
    avatarDataUrl: "",
    avatarUrl: "",
    avatarSource: "",
    connectedWallet: null,
    source: "web",
    createdAt: new Date(now).toISOString(),
    updatedAt: new Date(now).toISOString()
  };
  store.sessions = [
    ...store.sessions.filter((item) => Date.parse(item.expiresAt || "") > now),
    session.record
  ];
  await writeWebAuthStore(store);
  await audit("web_account_created", { userId, hasEmail: Boolean(email), hasPasswordLogin: Boolean(username), username, expiresAt: session.expiresAt });

  let emailSent = false;
  let emailError = null;
  if (email) {
    try {
      emailSent = await sendPortalReminderEmail(email);
    } catch (error) {
      emailError = friendlyError(error);
    }
  }

  return { userId, token: session.token, tokenHash: session.tokenHash, expiresAt: session.expiresAt, emailSent, emailError };
}

function issueWebSessionRecord(userId, chatId, now = Date.now()) {
  const token = crypto.randomBytes(32).toString("base64url");
  const tokenHash = hashWebSecret(token);
  const expiresAt = new Date(now + CONFIG.webSessionTtlHours * 60 * 60 * 1000).toISOString();
  return {
    token,
    tokenHash,
    expiresAt,
    record: {
      tokenHash,
      userId: String(userId),
      chatId: String(chatId || userId),
      createdAt: new Date(now).toISOString(),
      lastUsedAt: new Date(now).toISOString(),
      expiresAt
    }
  };
}

function normalizeWebUsername(value) {
  const username = String(value || "")
    .trim()
    .replace(/^@+/, "")
    .toLowerCase();

  if (!/^[a-z0-9][a-z0-9_.-]{2,23}$/.test(username)) {
    const error = new Error("Username must be 3-24 characters and use letters, numbers, dot, dash, or underscore.");
    error.statusCode = 400;
    throw error;
  }

  return username;
}

function normalizeWebPassword(value) {
  const password = String(value || "");
  if (password.length < 8 || password.length > 128) {
    const error = new Error("Password must be 8-128 characters.");
    error.statusCode = 400;
    throw error;
  }
  return password;
}

function assertWebUsernameAvailable(store, username, excludeUserId = "") {
  const existing = findWebProfileByUsername(store, username);
  if (existing && String(existing.userId) !== String(excludeUserId || "")) {
    const error = new Error("That username is already taken.");
    error.statusCode = 409;
    throw error;
  }
}

function findWebProfileByUsername(store, usernameValue) {
  const username = String(usernameValue || "").trim().toLowerCase();
  if (!username) return null;
  const entry = Object.entries(store.profiles || {}).find(([, profile]) => {
    const saved = String(profile.usernameNormalized || profile.username || "").trim().toLowerCase();
    return saved === username;
  });
  return entry ? { userId: entry[0], profile: entry[1] } : null;
}

function hashWebPassword(password) {
  const salt = crypto.randomBytes(16).toString("hex");
  const options = { N: 16384, r: 8, p: 1, maxmem: 64 * 1024 * 1024 };
  const hash = crypto.scryptSync(password, salt, 32, options).toString("hex");
  return {
    algorithm: "scrypt",
    salt,
    hash,
    keyLength: 32,
    N: options.N,
    r: options.r,
    p: options.p,
    createdAt: new Date().toISOString()
  };
}

function verifyWebPassword(password, record = {}) {
  try {
    if (record.algorithm !== "scrypt" || !record.salt || !record.hash) return false;
    const keyLength = Number.parseInt(record.keyLength || "32", 10);
    const expected = Buffer.from(String(record.hash), "hex");
    const actual = crypto.scryptSync(password, String(record.salt), keyLength, {
      N: Number.parseInt(record.N || "16384", 10),
      r: Number.parseInt(record.r || "8", 10),
      p: Number.parseInt(record.p || "1", 10),
      maxmem: 64 * 1024 * 1024
    });
    return expected.length === actual.length && crypto.timingSafeEqual(expected, actual);
  } catch {
    return false;
  }
}

async function authenticateWebRequest(request) {
  const token = webAuthTokenFromRequest(request);
  if (!token) {
    const error = new Error("Missing web session. Tap Create Account on the web panel, or log in again with a fresh Telegram /web code.");
    error.statusCode = 401;
    throw error;
  }

  const tokenHash = hashWebSecret(token);
  const store = await readWebAuthStore();
  const now = Date.now();
  const session = store.sessions.find((item) => item.tokenHash === tokenHash && Date.parse(item.expiresAt || "") > now);

  if (!session) {
    const error = new Error("Web session expired. Tap Create Account on the web panel, or open Telegram and request a fresh /web code.");
    error.statusCode = 401;
    throw error;
  }

  // Do NOT rewrite the whole store on every request. That read-modify-write ran on
  // every panel poll and was clobbering freshly-issued login sessions (a poll that
  // read the store a moment before your key-login wrote it back, dropping your new
  // session) — the cause of "I had to paste my key a few times to get in". Only
  // persist occasionally, and when we do, re-read inside a lock and merge so we can
  // never drop a session another request just added.
  const lastUsed = Date.parse(session.lastUsedAt || "") || 0;
  const hasExpired = store.sessions.some((item) => Date.parse(item.expiresAt || "") <= now);
  if (now - lastUsed > 5 * 60_000 || hasExpired) {
    try {
      await LockService.withLock("web-auth-store", 10_000, async () => {
        const fresh = await readWebAuthStore();
        const s = (fresh.sessions || []).find((item) => item.tokenHash === tokenHash);
        if (s) s.lastUsedAt = new Date(now).toISOString();
        fresh.sessions = (fresh.sessions || []).filter((item) => Date.parse(item.expiresAt || "") > now);
        await writeWebAuthStore(fresh);
      });
    } catch { /* best-effort; auth already succeeded */ }
  }

  return { userId: session.userId, chatId: session.chatId, tokenHash };
}

async function authenticateOptionalWebRequest(request) {
  const token = webAuthTokenFromRequest(request);
  if (!token) return null;
  try {
    return await authenticateWebRequest(request);
  } catch {
    return null;
  }
}

async function revokeWebSession(tokenHash) {
  const store = await readWebAuthStore();
  store.sessions = store.sessions.filter((item) => item.tokenHash !== tokenHash);
  await writeWebAuthStore(store);
}

function webAuthTokenFromRequest(request) {
  const auth = request.headers.authorization || "";
  if (/^bearer\s+/i.test(auth)) return auth.replace(/^bearer\s+/i, "").trim();
  return String(request.headers["x-ogre-session"] || "").trim();
}

function normalizeWebLoginCode(value) {
  return String(value || "").replace(/[^a-f0-9]/gi, "").toUpperCase();
}

function hashWebSecret(value) {
  return crypto.createHmac("sha256", CONFIG.appSecret).update(String(value)).digest("hex");
}

function assertWebLoginAttemptAllowed(request) {
  const key = webClientKey(request);
  const now = Date.now();
  const windowMs = 10 * 60 * 1000;
  const record = webLoginAttemptLimits.get(key) || { count: 0, resetAt: now + windowMs };

  if (record.resetAt <= now) {
    record.count = 0;
    record.resetAt = now + windowMs;
  }

  record.count += 1;
  webLoginAttemptLimits.set(key, record);

  if (record.count > 8) {
    const error = new Error("Too many login attempts. Wait a few minutes, then try again.");
    error.statusCode = 429;
    throw error;
  }
}

function clearWebLoginAttempts(request) {
  webLoginAttemptLimits.delete(webClientKey(request));
}

function webClientKey(request) {
  return String(request.headers["cf-connecting-ip"]
    || request.headers["x-forwarded-for"]
    || request.socket?.remoteAddress
    || "unknown").split(",")[0].trim();
}

function safeLockInText(value = "", max = 80) {
  return String(value || "")
    .replace(/[\r\n\t]+/g, " ")
    .replace(/[^\w .:/?&=#@-]/g, "")
    .trim()
    .slice(0, max);
}

async function recordLockInClickedEvent(body = {}, request = {}) {
  const width = Number.parseInt(body.viewport || body.viewportWidth || "0", 10);
  const event = {
    at: new Date().toISOString(),
    route: safeLockInText(body.route || "", 40),
    viewport: Number.isFinite(width) && width > 0 ? Math.min(width, 4096) : 0,
    source: safeLockInText(body.source || "", 60),
    client: safeLockInText(webClientKey(request), 80)
  };
  const store = await readJson(lockInEventsPath());
  if (!Array.isArray(store.events)) store.events = [];
  store.events.push(event);
  store.events = store.events.slice(-50);
  await writeJsonFile(lockInEventsPath(), store);
  try {
    console.info("LOCK_IN_CLICKED", {
      route: event.route,
      viewport: event.viewport,
      source: event.source,
      at: event.at
    });
  } catch {
    // Login diagnostics must never block the login flow.
  }
  return event;
}

function safeTerminalFeedText(value = "", max = 120) {
  return String(value || "")
    .replace(/[\r\n\t]+/g, " ")
    .replace(/[^\w .:/?&=#@,+-]/g, "")
    .trim()
    .slice(0, max);
}

async function recordTerminalFeedEvent(body = {}, request = {}) {
  const resultCount = Number.parseInt(body.resultCount || "0", 10);
  const renderedCount = Number.parseInt(body.renderedCount || "0", 10);
  const pageSize = Number.parseInt(body.pageSize || "0", 10);
  const maxPageSize = Number.parseInt(body.maxPageSize || "0", 10);
  const event = {
    at: new Date().toISOString(),
    tabKey: safeTerminalFeedText(body.tabKey || "", 40),
    label: safeTerminalFeedText(body.label || "", 80),
    category: safeTerminalFeedText(body.category || "", 80),
    endpoint: safeTerminalFeedText(body.endpoint || "", 140),
    cacheKey: safeTerminalFeedText(body.cacheKey || "", 100),
    requestId: safeTerminalFeedText(body.requestId || "", 80),
    status: safeTerminalFeedText(body.status || "", 40),
    reason: safeTerminalFeedText(body.reason || "", 80),
    resultCount: Number.isFinite(resultCount) && resultCount >= 0 ? Math.min(resultCount, 100_000) : 0,
    renderedCount: Number.isFinite(renderedCount) && renderedCount >= 0 ? Math.min(renderedCount, 100_000) : 0,
    pageSize: Number.isFinite(pageSize) && pageSize >= 0 ? Math.min(pageSize, 1_000) : 0,
    maxPageSize: Number.isFinite(maxPageSize) && maxPageSize >= 0 ? Math.min(maxPageSize, 1_000) : 0,
    supportsPagination: Boolean(body.supportsPagination),
    hasMore: Boolean(body.hasMore),
    nextCursor: safeTerminalFeedText(body.nextCursor || "", 80),
    stale: Boolean(body.stale),
    errorCode: safeTerminalFeedText(body.errorCode || "", 60),
    errorMessage: safeTerminalFeedText(body.errorMessage || "", 140),
    client: safeTerminalFeedText(webClientKey(request), 80)
  };
  const store = await readJson(terminalFeedEventsPath());
  if (!Array.isArray(store.events)) store.events = [];
  store.events.push(event);
  store.events = store.events.slice(-100);
  await writeJsonFile(terminalFeedEventsPath(), store);
  try {
    console.info("TERMINAL_FEED_EVENT", {
      tabKey: event.tabKey,
      category: event.category,
      cacheKey: event.cacheKey,
      status: event.status,
      resultCount: event.resultCount,
      renderedCount: event.renderedCount,
      hasMore: event.hasMore,
      stale: event.stale
    });
  } catch {
    // Feed diagnostics must never block the web app.
  }
  return event;
}

function safePerfEventText(value = "", max = 120) {
  return String(value || "")
    .replace(/[\r\n\t]+/g, " ")
    .replace(/[^\w .:/?&=#@,+-]/g, "")
    .trim()
    .slice(0, max);
}

async function recordPerformanceEvent(body = {}, request = {}) {
  const durationMs = Number(body.durationMs);
  const resultCount = Number.parseInt(body.resultCount || "0", 10);
  const event = {
    at: new Date().toISOString(),
    route: safePerfEventText(body.route || "", 40),
    component: safePerfEventText(body.component || "", 60),
    action: safePerfEventText(body.action || "", 70),
    durationMs: Number.isFinite(durationMs) && durationMs >= 0 ? Math.min(Math.round(durationMs), 600_000) : 0,
    resultCount: Number.isFinite(resultCount) && resultCount >= 0 ? Math.min(resultCount, 100_000) : 0,
    cacheHit: Boolean(body.cacheHit),
    stale: Boolean(body.stale),
    requestId: safePerfEventText(body.requestId || "", 80),
    errorCode: safePerfEventText(body.errorCode || "", 60),
    details: safePerfEventText(body.details || "", 140),
    client: safePerfEventText(webClientKey(request), 80)
  };
  const store = await readJson(performanceEventsPath());
  if (!Array.isArray(store.events)) store.events = [];
  store.events.push(event);
  store.events = store.events.slice(-300);
  await writeJsonFile(performanceEventsPath(), store);
  try {
    if (event.durationMs >= 150 || /long-task|refresh|dedupe/i.test(event.action)) {
      console.info("PERF_EVENT", {
        route: event.route,
        component: event.component,
        action: event.action,
        durationMs: event.durationMs,
        resultCount: event.resultCount,
        cacheHit: event.cacheHit,
        errorCode: event.errorCode
      });
    }
  } catch {
    // Performance diagnostics must never block app requests.
  }
  return event;
}

function normalizeManualSellAttemptId(value = "") {
  const text = String(value || "").trim().replace(/[^\w:-]/g, "").slice(0, 96);
  return text.length >= 8 ? text : "";
}

function manualSellUserHash(userId = "") {
  return crypto.createHash("sha256").update(String(userId || "")).digest("hex").slice(0, 16);
}

function manualSellTimingSummary(timings = {}) {
  const entries = Object.entries(timings)
    .filter(([, value]) => Number.isFinite(Number(value)) && Number(value) >= 0)
    .map(([key, value]) => [key, Math.round(Number(value))]);
  const slowest = entries.sort((a, b) => b[1] - a[1])[0] || ["none", 0];
  return Object.fromEntries([
    ...entries,
    ["slowestStep", slowest[0]],
    ["slowestStepMs", slowest[1]]
  ]);
}

async function recordManualSellTimingEvent(event = {}, request = {}) {
  await recordPerformanceEvent({
    route: "terminal",
    component: "manual-sell",
    action: event.action || "manual-sell-backend",
    durationMs: event.durationMs || 0,
    resultCount: event.resultCount || 0,
    cacheHit: Boolean(event.cacheHit),
    stale: false,
    requestId: event.manualSellAttemptId || "",
    errorCode: event.errorCode || "",
    details: [
      event.priority ? `priority=${event.priority}` : "priority=critical",
      event.slowestStep ? `slowest=${event.slowestStep}` : "",
      Number.isFinite(Number(event.queueWaitMs)) ? `queueWaitMs=${Math.round(Number(event.queueWaitMs))}` : "queueWaitMs=0",
      event.status ? `status=${event.status}` : ""
    ].filter(Boolean).join(";")
  }, request || {});
}

async function runManualSellCriticalAttempt(userId, body = {}, options = {}, task) {
  const manualSellAttemptId = normalizeManualSellAttemptId(firstString(body.manualSellAttemptId, body.clientRequestId));
  const request = options.request || {};
  if (!manualSellAttemptId) {
    return task({ manualSellAttemptId: "", queueWaitMs: 0, duplicate: false });
  }

  const resultKey = externalCacheKey(`manual-sell-result:${manualSellAttemptId}`, userId);
  const cached = await cacheGetJson(resultKey).catch(() => null);
  if (cached?.result) {
    const result = { ...cached.result, duplicate: true, status: "SUBMITTED" };
    await recordManualSellTimingEvent({
      action: "manual-sell-backend-duplicate-result",
      manualSellAttemptId,
      durationMs: 0,
      resultCount: result.successCount || (result.signature ? 1 : 0),
      cacheHit: true,
      queueWaitMs: 0,
      status: "duplicate-result"
    }, request).catch(() => {});
    return result;
  }

  const lockWaitStarted = Date.now();
  const lockName = `manual-sell:${manualSellUserHash(userId)}:${manualSellAttemptId}`;
  return LockService.withLock(lockName, 90_000, async () => {
    const duplicate = await cacheGetJson(resultKey).catch(() => null);
    if (duplicate?.result) return { ...duplicate.result, duplicate: true, status: "SUBMITTED" };
    const result = await task({
      manualSellAttemptId,
      queueWaitMs: Date.now() - lockWaitStarted,
      duplicate: false
    });
    await cacheSetJson(resultKey, { result }, 120_000).catch(() => false);
    return result;
  }, async () => {
    const skipped = {
      type: "bundle_sell",
      manualSellAttemptId,
      duplicate: true,
      status: "SUBMITTING",
      successCount: 0,
      failedCount: 0,
      results: [],
      message: "Sell is already submitting for this attempt. SlimeWire will not send a duplicate order."
    };
    await recordManualSellTimingEvent({
      action: "manual-sell-backend-dedupe-active",
      manualSellAttemptId,
      durationMs: Date.now() - lockWaitStarted,
      resultCount: 0,
      cacheHit: true,
      queueWaitMs: Date.now() - lockWaitStarted,
      status: "dedupe-active"
    }, request).catch(() => {});
    return skipped;
  });
}

function kvProviderName() {
  if (CONFIG.cacheProvider === "memory") return "memory";
  if (CONFIG.cacheProvider === "redis") return CONFIG.redisUrl ? "redis" : "memory";
  if (CONFIG.cacheProvider === "rest-kv") return CONFIG.kvRestUrl && CONFIG.kvRestToken ? "rest-kv" : "memory";
  if (CONFIG.redisUrl) return "redis";
  if (CONFIG.kvRestUrl && CONFIG.kvRestToken) return "rest-kv";
  return "memory";
}

function kvConfigured() {
  return kvProviderName() !== "memory";
}

function externalCacheKey(cacheName, userId = "") {
  const userHash = crypto.createHash("sha256").update(String(userId || "guest")).digest("hex").slice(0, 24);
  const name = String(cacheName || "cache").replace(/[^\w:-]/g, "_").slice(0, 80);
  return `${CONFIG.cacheNamespace}:${name}:${userHash}`;
}

function displayCacheEnvelope(value, cachedAt = Date.now()) {
  return {
    cachedAt,
    value
  };
}

function postgresHistoryConfigured() {
  return Boolean(CONFIG.postgresHistoryEnabled && CONFIG.databaseUrl);
}

function postgresStatsSnapshot() {
  return {
    ...postgresHistoryStats,
    configured: postgresHistoryConfigured(),
    enabled: Boolean(CONFIG.postgresHistoryEnabled),
    circuitOpen: postgresCircuitOpenUntil > Date.now()
  };
}

function postgresSslConfig() {
  try {
    const url = new URL(CONFIG.databaseUrl);
    const sslMode = String(url.searchParams.get("sslmode") || "").toLowerCase();
    if (sslMode === "require" || sslMode === "verify-ca" || sslMode === "verify-full") {
      return { rejectUnauthorized: false };
    }
  } catch {
    // Invalid/missing DATABASE_URL is handled by the connection attempt below.
  }
  return undefined;
}

async function postgresPool() {
  if (!postgresHistoryConfigured()) return null;
  postgresHistoryStats.configured = true;
  postgresHistoryStats.enabled = true;
  if (postgresCircuitOpenUntil > Date.now()) return null;
  if (postgresPoolClient) return postgresPoolClient;
  if (!postgresPoolPromise) {
    postgresPoolPromise = import("pg")
      .then((pgModule) => {
        const PoolCtor = pgModule?.Pool || pgModule?.default?.Pool;
        if (typeof PoolCtor !== "function") {
          throw new Error("Postgres Pool constructor unavailable from pg module.");
        }
        const pool = new PoolCtor({
          connectionString: CONFIG.databaseUrl,
          max: 2,
          idleTimeoutMillis: 10_000,
          connectionTimeoutMillis: CONFIG.cacheConnectTimeoutMs,
          ssl: postgresSslConfig()
        });
        pool.on("error", (error) => {
          postgresHistoryStats.errors += 1;
          postgresHistoryStats.lastError = safePerfEventText(error?.message || "Postgres pool error", 140);
        });
        return pool.query("select 1").then(() => {
          postgresPoolClient = pool;
          postgresCircuitOpenUntil = 0;
          return pool;
        });
      })
      .catch((error) => {
        postgresHistoryStats.errors += 1;
        postgresHistoryStats.lastError = safePerfEventText(error?.message || "Postgres connect failed", 140);
        postgresCircuitOpenUntil = Date.now() + CONFIG.cacheCircuitBreakerMs;
        postgresPoolPromise = null;
        postgresPoolClient = null;
        return null;
      });
  }
  return postgresPoolPromise;
}

