function postgresJson(value, maxChars = 40_000) {
  try {
    const raw = JSON.stringify(value ?? null);
    if (raw.length <= maxChars) return raw;
    return JSON.stringify({
      truncated: true,
      truncatedAt: new Date().toISOString(),
      preview: raw.slice(0, Math.max(1000, maxChars - 200))
    });
  } catch {
    return JSON.stringify(null);
  }
}

function postgresDate(value) {
  if (!value && value !== 0) return null;
  const direct = Number(value);
  const timestamp = Number.isFinite(direct)
    ? direct
    : Date.parse(String(value || ""));
  if (!Number.isFinite(timestamp) || timestamp <= 0) return null;
  try {
    return new Date(timestamp).toISOString();
  } catch {
    return null;
  }
}

function solanaPublicKeyLike(value = "") {
  return /^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(String(value || "").trim());
}

function devInfoMemoryKey(type = "summary", mint = "") {
  return `${String(type || "summary")}:${String(mint || "").trim()}`;
}

function devInfoExternalKey(type = "summary", mint = "") {
  return externalCacheKey(`devinfo:${String(type || "summary")}:${String(mint || "").trim().toLowerCase()}`, "global");
}

function cachedDevInfoMemory(type = "summary", mint = "", ttlMs = DEV_INFO_SUMMARY_TTL_MS) {
  const key = devInfoMemoryKey(type, mint);
  const cached = devInfoCache.get(key);
  if (!cached?.value) return null;
  if (Date.now() - Number(cached.cachedAt || 0) > ttlMs) return null;
  devInfoStats.cacheHits += 1;
  return {
    ...cached.value,
    cacheHit: true,
    cacheSource: "memory"
  };
}

function rememberDevInfoMemory(type = "summary", mint = "", value = null) {
  const key = devInfoMemoryKey(type, mint);
  if (!mint || !value) return value;
  devInfoCache.set(key, { cachedAt: Date.now(), value });
  return value;
}

async function readDevInfoKv(type = "summary", mint = "", ttlMs = DEV_INFO_SUMMARY_TTL_MS) {
  if (!mint) return null;
  const external = await cacheGetJson(devInfoExternalKey(type, mint)).catch(() => null);
  if (!external?.value || !Number.isFinite(Number(external.cachedAt))) return null;
  const ageMs = Date.now() - Number(external.cachedAt);
  if (ageMs > ttlMs) return null;
  devInfoStats.cacheHits += 1;
  rememberDevInfoMemory(type, mint, external.value);
  return {
    ...external.value,
    cacheHit: true,
    cacheSource: kvProviderName()
  };
}

async function writeDevInfoCaches(mint = "", result = null) {
  const cleanMint = String(mint || result?.mint || "").trim();
  if (!cleanMint || !result) return;
  const summary = devInfoSummaryFromResult(result);
  rememberDevInfoMemory("summary", cleanMint, summary);
  rememberDevInfoMemory("details", cleanMint, result);
  await Promise.allSettled([
    cacheSetJson(devInfoExternalKey("summary", cleanMint), displayCacheEnvelope(summary), DEV_INFO_SUMMARY_TTL_MS),
    cacheSetJson(devInfoExternalKey("details", cleanMint), displayCacheEnvelope(result), DEV_INFO_DETAILS_TTL_MS)
  ]);
}

function devInfoCandidateFromRow(row = {}) {
  const candidates = [
    ["creator", row.creatorWallet, row.creator, row.creatorAddress, row.creatorPublicKey, row.pumpCreator, row.pumpCreatorWallet],
    ["deployer", row.deployerWallet, row.deployer, row.deployerAddress],
    ["launch_wallet", row.launchWallet, row.launchWalletAddress, row.launchCreatorWallet],
    ["pool_creator", row.poolCreator, row.pairCreator, row.poolCreatorWallet, row.pairCreatorWallet],
    ["initial_liquidity", row.initialLiquidityWallet, row.initialLiquidityProvider, row.liquidityProvider],
    ["mint_authority", row.mintAuthority],
    ["metadata_authority", row.metadataAuthority, row.updateAuthority],
    ["first_funder", row.firstFunder, row.firstFundingWallet, row.fundingWallet],
    ["first_buyer", row.firstBuyer, row.firstBuyerWallet, row.earlyBuyer]
  ];
  for (const [source, ...values] of candidates) {
    const wallet = firstString(...values);
    if (!solanaPublicKeyLike(wallet)) continue;
    const confidence = ["creator", "deployer", "launch_wallet"].includes(source)
      ? "high"
      : ["pool_creator", "initial_liquidity", "mint_authority"].includes(source)
        ? "medium"
        : "low";
    return {
      mint: String(row.tokenMint || row.mint || "").trim(),
      pairAddress: firstString(row.pairAddress, row.raydiumPool),
      likelyDevWallet: wallet,
      confidence,
      source,
      evidence: {
        source,
        symbol: row.symbol || "",
        name: row.name || "",
        pairAddress: firstString(row.pairAddress, row.raydiumPool),
        seenAt: new Date().toISOString()
      }
    };
  }
  return null;
}

function devInfoReferenceLinks({ mint = "", wallet = "", pairAddress = "", row = {} } = {}) {
  const cleanMint = String(mint || row.tokenMint || row.mint || "").trim();
  const cleanWallet = String(wallet || row.creatorWallet || row.deployerWallet || "").trim();
  const cleanPair = firstString(pairAddress, row.pairAddress, row.raydiumPool);
  return [
    { label: "Solscan Token", url: cleanMint ? `https://solscan.io/token/${encodeURIComponent(cleanMint)}` : "" },
    { label: "Dex", url: firstString(row.dexUrl, cleanMint ? dexScreenerUrl(cleanMint) : "") },
    { label: "Solscan Wallet", url: cleanWallet ? `https://solscan.io/account/${encodeURIComponent(cleanWallet)}` : "" },
    { label: "KOLscan Wallet", url: cleanWallet ? kolscanAccountUrl(cleanWallet) : "" },
    { label: "Pair", url: cleanPair && !String(cleanPair).startsWith("mint:") ? `https://dexscreener.com/solana/${encodeURIComponent(cleanPair)}` : "" },
    { label: "X", url: firstString(row.twitterUrl, row.xUrl) },
    { label: "TG", url: firstString(row.telegramUrl) },
    { label: "Website", url: firstString(row.websiteUrl) }
  ].filter((link, index, links) => /^https?:\/\//i.test(String(link.url || ""))
    && links.findIndex((candidate) => String(candidate.url || "") === String(link.url || "")) === index);
}

async function readPostgresMarketRowForMint(mint = "") {
  const cleanMint = String(mint || "").trim();
  if (!cleanMint || !await ensurePostgresHistorySchema()) return null;
  const pool = await postgresPool();
  if (!pool) return null;
  try {
    const [metadataResult, pairResult] = await Promise.all([
      pool.query("select * from token_metadata where mint = $1 limit 1", [cleanMint]),
      pool.query(`
        select * from pairs
        where mint = $1
        order by last_seen_at desc nulls last, updated_at desc nulls last
        limit 1
      `, [cleanMint])
    ]);
    postgresHistoryStats.reads += 1;
    postgresHistoryStats.lastReadAt = new Date().toISOString();
    const meta = metadataResult.rows[0] || {};
    const pair = pairResult.rows[0] || {};
    if (!meta.mint && !pair.mint) return null;
    const raw = pair.raw_pair_json && typeof pair.raw_pair_json === "object" ? pair.raw_pair_json : {};
    const links = raw.links && typeof raw.links === "object" ? raw.links : {};
    const row = {
      tokenMint: cleanMint,
      mint: cleanMint,
      symbol: firstString(meta.symbol, raw.symbol),
      name: firstString(meta.name, raw.name),
      avatarUrl: firstString(meta.avatar_url, raw.avatarUrl, raw.imageUrl),
      imageUrl: firstString(meta.avatar_url, raw.imageUrl, raw.avatarUrl),
      metadataUri: firstString(meta.metadata_uri, raw.metadataUri),
      websiteUrl: firstString(meta.website_url, raw.websiteUrl, links.website, links.web),
      twitterUrl: firstString(meta.twitter_url, raw.twitterUrl, raw.xUrl, links.twitter, links.x),
      telegramUrl: firstString(meta.telegram_url, raw.telegramUrl, links.telegram),
      decimals: firstMeaningfulNumber(meta.decimals, raw.decimals),
      totalSupply: firstMeaningfulNumber(raw.totalSupply),
      priceUsd: firstMeaningfulNumber(raw.priceUsd),
      source: firstString(meta.source, pair.dex, raw.source, "postgres-history"),
      pairAddress: firstString(pair.pair_address, raw.pairAddress, raw.raydiumPool),
      raydiumPool: firstString(raw.raydiumPool, pair.pair_address),
      dexId: firstString(pair.dex, raw.dexId, raw.dexName),
      pairCreatedAt: pair.created_at_chain ? new Date(pair.created_at_chain).getTime() : null,
      liquidityUsd: firstMeaningfulNumber(pair.liquidity_usd, raw.liquidityUsd),
      marketCap: firstMeaningfulNumber(pair.market_cap, raw.marketCap),
      fdv: firstMeaningfulNumber(pair.fdv, raw.fdv),
      volume5m: firstMeaningfulNumber(pair.volume_5m, raw.volume5m),
      volumeH1: firstMeaningfulNumber(pair.volume_1h, raw.volumeH1),
      creatorWallet: firstString(raw.creatorWallet, raw.creator, raw.pumpCreator, raw.deployerWallet),
      deployerWallet: firstString(raw.deployerWallet, raw.deployer),
      poolCreator: firstString(raw.poolCreator, raw.pairCreator),
      metadataAuthority: firstString(raw.metadataAuthority, raw.updateAuthority),
      updateAuthority: firstString(raw.updateAuthority, raw.metadataAuthority),
      mintAuthority: firstString(raw.mintAuthority),
      freezeAuthority: firstString(raw.freezeAuthority),
      launchWallet: firstString(raw.launchWallet, raw.launchCreatorWallet),
      firstFunder: firstString(raw.firstFunder, raw.firstFundingWallet),
      heliusDasIndexedAt: firstString(raw.heliusDasIndexedAt),
      heliusDasSource: firstString(raw.heliusDasSource),
      riskFlags: Array.isArray(raw.riskFlags) ? raw.riskFlags.slice(0, 8) : [],
      scoreWarnings: Array.isArray(raw.scoreWarnings) ? raw.scoreWarnings.slice(0, 8) : [],
      bestPickWarnings: Array.isArray(raw.bestPickWarnings) ? raw.bestPickWarnings.slice(0, 8) : []
    };
    return row;
  } catch (error) {
    postgresHistoryStats.errors += 1;
    postgresHistoryStats.lastError = safePerfEventText(error?.message || "Postgres token context read failed", 140);
    return null;
  }
}

function devCurrentPositionFromEvents(events = [], wallet = "", mint = "") {
  const rows = Array.isArray(events) ? events.filter(Boolean) : [];
  if (!rows.length) return null;
  const buys = rows.filter((row) => /^(launch|buy|liquidity_add|transfer_in)$/i.test(String(row.eventType || row.event_type || "")));
  const sells = rows.filter((row) => /^(sell|liquidity_remove|transfer_out)$/i.test(String(row.eventType || row.event_type || "")));
  const snapshots = rows
    .filter((row) => /^(balance_snapshot|holding_snapshot)$/i.test(String(row.eventType || row.event_type || "")))
    .map((row) => ({
      amount: Number(row.tokenAmount ?? row.token_amount ?? row.amount ?? 0),
      supplyPercent: Number(row.supplyPercent ?? row.supply_percent),
      at: row.eventTime || row.event_time || row.createdAt || row.created_at || "",
      ts: Date.parse(row.eventTime || row.event_time || row.createdAt || row.created_at || "")
    }))
    .filter((row) => Number.isFinite(row.ts))
    .sort((a, b) => b.ts - a.ts);
  const initialTokenAmount = buys.reduce((sum, row) => sum + Math.max(0, Number(row.tokenAmount ?? row.token_amount ?? row.amount ?? 0)), 0);
  const soldTokenAmount = sells.reduce((sum, row) => sum + Math.max(0, Number(row.tokenAmount ?? row.token_amount ?? row.amount ?? 0)), 0);
  const latestSnapshot = snapshots[0] || null;
  const currentTokenAmount = latestSnapshot && Number.isFinite(latestSnapshot.amount)
    ? Math.max(0, latestSnapshot.amount)
    : initialTokenAmount > 0
      ? Math.max(0, initialTokenAmount - soldTokenAmount)
      : null;
  const estimatedSoldPercent = initialTokenAmount > 0 ? Math.min(100, (soldTokenAmount / initialTokenAmount) * 100) : null;
  const firstEventAt = rows
    .map((row) => Date.parse(row.eventTime || row.event_time || row.createdAt || row.created_at || ""))
    .filter(Number.isFinite)
    .sort((a, b) => a - b)[0] || null;
  const firstSell = sells
    .map((row) => ({
      at: row.eventTime || row.event_time || row.createdAt || row.created_at || "",
      ts: Date.parse(row.eventTime || row.event_time || row.createdAt || row.created_at || "")
    }))
    .filter((row) => Number.isFinite(row.ts))
    .sort((a, b) => a.ts - b.ts)[0] || null;
  const lastSell = sells
    .map((row) => ({
      at: row.eventTime || row.event_time || row.createdAt || row.created_at || "",
      ts: Date.parse(row.eventTime || row.event_time || row.createdAt || row.created_at || "")
    }))
    .filter((row) => Number.isFinite(row.ts))
    .sort((a, b) => b.ts - a.ts)[0] || null;
  const firstMajorSellMinutesAfterLaunch = firstSell && firstEventAt
    ? Math.max(0, (firstSell.ts - firstEventAt) / 60_000)
    : null;
  const positionStatus = !Number.isFinite(Number(estimatedSoldPercent))
    ? currentTokenAmount > 0
      ? "holding"
      : "unknown"
    : estimatedSoldPercent >= 95
      ? "exited"
      : estimatedSoldPercent >= 70
        ? "mostly_exited"
        : estimatedSoldPercent >= 25
          ? "partial_exit"
          : "holding";
  return {
    mint,
    likelyDevWallet: wallet || null,
    initialTokenAmount: initialTokenAmount || null,
    initialSupplyPercent: null,
    currentTokenAmount,
    currentSupplyPercent: Number.isFinite(latestSnapshot?.supplyPercent) ? latestSnapshot.supplyPercent : null,
    estimatedSoldPercent,
    firstMajorSellAt: firstSell?.at || null,
    firstMajorSellMinutesAfterLaunch,
    lastSellAt: lastSell?.at || null,
    positionStatus
  };
}

function devInfoResultFromPostgresRow(row = null) {
  if (!row) return null;
  const result = row.result_json || null;
  if (result && typeof result === "object") {
    return {
      ...result,
      externalLinks: Array.isArray(result.externalLinks) && result.externalLinks.length
        ? result.externalLinks
        : devInfoReferenceLinks({
          mint: row.mint || result.mint,
          wallet: row.likely_dev_wallet || result.likelyDevWallet,
          pairAddress: row.pair_address || result.pairAddress
        }),
      cacheHit: true,
      cacheSource: "postgres",
      stale: Date.now() - Date.parse(row.updated_at || result.updatedAt || "") > DEV_INFO_DETAILS_TTL_MS
    };
  }
  const computed = calculateDevInfoStatus({
    mint: row.mint,
    pairAddress: row.pair_address,
    likelyDevWallet: row.likely_dev_wallet,
    confidence: row.confidence,
    updatedAt: row.updated_at
  });
  return {
    ...computed,
    externalLinks: devInfoReferenceLinks({
      mint: row.mint,
      wallet: row.likely_dev_wallet,
      pairAddress: row.pair_address
    })
  };
}

async function readPostgresDevInfoCache(mint = "") {
  const cleanMint = String(mint || "").trim();
  if (!cleanMint || !await ensurePostgresHistorySchema()) return null;
  const pool = await postgresPool();
  if (!pool) return null;
  try {
    const result = await pool.query("select * from dev_info_cache where mint = $1 limit 1", [cleanMint]);
    postgresHistoryStats.reads += 1;
    postgresHistoryStats.lastReadAt = new Date().toISOString();
    devInfoStats.postgresReads += 1;
    return devInfoResultFromPostgresRow(result.rows[0] || null);
  } catch (error) {
    postgresHistoryStats.errors += 1;
    devInfoStats.errors += 1;
    devInfoStats.lastError = safePerfEventText(error?.message || "Dev Info cache read failed", 140);
    postgresHistoryStats.lastError = devInfoStats.lastError;
    return null;
  }
}

async function persistPostgresDevInfoResult(result = null) {
  if (!result?.mint || !await ensurePostgresHistorySchema()) return false;
  const pool = await postgresPool();
  if (!pool) return false;
  const summary = devInfoSummaryFromResult(result);
  try {
    await pool.query(`
      insert into dev_info_cache (mint, pair_address, likely_dev_wallet, status, confidence, score, summary, summary_json, result_json, updated_at)
      values ($1, $2, $3, $4, $5, $6, $7, $8::jsonb, $9::jsonb, coalesce($10::timestamptz, now()))
      on conflict (mint) do update set
        pair_address = excluded.pair_address,
        likely_dev_wallet = excluded.likely_dev_wallet,
        status = excluded.status,
        confidence = excluded.confidence,
        score = excluded.score,
        summary = excluded.summary,
        summary_json = excluded.summary_json,
        result_json = excluded.result_json,
        updated_at = excluded.updated_at
    `, [
      result.mint,
      result.pairAddress || null,
      result.likelyDevWallet || null,
      result.status || "unknown",
      result.confidence || "unknown",
      Number.isFinite(Number(result.score)) ? Math.round(Number(result.score)) : null,
      result.summary || "",
      postgresJson(summary, 12_000),
      postgresJson(result),
      result.updatedAt || null
    ]);
    postgresHistoryStats.writes += 1;
    postgresHistoryStats.lastWriteAt = new Date().toISOString();
    devInfoStats.postgresWrites += 1;
    return true;
  } catch (error) {
    postgresHistoryStats.errors += 1;
    devInfoStats.errors += 1;
    devInfoStats.lastError = safePerfEventText(error?.message || "Dev Info cache write failed", 140);
    postgresHistoryStats.lastError = devInfoStats.lastError;
    return false;
  }
}

async function upsertPostgresDevWalletCandidate(candidate = null) {
  if (!candidate?.mint || !candidate?.likelyDevWallet || !await ensurePostgresHistorySchema()) return false;
  const pool = await postgresPool();
  if (!pool) return false;
  try {
    await pool.query(`
      insert into dev_wallet_candidates (mint, pair_address, likely_dev_wallet, confidence, source, evidence_json, first_seen_at, updated_at)
      values ($1, $2, $3, $4, $5, $6::jsonb, now(), now())
      on conflict do nothing
    `, [
      candidate.mint,
      candidate.pairAddress || null,
      candidate.likelyDevWallet,
      candidate.confidence || "low",
      candidate.source || "inferred",
      postgresJson(candidate.evidence || candidate, 12_000)
    ]);
    await pool.query(`
      update dev_wallet_candidates
      set pair_address = $2,
          confidence = $4,
          evidence_json = $6::jsonb,
          updated_at = now()
      where mint = $1
        and coalesce(likely_dev_wallet, '') = coalesce($3, '')
        and coalesce(source, '') = coalesce($5, '')
    `, [
      candidate.mint,
      candidate.pairAddress || null,
      candidate.likelyDevWallet,
      candidate.confidence || "low",
      candidate.source || "inferred",
      postgresJson(candidate.evidence || candidate, 12_000)
    ]);
    postgresHistoryStats.writes += 1;
    postgresHistoryStats.lastWriteAt = new Date().toISOString();
    return true;
  } catch (error) {
    postgresHistoryStats.errors += 1;
    postgresHistoryStats.lastError = safePerfEventText(error?.message || "Dev candidate write failed", 140);
    return false;
  }
}

async function readPostgresDevWalletCandidate(mint = "") {
  const cleanMint = String(mint || "").trim();
  if (!cleanMint || !await ensurePostgresHistorySchema()) return null;
  const pool = await postgresPool();
  if (!pool) return null;
  try {
    const result = await pool.query(`
      select * from dev_wallet_candidates
      where mint = $1 and likely_dev_wallet is not null and likely_dev_wallet <> ''
      order by
        case confidence when 'high' then 3 when 'medium' then 2 when 'low' then 1 else 0 end desc,
        updated_at desc
      limit 1
    `, [cleanMint]);
    postgresHistoryStats.reads += 1;
    postgresHistoryStats.lastReadAt = new Date().toISOString();
    const row = result.rows[0];
    return row ? {
      mint: row.mint,
      pairAddress: row.pair_address || "",
      likelyDevWallet: row.likely_dev_wallet || "",
      confidence: row.confidence || "low",
      source: row.source || "postgres",
      evidence: row.evidence_json || {}
    } : null;
  } catch (error) {
    postgresHistoryStats.errors += 1;
    postgresHistoryStats.lastError = safePerfEventText(error?.message || "Dev candidate read failed", 140);
    return null;
  }
}

async function inferPostgresDevWalletCandidateFromTransactions(mint = "") {
  const cleanMint = String(mint || "").trim();
  if (!cleanMint || !await ensurePostgresHistorySchema()) return null;
  const pool = await postgresPool();
  if (!pool) return null;
  try {
    const result = await pool.query(`
      select wallet_address, pair_address, event_type, source, block_time, created_at
      from processed_transactions
      where mint = $1
        and wallet_address is not null
        and wallet_address <> ''
        and event_type in ('launch', 'liquidity_add', 'buy')
      order by
        case event_type when 'launch' then 0 when 'liquidity_add' then 1 else 2 end,
        block_time asc nulls last,
        created_at asc
      limit 1
    `, [cleanMint]);
    postgresHistoryStats.reads += 1;
    postgresHistoryStats.lastReadAt = new Date().toISOString();
    const row = result.rows[0];
    if (!row?.wallet_address || !solanaPublicKeyLike(row.wallet_address)) return null;
    const source = row.event_type === "launch"
      ? "processed_launch"
      : row.event_type === "liquidity_add"
        ? "processed_liquidity"
        : "processed_first_buy";
    return {
      mint: cleanMint,
      pairAddress: row.pair_address || "",
      likelyDevWallet: row.wallet_address,
      confidence: row.event_type === "launch" ? "medium" : "low",
      source,
      evidence: {
        source,
        eventType: row.event_type,
        provider: row.source || "",
        seenAt: row.block_time || row.created_at || new Date().toISOString()
      }
    };
  } catch (error) {
    postgresHistoryStats.errors += 1;
    postgresHistoryStats.lastError = safePerfEventText(error?.message || "Processed tx dev candidate read failed", 140);
    return null;
  }
}

