// === Volume Bot ===========================================================
// Persistent, server-side multi-wallet volume engine. Distinct from Bundle
// (one grouped buy/sell) and from the timed Volume Plan (single buy + TP/SL).
// Lifecycle: fund trading wallets from a managed source wallet, run randomized
// buy/sell cycles across them, then optionally sweep funds back to source.
// The worker advances ONE trade per due tick so it never starves TP/SL checks.
const VOLUME_BOT_LIMITS = {
  maxWallets: 12,
  maxCycles: 60,
  maxRounds: 250,
  maxFundPerWalletSol: 1,
  maxBuyAmountSol: 0.5,
  minDelaySecs: 3,
  maxDelaySecs: 600,
  maxLogEntries: 60,
  roundFeeBufferSol: 0.03
};

// Pick a randomized buy size centered on the target (60%-140%), capped.
function volumeBotRandomBuySol(targetSol) {
  const target = Math.max(0, Number(targetSol) || 0);
  const factor = 0.6 + Math.random() * 0.8;
  const size = target * factor;
  return Math.min(VOLUME_BOT_LIMITS.maxBuyAmountSol, Math.max(0.001, Number(size.toFixed(6))));
}

// Lean throwaway wallet for rolling mode (no backup-doc generation per round).
async function createEphemeralVolumeWallet(userId, label, volumeSource = "") {
  const store = await readWalletStore();
  const keypair = Keypair.generate();
  const record = walletRecord(cleanLabel(label || "SlimeBot"), keypair, userId);
  record.ephemeral = true;
  record.volumeBot = true;
  // Stamp the origin wallet so any sweep/stop/recovery can always return funds here
  // without the user having to manage these background wallets.
  if (volumeSource) record.volumeSource = String(volumeSource);
  store.wallets.push(record);
  await writeWalletStore(store);
  return record;
}

// Tag already-created wallets (fixed-pool auto-create) as background volume wallets
// with their origin, so they are hidden from the Wallets tab and always sweepable.
async function tagVolumeBotWallets(userId, publicKeys = [], volumeSource = "") {
  const keys = new Set((publicKeys || []).filter(Boolean));
  if (!keys.size) return;
  const store = await readWalletStore();
  let changed = false;
  for (const wallet of store.wallets) {
    if (wallet.ownerId === userId && keys.has(wallet.publicKey)) {
      if (!wallet.volumeBot) { wallet.volumeBot = true; changed = true; }
      if (volumeSource && wallet.volumeSource !== String(volumeSource)) { wallet.volumeSource = String(volumeSource); changed = true; }
    }
  }
  if (changed) await writeWalletStore(store);
}

async function pruneVolumeWallet(publicKey) {
  if (!publicKey) return;
  const store = await readWalletStore();
  const before = store.wallets.length;
  store.wallets = store.wallets.filter((wallet) => !(wallet.publicKey === publicKey && wallet.ephemeral));
  if (store.wallets.length !== before) await writeWalletStore(store);
}

async function volumeBotTransferSol(sourceRecord, destinationPublicKey, lamports) {
  const keypair = decryptWallet(sourceRecord);
  const destination = new PublicKey(destinationPublicKey);
  await assertDestinationCanReceiveSol(destination, lamports);
  const tx = new Transaction();
  tx.add(SystemProgram.transfer({ fromPubkey: keypair.publicKey, toPubkey: destination, lamports }));
  const signature = await sendLegacyTransaction(tx, [keypair]);
  invalidateWalletReadCache(sourceRecord.publicKey);
  invalidateWalletReadCache(destinationPublicKey);
  return signature;
}

function volumeBotError(message) {
  const error = new Error(message);
  error.statusCode = 400;
  return error;
}

function volumeBotLogPush(plan, message) {
  plan.log = [{ at: new Date().toISOString(), message: String(message || "") }, ...(plan.log || [])]
    .slice(0, VOLUME_BOT_LIMITS.maxLogEntries);
}

function webVolumeBotRow(plan) {
  const cfg = plan.config || {};
  const tradingCount = Array.isArray(plan.tradingPublicKeys) ? plan.tradingPublicKeys.length : 0;
  const rolling = Boolean(cfg.rollingWallets);
  return {
    id: plan.id,
    tokenMint: plan.tokenMint,
    shortMint: shortMint(plan.tokenMint || ""),
    status: plan.status,
    stage: plan.botStage || "",
    rolling,
    currentCycle: rolling ? Number(plan.roundsDone || 0) : Number(plan.currentCycle || 0),
    cycles: rolling ? Number(cfg.maxRounds || 0) : Number(cfg.cycles || 0),
    walletCount: rolling ? Number(plan.stats?.rounds || 0) : tradingCount,
    buyAmountSol: cfg.buyAmountSol,
    sellPercent: cfg.sellPercent,
    buyBias: cfg.buyBias,
    delaySecs: cfg.delaySecs,
    slippageBps: cfg.slippageBps,
    sweepBack: cfg.sweepBack !== false,
    autoCreate: Boolean(cfg.autoCreate),
    stats: plan.stats || {},
    log: plan.log || [],
    createdAt: plan.createdAt,
    updatedAt: plan.updatedAt,
    completedAt: plan.completedAt || null,
    dexUrl: plan.tokenMint ? `https://dexscreener.com/solana/${encodeURIComponent(plan.tokenMint)}` : "",
    message: volumeBotMessage(plan)
  };
}

function volumeBotMessage(plan) {
  const cfg = plan.config || {};
  if (plan.status === "completed") return "SlimeBot finished.";
  if (plan.botStage === "sweeping") return "Sweeping funds back to source wallet...";
  if (cfg.rollingWallets) {
    if (plan.botStage === "running") {
      return `Rolling fresh wallets: round ${Number(plan.roundsDone || 0) + 1}/${Number(cfg.maxRounds || 0)} (${plan.rollStage || "spawn"}).`;
    }
    return "Rolling SlimeBot armed.";
  }
  if (plan.botStage === "running") {
    return `Running cycle ${Number(plan.currentCycle || 0) + 1}/${Number(cfg.cycles || 0)} across ${Array.isArray(plan.tradingPublicKeys) ? plan.tradingPublicKeys.length : 0} wallet(s).`;
  }
  return "SlimeBot armed.";
}

// keepDust: leave a small holding so the recycled wallet still shows a token.
function volumeBotSellPercent(cfg, base = 100) {
  const pct = Number(base) || 100;
  return cfg && cfg.keepDust ? Math.min(pct, 98) : pct;
}

// Stagger the delay between actions so the flow does not look mechanical.
function volumeBotStaggerMs(cfg, baseMs, index = 0) {
  const pattern = String(cfg && cfg.staggerPattern || "steady");
  const i = Number(index) || 0;
  if (pattern === "waves") return (i % 4 < 2) ? Math.round(baseMs * 0.5) : Math.round(baseMs * 1.6);
  if (pattern === "organic") return Math.round(baseMs * (0.6 + Math.random() * 0.9));
  if (pattern === "ladder") return Math.round(baseMs * (0.7 + (i % 6) * 0.12));
  return baseMs;
}

// Best-effort current pool liquidity (USD) for the volume bot's auto-pause guard.
async function volumeBotTokenLiquidityUsd(mint) {
  try {
    const m = await getDexTokenMetadata(mint, { timeoutMs: 2_000 }).catch(() => null);
    const v = Number(m && (m.liquidityUsd ?? m.liquidity?.usd));
    return Number.isFinite(v) && v > 0 ? v : null;
  } catch { return null; }
}

async function webStartVolumeBot(userId, body = {}) {
  const tokenMint = parsePublicKey(String(body.tokenMint || "")).toBase58();
  const walletCount = clamp(Number.parseInt(body.walletCount || "0", 10) || 0, 1, VOLUME_BOT_LIMITS.maxWallets);
  const autoCreate = Boolean(body.autoCreateWallets);
  const cycles = clamp(Number.parseInt(body.cycles || "0", 10) || 0, 1, VOLUME_BOT_LIMITS.maxCycles);
  const buyAmountSol = parsePositiveNumber(String(body.buyAmountSol || ""));
  const sellPercent = parsePercent(String(body.sellPercent || "100"));
  const buyBias = clamp(Number.parseInt(body.buyBias ?? "60", 10) || 60, 5, 95);
  const delaySecs = clamp(Number.parseInt(body.delaySecs || "0", 10) || 0, VOLUME_BOT_LIMITS.minDelaySecs, VOLUME_BOT_LIMITS.maxDelaySecs);
  const slippageBps = parseWebSlippage(body.slippageBps);
  const sweepBack = body.sweepBack === undefined ? true : Boolean(body.sweepBack);
  const rollingWallets = Boolean(body.rollingWallets);
  const maxRounds = clamp(Number.parseInt(body.maxRounds || body.cycles || "0", 10) || 0, 1, VOLUME_BOT_LIMITS.maxRounds);
  const sourceIndex = parseWebWalletIndex(body.sourceWalletIndex || body.walletIndex);
  // New SlimeBot options (all additive; defaults preserve prior behavior).
  const keepDust = Boolean(body.keepDust); // leave a dust token in recycled wallets
  const offsetSell = Boolean(body.offsetSell); // pool mode: a different/earlier wallet sells while a fresh one buys
  const staggerPattern = ["steady", "waves", "organic", "ladder"].includes(String(body.staggerPattern || "").toLowerCase())
    ? String(body.staggerPattern).toLowerCase()
    : "steady";
  // Rolling ghost-POOL options: buys are a random size in [min,max] (falls back to ±40% of
  // buyAmountSol), and a small pool of recent ghost wallets stays open so a DIFFERENT/older wallet
  // sells partial amounts over a few ticks. poolSize caps how many open at once.
  const minBuyAmountSol = Math.min(VOLUME_BOT_LIMITS.maxBuyAmountSol, Math.max(0, parsePositiveNumber(String(body.minBuyAmountSol || "")) || 0));
  const maxBuyAmountSol = Math.min(VOLUME_BOT_LIMITS.maxBuyAmountSol, Math.max(minBuyAmountSol, parsePositiveNumber(String(body.maxBuyAmountSol || "")) || 0));
  const poolSize = clamp(Number.parseInt(body.poolSize || "3", 10) || 3, 2, 6);

  if (buyAmountSol > VOLUME_BOT_LIMITS.maxBuyAmountSol) {
    throw volumeBotError(`Buy amount per trade is capped at ${VOLUME_BOT_LIMITS.maxBuyAmountSol} SOL.`);
  }

  const store = await readWalletStore();
  const sourceRecord = getWalletAt(store, sourceIndex, userId);
  const planStore = await readTradePlans();
  const now = Date.now();
  const nowIso = new Date(now).toISOString();

  // --- Rolling mode: never reuse a wallet. Each round spawns a fresh wallet,
  // funds it from the source, buys a randomized size, sells, then sweeps back
  // to the source and discards the wallet. Runs until Stop or maxRounds. ---
  if (rollingWallets) {
    const effMaxBuy = maxBuyAmountSol > 0 ? maxBuyAmountSol : buyAmountSol;
    const sourceBalance = await getSolBalanceCached(decryptWallet(sourceRecord).publicKey, { force: true }).catch(() => 0);
    const perRoundSol = effMaxBuy * 1.1 + VOLUME_BOT_LIMITS.roundFeeBufferSol;
    if (sourceBalance > 0 && lamportsToSol(sourceBalance) < perRoundSol) {
      throw volumeBotError(`Source wallet needs about ${perRoundSol.toFixed(3)} SOL to run a round; it has ${lamportsToSol(sourceBalance)} SOL.`);
    }
    const plan = {
      id: crypto.randomUUID(),
      userId,
      chatId: null,
      source: "web_volume_bot",
      status: "volume_bot",
      executionMode: "managed_server",
      tokenMint,
      createdAt: nowIso,
      updatedAt: nowIso,
      config: { rollingWallets: true, maxRounds, buyAmountSol, minBuyAmountSol, maxBuyAmountSol, poolSize, sellPercent, buyBias, delaySecs, slippageBps, sweepBack, keepDust, offsetSell, staggerPattern, goalVolumeSol: Math.max(0, Number(body.goalVolumeSol) || 0), autoPauseLiquidity: body.autoPauseLiquidity !== false && body.autoPauseLiquidity !== "false", minLiquidityUsd: Math.max(0, Number(body.minLiquidityUsd) || 0) },
      sourcePublicKey: sourceRecord.publicKey,
      tradingPublicKeys: [],
      botStage: "running",
      rollStage: "spawn",
      activeWalletPublicKey: null,
      pool: [],
      roundsDone: 0,
      currentRoundBuySol: 0,
      nextActionAt: new Date(now + delaySecs * 1000).toISOString(),
      stats: { buys: 0, sells: 0, errors: 0, rounds: 0, fundedSol: 0 },
      log: [{ at: nowIso, message: `Rolling SlimeBot armed: ghost pool (≤${poolSize}), buys ${minBuyAmountSol > 0 ? minBuyAmountSol + "–" + effMaxBuy : "~" + buyAmountSol} SOL, partial sells from older wallets, up to ${maxRounds} buy(s).` }]
    };
    planStore.plans.push(plan);
    await writeTradePlans(planStore);
    await audit("web_volume_bot_start", { userId, planId: plan.id, tokenMint, rollingWallets: true, maxRounds, buyAmountSol, sweepBack });
    return webVolumeBotRow(plan);
  }

  // --- Fixed-pool mode ---
  const fundPerWalletSol = parsePositiveNumber(String(body.fundPerWalletSol || ""));
  if (fundPerWalletSol > VOLUME_BOT_LIMITS.maxFundPerWalletSol) {
    throw volumeBotError(`Fund per wallet is capped at ${VOLUME_BOT_LIMITS.maxFundPerWalletSol} SOL.`);
  }
  if (fundPerWalletSol < buyAmountSol + 0.02) {
    throw volumeBotError("Fund per wallet must cover at least the buy amount plus ~0.02 SOL for fees.");
  }

  let tradingPublicKeys = [];
  if (autoCreate) {
    const created = await createWebWalletSet(userId, {
      count: walletCount,
      label: cleanLabel(String(body.walletGroup || "SlimeBot"))
    });
    tradingPublicKeys = (created.wallets || []).map((wallet) => wallet.publicKey).filter(Boolean);
    // Auto-created pool wallets are background/temporary: tag them so they stay out of
    // the Wallets tab and always sweep back to the source.
    await tagVolumeBotWallets(userId, tradingPublicKeys, sourceRecord.publicKey);
  } else {
    const fresh = await readWalletStore();
    const selected = webSelectedWallets(fresh, userId, body.walletIndexes, body.walletGroup);
    tradingPublicKeys = selected
      .map((wallet) => wallet.publicKey)
      .filter((publicKey) => publicKey && publicKey !== sourceRecord.publicKey)
      .slice(0, walletCount);
  }
  if (!tradingPublicKeys.length) {
    throw volumeBotError("Select at least one trading wallet (not the source), or enable auto-create wallets.");
  }

  const fundResult = await webSendSolMany(userId, {
    fromWalletIndex: sourceIndex,
    destinations: tradingPublicKeys,
    amountSol: String(fundPerWalletSol)
  });

  const plan = {
    id: crypto.randomUUID(),
    userId,
    chatId: null,
    source: "web_volume_bot",
    status: "volume_bot",
    executionMode: "managed_server",
    tokenMint,
    createdAt: nowIso,
    updatedAt: nowIso,
    config: { walletCount: tradingPublicKeys.length, autoCreate, cycles, buyAmountSol, sellPercent, buyBias, delaySecs, slippageBps, sweepBack, keepDust, offsetSell, staggerPattern, goalVolumeSol: Math.max(0, Number(body.goalVolumeSol) || 0), autoPauseLiquidity: body.autoPauseLiquidity !== false && body.autoPauseLiquidity !== "false", minLiquidityUsd: Math.max(0, Number(body.minLiquidityUsd) || 0) },
    sourcePublicKey: sourceRecord.publicKey,
    tradingPublicKeys,
    botStage: "running",
    currentCycle: 0,
    actionCursor: 0,
    sweepCursor: 0,
    nextActionAt: new Date(now + delaySecs * 1000).toISOString(),
    stats: { buys: 0, sells: 0, errors: 0, fundedSol: Number((fundPerWalletSol * tradingPublicKeys.length).toFixed(6)) },
    log: [{ at: nowIso, message: `Funded ${tradingPublicKeys.length} wallet(s) with ${fundPerWalletSol} SOL each${fundResult?.signature ? ` (${fundResult.signature})` : ""}.` }]
  };
  planStore.plans.push(plan);
  await writeTradePlans(planStore);
  await audit("web_volume_bot_start", {
    userId,
    planId: plan.id,
    tokenMint,
    walletCount: tradingPublicKeys.length,
    autoCreate,
    cycles,
    buyAmountSol,
    fundPerWalletSol,
    sweepBack
  });
  return webVolumeBotRow(plan);
}

async function webStopVolumeBot(userId, body = {}) {
  const planId = String(body.planId || body.id || "").trim();
  const planStore = await readTradePlans();
  const plan = planStore.plans.find((entry) => entry.id === planId
    && String(entry.userId) === String(userId)
    && entry.source === "web_volume_bot");
  if (!plan) throw volumeBotError("SlimeBot not found.");
  if (plan.status === "completed" || plan.botStage === "done") return webVolumeBotRow(plan);
  const sweepBack = plan.config?.sweepBack !== false;
  plan.botStage = sweepBack ? "sweeping" : "done";
  plan.sweepCursor = 0;
  plan.nextActionAt = new Date().toISOString();
  plan.updatedAt = new Date().toISOString();
  volumeBotLogPush(plan, sweepBack ? "Stop requested. Sweeping funds back to source." : "Stop requested.");
  if (plan.botStage === "done") {
    plan.status = "completed";
    plan.completedAt = new Date().toISOString();
  }
  await writeTradePlans(planStore);
  await audit("web_volume_bot_stop", { userId, planId: plan.id });
  return webVolumeBotRow(plan);
}

async function webVolumeBotRows(userId) {
  const planStore = await readTradePlans();
  return (planStore.plans || [])
    .filter((plan) => plan.source === "web_volume_bot" && String(plan.userId) === String(userId))
    .sort((a, b) => Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .slice(0, 20)
    .map(webVolumeBotRow);
}

// Worker handler: advance one volume-bot action per due tick.
async function processVolumeBotPlan(plan, walletStore, persist) {
  const now = Date.now();
  if (!plan || plan.status !== "volume_bot") return { changed: false };
  if (plan.botStage === "done" || plan.botStage === "stopped") {
    plan.status = "completed";
    plan.completedAt = plan.completedAt || new Date().toISOString();
    if (typeof persist === "function") await persist();
    return { changed: true };
  }
  const dueAt = plan.nextActionAt ? Date.parse(plan.nextActionAt) : 0;
  if (Number.isFinite(dueAt) && now < dueAt) return { changed: false };

  const cfg = plan.config || {};
  const delayMs = clamp(Number(cfg.delaySecs || 5), VOLUME_BOT_LIMITS.minDelaySecs, VOLUME_BOT_LIMITS.maxDelaySecs) * 1000;
  const slippageBps = Number(cfg.slippageBps || 400);
  const owner = walletsForOwner(walletStore, plan.userId);
  const recordByPk = (publicKey) => owner.find((wallet) => wallet.publicKey === publicKey);
  const noBalance = (error) => /no token balance|rounded to zero|no token|insufficient token/i.test(String(error?.message || ""));

  try {
    if (cfg.rollingWallets) {
      await runRollingVolumeBotStep(plan, { slippageBps, noBalance });
    } else if (plan.botStage === "running") {
      // Goal-mode + auto-pause guards. Both only STOP the bot early (sweep funds back) —
      // never spend more — so the worst-case failure is stopping sooner, never overspending.
      const stopVolumeBot = (reason) => {
        plan.botStage = cfg.sweepBack === false ? "done" : "sweeping";
        plan.sweepCursor = 0;
        plan.autoStopReason = reason;
        volumeBotLogPush(plan, reason);
      };
      const goalVol = Number(cfg.goalVolumeSol || 0);
      if (goalVol > 0) {
        const volSoFar = (Number(plan.stats.buys || 0) + Number(plan.stats.sells || 0)) * Number(cfg.buyAmountSol || 0);
        if (volSoFar >= goalVol) stopVolumeBot(`Goal reached: ~${volSoFar.toFixed(2)} SOL volume generated (target ${goalVol} SOL). Sweeping back.`);
      }
      if (plan.botStage === "running" && cfg.autoPauseLiquidity !== false) {
        const liq = await volumeBotTokenLiquidityUsd(plan.tokenMint);
        if (Number.isFinite(liq) && liq > 0) {
          if (!plan.startLiquidityUsd) plan.startLiquidityUsd = liq;
          const floor = Number(cfg.minLiquidityUsd || 0);
          const dropFrac = plan.startLiquidityUsd > 0 ? liq / plan.startLiquidityUsd : 1;
          if (floor > 0 && liq < floor) stopVolumeBot(`Auto-paused: liquidity ${formatUsdCompact(liq)} fell below the ${formatUsdCompact(floor)} floor. Funds swept back.`);
          else if (dropFrac <= 0.5) stopVolumeBot(`Auto-paused: liquidity down ${Math.round((1 - dropFrac) * 100)}% from start (${formatUsdCompact(liq)}). Funds swept back.`);
        }
      }
      const pks = plan.botStage === "running" ? (plan.tradingPublicKeys || []) : [];
      if (plan.botStage !== "running") {
        // a guard stopped us this tick; the sweeping stage handles the rest next tick
      } else if (!pks.length) {
        plan.botStage = cfg.sweepBack === false ? "done" : "sweeping";
        plan.sweepCursor = 0;
      } else {
        const cursor = Number(plan.actionCursor || 0) % pks.length;
        const publicKey = pks[cursor];
        const record = recordByPk(publicKey);
        if (!record) {
          volumeBotLogPush(plan, `Wallet ${shortMint(publicKey)} missing from store; skipping.`);
        } else if (cfg.offsetSell && pks.length >= 2) {
          // Offset mode: this wallet BUYS while a different, earlier wallet
          // SELLS — never the same wallet buying then selling back-to-back.
          try {
            await buyTokenForPlan(record, plan.tokenMint, solToLamports(Number(cfg.buyAmountSol)), slippageBps, { userId: plan.userId });
            plan.stats.buys = Number(plan.stats.buys || 0) + 1;
            volumeBotLogPush(plan, `Buy ${cfg.buyAmountSol} SOL from ${shortMint(publicKey)}.`);
          } catch (error) {
            plan.stats.errors = Number(plan.stats.errors || 0) + 1;
            volumeBotLogPush(plan, `Buy failed ${shortMint(publicKey)}: ${friendlyError(error)}`);
          }
          const sellIdx = (cursor + Math.max(1, Math.floor(pks.length / 2))) % pks.length;
          const sellRecord = sellIdx !== cursor ? recordByPk(pks[sellIdx]) : null;
          if (sellRecord) {
            try {
              await sellTokenFromWallet(sellRecord, plan.tokenMint, volumeBotSellPercent(cfg, Number(cfg.sellPercent || 100)), slippageBps, { userId: plan.userId });
              plan.stats.sells = Number(plan.stats.sells || 0) + 1;
              volumeBotLogPush(plan, `Sell from ${shortMint(pks[sellIdx])} (offset behind buy).`);
            } catch (error) {
              if (!noBalance(error)) {
                plan.stats.errors = Number(plan.stats.errors || 0) + 1;
                volumeBotLogPush(plan, `Offset sell failed ${shortMint(pks[sellIdx])}: ${friendlyError(error)}`);
              }
            }
          }
        } else {
          const wantBuy = (Math.random() * 100) < Number(cfg.buyBias || 60);
          let didSell = false;
          if (!wantBuy) {
            try {
              await sellTokenFromWallet(record, plan.tokenMint, volumeBotSellPercent(cfg, Number(cfg.sellPercent || 100)), slippageBps, { userId: plan.userId });
              plan.stats.sells = Number(plan.stats.sells || 0) + 1;
              didSell = true;
              volumeBotLogPush(plan, `Sell ${cfg.sellPercent}% from ${shortMint(publicKey)}.`);
            } catch (error) {
              if (!noBalance(error)) {
                plan.stats.errors = Number(plan.stats.errors || 0) + 1;
                volumeBotLogPush(plan, `Sell failed ${shortMint(publicKey)}: ${friendlyError(error)}`);
              }
            }
          }
          if (wantBuy || !didSell) {
            try {
              await buyTokenForPlan(record, plan.tokenMint, solToLamports(Number(cfg.buyAmountSol)), slippageBps, { userId: plan.userId });
              plan.stats.buys = Number(plan.stats.buys || 0) + 1;
              volumeBotLogPush(plan, `Buy ${cfg.buyAmountSol} SOL from ${shortMint(publicKey)}.`);
            } catch (error) {
              plan.stats.errors = Number(plan.stats.errors || 0) + 1;
              volumeBotLogPush(plan, `Buy failed ${shortMint(publicKey)}: ${friendlyError(error)}`);
            }
          }
        }
        const nextCursor = cursor + 1;
        if (nextCursor >= pks.length) {
          plan.actionCursor = 0;
          plan.currentCycle = Number(plan.currentCycle || 0) + 1;
          if (plan.currentCycle >= Number(cfg.cycles || 1)) {
            plan.botStage = cfg.sweepBack === false ? "done" : "sweeping";
            plan.sweepCursor = 0;
            volumeBotLogPush(plan, plan.botStage === "sweeping" ? "Cycles complete. Sweeping funds back to source." : "Cycles complete.");
          }
        } else {
          plan.actionCursor = nextCursor;
        }
      }
    } else if (plan.botStage === "sweeping") {
      const pks = plan.tradingPublicKeys || [];
      const cursor = Number(plan.sweepCursor || 0);
      if (cursor >= pks.length) {
        // Self-heal: run up to 2 extra sweep passes so a wallet whose drain failed
        // mid-sweep (RPC blip, restart) is retried automatically instead of being
        // stranded. The manual "Sweep background wallets" button is the final backstop.
        const retries = Number(plan.sweepRetries || 0);
        if (cfg.sweepBack !== false && retries < 2) {
          plan.sweepRetries = retries + 1;
          plan.sweepCursor = 0;
          volumeBotLogPush(plan, `Sweep self-heal pass ${plan.sweepRetries}/2: re-checking wallets for leftover funds.`);
        } else {
          plan.botStage = "done";
        }
      } else {
        const publicKey = pks[cursor];
        const record = recordByPk(publicKey);
        if (record) {
          try {
            await sellTokenFromWallet(record, plan.tokenMint, volumeBotSellPercent(cfg, 100), slippageBps, { userId: plan.userId });
            volumeBotLogPush(plan, cfg.keepDust ? `Swept ${shortMint(publicKey)} (kept dust token).` : `Swept tokens from ${shortMint(publicKey)}.`);
          } catch (error) {
            if (!noBalance(error)) volumeBotLogPush(plan, `Token sweep skipped ${shortMint(publicKey)}: ${friendlyError(error)}`);
          }
          if (cfg.sweepBack !== false && plan.sourcePublicKey) {
            try {
              const keypair = decryptWallet(record);
              await drainSolFromWallet(keypair, new PublicKey(plan.sourcePublicKey));
              invalidateWalletReadCache(record.publicKey);
              volumeBotLogPush(plan, `Swept SOL back to source from ${shortMint(publicKey)}.`);
            } catch (error) {
              volumeBotLogPush(plan, `SOL sweep skipped ${shortMint(publicKey)}: ${friendlyError(error)}`);
            }
          }
        }
        plan.sweepCursor = cursor + 1;
      }
    }
  } catch (error) {
    plan.stats.errors = Number(plan.stats?.errors || 0) + 1;
    volumeBotLogPush(plan, `Tick error: ${friendlyError(error)}`);
  }

  if (plan.botStage === "done") {
    plan.status = "completed";
    plan.completedAt = new Date().toISOString();
    volumeBotLogPush(plan, "SlimeBot finished.");
  }
  plan.actionCount = Number(plan.actionCount || 0) + 1;
  plan.updatedAt = new Date().toISOString();
  plan.nextActionAt = new Date(Date.now() + volumeBotStaggerMs(cfg, delayMs, plan.actionCount)).toISOString();
  if (typeof persist === "function") await persist();
  return { changed: true };
}

// Rolling mode: one sub-step per due tick. spawn -> buy -> sell -> sweep,
// each round using a brand-new wallet that is funded from the source, traded,
// swept back, and discarded. Never reuses a wallet.
// Random buy size in [min,max] SOL; falls back to ±40% of the single target. Capped by the limit.
function volumeBotRandomBuyInRange(minSol, maxSol, fallbackSol) {
  let lo = Number(minSol) || 0, hi = Number(maxSol) || 0;
  if (!(lo > 0) || !(hi > 0)) return volumeBotRandomBuySol(fallbackSol);
  if (hi < lo) { const t = lo; lo = hi; hi = t; }
  const size = lo + Math.random() * (hi - lo);
  return Math.min(VOLUME_BOT_LIMITS.maxBuyAmountSol, Math.max(0.001, Number(size.toFixed(6))));
}

// Sell everything left in a ghost wallet, sweep its SOL back to the source, and discard it.
async function rollingCloseWallet(plan, publicKey, byPk, slippageBps, noBalance) {
  const record = byPk(publicKey);
  if (!record) return;
  const cfg = plan.config || {};
  try {
    await sellTokenFromWallet(record, plan.tokenMint, volumeBotSellPercent(cfg, 100), slippageBps, { userId: plan.userId });
  } catch (error) {
    if (!noBalance(error)) volumeBotLogPush(plan, `Close-sell skipped ${shortMint(publicKey)}: ${friendlyError(error)}`);
  }
  let drained = false;
  if (cfg.sweepBack !== false && plan.sourcePublicKey) {
    try {
      await drainSolFromWallet(decryptWallet(record), new PublicKey(plan.sourcePublicKey));
      invalidateWalletReadCache(record.publicKey);
      drained = true;
    } catch (error) {
      volumeBotLogPush(plan, `SOL sweep skipped ${shortMint(publicKey)}: ${friendlyError(error)}`);
    }
  }
  if (!cfg.keepDust && (drained || cfg.sweepBack === false)) await pruneVolumeWallet(publicKey).catch(() => {});
}

// Rolling GHOST POOL: keeps a handful of fresh throwaway wallets open at once. Each tick it either
// BUYS (spawn a new wallet, fund it a random size in [min,max], buy) or SELLS a partial random %
// from the OLDEST open wallet — selling the remainder a couple of ticks later, then sweeping its SOL
// back and discarding it. So buys and sells are always DIFFERENT wallets, sizes vary, and positions
// clear over several transactions = an organic tape with nothing to clean up afterwards.
async function runRollingVolumeBotStep(plan, { slippageBps, noBalance }) {
  const cfg = plan.config || {};
  const store = await readWalletStore();
  const owner = walletsForOwner(store, plan.userId);
  const byPk = (publicKey) => owner.find((wallet) => wallet.publicKey === publicKey);
  const sourceRecord = byPk(plan.sourcePublicKey);
  if (!sourceRecord) {
    volumeBotLogPush(plan, "Source wallet missing from store; stopping bot.");
    plan.botStage = "done";
    return;
  }
  // Init / heal the pool, and migrate any in-flight old-format wallet into it on first run.
  plan.pool = Array.isArray(plan.pool) ? plan.pool.filter((e) => e && byPk(e.publicKey)) : [];
  if (plan.activeWalletPublicKey && byPk(plan.activeWalletPublicKey) && !plan.pool.some((e) => e.publicKey === plan.activeWalletPublicKey)) {
    plan.pool.push({ publicKey: plan.activeWalletPublicKey, buySol: Number(plan.currentRoundBuySol || 0), sells: 0 });
    plan.activeWalletPublicKey = null;
  }
  plan.stats = plan.stats || {};

  // Graceful stop / completion: liquidate the whole pool one wallet per tick, then finish.
  if (plan.botStage === "sweeping") {
    const entry = plan.pool[0];
    if (!entry) { plan.botStage = "done"; volumeBotLogPush(plan, "Pool cleared and swept back to source. Done."); return; }
    await rollingCloseWallet(plan, entry.publicKey, byPk, slippageBps, noBalance);
    plan.stats.sells = Number(plan.stats.sells || 0) + 1;
    plan.pool.shift();
    return;
  }

  const poolTarget = clamp(Number(cfg.poolSize || 3) || 3, 2, 6);
  const buyBias = clamp(Number(cfg.buyBias || 55) || 55, 5, 95);
  const roundsDone = Number(plan.roundsDone || 0);
  const maxRounds = Number(cfg.maxRounds || 50);
  const canBuy = roundsDone < maxRounds;

  // Decide buy vs sell: must buy if nothing is open; keep the pool filling early; else weight by bias.
  let doBuy;
  if (!plan.pool.length) doBuy = canBuy;
  else if (!canBuy) doBuy = false;
  else if (plan.pool.length < poolTarget) doBuy = Math.random() < 0.75;
  else doBuy = (Math.random() * 100) < buyBias;

  if (doBuy) {
    const buySol = volumeBotRandomBuyInRange(cfg.minBuyAmountSol, cfg.maxBuyAmountSol, cfg.buyAmountSol);
    const fundSol = Number((buySol + VOLUME_BOT_LIMITS.roundFeeBufferSol).toFixed(6));
    // Run until the source SOL runs out: when it can't fund another buy, stop spawning and wind the
    // pool down (no fixed wallet count / round cap — the user's SOL is the only limit).
    const srcBal = await getSolBalanceCached(decryptWallet(sourceRecord).publicKey, { force: true }).catch(() => 0);
    if (lamportsToSol(srcBal) < fundSol + 0.003) {
      if (plan.pool.length) { plan.botStage = "sweeping"; volumeBotLogPush(plan, "Source SOL spent — winding the pool down."); }
      else { plan.botStage = "done"; volumeBotLogPush(plan, "Source SOL spent. Done."); }
      return;
    }
    let record;
    try {
      record = await createEphemeralVolumeWallet(plan.userId, `SlimeBot ${roundsDone + 1}`, plan.sourcePublicKey);
    } catch (error) {
      plan.stats.errors = Number(plan.stats.errors || 0) + 1;
      volumeBotLogPush(plan, `Spawn failed: ${friendlyError(error)}`);
      return;
    }
    try {
      await volumeBotTransferSol(sourceRecord, record.publicKey, solToLamports(fundSol));
      await buyTokenForPlan(record, plan.tokenMint, solToLamports(buySol), slippageBps, { userId: plan.userId });
      plan.pool.push({ publicKey: record.publicKey, buySol, sells: 0 });
      plan.roundsDone = roundsDone + 1;
      plan.stats.buys = Number(plan.stats.buys || 0) + 1;
      plan.stats.rounds = plan.roundsDone;
      plan.stats.fundedSol = Number((Number(plan.stats.fundedSol || 0) + fundSol).toFixed(6));
      volumeBotLogPush(plan, `Round ${plan.roundsDone}: ${shortMint(record.publicKey)} bought ${buySol.toFixed(4)} SOL.`);
    } catch (error) {
      plan.stats.errors = Number(plan.stats.errors || 0) + 1;
      await pruneVolumeWallet(record.publicKey).catch(() => {});
      volumeBotLogPush(plan, `Buy failed ${shortMint(record.publicKey)}: ${friendlyError(error)}`);
    }
    if (plan.roundsDone >= maxRounds) { plan.botStage = "sweeping"; volumeBotLogPush(plan, "Buy quota reached — winding the pool down."); }
    return;
  }

  // SELL: oldest open wallet sells a partial random %, then closes out after a couple of goes.
  const entry = plan.pool[0];
  const record = entry && byPk(entry.publicKey);
  if (!record) { if (entry) plan.pool.shift(); return; }
  entry.sells = Number(entry.sells || 0) + 1;
  const finish = entry.sells >= 2 || Math.random() < 0.35;
  if (finish) {
    await rollingCloseWallet(plan, entry.publicKey, byPk, slippageBps, noBalance);
    plan.stats.sells = Number(plan.stats.sells || 0) + 1;
    plan.pool.shift();
    volumeBotLogPush(plan, `${shortMint(entry.publicKey)} sold out + swept back, discarded.`);
  } else {
    const pct = Math.round(40 + Math.random() * 40);
    try {
      await sellTokenFromWallet(record, plan.tokenMint, volumeBotSellPercent(cfg, pct), slippageBps, { userId: plan.userId });
      plan.stats.sells = Number(plan.stats.sells || 0) + 1;
      volumeBotLogPush(plan, `${shortMint(record.publicKey)} sold ${volumeBotSellPercent(cfg, pct)}% (partial).`);
    } catch (error) {
      if (noBalance(error)) { await rollingCloseWallet(plan, entry.publicKey, byPk, slippageBps, noBalance); plan.pool.shift(); }
      else { plan.stats.errors = Number(plan.stats.errors || 0) + 1; volumeBotLogPush(plan, `Sell failed ${shortMint(record.publicKey)}: ${friendlyError(error)}`); }
    }
  }
}

// Sell any remaining tokens, sweep SOL back to source, and discard the wallet.
async function rollingExitActiveWallet(plan, byPk, slippageBps, noBalance) {
  const publicKey = plan.activeWalletPublicKey;
  if (!publicKey) return;
  const record = byPk(publicKey);
  if (!record) return;
  const cfg = plan.config || {};
  try {
    await sellTokenFromWallet(record, plan.tokenMint, volumeBotSellPercent(cfg, 100), slippageBps, { userId: plan.userId });
    volumeBotLogPush(plan, cfg.keepDust ? `Swept ${shortMint(publicKey)} (kept dust token).` : `Swept tokens from ${shortMint(publicKey)}.`);
  } catch (error) {
    if (!noBalance(error)) volumeBotLogPush(plan, `Token sweep skipped ${shortMint(publicKey)}: ${friendlyError(error)}`);
  }
  let drained = false;
  if (cfg.sweepBack !== false && plan.sourcePublicKey) {
    try {
      const keypair = decryptWallet(record);
      await drainSolFromWallet(keypair, new PublicKey(plan.sourcePublicKey));
      invalidateWalletReadCache(record.publicKey);
      drained = true;
      volumeBotLogPush(plan, `Swept SOL back to source from ${shortMint(publicKey)}.`);
    } catch (error) {
      volumeBotLogPush(plan, `SOL sweep skipped ${shortMint(publicKey)}: ${friendlyError(error)}`);
    }
  }
  // Only discard the throwaway wallet once it is empty, so funds are never
  // stranded. With keepDust the wallet intentionally holds a token, so keep it.
  if (!cfg.keepDust && (drained || cfg.sweepBack === false)) {
    await pruneVolumeWallet(publicKey).catch(() => {});
  }
}

// Ogre A.I. scan categories. super_fresh keeps the well-tuned fresh-ape
// behavior (default + back-compat); the other three retarget the scan toward
// runners, established/safer pairs, and larger longer-horizon plays. The
// category is layered onto the scan defaults via applyOgreAiCategory so the
// existing fresh-ape scoring path stays untouched for super_fresh.
function normalizeOgreAiCategory(value) {
  const c = String(value || "super_fresh").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (["strong", "best", "win", "winner", "smart_pick", "ogre_strong", "highwin", "high_win"].includes(c)) return "strong";
  if (["volume", "vol", "runner", "runners", "momentum", "fast"].includes(c)) return "volume";
  if (["safe", "safer", "secure", "low_risk"].includes(c)) return "safe";
  if (["long_term", "longterm", "long", "hold", "established", "steady"].includes(c)) return "long_term";
  return "super_fresh";
}

function ogreAiModeForCategory(category) {
  switch (normalizeOgreAiCategory(category)) {
    case "strong": return "strong";
    case "volume": return "fast";
    case "safe": return "safer";
    case "long_term": return "steady";
    default: return "fresh_ape";
  }
}

function ogreAiCategoryLabel(category) {
  switch (normalizeOgreAiCategory(category)) {
    case "strong": return "Strong";
    case "volume": return "Volume";
    case "safe": return "Safe";
    case "long_term": return "Long-term";
    default: return "Super-fresh";
  }
}

function normalizeOgreAiMode(value) {
  const mode = String(value || "fresh_ape").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (["strong", "best", "win", "winner", "ogre_strong", "highwin", "high_win"].includes(mode)) return "strong";
  if (["volume", "vol", "runner", "runners", "momentum", "fast"].includes(mode)) return "fast";
  if (["safe", "safer", "secure", "low_risk"].includes(mode)) return "safer";
  if (["long_term", "longterm", "long", "hold", "established", "steady"].includes(mode)) return "steady";
  // Everything else (quick/scalp/new/launch/ape/...) collapses to fresh ape.
  return "fresh_ape";
}

// Overlay category tuning onto the scan defaults. Only touches scan shaping
// (buckets / market-cap band / score / liquidity / volume / age) plus a
// scan-band takeProfit hint used purely for ranking; the real exit TP/SL the
// user picked still flows through webStartOgreAiRun from the request body.
function applyOgreAiCategory(defaults, category) {
  const cat = normalizeOgreAiCategory(category);
  defaults.category = cat;
  defaults.categoryLabel = ogreAiCategoryLabel(cat);
  if (cat === "super_fresh") return defaults;

  const liftMin = (key, floor) => { defaults[key] = Math.max(Number(defaults[key] || 0), floor); };

  if (cat === "volume") {
    defaults.buckets = [...new Set(["live", "under1h", "under3h"])];
    liftMin("minMarketCap", 8_000);
    defaults.preferredMaxMarketCap = 120_000;
    defaults.maxMarketCap = 350_000;
    defaults.maxAgeMinutes = 240;
    liftMin("minStartingVolumeUsd", 4_000);
    liftMin("minLiquidityUsd", 1_500);
    liftMin("minScore", 32);
    defaults.preferFreshLaunches = false;
    defaults.takeProfitPct = 55; // ranking band: fast momentum
    defaults.targetTakeProfitPct = 55;
    return defaults;
  }
  if (cat === "safe") {
    defaults.buckets = [...new Set(["under1h", "under3h", "under1d"])];
    liftMin("minMarketCap", 50_000);
    defaults.preferredMaxMarketCap = 400_000;
    defaults.maxMarketCap = 1_200_000;
    defaults.maxAgeMinutes = 24 * 60;
    liftMin("minStartingVolumeUsd", 8_000);
    liftMin("minLiquidityUsd", 15_000);
    liftMin("minScore", 56);
    defaults.preferFreshLaunches = false;
    defaults.defaultSlippageBps = Math.min(Number(defaults.defaultSlippageBps || 500), 300);
    defaults.takeProfitPct = 25; // ranking band: steady breakout
    defaults.targetTakeProfitPct = 25;
    return defaults;
  }
  if (cat === "long_term") {
    defaults.buckets = [...new Set(["under3h", "under1d"])];
    liftMin("minMarketCap", 150_000);
    defaults.preferredMaxMarketCap = 1_500_000;
    defaults.maxMarketCap = 5_000_000;
    defaults.maxAgeMinutes = 24 * 60;
    liftMin("minStartingVolumeUsd", 20_000);
    liftMin("minLiquidityUsd", 40_000);
    liftMin("minScore", 60);
    defaults.preferFreshLaunches = false;
    defaults.defaultSlippageBps = Math.min(Number(defaults.defaultSlippageBps || 500), 250);
    defaults.takeProfitPct = 22; // ranking band: steady breakout, larger caps
    defaults.targetTakeProfitPct = 22;
    return defaults;
  }
  return defaults;
}

function ogreAiModeDefaults(mode) {
  // STRONG: the highest-win-rate mode. Waits for survivors (1.5-12 min old)
  // with proven demand and healthy liquidity, then targets a 2x. This is the
  // recommended "click, wait, win more than you lose" path.
  if (normalizeOgreAiMode(mode) === "strong") {
    return {
      buckets: ["live", "under1h"],
      minScore: 34,
      minMarketCap: 6_000,
      preferredMaxMarketCap: 60_000,
      maxMarketCap: 120_000,
      minAgeMinutes: 1.5,
      maxAgeMinutes: 12,
      minStartingVolumeUsd: 800,
      minLiquidityUsd: 1_500,
      preferFreshLaunches: true,
      targetBand: "strong",
      diversityWindow: 14,
      // 2x target, room to run, 30-min fallback so winners have time to develop.
      defaultSellDelay: "30",
      defaultTakeProfitPct: "100",
      defaultStopLossPct: "35",
      defaultSlippageBps: 500
    };
  }
  return {
    buckets: ["live"],
    minScore: 12,
    // Fresh APE: brand-new pairs (under ~2 min) with at least $3k market cap.
    // 30s was too tight - no buyer confirmation can register that fast, so it
    // found nothing. ~2 min keeps it fresh while letting a couple of real
    // buys show up so the pick is not a pure dev-buy bundle.
    minMarketCap: 3_000,
    preferredMaxMarketCap: 8_000,
    maxMarketCap: 15_000,
    maxAgeMinutes: 2,
    minStartingVolumeUsd: 60,
    minLiquidityUsd: 20,
    preferFreshLaunches: true,
    targetBand: "fresh_ape",
    diversityWindow: 18,
    // Runner-hunting exit: aim for a 2x (TP 100%), give the trade room to run
    // with a wide stop (fresh pairs swing hard - a tight stop sells you out of
    // every winner on normal noise; hard rugs lose 100% regardless, so the
    // entry filter is the real rug defense), and a 1h fallback timer so a
    // bag that never moves frees its slot instead of sitting forever.
    defaultSellDelay: "60",
    defaultTakeProfitPct: "100",
    defaultStopLossPct: "40",
    defaultSlippageBps: 500
  };
}

function applyOgreAiTargetDefaults(defaults, targetPct, mode) {
  const safeMode = normalizeOgreAiMode(mode);
  if (safeMode === "strong") {
    // Strong manages its own band (survivor window + demand); the requested
    // take-profit still flows through as the real exit. Don't let the generic
    // target overrides reshape it.
    defaults.targetBand = "strong";
    defaults.preferFreshLaunches = true;
    defaults.buckets = [...new Set(defaults.buckets && defaults.buckets.length ? defaults.buckets : ["live", "under1h"])];
    defaults.defaultSellDelay = defaults.defaultSellDelay || "30";
    defaults.defaultTakeProfitPct = defaults.defaultTakeProfitPct || "100";
    defaults.defaultStopLossPct = defaults.defaultStopLossPct || "35";
    defaults.defaultSlippageBps = Math.max(Number(defaults.defaultSlippageBps || 500), 500);
    return defaults;
  }
  if (safeMode === "fresh_ape") {
    defaults.targetBand = "fresh_ape";
    defaults.buckets = [...new Set(["live"])];
    defaults.minScore = Math.min(Number(defaults.minScore || 12), 12);
    defaults.minMarketCap = Math.max(Number(defaults.minMarketCap || 3_000), 3_000);
    defaults.preferredMaxMarketCap = Number(defaults.preferredMaxMarketCap || 8_000);
    defaults.maxMarketCap = Math.min(Number(defaults.maxMarketCap || 15_000), 15_000);
    defaults.maxAgeMinutes = Math.min(Number(defaults.maxAgeMinutes || 2), 2);
    defaults.minStartingVolumeUsd = Math.min(Number(defaults.minStartingVolumeUsd || 60), 60);
    defaults.minLiquidityUsd = Math.min(Number(defaults.minLiquidityUsd || 20), 20);
    defaults.preferFreshLaunches = true;
    defaults.diversityWindow = Math.max(Number(defaults.diversityWindow || 0), 18);
    defaults.defaultSellDelay = "60";
    defaults.defaultTakeProfitPct = defaults.defaultTakeProfitPct || "100";
    defaults.defaultStopLossPct = defaults.defaultStopLossPct || "40";
    defaults.defaultSlippageBps = Math.max(Number(defaults.defaultSlippageBps || 500), 500);
    return defaults;
  }
  const pct = Number(targetPct);
  if (!Number.isFinite(pct) || pct <= 0) return defaults;
  if (pct >= 80) {
    defaults.targetBand = "fresh_low_mc";
    defaults.buckets = [...new Set(["live", "under1h"])];
    defaults.minScore = Math.min(Number(defaults.minScore || 54), safeMode === "safer" ? 46 : 38);
    defaults.maxMarketCap = Math.min(Number(defaults.maxMarketCap || 220_000), safeMode === "safer" ? 300_000 : 220_000);
    defaults.minLiquidityUsd = Math.min(Number(defaults.minLiquidityUsd || 90), 90);
    defaults.defaultSellDelay = "3";
    defaults.defaultSlippageBps = Math.max(Number(defaults.defaultSlippageBps || 400), 500);
    return defaults;
  }
  if (pct <= 30) {
    defaults.targetBand = "steady_breakout";
    defaults.buckets = [...new Set(["under3h", "under1d", "under1h", "live"])];
    defaults.minScore = Math.max(Number(defaults.minScore || 54), safeMode === "fresh" ? 52 : 56);
    defaults.maxMarketCap = Math.max(Number(defaults.maxMarketCap || 750_000), safeMode === "safer" ? 1_800_000 : 1_400_000);
    defaults.minLiquidityUsd = Math.max(Number(defaults.minLiquidityUsd || 350), safeMode === "fresh" ? 500 : 800);
    defaults.defaultSellDelay = safeMode === "fresh" ? "5" : "10";
    defaults.defaultSlippageBps = Math.min(Number(defaults.defaultSlippageBps || 400), 350);
    return defaults;
  }
  if (pct >= 50) {
    defaults.targetBand = "fast_momentum";
    defaults.buckets = [...new Set(["live", "under1h", "under3h"])];
    defaults.minScore = Math.min(Number(defaults.minScore || 54), 48);
    defaults.maxMarketCap = Math.min(Number(defaults.maxMarketCap || 750_000), 650_000);
    defaults.minLiquidityUsd = Math.min(Number(defaults.minLiquidityUsd || 250), 250);
  }
  return defaults;
}

function normalizeOgreAiRecentMints(input) {
  const values = Array.isArray(input)
    ? input
    : String(input || "").split(/[,\s]+/);
  const seen = new Set();
  const mints = [];
  for (const value of values) {
    const mint = String(value || "").trim();
    if (!mint || seen.has(mint)) continue;
    seen.add(mint);
    mints.push(mint);
    if (mints.length >= 30) break;
  }
  return mints;
}

function applyOgreAiTimerIntentDefaults(defaults, body = {}, mode = "quick") {
  const safeMode = normalizeOgreAiMode(mode);
  if (safeMode === "strong") {
    defaults.targetBand = "strong";
    defaults.preferFreshLaunches = true;
    defaults.buckets = [...new Set(defaults.buckets && defaults.buckets.length ? defaults.buckets : ["live", "under1h"])];
    return defaults;
  }
  if (safeMode === "fresh_ape") {
    defaults.targetBand = "fresh_ape";
    defaults.preferFreshLaunches = true;
    defaults.diversityWindow = Math.max(Number(defaults.diversityWindow || 0), 18);
    defaults.buckets = [...new Set(["live"])];
    defaults.minScore = Math.min(Number(defaults.minScore || 12), 12);
    defaults.minMarketCap = Math.max(Number(defaults.minMarketCap || 3_000), 3_000);
    defaults.preferredMaxMarketCap = Number(defaults.preferredMaxMarketCap || 8_000);
    defaults.maxMarketCap = Math.min(Number(defaults.maxMarketCap || 15_000), 15_000);
    defaults.maxAgeMinutes = Math.min(Number(defaults.maxAgeMinutes || 2), 2);
    defaults.minStartingVolumeUsd = Math.min(Number(defaults.minStartingVolumeUsd || 60), 60);
    defaults.minLiquidityUsd = Math.min(Number(defaults.minLiquidityUsd || 20), 20);
    return defaults;
  }
  const targetPct = Number(defaults.takeProfitPct || defaults.targetTakeProfitPct || defaults.defaultTakeProfitPct || 25);
  if (!Number.isFinite(targetPct) || targetPct < 80) return defaults;
  let sellDelaySeconds = null;
  try {
    sellDelaySeconds = parseOptionalSellDelaySeconds(firstString(body.sellDelay, body.sellDelaySeconds, defaults.defaultSellDelay, "3"));
  } catch {
    sellDelaySeconds = null;
  }
  if (!Number.isFinite(sellDelaySeconds) || sellDelaySeconds <= 0 || sellDelaySeconds > 10 * 60) return defaults;

  defaults.targetBand = "fresh_low_mc_timer";
  defaults.preferFreshLaunches = true;
  defaults.diversityWindow = Math.max(Number(defaults.diversityWindow || 0), safeMode === "safer" ? 12 : 18);
  defaults.buckets = [...new Set(["live", "under1h", "under3h"])];
  defaults.minScore = Math.min(Number(defaults.minScore || 54), safeMode === "safer" ? 44 : 38);
  defaults.maxMarketCap = Math.min(Number(defaults.maxMarketCap || 260_000), safeMode === "safer" ? 300_000 : 260_000);
  defaults.minLiquidityUsd = Math.min(Number(defaults.minLiquidityUsd || 120), safeMode === "safer" ? 150 : 90);
  return defaults;
}

function ogreAiScannerModesForTarget(defaults = {}, mode = "quick") {
  const pct = Number(defaults.takeProfitPct || defaults.targetTakeProfitPct || defaults.defaultTakeProfitPct || 25);
  const safeMode = normalizeOgreAiMode(mode);
  if (safeMode === "strong") return ["fast", "smart", "moonshot"];
  if (safeMode === "fresh_ape") return ["pumpsnipe", "moonshot", "fast"];
  if (pct >= 80) return safeMode === "safer" ? ["moonshot", "pumpsnipe"] : ["pumpsnipe", "moonshot"];
  if (pct <= 30) return safeMode === "fresh" ? ["fast", "smart"] : ["smart", "safe", "fast"];
  if (pct >= 50) return ["fast", "moonshot", "pumpsnipe"];
  return ["fast", "smart"];
}

async function withOgreAiSoftTimeout(promise, timeoutMs, fallback = null) {
  let timer = null;
  const guarded = Promise.resolve(promise).catch(() => fallback);
  const timeout = new Promise((resolve) => {
    timer = setTimeout(() => resolve(fallback), Math.max(500, timeoutMs));
  });
  const result = await Promise.race([guarded, timeout]);
  if (timer) clearTimeout(timer);
  return result;
}

async function ogreAiScannerRows(userId, defaults = {}, mode = "quick") {
  const scannerModes = ogreAiScannerModesForTarget(defaults, mode);
  const scans = await Promise.allSettled(scannerModes.map(async (scannerMode) => {
        const scan = await withOgreAiSoftTimeout(webSniperScan(userId, scannerMode), OGRE_AI_SOURCE_SOFT_TIMEOUT_MS, null);
    return { scannerMode, scan };
  }));
  return scans.flatMap((result) => {
    if (result.status !== "fulfilled") return [];
    const { scannerMode, scan } = result.value || {};
    return Array.isArray(scan?.rows)
      ? scan.rows.map((row) => ({
        ...row,
        ogreAiBucket: `scanner:${scannerMode}`,
        ogreAiSource: `scanner:${scannerMode}`
      }))
      : [];
  });
}

function cachedOgreAiMarketRows(defaults = {}, mode = "quick") {
  try {
    return uniqueSniperScoreRows(rowsFromCachedMarketFeeds())
      .filter((row) => !isPumpMayhemToken(row))
      .filter((row) => !isKnownBelowExitFloor(row))
      .filter((row) => !hasHardBlockedLivePairRisk(row))
      .filter((row) => !isOgreAiBlockedRisk(row))
      .map((row) => ({
        ...row,
        ogreAiBucket: row.ogreAiBucket || row.bucket || "cached:market",
        ogreAiSource: row.ogreAiSource || row.source || "cached-market"
      }))
      .sort((a, b) => compareOgreAiCandidates(a, b, defaults, mode))
      .slice(0, OGRE_AI_MAX_SCAN_ROWS);
  } catch {
    return [];
  }
}

async function selectOgreAiPicks(userId, body = {}, limit = 1) {
  const category = normalizeOgreAiCategory(firstString(body.category, body.mode));
  const mode = ogreAiModeForCategory(category);
  const defaults = ogreAiModeDefaults(mode);
  const requestedTakeProfitPct = Number.parseFloat(String(firstString(body.takeProfitPct, body.targetTakeProfitPct, defaults.defaultTakeProfitPct) || ""));
  if (Number.isFinite(requestedTakeProfitPct) && requestedTakeProfitPct > 0) {
    defaults.takeProfitPct = clamp(requestedTakeProfitPct, 5, 500);
    defaults.targetTakeProfitPct = defaults.takeProfitPct;
  }
  applyOgreAiTargetDefaults(defaults, defaults.takeProfitPct || defaults.targetTakeProfitPct || defaults.defaultTakeProfitPct, mode);
  applyOgreAiTimerIntentDefaults(defaults, body, mode);
  applyOgreAiCategory(defaults, category);
  const recentMints = normalizeOgreAiRecentMints(
    body.recentMints !== undefined && body.recentMints !== null ? body.recentMints : body.avoidMints
  );
  defaults.recentMints = recentMints;
  defaults.desiredPickCount = Math.max(1, limit, Number(defaults.diversityWindow || 0));
  // fresh_ape and strong manage their own score/cap bands; don't let an
  // incoming autopilot minScore (default 62) over-restrict them.
  const selfTunedBand = mode === "fresh_ape" || mode === "strong";
  const minScoreInput = Number.parseInt(String(body.minScore || ""), 10);
  if (!selfTunedBand && Number.isFinite(minScoreInput) && minScoreInput > 0) {
    defaults.minScore = clamp(minScoreInput, 1, 100);
  }
  const maxMarketCapInput = Number.parseFloat(String(body.maxMarketCap || ""));
  if (!selfTunedBand && Number.isFinite(maxMarketCapInput) && maxMarketCapInput > 0) {
    defaults.maxMarketCap = maxMarketCapInput;
  }

  const feedResultsPromise = Promise.allSettled(defaults.buckets.map(async (bucket) => {
      const feed = await withOgreAiSoftTimeout(webLivePairs(userId, bucket, { sort: "best", force: false }), OGRE_AI_SOURCE_SOFT_TIMEOUT_MS, null);
    return { bucket, feed };
  }));
  const scannerRowsPromise = ogreAiScannerRows(userId, defaults, mode);
  const [feedResults, scannerRows] = await Promise.all([feedResultsPromise, scannerRowsPromise]);
  const feedRows = feedResults.flatMap((result) => {
    if (result.status !== "fulfilled") return [];
    const { bucket, feed } = result.value || {};
    return Array.isArray(feed?.rows) ? feed.rows.map((row) => ({ ...row, ogreAiBucket: bucket })) : [];
  });
  const cachedRows = cachedOgreAiMarketRows(defaults, mode);
  const rows = uniqueSniperScoreRows(feedRows.concat(scannerRows, cachedRows));

  const baseRows = uniqueSniperScoreRows(rows)
    .filter((row) => !isPumpMayhemToken(row))
    .filter((row) => !isKnownBelowExitFloor(row))
    .filter((row) => !hasHardBlockedLivePairRisk(row))
    .filter((row) => !isOgreAiBlockedRisk(row));
  const rankedBaseRows = uniqueSniperScoreRows(baseRows)
    .sort((a, b) => compareOgreAiCandidates(a, b, defaults, mode));
  const requestedPlanCount = clamp(Number.parseInt(String(body.runCount || limit), 10) || 1, 1, OGRE_AI_PLANS_PER_RUN_LIMIT);
  const scanLimit = mode === "fresh_ape"
    ? Math.max(24, Math.min(OGRE_AI_MAX_SCAN_ROWS, Math.max(requestedPlanCount * 12, Math.min(limit, 12) * 3, 32)))
    : Math.max(40, Math.min(OGRE_AI_MAX_SCAN_ROWS, Math.max(limit * 20, 50)));
  const safetyRows = await filterOgreAiRowsForHardSafety(rankedBaseRows, scanLimit, defaults, mode, {
    requestedRunCount: requestedPlanCount,
    diversityLimit: Math.max(limit, Number(defaults.diversityWindow || 0))
  });
  const routePrecheckFallbackRows = safetyRows.length ? safetyRows : rankedBaseRows
    .slice(0, Math.min(rankedBaseRows.length, Math.max(requestedPlanCount, limit, 12)))
    .map((row) => ({
      ...row,
      safetyStatus: row.safetyStatus || "pending",
      safetyNote: row.safetyNote || "Safety lookup timed out; buy precheck still runs before any swap."
    }));
  const pool = buildOgreAiCandidatePool(routePrecheckFallbackRows, defaults, mode);
  const scanState = nextSniperScanState(`web:${userId}`, `ogre-ai:${mode}`);
  const rankedCandidates = pool.candidates.sort((a, b) => compareOgreAiCandidates(a, b, defaults, mode));
  const rotated = rotateRowsForRefresh(rankedCandidates, Math.max(1, limit), scanState.refreshCount, { stickyCount: 0 });
  const filtered = diversifyOgreAiCandidates(rotated, defaults, mode, {
    recentMints,
    desiredPickCount: Math.max(1, limit)
  });
  return {
    mode,
    category,
    categoryLabel: ogreAiCategoryLabel(category),
    defaults,
    selectedTier: pool.selectedTier,
    tierCounts: pool.tierCounts,
    refreshCount: scanState.refreshCount,
    scanned: rows.length,
    qualified: filtered.length,
    rows: filtered.slice(0, limit)
  };
}

async function filterOgreAiRowsForHardSafety(rows = [], limit = 40, defaults = {}, mode = "quick", options = {}) {
  const requestedRunCount = Math.max(1, Number(options.requestedRunCount || 1) || 1);
  const accepted = [];
  const acceptedKeys = new Set();
  const diversityLimit = Math.max(0, Number(options.diversityLimit || 0) || 0);
  const targetKeep = Math.min(
    OGRE_AI_MAX_SCAN_ROWS,
    Math.max(requestedRunCount, requestedRunCount * OGRE_AI_PLAN_BACKUP_MULTIPLIER, diversityLimit)
  );
  const startedAt = Date.now();
  const safetyBudgetMs = Math.max(1_200, Number(options.safetyBudgetMs || OGRE_AI_SAFETY_SCAN_BUDGET_MS) || OGRE_AI_SAFETY_SCAN_BUDGET_MS);
  const uniqueRows = uniqueSniperScoreRows(rows);
  const scanLimit = Math.min(
    uniqueRows.length,
    Math.max(40, Math.min(OGRE_AI_MAX_SCAN_ROWS, Math.max(Number(limit) || 40, requestedRunCount * OGRE_AI_SCAN_BATCH_SIZE)))
  );
  const candidates = uniqueRows
    .filter((row) => !hasHardBlockedLivePairRisk(row))
    .filter((row) => !isOgreAiBlockedRisk(row))
    .sort((a, b) => compareOgreAiCandidates(a, b, defaults, mode))
    .slice(0, Math.min(uniqueRows.length, scanLimit));

  const chunkSize = OGRE_AI_SCAN_BATCH_SIZE;
  const batchDelayMs = OGRE_AI_SCAN_BATCH_DELAY_MS;
  const pushAccepted = (row, extra = {}) => {
    const key = ogreAiSignalKey(row);
    if (!key || acceptedKeys.has(key)) return;
    acceptedKeys.add(key);
    accepted.push({ ...row, ...extra });
  };

  for (const row of candidates) {
    const riskFlags = new Set(Array.isArray(row.riskFlags) ? row.riskFlags.map((flag) => String(flag)) : []);
    const tokenProgram = String(row.tokenProgram || "");
    const token2022Known = riskFlags.has("token2022") || tokenProgram === TOKEN_2022_PROGRAM_ID.toBase58();
    const trustedToken2022 = hasTrustedToken2022Pool(row);
    const knownUnsafe = row.freezeAuthority
      || row.mintAuthority
      || riskFlags.has("freezeAuthorityActive")
      || riskFlags.has("mintAuthorityActive")
      || (token2022Known && !trustedToken2022);
    if (knownUnsafe) continue;
    const knownSafe = row.safetyStatus === "passed"
      || /mint\/freeze safety passed|safety passed|trade safety runs before buy/i.test(String(row.safetyNote || ""));
    if (knownSafe || (token2022Known && trustedToken2022)) {
      pushAccepted(row, {
        tokenProgram: row.tokenProgram || "",
        token2022PoolLabel: token2022Known ? trustedToken2022PoolLabel(row) : row.token2022PoolLabel || "",
        safetyNote: row.safetyNote || (token2022Known
          ? "Token-2022 trusted pool; buy precheck verifies route before swap."
          : "Ogre A.I. mint/freeze safety passed")
      });
    }
    if (accepted.length >= targetKeep) {
      return accepted.sort((a, b) => compareOgreAiCandidates(a, b, defaults, mode));
    }
  }

  for (let index = 0; index < candidates.length; index += chunkSize) {
    if (Date.now() - startedAt >= safetyBudgetMs && accepted.length >= requestedRunCount) break;
    const chunk = candidates.slice(index, index + chunkSize);
    await runWithConcurrency(chunk, Math.min(6, Math.max(2, CONFIG.balanceConcurrency)), async (row) => {
      if (accepted.length >= targetKeep) return;
      const key = ogreAiSignalKey(row);
      if (!key || acceptedKeys.has(key)) return;
      try {
        const safety = await getMintSafetyInfo(row.tokenMint);
        const safetyToken2022 = safety.tokenProgram === TOKEN_2022_PROGRAM_ID.toBase58();
        if (safetyToken2022 && !hasTrustedToken2022Pool(row)) return;
        if (safety.freezeAuthority || safety.mintAuthority) return;
        pushAccepted(row, {
          tokenProgram: safety.tokenProgram,
          token2022PoolLabel: safetyToken2022 ? trustedToken2022PoolLabel(row) : row.token2022PoolLabel || "",
          safetyNote: safetyToken2022
            ? "Token-2022 trusted pool; mint/freeze safety passed"
            : "Ogre A.I. mint/freeze safety passed"
        });
      } catch {
        pushAccepted(row, {
          tokenProgram: row.tokenProgram || "",
          safetyStatus: "pending",
          safetyNote: "Safety check pending; buy precheck still runs before any swap."
        });
      }
    });

    if (accepted.length >= targetKeep) break;
    if (index + chunkSize < candidates.length && Date.now() - startedAt + batchDelayMs < safetyBudgetMs) {
      await sleep(batchDelayMs);
    }
  }

  return accepted.sort((a, b) => compareOgreAiCandidates(a, b, defaults, mode));
}

function webOgreAiReasonList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => String(item || "").trim()).filter(Boolean);
  }
  if (value && typeof value === "object") {
    return Object.entries(value)
      .map(([key, entry]) => {
        if (entry === null || entry === undefined || entry === "") return "";
        const label = String(key || "").replace(/([a-z])([A-Z])/g, "$1 $2").replace(/[_-]+/g, " ");
        return `${label}: ${String(entry).slice(0, 48)}`;
      })
      .filter(Boolean);
  }
  const text = String(value || "").trim();
  return text ? [text] : [];
}

function webOgreAiPickReasons(row = {}) {
  const reasons = [];
  const targetPct = Math.round(Number(row.ogreAiTargetPct || 0));
  const targetFit = Math.round(Number(row.ogreAiTargetFit || 0));
  if (targetPct > 0) {
    reasons.push(`Fits selected +${targetPct}% target${targetFit > 0 ? ` with ${targetFit}/100 target-fit` : ""}`);
  }
  if (row.ogreAiTier) {
    reasons.push(`${String(row.ogreAiTier).replace(/^\w/, (letter) => letter.toUpperCase())} ${row.ogreAiBucket || "feed"} setup`);
  }
  const m5 = firstMeaningfulNumber(row.m5, row.priceChangeM5, row.change5m) || 0;
  const h1 = firstMeaningfulNumber(row.h1, row.priceChangeH1, row.change1h) || 0;
  const volume = firstMeaningfulNumber(row.volume5m, row.volumeM15, row.volumeM30, row.volumeH1) || 0;
  const liquidity = firstMeaningfulNumber(row.liquidityUsd) || 0;
  const poolLabel = row.token2022PoolLabel || trustedToken2022PoolLabel(row);
  if (m5 > 0 || h1 > 0) reasons.push(`Momentum ${m5 ? `${m5.toFixed(1)}% 5m` : ""}${h1 ? `${m5 ? " / " : ""}${h1.toFixed(1)}% 1h` : ""}`);
  if (volume > 0) reasons.push(`Recent volume ${formatUsdCompact(volume)}`);
  if (liquidity > 0) reasons.push(`Liquidity ${formatUsdCompact(liquidity)}`);
  if (poolLabel) reasons.push(`${poolLabel} pool`);
  for (const reason of [
    ...webOgreAiReasonList(row.bestPickInputs),
    ...webOgreAiReasonList(row.reasons)
  ]) {
    if (!reasons.some((item) => item.toLowerCase() === reason.toLowerCase())) reasons.push(reason);
  }
  return reasons.slice(0, 5);
}

function webOgreAiPickSummary(row = {}) {
  const tokenMint = ogreAiSignalKey(row);
  const ageSeconds = Number(row.pairAgeSeconds);
  const ageLabel = row.pairAgeLabel || (Number.isFinite(ageSeconds)
    ? ageSeconds < 60 ? `${Math.max(0, Math.round(ageSeconds))}s` : `${Math.max(1, Math.round(ageSeconds / 60))}m`
    : "age unknown");
  return {
    tokenMint,
    shortMint: shortMint(tokenMint),
    symbol: row.symbol || shortMint(tokenMint),
    name: row.name || "Best pick",
    score: Number(row.bestPickScore || row.score || 0),
    marketCapLabel: row.marketCapLabel || formatUsdCompact(row.marketCap || row.fdv || 0) || "n/a",
    liquidityLabel: row.liquidityLabel || formatUsdCompact(row.liquidityUsd || 0) || "n/a",
    volumeLabel: row.volume5mLabel || row.volumeH1Label || formatUsdCompact(row.volume5m || row.volumeH1 || 0) || "n/a",
    ageLabel,
    bucket: row.ogreAiBucket || "",
    targetFit: Number(row.ogreAiTargetFit || 0),
    targetPct: Number(row.ogreAiTargetPct || 0),
    dexId: row.dexId || row.dexName || "",
    poolLabel: row.token2022PoolLabel || trustedToken2022PoolLabel(row) || row.dexName || row.dexId || "",
    dexUrl: row.dexUrl || dexScreenerUrl(tokenMint),
    pumpUrl: row.pumpUrl || (webLivePairIsPump(row) ? pumpFunUrl(tokenMint) : ""),
    reasons: webOgreAiPickReasons(row)
  };
}

async function webStartOgreAiRun(userId, body = {}) {
  const store = await readWalletStore();
  const wallets = webSelectedWallets(store, userId, body.walletIndexes, body.walletGroup);
  const runCount = clamp(Number.parseInt(String(body.runCount || "1"), 10) || 1, 1, OGRE_AI_PLANS_PER_RUN_LIMIT);
  const category = normalizeOgreAiCategory(firstString(body.category, body.mode));
  const mode = ogreAiModeForCategory(category);
  const candidateLimit = Math.min(
    OGRE_AI_MAX_SCAN_ROWS,
    Math.max(runCount, runCount * OGRE_AI_PLAN_BACKUP_MULTIPLIER, 12)
  );
  const selection = await selectOgreAiPicks(userId, body, candidateLimit);
  if (!selection.rows.length) {
    throw new Error(`Ogre A.I. did not find a fresh low-MC pair with starting volume yet. Scanned ${selection.scanned}; try Scan & Ape again or review Live Pairs manually.`);
  }

  const errors = [];
  const plans = [];
  const attemptedPicks = [];
  const maxPlanAttempts = Math.min(selection.rows.length, Math.max(runCount, runCount + 4));

  for (const pick of selection.rows.slice(0, maxPlanAttempts)) {
    if (plans.length >= runCount) break;
    const pickSummary = webOgreAiPickSummary(pick);
    attemptedPicks.push(pickSummary);
    // Final SlimeShield gate before any SOL moves: the row filters catch hard flags,
    // but the shield folds in dev info, authority risk, and KOL dump pressure the
    // feed row may not carry. The TP/SL plan is the real risk control.
    //
    // Fresh-ape mode loosens this on purpose: a 20-30s-old pump.fun launch is
    // EXPECTED to be thin on liquidity/volume, which alone tips the shield to
    // AVOID. We only block genuine danger there - mayhem, mint/freeze authority,
    // honeypot/can't-sell, blacklist, rug. Other modes keep the full AVOID gate.
    try {
      const shield = await webSlimeShield(pick.tokenMint);
      const verdict = String(shield?.verdict || "").toUpperCase();
      const blocked = mode === "fresh_ape" ? slimeShieldHasHardDanger(shield) : verdict === "AVOID";
      if (blocked) {
        errors.push({
          tokenMint: pick.tokenMint,
          shortMint: shortMint(pick.tokenMint),
          pick: pickSummary,
          message: mode === "fresh_ape"
            ? `SlimeShield hard-danger flag (mayhem/mint/freeze/honeypot): ${String(shield?.summary || "blocked").slice(0, 120)}`
            : `SlimeShield ${verdict} (score ${shield?.score ?? "?"}): ${String(shield?.summary || "blocked").slice(0, 120)}`
        });
        continue;
      }
    } catch {
      // Shield unavailable: fall through - the buy precheck still runs before swaps.
    }
    // Freshness guard: re-read the LIVE market cap right before buying. The pick
    // came from a scan that can be seconds stale; if it already dumped (e.g.
    // signalled at $3k, now $1.9k) we skip instead of aping the dump.
    try {
      const signalMc = Number(pick.marketCap || pick.fdv || 0);
      const freshPairs = await fetchDexScreenerTokenPairsFallback(pick.tokenMint, { timeoutMs: 3000 }).catch(() => []);
      const best = bestDexPairForToken(pick.tokenMint, freshPairs);
      const freshMc = Number(best?.marketCap || best?.fdv || 0);
      if (freshMc > 0) {
        if (signalMc > 0 && freshMc < signalMc * 0.70) {
          errors.push({ tokenMint: pick.tokenMint, shortMint: shortMint(pick.tokenMint), pick: pickSummary,
            message: `Skipped — dumped ${Math.round((1 - freshMc / signalMc) * 100)}% since signal ($${Math.round(signalMc)}→$${Math.round(freshMc)} MC).` });
          continue;
        }
        if (freshMc < 1500) {
          errors.push({ tokenMint: pick.tokenMint, shortMint: shortMint(pick.tokenMint), pick: pickSummary,
            message: `Skipped — MC collapsed to $${Math.round(freshMc)} before buy.` });
          continue;
        }
      }
    } catch { /* live read failed -> fall through; the buy/route precheck still applies */ }
    try {
      const defaults = selection.defaults;
      const plan = await webCreateManagedBuyPlan(userId, wallets, {
        ...body,
        tokenMint: pick.tokenMint,
        sellPercent: "100"
      }, {
        source: "ogre_ai",
        label: "Ogre A.I. plan",
        auditType: "web_create_ogre_ai_plan",
        defaultSellDelay: firstString(body.sellDelay, body.sellDelaySeconds, defaults.defaultSellDelay),
        defaultTakeProfitPct: firstString(body.takeProfitPct, defaults.defaultTakeProfitPct),
        defaultStopLossPct: firstString(body.stopLossPct, defaults.defaultStopLossPct),
        defaultSlippageBps: firstMeaningfulNumber(body.slippageBps, defaults.defaultSlippageBps)
      });
      plans.push({
        ...plan,
        pick: pickSummary
      });
    } catch (error) {
      errors.push({
        tokenMint: pick.tokenMint,
        shortMint: shortMint(pick.tokenMint),
        pick: pickSummary,
        message: friendlyError(error)
      });
    }
  }

  if (!plans.length) {
    await audit("web_ogre_ai_run_no_plan", {
      userId,
      mode,
      runCount,
      scanned: selection.scanned,
      qualified: selection.qualified,
      candidateMints: attemptedPicks.map((pick) => pick.tokenMint),
      errors
    });

    return {
      mode,
      category,
      categoryLabel: ogreAiCategoryLabel(category),
      refreshCount: selection.refreshCount,
      scanned: selection.scanned,
      qualified: selection.qualified,
      walletCount: wallets.length,
      armedCount: 0,
      failedCount: errors.length,
      selectedTier: selection.selectedTier,
      tierCounts: selection.tierCounts,
      executionMode: "managed_server",
      plans: [],
      picks: attemptedPicks.slice(0, Math.max(1, runCount)),
      errors,
      message: `Ogre A.I. (${ogreAiCategoryLabel(category)}) picked ${Math.max(1, attemptedPicks.length)} setup(s), but no buy was armed. ${errors[0]?.message || "Route or wallet precheck failed."}`
    };
  }

  await audit("web_ogre_ai_run", {
    userId,
    mode,
    runCount,
    scanned: selection.scanned,
    qualified: selection.qualified,
    planIds: plans.map((plan) => plan.id),
    tokenMints: plans.map((plan) => plan.tokenMint),
    errors
  });

  return {
    mode,
    category,
    categoryLabel: ogreAiCategoryLabel(category),
    refreshCount: selection.refreshCount,
    scanned: selection.scanned,
    qualified: selection.qualified,
    walletCount: wallets.length,
    armedCount: plans.length,
    failedCount: errors.length,
    selectedTier: selection.selectedTier,
    tierCounts: selection.tierCounts,
    executionMode: "managed_server",
    plans,
    picks: plans.map((plan) => plan.pick).filter(Boolean),
    errors,
    message: `Ogre A.I. (${ogreAiCategoryLabel(category)}) armed ${plans.length} managed plan(s) from ${selection.qualified} qualified setup(s). TP/SL watchers are running for managed wallets.`
  };
}

async function webBundleBuy(userId, body = {}) {
  const store = await readWalletStore();
  const wallets = webSelectedWallets(store, userId, body.walletIndexes, body.walletGroup);
  const tokenMint = parsePublicKey(String(body.tokenMint || "")).toBase58();
  const amountSol = parsePositiveNumber(String(body.amountSol || ""));
  const amountLamports = solToLamports(amountSol);
  const slippageBps = parseWebSlippage(body.slippageBps);
  const results = [];
  const tradeEvents = [];

  await runWithConcurrency(wallets, CONFIG.bundleConcurrency, async (wallet) => {
    try {
      const result = await buyTokenForPlan(wallet, tokenMint, amountLamports, slippageBps, { trackTokenDelta: true, userId });
      results.push({
        ok: true,
        walletLabel: wallet.label,
        walletPublicKey: wallet.publicKey,
        spentSol: lamportsToSol(result.amountLamports),
        netSwapSol: lamportsToSol(result.swapLamports),
        feeSol: lamportsToSol(result.feeLamports),
        signature: result.signature,
        message: `${wallet.label}: bought with ${lamportsToSol(result.amountLamports)} SOL`
      });
      tradeEvents.push({
        userId,
        type: "buy",
        source: "web_bundle",
        tokenMint,
        walletLabel: wallet.label,
        walletPublicKey: wallet.publicKey,
        solLamportsSpent: String(result.amountLamports),
        tokenAmount: result.tokenDeltaAmount || result.outputAmount || null,
        signature: result.signature
      });
    } catch (error) {
      results.push({
        ok: false,
        walletLabel: wallet.label,
        walletPublicKey: wallet.publicKey,
        message: `${wallet.label}: buy failed - ${friendlyError(error)}`
      });
    }
  });

  await recordTradeEvents(tradeEvents);
  await audit("web_bundle_buy", {
    userId,
    tokenMint,
    walletCount: wallets.length,
    successCount: tradeEvents.length,
    amountSol,
    slippageBps
  });

  return webBundleResult("bundle_buy", tokenMint, wallets.length, tradeEvents.length, results);
}

async function webBundleSell(userId, body = {}, options = {}) {
  return runManualSellCriticalAttempt(userId, body, options, (attempt) => webBundleSellCore(userId, body, options, attempt));
}

async function webBundleSellCore(userId, body = {}, options = {}, attempt = {}) {
  const backendStartedAt = Date.now();
  const store = await readWalletStore();
  const wallets = webSelectedWallets(store, userId, body.walletIndexes, body.walletGroup);
  const tokenMint = parsePublicKey(String(body.tokenMint || "")).toBase58();
  const percent = parsePercent(String(body.percent || "100"));
  const slippageBps = parseWebSlippage(body.slippageBps);
  const results = [];
  const tradeEvents = [];
  const validationMs = Date.now() - backendStartedAt;

  const submitStartedAt = Date.now();
  await runWithConcurrency(wallets, CONFIG.bundleConcurrency, async (wallet) => {
    try {
      const sell = await sellTokenFromWallet(wallet, tokenMint, percent, slippageBps, { userId });
      const outputLamports = BigInt(sell.outputLamports || 0);
      const feeLamports = BigInt(sell.feeLamports || 0);
      const netLamports = outputLamports > feeLamports ? outputLamports - feeLamports : 0n;
      results.push({
        ok: true,
        walletLabel: wallet.label,
        walletPublicKey: wallet.publicKey,
        percent,
        netSol: lamportsBigToSol(netLamports),
        feeSol: lamportsBigToSol(feeLamports),
        signature: sell.signature,
        message: `${wallet.label}: sold ${percent}% for ${lamportsBigToSol(netLamports)} SOL after fee`
      });
      tradeEvents.push({
        userId,
        type: "sell",
        source: "web_bundle",
        tokenMint,
        walletLabel: wallet.label,
        walletPublicKey: wallet.publicKey,
        tokenAmount: sell.tokenAmount,
        solLamportsReceived: sell.outputLamports,
        signature: sell.signature
      });
    } catch (error) {
      results.push({
        ok: false,
        walletLabel: wallet.label,
        walletPublicKey: wallet.publicKey,
        message: `${wallet.label}: sell failed - ${friendlyError(error)}`
      });
    }
  });
  const submitMs = Date.now() - submitStartedAt;

  const recordStartedAt = Date.now();
  await recordTradeEvents(tradeEvents);
  await audit("web_bundle_sell", {
    userId,
    tokenMint,
    walletCount: wallets.length,
    successCount: tradeEvents.length,
    percent,
    slippageBps
  });
  const recordMs = Date.now() - recordStartedAt;
  const backendMs = Date.now() - backendStartedAt;

  const result = webBundleResult("bundle_sell", tokenMint, wallets.length, tradeEvents.length, results);
  const manualSellTiming = manualSellTimingSummary({
    backendMs,
    validationMs,
    queueWaitMs: attempt.queueWaitMs || 0,
    submitMs,
    recordMs
  });
  result.manualSellAttemptId = attempt.manualSellAttemptId || "";
  result.manualSellTiming = manualSellTiming;
  result.status = tradeEvents.length ? "SUBMITTED" : "FAILED";
  await recordManualSellTimingEvent({
    action: "manual-sell-backend",
    manualSellAttemptId: attempt.manualSellAttemptId || "",
    durationMs: backendMs,
    resultCount: tradeEvents.length,
    queueWaitMs: attempt.queueWaitMs || 0,
    slowestStep: manualSellTiming.slowestStep,
    status: result.status.toLowerCase()
  }, options.request).catch(() => {});

  return result;
}

function webBundleResult(type, tokenMint, walletCount, successCount, results) {
  return {
    type,
    tokenMint,
    shortMint: shortMint(tokenMint),
    walletCount,
    successCount,
    failedCount: Math.max(0, walletCount - successCount),
    dexUrl: dexScreenerUrl(tokenMint),
    results,
    message: `${type === "bundle_buy" ? "Bundle buy" : "Bundle sell"} complete: ${successCount}/${walletCount} wallet(s) succeeded.`
  };
}

function cleanLaunchText(value, maxLength = 256) {
  return String(value || "")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, maxLength);
}

const SLIMEWIRE_LAUNCH_ATTRIBUTION = "Launched from slimewire.org";

function launchDescriptionWithSlimeWireAttribution(value, maxLength = 800) {
  const clean = cleanLaunchText(value, maxLength);
  if (clean.toLowerCase().includes(SLIMEWIRE_LAUNCH_ATTRIBUTION.toLowerCase())) return clean;
  const separator = clean ? "\n\n" : "";
  const maxBaseLength = Math.max(0, maxLength - separator.length - SLIMEWIRE_LAUNCH_ATTRIBUTION.length);
  const base = clean.slice(0, maxBaseLength).trim();
  return `${base}${base ? separator : ""}${SLIMEWIRE_LAUNCH_ATTRIBUTION}`.slice(0, maxLength);
}

function cleanLaunchUrl(value) {
  const text = String(value || "").trim();
  if (!text || text.startsWith("@")) return "";
  try {
    const url = new URL(text);
    if (!["http:", "https:"].includes(url.protocol)) return "";
    return url.toString();
  } catch {
    return "";
  }
}

function cleanLaunchBoolean(value) {
  if (typeof value === "boolean") return value;
  const text = String(value || "").trim().toLowerCase();
  return ["1", "true", "yes", "on"].includes(text);
}

function cleanLaunchNumber(value, fallback = 0, min = 0, max = 10000) {
  const parsed = Number.parseFloat(String(value ?? "").replace(/,/g, "").trim());
  if (!Number.isFinite(parsed)) return fallback;
  return Math.min(max, Math.max(min, parsed));
}

function normalizeLaunchResponseMint(data = {}) {
  return firstString(
    data.tokenMint,
    data.mint,
    data.ca,
    data.address,
    data.contractAddress,
    data.token?.mint,
    data.token?.address,
    data.result?.tokenMint,
    data.result?.mint,
    data.result?.ca,
    data.result?.address
  );
}

function compactLaunchPayload(value) {
  if (Array.isArray(value)) {
    return value
      .map(compactLaunchPayload)
      .filter((item) => item !== null && item !== undefined && item !== "");
  }
  if (value && typeof value === "object") {
    const entries = Object.entries(value)
      .map(([key, entry]) => [key, compactLaunchPayload(entry)])
      .filter(([, entry]) => {
        if (entry === null || entry === undefined || entry === "") return false;
        if (Array.isArray(entry)) return entry.length > 0;
        if (entry && typeof entry === "object") return Object.keys(entry).length > 0;
        return true;
      });
    return Object.fromEntries(entries);
  }
  return value;
}

function buildPumpLaunchPayload(basePayload) {
  const format = CONFIG.pumpLaunchApiFormat;
  const imageField = CONFIG.pumpLaunchImageField
    || (CONFIG.pumpLaunchRequestMode === "multipart" ? "image" : "imageDataUrl");
  const attachImage = (payload) => {
    if (basePayload.imageDataUrl && CONFIG.pumpLaunchRequestMode !== "multipart" && !/^none$/i.test(imageField)) {
      payload[imageField] = basePayload.imageDataUrl;
    }
    return payload;
  };

  if (["minimal", "flat", "pump"].includes(format)) {
    const minimal = attachImage(compactLaunchPayload({
      name: basePayload.name,
      symbol: basePayload.symbol || basePayload.ticker,
      description: basePayload.description,
      website: basePayload.website,
      twitter: basePayload.twitter,
      telegram: basePayload.telegram
    }));
    if (format === "minimal") return minimal;

    const flat = attachImage(compactLaunchPayload({
      ...minimal,
      ticker: basePayload.symbol,
      x: basePayload.twitter,
      imageName: basePayload.imageName,
      imageType: basePayload.imageType,
      creatorFeeBps: basePayload.creatorFeeBps,
      creatorFeeRecipient: basePayload.creatorFeeRecipient,
      buybackWallet: basePayload.buybackWallet,
      burnCreatorFees: basePayload.burnCreatorFees,
      feeMode: basePayload.feeMode,
      devBuySol: basePayload.devBuy?.amountSol,
      initialBuySol: basePayload.devBuy?.amountSol,
      devBuyEnabled: basePayload.devBuy?.enabled,
      devWalletIndex: basePayload.devBuy?.walletIndex,
      clientRequestId: basePayload.clientRequestId,
      source: basePayload.source
    }));
    if (format !== "pump") return flat;
    return compactLaunchPayload({
      action: "create",
      ...flat,
      denominatedInSol: "true",
      amount: flat.initialBuySol || 0,
      pool: "pump"
    });
  }
  return compactLaunchPayload(basePayload);
}

function decodeLaunchImageDataUrl(dataUrl, basePayload = {}) {
  return decodeLaunchImageDataUrlInput(dataUrl, basePayload);
}

function appendPumpLaunchFormValue(form, key, value) {
  if (value === null || value === undefined || value === "") return;
  if (Array.isArray(value) || (value && typeof value === "object")) {
    form.append(key, JSON.stringify(value));
    return;
  }
  form.append(key, String(value));
}

function appendPumpLaunchSearchValue(search, key, value) {
  if (value === null || value === undefined || value === "") return;
  if (Array.isArray(value) || (value && typeof value === "object")) {
    search.append(key, JSON.stringify(value));
    return;
  }
  search.append(key, String(value));
}

function buildPumpLaunchRequestOptions(basePayload, payload, timeoutMs) {
  const mode = CONFIG.pumpLaunchRequestMode || "json";
  const headers = {};
  if (CONFIG.pumpLaunchApiKey) headers.Authorization = `Bearer ${CONFIG.pumpLaunchApiKey}`;

  if (mode === "multipart") {
    if (typeof FormData === "undefined" || typeof Blob === "undefined") {
      throw new Error("This Node runtime does not support multipart launch uploads. Use Node 20+ or set PUMP_LAUNCH_REQUEST_MODE=json.");
    }

    const imageField = CONFIG.pumpLaunchImageField || "image";
    const textPayload = compactLaunchPayload({ ...payload });
    for (const key of ["image", "imageDataUrl", "file", "media", imageField]) {
      if (key && !/^none$/i.test(key)) delete textPayload[key];
    }

    const form = new FormData();
    for (const [key, value] of Object.entries(textPayload)) {
      appendPumpLaunchFormValue(form, key, value);
    }

    if (basePayload.imageDataUrl && !/^none$/i.test(imageField)) {
      const image = decodeLaunchImageDataUrl(basePayload.imageDataUrl, basePayload);
      if (image) {
        form.append(imageField, new Blob([image.buffer], { type: image.contentType }), image.filename);
      }
    }

    return {
      method: "POST",
      headers,
      body: form,
      timeoutMs
    };
  }

  if (mode === "form") {
    const search = new URLSearchParams();
    for (const [key, value] of Object.entries(compactLaunchPayload(payload))) {
      appendPumpLaunchSearchValue(search, key, value);
    }
    return {
      method: "POST",
      headers: {
        ...headers,
        "Content-Type": "application/x-www-form-urlencoded"
      },
      body: search.toString(),
      timeoutMs
    };
  }

  return {
    method: "POST",
    headers: {
      ...headers,
      "Content-Type": "application/json"
    },
    body: JSON.stringify(payload),
    timeoutMs
  };
}

function isPumpPortalLocalLaunch() {
  const format = String(CONFIG.pumpLaunchApiFormat || "").toLowerCase();
  const url = String(CONFIG.pumpLaunchApiUrl || "").toLowerCase();
  return ["pumpportal", "pumpportal-local", "trade-local"].includes(format) || url.includes("pumpportal.fun/api/trade-local");
}

async function launchImageBufferForUpload(basePayload = {}) {
  const decoded = decodeLaunchImageDataUrl(basePayload.imageDataUrl, basePayload);
  const source = decoded || await defaultLaunchImageInput(basePayload.symbol || basePayload.name || "SW");
  const processed = await processLaunchImage(source, {
    maxInputBytes: CONFIG.pumpLaunchBodyLimitBytes,
    outputSize: 1000
  });
  const diagnostics = safeLaunchImageDiagnostics(processed);
  logPumpLaunchEvent("pump_launch_image_processed", {
    launchAttemptId: basePayload.clientRequestId || "",
    originalFilename: diagnostics.originalFilename,
    reportedMime: diagnostics.reportedMime,
    detectedMime: diagnostics.detectedMime,
    originalBytes: diagnostics.originalBytes,
    originalWidth: diagnostics.originalWidth,
    originalHeight: diagnostics.originalHeight,
    outputMime: diagnostics.outputMime,
    outputBytes: diagnostics.outputBytes,
    outputWidth: diagnostics.outputWidth,
    outputHeight: diagnostics.outputHeight,
    warnings: diagnostics.warnings
  });
  return {
    ...processed,
    contentType: processed.contentType,
    imageProcessing: diagnostics
  };
}

// Optional pump.fun coin-page BANNER (separate from the square logo). Pump.fun wants
// 3:1 / 1500x500, images or animated GIFs up to 5MB, and it can ONLY be set at
// creation. We resize stills to 1500x500 (cover) and pass animated GIFs through
// untouched so they stay animated. Returns null when no banner was provided, and
// never throws — a bad banner must never block the actual coin launch.
async function launchBannerBufferForUpload(basePayload = {}) {
  const raw = String(basePayload.bannerDataUrl || "");
  if (!raw) return null;
  let decoded = null;
  try {
    decoded = decodeLaunchImageDataUrl(raw, { symbol: basePayload.symbol, name: basePayload.name, imageName: basePayload.bannerName });
  } catch { decoded = null; }
  if (!decoded || !decoded.buffer || !decoded.buffer.length) return null;
  const symbolSlug = String(basePayload.symbol || basePayload.name || "banner").toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "") || "banner";
  const MAX_BANNER_BYTES = 5 * 1024 * 1024;
  // Animated GIF banner: keep as-is so the animation survives (within pump.fun's 5MB cap).
  if (String(decoded.contentType || "").includes("gif") && decoded.buffer.length <= MAX_BANNER_BYTES) {
    return { buffer: decoded.buffer, contentType: "image/gif", filename: `${symbolSlug}-banner.gif` };
  }
  try {
    const buffer = await sharp(decoded.buffer, { animated: false, limitInputPixels: 268402689 })
      .rotate()
      .resize(1500, 500, { fit: "cover", position: "centre" })
      .flatten({ background: "#050805" })
      .jpeg({ quality: 86, mozjpeg: true })
      .toBuffer();
    return { buffer, contentType: "image/jpeg", filename: `${symbolSlug}-banner-1500x500.jpg` };
  } catch (error) {
    console.warn(`[pump-launch] banner process failed: ${error && error.message}`);
    return null;
  }
}

// Pin a processed banner to IPFS via pump.fun's own gateway and return the pinned
// image URI (the same `ipfs.io/ipfs/...` format pump.fun uses for banner_uri). Used
// so the banner is permanent + portable. Best-effort: returns "" on any failure.
async function pinBannerToPumpFunIpfs(banner) {
  if (!banner || !banner.buffer || !banner.buffer.length) return "";
  if (typeof FormData === "undefined" || typeof Blob === "undefined") return "";
  try {
    const form = new FormData();
    form.append("file", new Blob([banner.buffer], { type: banner.contentType || "image/jpeg" }), banner.filename || "banner.jpg");
    const response = await fetch(CONFIG.pumpLaunchPumpFunIpfsUrl, {
      method: "POST",
      body: form,
      signal: AbortSignal.timeout ? AbortSignal.timeout(CONFIG.pumpLaunchTimeoutMs || 30000) : undefined
    });
    if (!response.ok) return "";
    const data = JSON.parse(await response.text());
    return String(data?.metadata?.image || data?.imageUri || data?.image || "").trim();
  } catch (error) {
    console.warn(`[pump-launch] banner pin failed: ${error && error.message}`);
    return "";
  }
}

function hostedPumpMetadataBaseUrl() {
  const baseUrl = String(CONFIG.pumpLaunchHostedMetadataBaseUrl || "").trim().replace(/\/$/, "");
  if (!baseUrl) {
    throw createPumpLaunchError(
      "Hosted metadata fallback needs PUMP_LAUNCH_HOSTED_METADATA_BASE_URL or TELEGRAM_WEBHOOK_URL on Render.",
      "PUMP_METADATA_HOSTED_BASE_URL_MISSING",
      500,
      {
        stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD
      }
    );
  }
  return baseUrl;
}

function hostedPumpMetadataUrl(launchId, filename) {
  return `${hostedPumpMetadataBaseUrl()}/pump/metadata/${encodeURIComponent(launchId)}/${encodeURIComponent(filename)}`;
}

function hostedImageFilename(image = {}) {
  return `image.${launchImageExtension(image.contentType || "image/png")}`;
}

async function uploadHostedPumpLaunchMetadata(basePayload = {}) {
  const image = await launchImageBufferForUpload(basePayload);
  const launchId = crypto.randomUUID();
  const directory = path.join(pumpLaunchHostedMetadataRoot(), launchId);
  await fs.mkdir(directory, { recursive: true });

  const imageFilename = hostedImageFilename(image);
  const metadataFilename = "metadata.json";
  const imageUri = hostedPumpMetadataUrl(launchId, imageFilename);
  // Optional coin-page banner (3:1). We host the file ourselves and reference it in
  // the metadata JSON under "banner" — the field pump.fun reads for the coin banner.
  const banner = await launchBannerBufferForUpload(basePayload);
  let bannerUri = "";
  let bannerFilename = "";
  if (banner) {
    bannerFilename = `banner.${banner.contentType && banner.contentType.includes("gif") ? "gif" : "jpg"}`;
    bannerUri = hostedPumpMetadataUrl(launchId, bannerFilename);
  }
  const metadata = compactLaunchPayload({
    name: basePayload.name,
    symbol: basePayload.symbol,
    description: basePayload.description || "",
    image: imageUri,
    banner: bannerUri,
    twitter: basePayload.twitter || "",
    telegram: basePayload.telegram || "",
    website: basePayload.website || "",
    showName: true,
    createdOn: "https://pump.fun"
  });

  await fs.writeFile(path.join(directory, imageFilename), image.buffer);
  if (banner && bannerFilename) await fs.writeFile(path.join(directory, bannerFilename), banner.buffer);
  await fs.writeFile(path.join(directory, metadataFilename), JSON.stringify(metadata, null, 2));

  return {
    uri: hostedPumpMetadataUrl(launchId, metadataFilename),
    imageUri,
    bannerUri,
    imageBytes: image.buffer.length,
    imageContentType: image.contentType,
    imageProcessing: image.imageProcessing || safeLaunchImageDiagnostics(image),
    metadata,
    provider: "slimewire-hosted",
    cidOrId: launchId
  };
}

function cidFromIpfsUri(uri = "") {
  const text = String(uri || "").trim();
  const protocolMatch = /^ipfs:\/\/([^/?#]+)/i.exec(text);
  if (protocolMatch) return protocolMatch[1];
  const match = /\/ipfs\/([^/?#]+)/i.exec(text);
  return match ? match[1] : "";
}

async function uploadPumpFunIpfsLaunchMetadata(basePayload = {}) {
  if (typeof FormData === "undefined" || typeof Blob === "undefined") {
    throw createPumpLaunchError("This Node runtime does not support Pump.fun metadata uploads. Use Node 20+.", "PUMP_METADATA_RUNTIME_UNSUPPORTED", 500, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD
    });
  }
  const image = await launchImageBufferForUpload(basePayload);
  const form = new FormData();
  form.append("name", String(basePayload.name || "").trim());
  form.append("symbol", String(basePayload.symbol || "").trim().toUpperCase());
  form.append("description", String(basePayload.description || ""));
  form.append("twitter", String(basePayload.twitter || ""));
  form.append("telegram", String(basePayload.telegram || ""));
  form.append("website", String(basePayload.website || ""));
  form.append("showName", "true");
  form.append("createdOn", "https://pump.fun");
  form.append("file", new Blob([image.buffer], { type: image.contentType || "image/png" }), image.filename || "token-image.png");
  let response;
  let text = "";
  const delays = [0, 5_000, 15_000, 30_000];
  for (let attempt = 0; attempt < delays.length; attempt += 1) {
    if (delays[attempt] > 0) await sleep(delays[attempt]);
    try {
      response = await fetch(CONFIG.pumpLaunchPumpFunIpfsUrl, {
        method: "POST",
        body: form,
        signal: AbortSignal.timeout ? AbortSignal.timeout(CONFIG.pumpLaunchTimeoutMs || 30000) : undefined
      });
      text = await response.text();
    } catch (error) {
      if (attempt < delays.length - 1) continue;
      throw createPumpLaunchError(`Pump.fun metadata upload failed: ${friendlyError(error)}`, "PUMP_METADATA_PUMPFUN_UPLOAD_FAILED", 502, {
        stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD
      });
    }
    if (response.ok || response.status !== 429 || attempt === delays.length - 1) break;
  }

  let data = {};
  try {
    data = text ? JSON.parse(text) : {};
  } catch {
    data = {};
  }
  if (!response.ok) {
    throw createPumpLaunchError("Pump.fun metadata upload failed.", "PUMP_METADATA_PUMPFUN_UPLOAD_FAILED", 502, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD,
      providerStatus: response.status,
      providerResponseBody: sanitizeProviderBody(text)
    });
  }
  const uri = String(data.metadataUri || data.metadata_uri || data.uri || "").trim();
  const imageUri = String(data.metadata?.image || data.imageUri || data.image || "").trim();
  if (!uri) {
    throw createPumpLaunchError("Pump.fun metadata upload did not return a metadata URI.", "PUMP_METADATA_UPLOAD_NO_URI", 502, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD,
      providerResponseBody: sanitizeProviderBody(text)
    });
  }
  // Optional coin banner: pump.fun's metadata endpoint ignores a banner field (only
  // its authenticated website writes the DB banner_uri), so we pin the banner to IPFS
  // ourselves and hand the URI back. SlimeWire renders it on our surfaces, and it's
  // ready for any indexer that reads a metadata banner. Best-effort, never blocks.
  const banner = await launchBannerBufferForUpload(basePayload);
  const bannerUri = banner ? await pinBannerToPumpFunIpfs(banner) : "";
  return {
    uri,
    imageUri,
    bannerUri,
    imageBytes: image.buffer.length,
    imageContentType: image.contentType,
    imageProcessing: image.imageProcessing || safeLaunchImageDiagnostics(image),
    provider: "pumpfun-ipfs",
    cidOrId: cidFromIpfsUri(uri)
  };
}

async function uploadPinataPumpLaunchMetadata(basePayload = {}) {
  const pinataConfig = assertPinataConfigured({
    tokenValue: CONFIG.pumpLaunchPinataJwt,
    metadataUrl: CONFIG.pumpLaunchMetadataUrl
  });
  try {
    await assertPinataAuthWorks({
      tokenValue: CONFIG.pumpLaunchPinataJwt,
      timeoutMs: Math.min(CONFIG.pumpLaunchTimeoutMs || 30000, 15000)
    });
  } catch (error) {
    throw pinataProviderError(error, "Pinata auth preflight failed.");
  }

  const image = await launchImageBufferForUpload(basePayload);
  const imageUpload = await uploadImage({
    image,
    tokenValue: CONFIG.pumpLaunchPinataJwt,
    metadataUrl: pinataConfig.metadataUrl,
    timeoutMs: CONFIG.pumpLaunchTimeoutMs
  });
  const imageUri = imageUpload.imageUri;
  const metadata = compactLaunchPayload({
    name: basePayload.name,
    symbol: basePayload.symbol,
    description: basePayload.description || "",
    image: imageUri,
    twitter: basePayload.twitter || "",
    telegram: basePayload.telegram || "",
    website: basePayload.website || "",
    showName: true,
    createdOn: "https://pump.fun"
  });
  const metadataUpload = await uploadJsonMetadata({
    metadata,
    filename: `${cleanTickerSymbol(basePayload.symbol || "token").toLowerCase() || "token"}-metadata.json`,
    tokenValue: CONFIG.pumpLaunchPinataJwt,
    metadataUrl: pinataConfig.metadataUrl,
    timeoutMs: CONFIG.pumpLaunchTimeoutMs
  });
  const uri = metadataUpload.uri;
  if (!uri) {
    throw new Error("Pinata metadata upload did not return a metadata URI.");
  }
  return {
    uri,
    imageUri,
    imageBytes: image.buffer.length,
    imageContentType: image.contentType,
    imageProcessing: image.imageProcessing || safeLaunchImageDiagnostics(image),
    metadata,
    provider: "pinata",
    cidOrId: metadataUpload.cid
  };
}

function shouldFallbackToPumpFunIpfsMetadata(error) {
  const code = String(error?.code || "");
  return CONFIG.pumpLaunchMetadataProvider === "auto" && code.startsWith("PUMP_METADATA_");
}

async function uploadPumpLaunchMetadata(basePayload = {}) {
  const provider = CONFIG.pumpLaunchMetadataProvider;
  if (provider === "slimewire-hosted") {
    return uploadHostedPumpLaunchMetadata(basePayload);
  }
  if (provider === "pumpfun-ipfs") {
    return uploadPumpFunIpfsLaunchMetadata(basePayload);
  }

  // Explicit Pinata: keep Pinata primary, fall back to Pump.fun IPFS on provider error.
  if (provider === "pinata") {
    try {
      return await uploadPinataPumpLaunchMetadata(basePayload);
    } catch (error) {
      if (!shouldFallbackToPumpFunIpfsMetadata(error)) throw error;
      logPumpLaunchEvent("pump_launch_metadata_pinata_fallback", {
        provider: "pinata",
        fallbackProvider: "pumpfun-ipfs",
        errorCode: error.code || "PUMP_METADATA_FAILED",
        providerStatus: error.providerStatus || error.status || error.statusCode || null,
        reason: sanitizeProviderBody(error.message)
      });
      return uploadPumpFunIpfsLaunchMetadata(basePayload);
    }
  }

  // "auto": upload through Pump.fun's own IPFS first so the coin's image hosts on
  // Pump.fun's infrastructure and reliably renders on pump.fun (a Pinata-hosted image
  // URL frequently does not show in the Pump.fun UI). Fall back to Pinata only if
  // Pump.fun's uploader fails and a Pinata JWT is configured, so launches still work.
  try {
    return await uploadPumpFunIpfsLaunchMetadata(basePayload);
  } catch (error) {
    if (!CONFIG.pumpLaunchPinataJwt) throw error;
    logPumpLaunchEvent("pump_launch_metadata_pumpfun_fallback", {
      provider: "pumpfun-ipfs",
      fallbackProvider: "pinata",
      errorCode: error.code || "PUMP_METADATA_FAILED",
      providerStatus: error.providerStatus || error.status || error.statusCode || null,
      reason: sanitizeProviderBody(error.message)
    });
    return uploadPinataPumpLaunchMetadata(basePayload);
  }
}

function metadataUriGatewayCandidates(uri) {
  const clean = String(uri || "").trim();
  const cid = cidFromIpfsUri(clean);
  if (!cid) return [clean].filter(Boolean);
  return [...new Set([
    /^ipfs:\/\//i.test(clean) ? "" : clean,
    `https://gateway.pinata.cloud/ipfs/${cid}`,
    `https://ipfs.io/ipfs/${cid}`,
    `https://cloudflare-ipfs.com/ipfs/${cid}`
  ].filter(Boolean))];
}

function imageUriGatewayCandidates(uri) {
  const clean = String(uri || "").trim();
  const cid = cidFromIpfsUri(clean);
  if (!cid) return [clean].filter(Boolean);
  return [...new Set([
    /^ipfs:\/\//i.test(clean) ? "" : clean,
    `https://gateway.pinata.cloud/ipfs/${cid}`,
    `https://ipfs.io/ipfs/${cid}`,
    `https://cloudflare-ipfs.com/ipfs/${cid}`
  ].filter(Boolean))];
}

function isAbortOrTimeoutError(error) {
  return error?.name === "AbortError" || /abort|timeout|timed out/i.test(String(error?.message || error || ""));
}

async function fetchTextWithBackoff(url, { timeoutMs = 20_000, retries = 2 } = {}) {
  const attempts = [];
  let lastError = null;
  for (let attempt = 0; attempt <= retries; attempt += 1) {
    if (attempt > 0) await sleep(Math.min(6_000, 1_500 * attempt));
    try {
      const response = await fetch(url, {
        method: "GET",
        headers: { "Accept": "application/json,text/plain,*/*" },
        signal: AbortSignal.timeout ? AbortSignal.timeout(timeoutMs) : undefined
      });
      const text = await response.text();
      attempts.push({
        attempt: attempt + 1,
        status: response.status,
        contentType: response.headers.get("content-type") || "",
        ok: response.ok
      });
      if (response.ok) {
        return {
          url,
          response,
          text,
          attempts
        };
      }
      lastError = createPumpLaunchError(`HTTP ${response.status}`, "PUMPPORTAL_CREATE_METADATA_URI_UNFETCHABLE", 400, {
        providerStatus: response.status,
        providerResponseBody: sanitizeProviderBody(text)
      });
    } catch (error) {
      attempts.push({
        attempt: attempt + 1,
        status: "fetch_error",
        contentType: "",
        ok: false,
        error: friendlyError(error)
      });
      lastError = error;
    }
  }
  const timedOut = attempts.some((attempt) => /abort|timeout|timed out/i.test(String(attempt.error || ""))) || isAbortOrTimeoutError(lastError);
  throw createPumpLaunchError(
    timedOut
      ? "Token metadata URI is not publicly fetchable: The operation was aborted due to timeout"
      : `Token metadata URI is not publicly fetchable: ${friendlyError(lastError)}`,
    timedOut ? "PUMPPORTAL_CREATE_METADATA_URI_TIMEOUT" : "PUMPPORTAL_CREATE_METADATA_URI_UNFETCHABLE",
    400,
    {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD,
      metadataUri: url,
      metadataFetchAttempts: attempts,
      providerStatus: lastError?.providerStatus || lastError?.status || lastError?.statusCode || null,
      providerResponseBody: sanitizeProviderBody(lastError?.providerResponseBody || lastError?.responseBody || "")
    }
  );
}

async function fetchPublicImageWithBackoff(url, { timeoutMs = 20_000, retries = 2 } = {}) {
  const attempts = [];
  let lastError = null;
  for (let attempt = 0; attempt <= retries; attempt += 1) {
    if (attempt > 0) await sleep(Math.min(6_000, 1_500 * attempt));
    try {
      const response = await fetch(url, {
        method: "GET",
        headers: { "Accept": "image/*,*/*" },
        signal: AbortSignal.timeout ? AbortSignal.timeout(timeoutMs) : undefined
      });
      attempts.push({
        attempt: attempt + 1,
        status: response.status,
        contentType: response.headers.get("content-type") || "",
        ok: response.ok
      });
      if (response.ok) {
        await response.arrayBuffer().catch(() => null);
        return {
          url,
          status: response.status,
          contentType: response.headers.get("content-type") || "",
          attempts
        };
      }
      lastError = new Error(`HTTP ${response.status}`);
      lastError.status = response.status;
    } catch (error) {
      attempts.push({
        attempt: attempt + 1,
        status: "fetch_error",
        contentType: "",
        ok: false,
        error: friendlyError(error)
      });
      lastError = error;
    }
  }
  const timedOut = attempts.some((attempt) => /abort|timeout|timed out/i.test(String(attempt.error || ""))) || isAbortOrTimeoutError(lastError);
  throw createPumpLaunchError(
    timedOut
      ? "Token metadata image is not publicly fetchable fast enough for PumpPortal."
      : `Token metadata image is not publicly fetchable: ${friendlyError(lastError)}`,
    timedOut ? "PUMP_METADATA_IMAGE_FETCH_TIMEOUT" : "PUMP_METADATA_IMAGE_UNFETCHABLE",
    400,
    {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD,
      imageUri: url,
      imageFetchAttempts: attempts
    }
  );
}

async function validatePumpPortalMetadataUri(metadataUri) {
  let uri = String(metadataUri || "").trim();
  if (!uri) {
    throw createPumpLaunchError("Token metadata URI is missing before PumpPortal create.", "PUMPPORTAL_CREATE_METADATA_URI_INVALID", 400, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD
    });
  }
  let parsed;
  try {
    parsed = new URL(uri);
  } catch {
    throw createPumpLaunchError("Token metadata URI must be a public http(s) URL before PumpPortal create.", "PUMPPORTAL_CREATE_METADATA_URI_INVALID", 400, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD
    });
  }
  if (parsed.protocol === "ipfs:") {
    const cid = cidFromIpfsUri(uri);
    uri = cid ? `https://gateway.pinata.cloud/ipfs/${cid}` : uri;
    parsed = new URL(uri);
  }
  if (!["http:", "https:"].includes(parsed.protocol)) {
    throw createPumpLaunchError("Token metadata URI must be a public http(s) URL before PumpPortal create.", "PUMPPORTAL_CREATE_METADATA_URI_INVALID", 400, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD
    });
  }
  if (/\.(?:png|jpe?g|gif|webp|svg)(?:$|[?#])/i.test(parsed.pathname)) {
    throw createPumpLaunchError("Token metadata URI points to an image, not metadata JSON.", "PUMPPORTAL_CREATE_METADATA_URI_IMAGE", 400, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD
    });
  }

  let fetched = null;
  let lastError = null;
  for (const candidate of metadataUriGatewayCandidates(uri)) {
    try {
      fetched = await fetchTextWithBackoff(candidate, {
        timeoutMs: Math.max(15_000, Math.min(CONFIG.pumpLaunchTimeoutMs || 30_000, 30_000)),
        retries: 2
      });
      break;
    } catch (error) {
      lastError = error;
    }
  }
  if (!fetched) throw lastError;

  const response = fetched.response;
  const text = fetched.text;
  const contentType = response.headers.get("content-type") || "";
  if (/^image\//i.test(contentType)) {
    throw createPumpLaunchError("Token metadata URI returned an image content type, not metadata JSON.", "PUMPPORTAL_CREATE_METADATA_URI_IMAGE", 400, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD,
      metadataUri: fetched.url,
      providerResponseBody: sanitizeProviderBody(text.slice(0, 120))
    });
  }
  let metadata;
  try {
    metadata = JSON.parse(text);
    if (!metadata || typeof metadata !== "object" || Array.isArray(metadata)) {
      throw new Error("metadata is not an object");
    }
    if (!metadata.name || !metadata.symbol || !metadata.image) {
      throw new Error("metadata is missing name, symbol, or image");
    }
  } catch (error) {
    throw createPumpLaunchError(`Token metadata URI must return metadata JSON: ${friendlyError(error)}`, "PUMPPORTAL_CREATE_METADATA_JSON_INVALID", 400, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD,
      providerResponseBody: sanitizeProviderBody(text)
    });
  }

  let imageValidation = null;
  let imageUri = String(metadata.image || "").trim();
  if (/^ipfs:\/\//i.test(imageUri)) {
    const imageCid = cidFromIpfsUri(imageUri);
    imageUri = imageCid ? `https://gateway.pinata.cloud/ipfs/${imageCid}` : imageUri;
  }
  if (!/^https?:\/\//i.test(imageUri)) {
    throw createPumpLaunchError("Token metadata image must be a public http(s) URL.", "PUMP_METADATA_IMAGE_UNFETCHABLE", 400, {
      stage: PUMP_LAUNCH_STAGE.METADATA_UPLOAD,
      metadataUri: fetched.url,
      providerResponseBody: sanitizeProviderBody(text)
    });
  }
  let imageError = null;
  for (const candidate of imageUriGatewayCandidates(imageUri)) {
    try {
      imageValidation = await fetchPublicImageWithBackoff(candidate, {
        timeoutMs: Math.max(15_000, Math.min(CONFIG.pumpLaunchTimeoutMs || 30_000, 30_000)),
        retries: 2
      });
      break;
    } catch (error) {
      imageError = error;
    }
  }
  if (!imageValidation) throw imageError;
  return {
    ok: true,
    uri: fetched.url,
    status: response.status,
    contentType,
    bodySnippet: sanitizeProviderBody(text),
    metadataFetchAttempts: fetched.attempts,
    imageUri: imageValidation.url,
    imageFetchStatus: imageValidation.status,
    imageContentType: imageValidation.contentType,
    imageFetchAttempts: imageValidation.attempts
  };
}

function decodePumpPortalTransaction(value) {
  if (!value) return null;
  if (value instanceof Uint8Array || Buffer.isBuffer(value)) {
    return VersionedTransaction.deserialize(new Uint8Array(value));
  }
  if (Array.isArray(value) && value.every((item) => Number.isInteger(item) && item >= 0 && item <= 255)) {
    return VersionedTransaction.deserialize(Uint8Array.from(value));
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      const tx = decodePumpPortalTransaction(item);
      if (tx) return tx;
    }
    return null;
  }
  if (typeof value === "object") {
    return decodePumpPortalTransaction(firstPumpPortalTransactionValue(value));
  }
  const encoded = String(value || "").trim();
  if (!encoded) return null;

  const decoders = [
    () => Buffer.from(encoded, "base64"),
    () => Buffer.from(bs58.decode(encoded))
  ];
  for (const decode of decoders) {
    try {
      return VersionedTransaction.deserialize(new Uint8Array(decode()));
    } catch {
      // Try the next encoding.
    }
  }
  return null;
}

function firstPumpPortalTransactionValue(value = {}) {
  if (!value || typeof value !== "object") return value;
  for (const candidate of [
    value.transaction,
    value.tx,
    value.serializedTransaction,
    value.signedTransaction,
    value.rawTransaction,
    value.data,
    value.result?.transaction,
    value.result?.tx,
    value.result?.serializedTransaction,
    value.result?.data
  ]) {
    if (candidate) return candidate;
  }
  return null;
}

function pumpLaunchAttemptIdFrom(body = {}, error = {}) {
  return firstString(
    error.launchAttemptId,
    error.requestId,
    body.launchAttemptId,
    body.clientRequestId
  );
}

function pumpLaunchWebErrorPayload(error, body = {}) {
  const launchAttemptId = pumpLaunchAttemptIdFrom(body, error);
  if (launchAttemptId && !error.launchAttemptId) error.launchAttemptId = launchAttemptId;
  const safeMessage = formatPumpLaunchUserError(error);
  const errorCode = error.code || error.errorCode || "PUMP_LAUNCH_FAILED";
  const stage = error.stage || error.cause?.stage || "";
  const providerStatus = error.providerStatus || error.status || error.statusCode || null;
  const providerBodySnippet = sanitizeProviderBody(error.providerResponseBody || error.responseBody || "");
  return {
    ok: false,
    error: errorCode,
    errorCode,
    message: safeMessage,
    launchAttemptId,
    stage,
    providerStatus,
    providerBodySnippet,
    launch: {
      launchAttemptId,
      status: PUMP_LAUNCH_STATUS.FAILED,
      stage,
      errorCode,
      failureReason: safeMessage,
      providerStatus,
      providerBodySnippet,
      txSignature: error.txSignature || ""
    }
  };
}

async function recordPumpLaunchEarlyFailure({
  launchAttemptId,
  userId,
  body = {},
  name = "",
  symbol = "",
  selectedDevWalletId = "",
  error
}) {
  const id = String(launchAttemptId || body.launchAttemptId || body.clientRequestId || "").trim();
  if (!id || !error) return;
  if (!error.launchAttemptId) error.launchAttemptId = id;
  const safeMessage = formatPumpLaunchUserError(error);
  const attempt = {
    id,
    launchAttemptId: id,
    userId,
    selectedDevWalletId: selectedDevWalletId || firstString(body.selectedDevWalletId, body.devWalletIndex, body.devWalletPublicKey),
    tokenName: name || cleanLaunchText(body.name, 64),
    symbol: symbol || cleanTickerSymbol(body.symbol || body.ticker || ""),
    status: PUMP_LAUNCH_STATUS.FAILED,
    stage: error.stage || PUMP_LAUNCH_STAGE.CONFIG,
    errorCode: error.code || "PUMP_LAUNCH_FAILED",
    errorMessage: friendlyError(error),
    failureReason: safeMessage,
    providerStatus: error.providerStatus || error.status || error.statusCode || null,
    providerResponseBody: sanitizeProviderBody(error.providerResponseBody || error.responseBody || ""),
    failedAt: new Date().toISOString()
  };
  await upsertPumpLaunchAttempt(attempt);
  logPumpLaunchEvent("pump_launch_failed", attempt);
}

async function requestPumpPortalLocalTransaction(requestPayload, timeoutMs, options = {}) {
  const url = options.url || CONFIG.pumpLaunchApiUrl || "https://pumpportal.fun/api/trade-local";
  const requestMeta = {
    ...pumpPortalRequestMeta(requestPayload),
    endpoint: url
  };
  const response = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(requestPayload),
    signal: AbortSignal.timeout ? AbortSignal.timeout(timeoutMs) : undefined
  });
  const responseContentType = response.headers.get("content-type") || "";

  if (!response.ok) {
    const text = (await response.text()).trim();
    const statusText = String(response.statusText || "").trim();
    let detail = statusText || `HTTP ${response.status}`;
    try {
      detail = fetchJsonErrorMessage(JSON.parse(text), text, response.status);
    } catch {
      if (/^<!doctype html|<html[\s>]/i.test(text)) {
        detail = `HTTP ${response.status}: PumpPortal returned an HTML page instead of a transaction. Check PUMP_LAUNCH_API_URL and provider access.`;
      } else if (text) {
        const compactText = text.replace(/\s+/g, " ").slice(0, 500);
        detail = statusText && statusText !== compactText
          ? `${compactText}: ${statusText}`.slice(0, 500)
          : compactText;
      }
    }
    const error = new Error(detail);
    error.status = response.status;
    error.responseBody = statusText && !text.includes(statusText)
      ? `statusText=${statusText}\nbody=${text}`.slice(0, 1000)
      : text.slice(0, 1000);
    error.providerStatusText = statusText;
    error.responseContentType = responseContentType;
    error.requestMeta = requestMeta;
    throw error;
  }

  const raw = Buffer.from(await response.arrayBuffer());
  const text = raw.toString("utf8").trim();

  if (text.startsWith("{") || text.startsWith("[")) {
    const parsed = JSON.parse(text);
    const tx = decodePumpPortalTransaction(parsed);
    if (tx) return tx;
    const signature = Array.isArray(parsed)
      ? firstString(...parsed.map((item) => item?.signature || item?.txid))
      : firstString(parsed.signature, parsed.txid, parsed.result?.signature, parsed.result?.txid);
    if (signature) return { signature };
    throw new Error(`PumpPortal JSON response did not include a readable transaction. Response: ${providerErrorValue(parsed) || text.replace(/\s+/g, " ").slice(0, 500)}`);
  }

  const tx = decodePumpPortalTransaction(raw);
  if (!tx) {
    throw new Error("PumpPortal did not return a readable create transaction.");
  }
  return tx;
}

async function sendVersionedTransaction(tx, label = "send versioned transaction") {
  const raw = tx.serialize(); // already signed by the caller; reuse the same bytes everywhere
  try {
    const signature = await rpcWithRetry(label, () => connection.sendRawTransaction(raw, { skipPreflight: false, maxRetries: 10 }));
    await rpcWithRetry("confirm versioned transaction", () => connection.confirmTransaction(signature, "confirmed"));
    return signature;
  } catch (error) {
    if (!backupConnection || !isTransientSendError(error)) throw error;
    console.warn(`${label}: primary RPC failed (${friendlyError(error)}); re-broadcasting same signed tx to backup RPC.`);
    rpcStats.sendFailoverCount = (rpcStats.sendFailoverCount || 0) + 1;
    const signature = await rpcWithRetry(`${label} (backup)`, () => backupConnection.sendRawTransaction(raw, { skipPreflight: false, maxRetries: 10 }));
    await rpcWithRetry("confirm versioned transaction (backup)", () => backupConnection.confirmTransaction(signature, "confirmed"));
    return signature;
  }
}

// --- Jito atomic anti-snipe launch bundle (flag-gated; OFF by default) --------
// Builds [create, dev buy, first wallet buys] via PumpPortal's multi-transaction
// endpoint, signs each with the correct keypair, and submits them as ONE atomic Jito
// bundle so they all land in the same block — nothing can snipe between the launch and
// the first buys. A Jito bundle is all-or-none: if it does not land, nothing executes
// and no SOL is spent, so a failed bundle is safe to retry. Capped at Jito's 5-tx limit.
async function requestPumpPortalBundleTxs(actions, timeoutMs) {
  const url = CONFIG.pumpLaunchApiUrl || "https://pumpportal.fun/api/trade-local";
  const response = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(actions),
    signal: AbortSignal.timeout ? AbortSignal.timeout(timeoutMs) : undefined
  });
  if (!response.ok) {
    const text = (await response.text()).replace(/\s+/g, " ").slice(0, 600);
    const error = new Error(`PumpPortal bundle build failed: HTTP ${response.status} ${text}`);
    error.status = response.status;
    throw error;
  }
  const data = await response.json();
  const list = Array.isArray(data) ? data : (Array.isArray(data?.transactions) ? data.transactions : []);
  if (list.length !== actions.length) {
    throw new Error(`PumpPortal returned ${list.length} transaction(s) for ${actions.length} bundle action(s).`);
  }
  return list.map((item) => {
    const value = typeof item === "string" ? item : (item?.transaction || item?.tx || "");
    if (!value) throw new Error("PumpPortal bundle item contained no transaction.");
    try { return bs58.decode(value); } catch { return new Uint8Array(Buffer.from(value, "base64")); }
  });
}

// All Jito regional block engines: the global endpoint rate-limits under load
// (seen live), so the same bundle goes to every region at once - any single
// acceptance is enough, and regional engines often answer when global won't.
const JITO_BLOCK_ENGINES = [
  "https://mainnet.block-engine.jito.wtf/api/v1/bundles",
  "https://ny.mainnet.block-engine.jito.wtf/api/v1/bundles",
  "https://amsterdam.mainnet.block-engine.jito.wtf/api/v1/bundles",
  "https://frankfurt.mainnet.block-engine.jito.wtf/api/v1/bundles",
  "https://tokyo.mainnet.block-engine.jito.wtf/api/v1/bundles",
  "https://slc.mainnet.block-engine.jito.wtf/api/v1/bundles"
];

async function submitJitoBundle(base64Txs, timeoutMs) {
  const endpoints = [...new Set([CONFIG.pumpLaunchJitoUrl, ...JITO_BLOCK_ENGINES])];
  const sendTo = async (endpoint) => {
    const response = await fetch(endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ jsonrpc: "2.0", id: 1, method: "sendBundle", params: [base64Txs, { encoding: "base64" }] }),
      signal: AbortSignal.timeout ? AbortSignal.timeout(timeoutMs) : undefined
    });
    const text = await response.text();
    let data = {};
    try { data = JSON.parse(text); } catch { /* non-JSON */ }
    if (!response.ok || data.error) {
      throw new Error(`${endpoint.split("//")[1].split(".")[0]}: HTTP ${response.status} ${(data.error ? JSON.stringify(data.error) : text).slice(0, 200)}`);
    }
    return String(data.result || "");
  };
  try {
    return await Promise.any(endpoints.map(sendTo));
  } catch (aggregate) {
    const reasons = (aggregate.errors || []).map((error) => error.message).join(" | ").slice(0, 500);
    throw new Error(`Jito sendBundle failed on every block engine: ${reasons}`);
  }
}

// Canonical Jito mainnet tip accounts (public list; pick one at random per bundle to avoid contention).
const JITO_TIP_ACCOUNTS = [
  "96gYZGLnJYVFmbjzopPSU6QiEV5fGqZNyN9nmNhvrZU5",
  "HFqU5x63VTqvQss8hp11i4wVV8bD44PvwucfZ2bU7gRe",
  "Cw8CFyM9FkoMi7K7Crf6HNQqf4uEMzpKw6QNghXLvLkY",
  "ADaUMid9yfUytqMBgopwjb2DTLSokTSzL1zt6iGPaS49",
  "DfXygSm4jCyNCybVYYK6DwvWqjKee8pbDmJGcLWNDXjh",
  "ADuUkR4vqLUMWXxW9gh6D6L8pMSawimctcNZ5pGwDcEt",
  "DttWaMuVvTiduZRnguLF7jNxTgiMBZ1hyAumKUiL2KRL",
  "3AVi9Tg9Uo68tJfuvoKvqKNWKkC5wPdSSdeBnizKZ6jT"
];

// JITO TRADE SEND — route a SIGNED pump trade tx through a Jito bundle (swap tx + a tiny tip tx) for
// FAST, sandwich-proof landing; fall back to the normal RPC send on ANY Jito failure or timeout.
// SAFE BY CONSTRUCTION: (1) the swap tx already has its single fee-payer signature, so it can execute
// AT MOST ONCE — a fallback re-broadcast of the same bytes can never double-trade; (2) the bundle is
// atomic, so the separate tip tx only pays if the swap lands; (3) tips are kept LOW + per-type.
// Behaviour is IDENTICAL to before when CONFIG.tradeJitoBundle is false (the default), so shipping
// this changes nothing live until the env flag is flipped + verified on a real send.
let lastJitoBundleSubmitMs = 0;
const JITO_MIN_SUBMIT_GAP_MS = 1200; // free public tier ~1 req/sec/engine per IP; stay under it to dodge the escalating ban
async function sendPumpTradeTx(tx, keypair, label, opts = {}) {
  if (!CONFIG.tradeJitoBundle) return sendVersionedTransaction(tx, label);
  // Jito's free block engines rate-limit to ~1 bundle/sec per engine per IP, and hammering them earns an
  // escalating back-off (observed live: "Retry after 120000ms"). The autopilot fires sells in bursts, so if
  // a bundle went out <1.2s ago, skip Jito for THIS tx and take the safe, instant RPC path — never stall a sell.
  const nowMs = Date.now();
  if (nowMs - lastJitoBundleSubmitMs < JITO_MIN_SUBMIT_GAP_MS) return sendVersionedTransaction(tx, label);
  lastJitoBundleSubmitMs = nowMs;
  const tipSol = Math.max(0.00001, Number(opts.tipSol) || CONFIG.tradeJitoTipSol || 0.0001);
  try {
    const swapSig = bs58.encode(Buffer.from(tx.signatures[0]));
    const tipLamports = Math.max(1000, Math.round(tipSol * 1e9));
    const tipAccount = new PublicKey(JITO_TIP_ACCOUNTS[Math.floor(Math.random() * JITO_TIP_ACCOUNTS.length)]);
    const { blockhash } = await rpcWithRetry("jito tip blockhash", () => connection.getLatestBlockhash("confirmed"));
    const tipTx = new Transaction().add(SystemProgram.transfer({ fromPubkey: keypair.publicKey, toPubkey: tipAccount, lamports: tipLamports }));
    tipTx.recentBlockhash = blockhash;
    tipTx.feePayer = keypair.publicKey;
    tipTx.sign(keypair);
    const bundle = [Buffer.from(tx.serialize()).toString("base64"), tipTx.serialize().toString("base64")];
    const bundleId = await submitJitoBundle(bundle, 8_000);
    console.log(`[jito] ${label} — bundle ${String(bundleId).slice(0, 10)} sent (tip ${tipSol} SOL); waiting to land`);
    const deadline = Date.now() + (Number(CONFIG.tradeJitoConfirmMs) || 12_000);
    while (Date.now() < deadline) {
      try {
        const st = await connection.getSignatureStatus(swapSig);
        const v = st && st.value;
        if (v && (v.confirmationStatus === "confirmed" || v.confirmationStatus === "finalized")) {
          console.log(`[jito] ${label} — LANDED via bundle (${swapSig.slice(0, 8)}…)`);
          return swapSig;
        }
        if (v && v.err) break;   // tx errored on-chain — let the normal path surface it
      } catch { /* status check hiccup — keep waiting */ }
      await sleep(900);
    }
    console.warn(`[jito] ${label} — bundle didn't confirm in time; re-broadcasting the SAME signed tx via RPC (safe: one signature)`);
  } catch (e) {
    console.warn(`[jito] ${label} — bundle error (${e && e.message}); falling back to RPC send`);
  }
  return sendVersionedTransaction(tx, label);
}

// After a fallback (non-atomic) launch the first buys MUST still be instant AND
// managed: they run through webCreateManagedBuyPlan - the same engine behind the
// Buy buttons - so the buys execute in PARALLEL and the launch sheet's TP/SL/
// timer arm in the same call. If the plan path can't run (e.g. automation
// permission missing) it degrades to raw PumpPortal buys so SOL still deploys.
async function firePostLaunchBuysServerSide({ mint, body, devWallet, devKeypair, devBuySol, bundleWallets, bundleAmountSol, slippagePct, launchAttemptId, userId }) {
  const outcome = { dev: false, wallets: 0, planned: false };
  const exitFields = {
    tokenMint: mint,
    takeProfitPct: body.takeProfitPct,
    stopLossPct: body.stopLossPct,
    sellDelay: body.sellDelay,
    sellPercent: body.sellPercent || "100",
    slippageBps: Math.max(Number(body.slippageBps) || 300, 1_000),
    loopCount: "1",
    loopDelay: "0"
  };
  const rawBuy = async (keypair, amountSol, label) => {
    const action = {
      publicKey: keypair.publicKey.toBase58(), action: "buy", mint,
      denominatedInSol: "true", amount: amountSol, slippage: slippagePct,
      priorityFee: Math.max(CONFIG.pumpLaunchPriorityFeeSol || 0.00005, 0.00005), pool: "pump"
    };
    const [bytes] = await requestPumpPortalBundleTxs([action], CONFIG.pumpLaunchTimeoutMs || 30000);
    const tx = VersionedTransaction.deserialize(bytes);
    tx.sign([keypair]);
    const signature = await sendVersionedTransaction(tx, `post-launch ${label} buy`);
    invalidateWalletReadCache(keypair.publicKey.toBase58());
    logPumpLaunchEvent("pump_launch_fallback_buy", { launchAttemptId, userId, mint, label, amountSol, txSignature: signature, managed: false });
  };
  const planBuy = async (wallets, amountSol, label) => {
    await webCreateManagedBuyPlan(userId, wallets, { ...exitFields, amountSol: String(amountSol) }, {
      source: "pump_launch_first_buys",
      label,
      auditType: "web_pump_launch_first_buys",
      defaultSellDelay: "off",
      defaultTakeProfitPct: "40",
      defaultStopLossPct: "8",
      defaultSlippageBps: 1_000,
      trustedLaunchMint: true
    });
    logPumpLaunchEvent("pump_launch_fallback_buy", { launchAttemptId, userId, mint, label, amountSol, walletCount: wallets.length, managed: true });
  };
  const devTask = async () => {
    if (!(devBuySol > 0 && devWallet)) return;
    try {
      await planBuy([devWallet], devBuySol, "Launch dev buy");
      outcome.dev = true;
      outcome.planned = true;
    } catch (error) {
      logPumpLaunchEvent("pump_launch_fallback_plan_failed", { launchAttemptId, userId, mint, label: "dev", errorMessage: String(error.message || "").slice(0, 200) });
      try {
        await rawBuy(devKeypair, devBuySol, "dev");
        outcome.dev = true;
      } catch (rawError) {
        logPumpLaunchEvent("pump_launch_fallback_buy_failed", { launchAttemptId, userId, mint, label: "dev", errorMessage: String(rawError.message || "").slice(0, 200) });
      }
    }
  };
  const bundleTask = async () => {
    if (!(bundleWallets.length && bundleAmountSol > 0)) return;
    try {
      await planBuy(bundleWallets, bundleAmountSol, "Launch bundle buys");
      outcome.wallets = bundleWallets.length;
      outcome.planned = true;
    } catch (error) {
      logPumpLaunchEvent("pump_launch_fallback_plan_failed", { launchAttemptId, userId, mint, label: "bundle", errorMessage: String(error.message || "").slice(0, 200) });
      await Promise.all(bundleWallets.map(async (wallet) => {
        try {
          await rawBuy(decryptWallet(wallet), bundleAmountSol, shortMint(wallet.publicKey));
          outcome.wallets += 1;
        } catch (rawError) {
          logPumpLaunchEvent("pump_launch_fallback_buy_failed", { launchAttemptId, userId, mint, label: shortMint(wallet.publicKey), errorMessage: String(rawError.message || "").slice(0, 200) });
        }
      }));
    }
  };
  // Dev buy + every bundle wallet fire AT THE SAME TIME the create lands - the
  // dev buy used to finish (21s) before bundle buys even started, so bundle
  // wallets landed 40s late and looked like they never bought.
  await Promise.all([devTask(), bundleTask()]);
  // SOL just moved in every one of these wallets - kill all cached reads so the
  // very next refresh shows true balances ("0.1 off for a long time" was stale
  // cache, not lost SOL).
  try {
    invalidateWalletReadCache(devKeypair.publicKey.toBase58());
    for (const wallet of bundleWallets) invalidateWalletReadCache(wallet.publicKey);
    positionValueCache.clear();
  } catch {
    // cache hygiene only
  }
  return outcome;
}

async function webLaunchPumpJitoBundle(userId, body, basePayload) {
  const store = await readWalletStore();
  const selectedDevWalletId = firstString(
    basePayload.devBuy.walletIndex, body.selectedDevWalletId, body.devWalletPublicKey,
    Array.isArray(body.walletIndexes) ? body.walletIndexes[0] : ""
  );
  const devSelection = selectPumpLaunchWallet(store, userId, selectedDevWalletId);
  const devKeypair = decryptWallet(devSelection.wallet);
  const devBuySol = Math.max(0, Number(basePayload.devBuy.amountSol) || 0);
  // In-bundle buys execute atomically with the create - nothing can front-run
  // between them - so high slippage is FREE safety here. Each buy moves the curve
  // for the next one; tight user slippage (3%) made later buys fail simulation,
  // which silently kills the whole all-or-none bundle no matter the tip.
  const slippageBps = Math.max(Number(basePayload.slippageBps) || 300, 2_000);
  // PumpPortal's API takes `slippage` as a PERCENT - it silently ignores an
  // unknown `slippageBps` field, which built every bundle buy with zero
  // tolerance and made the all-or-none bundle unincludable at any tip.
  const slippagePct = Math.min(99, slippageBps / 100);

  // First-block wallet buys (the "bundle") that land atomically with the dev buy.
  const bundle = body.bundleBuy || {};
  const bundleAmountSol = Math.max(0, Number(bundle.amountSol) || 0);
  let bundleWallets = [];
  if (bundleAmountSol > 0 && (bundle.walletIndexes || bundle.walletGroup)) {
    bundleWallets = webSelectedWallets(store, userId, bundle.walletIndexes, bundle.walletGroup)
      .filter((wallet) => wallet.publicKey && wallet.publicKey !== devSelection.wallet.publicKey);
  }
  // Jito bundles allow at most 5 transactions: create + dev buy + remaining wallet buys.
  const reserved = 1 + (devBuySol > 0 ? 1 : 0);
  bundleWallets = bundleWallets.slice(0, Math.max(0, 5 - reserved));

  // Pre-flight balances: ONE underfunded wallet makes an all-or-none bundle
  // unincludable at any tip. Check everything and name the exact problem first.
  const maxTipSol = Math.min(0.01, CONFIG.pumpLaunchJitoTipSol * 8);
  const devNeedsSol = 0.028 + devBuySol * 1.02 + maxTipSol + 0.005;
  const devBalanceLamports = await rpcWithRetry("read dev wallet balance for bundle", () => connection.getBalance(devKeypair.publicKey, "confirmed"), CONFIG.rpcRetries);
  if (devBalanceLamports < Math.ceil(devNeedsSol * 1e9)) {
    const error = new Error(`Dev wallet ${shortMint(devSelection.wallet.publicKey)} has ${(devBalanceLamports / 1e9).toFixed(4)} SOL but the bundle needs ~${devNeedsSol.toFixed(3)} SOL (create ~0.028 + dev buy ${devBuySol} + tip up to ${maxTipSol} + buffer). Top it up and launch again - nothing was spent.`);
    error.statusCode = 400;
    throw error;
  }
  if (bundleWallets.length && bundleAmountSol > 0) {
    const perWalletNeedsSol = bundleAmountSol * 1.02 + 0.0045;
    const needLamports = Math.ceil(perWalletNeedsSol * 1e9);
    const checked = [];
    const skipped = [];
    for (const wallet of bundleWallets) {
      const balance = await rpcWithRetry("read bundle wallet balance", () => connection.getBalance(new PublicKey(wallet.publicKey), "confirmed"), CONFIG.rpcRetries).catch(() => 0);
      if (balance < needLamports) skipped.push({ wallet, balance });
      else checked.push(wallet);
    }
    // Skip an underfunded wallet instead of aborting the launch - the funded
    // wallets (and the dev buy) still go. Only fail if NOTHING can buy.
    if (skipped.length) {
      logPumpLaunchEvent("pump_launch_bundle_wallet_skipped", {
        launchAttemptId: basePayload.clientRequestId, userId,
        skipped: skipped.map((item) => `${shortMint(item.wallet.publicKey)}:${(item.balance / 1e9).toFixed(4)}`)
      });
    }
    if (!checked.length && devBuySol <= 0) {
      const error = new Error(`Every bundle wallet is underfunded - each needs ~${perWalletNeedsSol.toFixed(4)} SOL for a ${bundleAmountSol} SOL buy. Fund them or lower the buy amount. Nothing was spent.`);
      error.statusCode = 400;
      throw error;
    }
    bundleWallets = checked;
  }

  const metadata = await uploadPumpLaunchMetadata(basePayload);
  const mintKeypair = Keypair.generate();
  const mint = mintKeypair.publicKey.toBase58();

  // Track which keypairs sign which tx. PumpPortal uses the FIRST action's priorityFee
  // as the Jito tip for the whole bundle.
  const plan = [];
  plan.push({
    action: {
      publicKey: devKeypair.publicKey.toBase58(), action: "create",
      tokenMetadata: { name: basePayload.name, symbol: basePayload.symbol, uri: metadata.uri },
      mint, denominatedInSol: "true", amount: 0, slippage: slippagePct, priorityFee: CONFIG.pumpLaunchJitoTipSol, pool: "pump"
    },
    signers: [mintKeypair, devKeypair]
  });
  if (devBuySol > 0) {
    plan.push({
      action: { publicKey: devKeypair.publicKey.toBase58(), action: "buy", mint, denominatedInSol: "true", amount: devBuySol, slippage: slippagePct, priorityFee: 0, pool: "pump" },
      signers: [devKeypair]
    });
  }
  for (const wallet of bundleWallets) {
    const keypair = decryptWallet(wallet);
    plan.push({
      action: { publicKey: keypair.publicKey.toBase58(), action: "buy", mint, denominatedInSol: "true", amount: bundleAmountSol, slippage: slippagePct, priorityFee: 0, pool: "pump" },
      signers: [keypair]
    });
  }

  logPumpLaunchEvent("pump_launch_jito_bundle_build", {
    launchAttemptId: basePayload.clientRequestId, userId, mint,
    txCount: plan.length, devBuySol, bundleWalletCount: bundleWallets.length, tipSol: CONFIG.pumpLaunchJitoTipSol
  });

  // Submit-and-CONFIRM with escalating tips. A submitted bundle is only a lottery
  // ticket - low-tip bundles routinely never land (first live test: submitted fine,
  // mint never existed). All-or-none means a missed bundle spent nothing, so we
  // rebuild with a fresh blockhash and a bigger tip and try again.
  const timeoutMs = CONFIG.pumpLaunchTimeoutMs || 30000;
  // ONE decent-tip shot then fall back to the standard path - speed beats
  // stubbornness, and the fallback fires managed buys seconds later anyway.
  const tipSchedule = [3].map((multiplier) => Math.min(0.01, CONFIG.pumpLaunchJitoTipSol * multiplier));
  const mintPubkey = new PublicKey(mint);
  const mintLanded = async (waitMs) => {
    const deadline = Date.now() + waitMs;
    while (Date.now() < deadline) {
      const info = await connection.getAccountInfo(mintPubkey, "confirmed").catch(() => null);
      if (info) return true;
      await new Promise((resolve) => setTimeout(resolve, 2_500));
    }
    return false;
  };
  // Atomic simulation (Helius supports simulateBundle): if any tx in the bundle
  // would fail, say exactly WHICH and WHY instead of losing the block lottery
  // forever in silence. RPCs without the method just skip this check.
  const simulateBundleOnRpc = async (signedBase64) => {
    try {
      const response = await fetch(connection.rpcEndpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ jsonrpc: "2.0", id: 1, method: "simulateBundle", params: [{ encodedTransactions: signedBase64 }] })
      });
      const data = await response.json().catch(() => null);
      if (!data || data.error) {
        logPumpLaunchEvent("pump_launch_jito_sim_unavailable", {
          launchAttemptId: basePayload.clientRequestId, userId, mint,
          error: String(data?.error?.message || data?.error?.code || "no JSON").slice(0, 160)
        });
        return null;
      }
      const results = data.result?.value?.transactionResults || [];
      const failedIndex = results.findIndex((item) => item?.err);
      if (failedIndex >= 0) {
        return {
          ok: false,
          failedIndex,
          err: JSON.stringify(results[failedIndex].err).slice(0, 200),
          logs: (results[failedIndex].logs || []).slice(-3).join(" | ").slice(0, 300)
        };
      }
      return { ok: true };
    } catch {
      return null;
    }
  };

  let bundleId = "";
  let landed = false;
  for (let attempt = 0; attempt < tipSchedule.length && !landed; attempt += 1) {
    plan[0].action.priorityFee = tipSchedule[attempt];
    const txBytes = await requestPumpPortalBundleTxs(plan.map((entry) => entry.action), timeoutMs);
    const signed = txBytes.map((bytes, index) => {
      const tx = VersionedTransaction.deserialize(bytes);
      tx.sign(plan[index].signers);
      return Buffer.from(tx.serialize()).toString("base64");
    });
    if (attempt === 0) {
      const sim = await simulateBundleOnRpc(signed);
      if (sim && !sim.ok) {
        const stage = sim.failedIndex === 0
          ? "the create transaction"
          : (devBuySol > 0 && sim.failedIndex === 1)
            ? "the dev buy"
            : `bundle wallet buy #${sim.failedIndex - (devBuySol > 0 ? 1 : 0)}`;
        logPumpLaunchEvent("pump_launch_jito_bundle_sim_failed", {
          launchAttemptId: basePayload.clientRequestId, userId, mint, failedIndex: sim.failedIndex, err: sim.err
        });
        const error = new Error(`Launch bundle simulation failed on ${stage}: ${sim.err}. Nothing was submitted and no SOL was spent.${sim.logs ? ` Details: ${sim.logs}` : ""}`);
        error.statusCode = 400;
        throw error;
      }
    }
    bundleId = await submitJitoBundle(signed, timeoutMs);
    logPumpLaunchEvent("pump_launch_jito_bundle_submitted", {
      launchAttemptId: basePayload.clientRequestId, userId, mint, bundleId,
      txCount: plan.length, attempt: attempt + 1, tipSol: tipSchedule[attempt]
    });
    // Pump-speed budget: a bundle that lands does so within a few blocks; if it
    // has not appeared in 8s, the standard path with instant managed buys is
    // faster than waiting on the lottery.
    landed = await mintLanded(8_000);
  }

  if (!landed) {
    logPumpLaunchEvent("pump_launch_jito_bundle_missed", {
      launchAttemptId: basePayload.clientRequestId, userId, mint, bundleId, attempts: tipSchedule.length, fallback: "pumpportal-local"
    });
    // The launch must NEVER dead-end on the block lottery: fall back to the
    // proven sequential path, then the SERVER fires the dev buy and every
    // bundle wallet buy itself - instant, no client follow-ups to stall on.
    const fallback = await webLaunchPumpPortalLocal(userId, body, basePayload);
    const fallbackMint = String(fallback?.tokenMint || fallback?.mint || "");
    let buys = { dev: false, wallets: 0 };
    if (fallbackMint) {
      buys = await firePostLaunchBuysServerSide({
        mint: fallbackMint, body, devWallet: devSelection.wallet, devKeypair, devBuySol,
        bundleWallets, bundleAmountSol, slippagePct,
        launchAttemptId: basePayload.clientRequestId, userId
      }).catch(() => ({ dev: false, wallets: 0, planned: false }));
    }
    // bundled:true tells the client the buys are DONE - it must not re-run them.
    return {
      ...fallback,
      bundled: true,
      bundleFallback: true,
      devBuyIncluded: buys.dev,
      bundledWalletCount: buys.wallets,
      message: `Atomic bundle missed the block lottery (nothing spent on it) - launched standard instead. Server fired ${buys.dev ? "the dev buy" : "no dev buy"}${buys.wallets ? ` + ${buys.wallets} bundle wallet buy(s)` : ""}${buys.planned ? " with your TP/SL/timer armed" : ""} right behind the create.`
    };
  }

  logPumpLaunchEvent("pump_launch_jito_bundle_landed", {
    launchAttemptId: basePayload.clientRequestId, userId, mint, bundleId, txCount: plan.length
  });
  // The in-block buys exist but carry no exit plans - auto-arm them with the
  // launch sheet's TP/SL/timer. Presets set = protection on, zero user steps.
  let atomicExitsArmed = false;
  try {
    await webArmExitsForExistingPositions(userId, {
      tokenMint: mint,
      takeProfitPct: body.takeProfitPct,
      stopLossPct: body.stopLossPct,
      sellDelay: body.sellDelay,
      sellPercent: body.sellPercent || "100",
      slippageBps: Math.max(Number(body.slippageBps) || 300, 1_000),
      source: "pump_launch_atomic_arm"
    });
    atomicExitsArmed = true;
    logPumpLaunchEvent("pump_launch_atomic_exits_armed", { launchAttemptId: basePayload.clientRequestId, userId, mint });
  } catch (error) {
    logPumpLaunchEvent("pump_launch_atomic_exits_arm_failed", { launchAttemptId: basePayload.clientRequestId, userId, mint, errorMessage: String(error.message || "").slice(0, 200) });
  }
  // Ledger entry: this is what powers the /t "LAUNCHED ON SLIMEWIRE" badge and
  // the milestone auto-posts - bundled launches were invisible to both.
  await upsertPumpLaunchAttempt({
    id: basePayload.clientRequestId,
    userId,
    selectedDevWalletId,
    devWalletPublicKey: devSelection.wallet.publicKey,
    tokenName: basePayload.name,
    symbol: basePayload.symbol,
    tokenMint: mint,
    status: PUMP_LAUNCH_STATUS.COMPLETE,
    provider: "jito-bundle",
    bundleId,
    completedAt: new Date().toISOString()
  }).catch((error) => console.warn(`[pump-launch] bundle ledger write failed: ${error.message}`));
  return {
    status: PUMP_LAUNCH_STATUS.COMPLETE, tokenMint: mint, mint, bundleId, bundled: true,
    bundledWalletCount: bundleWallets.length, devBuyIncluded: devBuySol > 0,
    exitsArmed: atomicExitsArmed,
    provider: "jito-bundle", metadataUri: metadata.uri
  };
}

async function webLaunchPumpPortalLocal(userId, body, basePayload) {
  const store = await readWalletStore();
  const selectedDevWalletId = firstString(
    basePayload.devBuy.walletIndex,
    body.selectedDevWalletId,
    body.devWalletPublicKey,
    Array.isArray(body.walletIndexes) ? body.walletIndexes[0] : ""
  );
  let walletSelection;
  try {
    walletSelection = selectPumpLaunchWallet(store, userId, selectedDevWalletId);
  } catch (error) {
    error.launchAttemptId = error.launchAttemptId || basePayload.clientRequestId;
    await upsertPumpLaunchAttempt({
      id: basePayload.clientRequestId,
      userId,
      selectedDevWalletId,
      tokenName: basePayload.name,
      symbol: basePayload.symbol,
      status: PUMP_LAUNCH_STATUS.FAILED,
      stage: error.stage || PUMP_LAUNCH_STAGE.WALLET_AUTH,
      errorCode: error.code || "DEV_WALLET_AUTH_FAILED",
      errorMessage: friendlyError(error),
      failureReason: formatPumpLaunchUserError(error),
      failedAt: new Date().toISOString()
    });
    logPumpLaunchEvent("pump_launch_failed", {
      launchAttemptId: basePayload.clientRequestId,
      userId,
      selectedDevWalletId,
      tokenName: basePayload.name,
      symbol: basePayload.symbol,
      status: PUMP_LAUNCH_STATUS.FAILED,
      stage: error.stage || PUMP_LAUNCH_STAGE.WALLET_AUTH,
      errorCode: error.code || "DEV_WALLET_AUTH_FAILED",
      errorMessage: friendlyError(error),
      failureReason: formatPumpLaunchUserError(error)
    });
    throw error;
  }
  const creatorWallet = walletSelection.wallet;
  let creatorKeypair;
  try {
    creatorKeypair = decryptWallet(creatorWallet);
  } catch (error) {
    const wrapped = createPumpLaunchError("Selected dev wallet could not be decrypted for signing.", "DEV_WALLET_DECRYPT_FAILED", 500, {
      stage: PUMP_LAUNCH_STAGE.WALLET_AUTH,
      cause: error,
      launchAttemptId: basePayload.clientRequestId,
      devWalletPublicKey: creatorWallet.publicKey
    });
    await upsertPumpLaunchAttempt({
      id: basePayload.clientRequestId,
      userId,
      selectedDevWalletId,
      devWalletPublicKey: creatorWallet.publicKey,
      tokenName: basePayload.name,
      symbol: basePayload.symbol,
      status: PUMP_LAUNCH_STATUS.FAILED,
      stage: PUMP_LAUNCH_STAGE.WALLET_AUTH,
      errorCode: wrapped.code,
      errorMessage: friendlyError(wrapped),
      failureReason: formatPumpLaunchUserError(wrapped),
      failedAt: new Date().toISOString()
    });
    logPumpLaunchEvent("pump_launch_failed", {
      launchAttemptId: basePayload.clientRequestId,
      userId,
      selectedDevWalletId,
      devWalletPublicKey: creatorWallet.publicKey,
      tokenName: basePayload.name,
      symbol: basePayload.symbol,
      status: PUMP_LAUNCH_STATUS.FAILED,
      stage: PUMP_LAUNCH_STAGE.WALLET_AUTH,
      errorCode: wrapped.code,
      errorMessage: friendlyError(wrapped),
      failureReason: formatPumpLaunchUserError(wrapped)
    });
    throw wrapped;
  }
  const timeoutMs = Number.isFinite(CONFIG.pumpLaunchTimeoutMs) && CONFIG.pumpLaunchTimeoutMs > 0
    ? CONFIG.pumpLaunchTimeoutMs
    : 30000;
  const service = new PumpLaunchService({
    getBalanceLamports: (publicKey) => rpcWithRetry("read pump launch dev wallet SOL", () => connection.getBalance(publicKey, "confirmed"), CONFIG.rpcRetries),
    uploadMetadata: uploadPumpLaunchMetadata,
    validateMetadataUri: validatePumpPortalMetadataUri,
    requestLocalTransaction: (requestPayload, requestTimeoutMs) => requestPumpPortalLocalTransaction(requestPayload, requestTimeoutMs, {
      url: CONFIG.pumpLaunchApiUrl
    }),
    sendTransaction: (tx) => sendVersionedTransaction(tx, "send pump launch transaction"),
    generateMintKeypair: () => Keypair.generate(),
    encryptMintSecret: (keypair) => encryptSecret(Buffer.from(keypair.secretKey)),
    saveAttempt: upsertPumpLaunchAttempt,
    recordTradeEvent: async (event) => recordTradeEvents([event]),
    log: logPumpLaunchEvent
  });

  const launchResult = await service.launch({
    launchAttemptId: basePayload.clientRequestId,
    userId,
    wallet: creatorWallet,
    walletKeypair: creatorKeypair,
    basePayload,
    body,
    config: {
      apiUrl: CONFIG.pumpLaunchApiUrl,
      timeoutMs,
      priorityFeeSol: CONFIG.pumpLaunchPriorityFeeSol,
      requiredBufferSol: CONFIG.pumpLaunchRequiredBufferSol,
      pool: "pump"
    }
  });
  if (String(launchResult?.status || "").toUpperCase() === "COMPLETE" && launchResult.tokenMint) {
    const sym = escapeTelegramHtml(basePayload.symbol || basePayload.name || "???");
    const launchText = buildLaunchAnnounceCaption(sym, launchResult.tokenMint);
    const draft = { name: basePayload.name, symbol: basePayload.symbol, description: basePayload.description, imageDataUrl: basePayload.imageDataUrl, bannerDataUrl: basePayload.bannerDataUrl, bannerUri: launchResult.bannerUri || "", x: basePayload.twitter, telegram: basePayload.telegram, website: basePayload.website };
    announceLaunchCard("launch", launchResult.tokenMint, draft, launchText, launchAnnounceKb(launchResult.tokenMint));
    fulfillLaunchHype(userId, launchResult.tokenMint, basePayload.symbol).catch((error) => console.warn(`[hype] fulfill failed: ${error.message}`));
  }
  return launchResult;
}

function pumpLaunchProviderHint(status) {
  const mode = CONFIG.pumpLaunchRequestMode || "json";
  if (mode === "json" && [400, 413, 415].includes(Number(status))) {
    return " Provider rejected the JSON fields. Try PUMP_LAUNCH_API_FORMAT=minimal first; if the docs require file upload, set PUMP_LAUNCH_REQUEST_MODE=multipart and set PUMP_LAUNCH_IMAGE_FIELD to the provider's image field.";
  }
  if (mode === "form" && Number(status) === 400) {
    return " Provider rejected the form fields. Check PUMP_LAUNCH_API_FORMAT and field names, or switch PUMP_LAUNCH_REQUEST_MODE to json or multipart based on the provider docs.";
  }
  if (mode === "multipart" && Number(status) === 400) {
    return " Provider rejected the multipart fields. Check PUMP_LAUNCH_IMAGE_FIELD and remove unsupported launch fields by using PUMP_LAUNCH_API_FORMAT=minimal.";
  }
  return "";
}

function launchProviderErrorDetail(error) {
  const detail = fetchJsonErrorMessage(error?.providerData || {}, error?.responseBody || error?.message || "", error?.status || error?.statusCode || 0);
  return detail ? detail.replace(/\s+/g, " ").trim().slice(0, 500) : "";
}

async function webLaunchPumpCoin(userId, body = {}) {
  const launchAttemptId = firstString(body.launchAttemptId, body.clientRequestId) || crypto.randomUUID();
  if (!CONFIG.pumpLaunchEnabled || !CONFIG.pumpLaunchApiUrl) {
    const error = createPumpLaunchError(
      "Direct Pump launch is not enabled yet. Set PUMP_LAUNCH_ENABLED=true and PUMP_LAUNCH_API_URL=https://pumpportal.fun/api/trade-local on Render.",
      "PUMP_LAUNCH_NOT_ENABLED",
      501,
      {
        stage: PUMP_LAUNCH_STAGE.CONFIG,
        launchAttemptId
      }
    );
    await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, error });
    throw error;
  }

  const name = cleanLaunchText(body.name, 64);
  const symbol = cleanTickerSymbol(body.symbol || body.ticker || "");
  const description = launchDescriptionWithSlimeWireAttribution(body.description, 800);
  if (!name) {
    const error = createPumpLaunchError("Token name is required.", "PUMP_LAUNCH_NAME_REQUIRED", 400, {
      stage: PUMP_LAUNCH_STAGE.CONFIG,
      launchAttemptId
    });
    await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, error });
    throw error;
  }
  if (!symbol) {
    const error = createPumpLaunchError("Token ticker/symbol is required.", "PUMP_LAUNCH_SYMBOL_REQUIRED", 400, {
      stage: PUMP_LAUNCH_STAGE.CONFIG,
      launchAttemptId
    });
    await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, name, error });
    throw error;
  }

  const imageDataUrl = String(body.imageDataUrl || "");
  if (imageDataUrl && !/^data:image\/(?:png|jpe?g|webp|gif|heic|heif|avif|svg\+xml);base64,/i.test(imageDataUrl)) {
    const error = createPumpLaunchError("Upload a PNG, JPG, WEBP, GIF, HEIC/HEIF, AVIF, or phone screenshot token image.", "PUMP_LAUNCH_IMAGE_TYPE_INVALID", 400, {
      stage: PUMP_LAUNCH_STAGE.CONFIG,
      launchAttemptId
    });
    await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, name, symbol, error });
    throw error;
  }
  const decodedLaunchImage = imageDataUrl ? decodeLaunchImageDataUrl(imageDataUrl, { symbol, name, imageName: body.imageName }) : null;
  if (imageDataUrl && !decodedLaunchImage) {
    const error = createPumpLaunchError("Token image could not be decoded from the browser upload. Upload a smaller PNG, JPG, WEBP, GIF, HEIC/HEIF, AVIF, or phone screenshot.", "PUMP_LAUNCH_IMAGE_DECODE_FAILED", 400, {
      stage: PUMP_LAUNCH_STAGE.CONFIG,
      launchAttemptId
    });
    await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, name, symbol, error });
    throw error;
  }
  const imageMaxBytes = Math.max(100_000, Math.min(CONFIG.pumpLaunchBodyLimitBytes, 12 * 1024 * 1024));
  if (decodedLaunchImage && decodedLaunchImage.buffer.length > imageMaxBytes) {
    const actualKb = Math.ceil(decodedLaunchImage.buffer.length / 1024);
    const maxKb = Math.floor(imageMaxBytes / 1024);
    const error = createPumpLaunchError(`Token image is ${actualKb}KB. Limit is ${maxKb}KB before backend conversion. Use a smaller phone screenshot or image and try again.`, "PUMP_LAUNCH_IMAGE_TOO_LARGE", 413, {
      stage: PUMP_LAUNCH_STAGE.CONFIG,
      launchAttemptId
    });
    await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, name, symbol, error });
    throw error;
  }

  // Optional pump.fun coin-page banner (3:1, set only at creation). Validated lightly
  // and never required — a bad/oversized banner is dropped, the launch still proceeds.
  let bannerDataUrl = String(body.bannerDataUrl || "");
  if (bannerDataUrl && !/^data:image\/(?:png|jpe?g|webp|gif|heic|heif|avif);base64,/i.test(bannerDataUrl)) {
    bannerDataUrl = ""; // unknown type -> ignore rather than fail the launch
  }
  if (bannerDataUrl && bannerDataUrl.length > 7_500_000) {
    bannerDataUrl = ""; // ~5MB image + base64 overhead; oversized -> ignore
  }

  const creatorFeeBps = cleanLaunchNumber(body.creatorFeeBps, 0, 0, 1000);
  const devBuyEnabled = cleanLaunchBoolean(body.devBuyEnabled);
  const feeModeRaw = cleanLaunchText(body.feeMode, 24).toLowerCase();
  const feeMode = ["standard", "dev", "buyback", "burn", "split"].includes(feeModeRaw)
    ? feeModeRaw
    : "standard";
  const creatorFeeRecipient = cleanLaunchText(body.creatorFeeRecipient || body.feeRecipient, 64);
  const buybackWallet = cleanLaunchText(body.buybackWallet, 64);
  const burnCreatorFees = cleanLaunchBoolean(body.burnCreatorFees) || feeMode === "burn";

  const basePayload = {
    name,
    symbol,
    description,
    website: cleanLaunchUrl(body.website),
    twitter: cleanLaunchUrl(body.x) || cleanLaunchUrl(body.twitter),
    telegram: cleanLaunchUrl(body.telegram),
    imageDataUrl,
    imageName: cleanLaunchText(body.imageName, 120),
    imageType: cleanLaunchText(body.imageType, 80),
    bannerDataUrl,
    bannerName: cleanLaunchText(body.bannerName, 120),
    creatorFeeBps,
    burnCreatorFees,
    creatorFeeRecipient,
    buybackWallet,
    feeMode,
    feeRouting: {
      mode: feeMode,
      creatorFeeBps,
      creatorFeeRecipient,
      buybackWallet,
      burnCreatorFees
    },
    devBuy: {
      enabled: devBuyEnabled,
      amountSol: cleanLaunchNumber(body.devBuySol, 0, 0, 1000),
      walletIndex: cleanLaunchText(body.devWalletIndex || body.selectedDevWalletId || body.devWalletPublicKey, 64)
    },
    slippageBps: cleanLaunchNumber(body.slippageBps, 300, 1, 5000),
    clientRequestId: launchAttemptId,
    source: "slimewire_web"
  };

  if (isPumpPortalLocalLaunch()) {
    try {
      validatePumpPortalLocalApiUrl(CONFIG.pumpLaunchApiUrl);
    } catch (error) {
      error.launchAttemptId = launchAttemptId;
      await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, name, symbol, error });
      throw error;
    }
    try {
      // Flag-gated atomic anti-snipe path. When PUMP_LAUNCH_JITO_BUNDLE is OFF (default)
      // this is never reached, so normal launches are unchanged. When ON, the create +
      // dev buy + first-block wallet buys land together in one all-or-none Jito bundle.
      const useJito = CONFIG.pumpLaunchJitoBundle && (Number(basePayload.devBuy?.amountSol) > 0 || Number(body.bundleBuy?.amountSol) > 0);
      const result = useJito
        ? await webLaunchPumpJitoBundle(userId, body, basePayload)
        : await webLaunchPumpPortalLocal(userId, body, basePayload);
      // The local path announces internally; the bundle path needs the same sends
      // (TG launch post + hype-page fulfillment) once the bundle is CONFIRMED landed.
      if (useJito && String(result?.status || "").toUpperCase() === "COMPLETE" && result.tokenMint) {
        const sym = escapeTelegramHtml(symbol || name || "???");
        const launchText = buildLaunchAnnounceCaption(sym, result.tokenMint);
        const draft = { name, symbol, description: body.description, imageDataUrl: body.imageDataUrl, bannerDataUrl: body.bannerDataUrl, x: body.x || body.twitter, telegram: body.telegram, website: body.website };
        announceLaunchCard("launch", result.tokenMint, draft, launchText, launchAnnounceKb(result.tokenMint));
        fulfillLaunchHype(userId, result.tokenMint, symbol).catch((error) => console.warn(`[hype] fulfill failed: ${error.message}`));
      }
      await audit("web_launch_pump_coin", {
        userId,
        symbol,
        status: result.status,
        tokenMint: shortMint(result.tokenMint),
        hasImage: Boolean(imageDataUrl),
        provider: result.provider
      });
      // Persist the banner for this mint so SlimeWire renders a pump.fun-style coin
      // page (wide banner + overlapping pfp). Best-effort; never affects the launch.
      if (result?.tokenMint && basePayload.bannerDataUrl) {
        try {
          let bannerUri = String(result.bannerUri || "");
          if (!bannerUri) {
            const banner = await launchBannerBufferForUpload(basePayload);
            bannerUri = banner ? await pinBannerToPumpFunIpfs(banner) : "";
          }
          if (bannerUri) recordCoinBanner(result.tokenMint, { bannerUri, symbol, name });
        } catch (e) { console.warn(`[pump-launch] banner record failed: ${e && e.message}`); }
      }
      return {
        ...result,
        launchAttemptId,
        pumpUrl: pumpFunUrl(result.tokenMint),
        dexUrl: dexScreenerUrl(result.tokenMint),
        bannerUri: result.bannerUri || (coinBanners.get(result.tokenMint)?.bannerUri || ""),
        message: `Pump launch returned ${shortMint(result.tokenMint)}.`
      };
    } catch (error) {
      const wrapped = new Error(formatPumpLaunchUserError(error));
      wrapped.statusCode = Number(error.status || error.statusCode || 502);
      wrapped.code = error.code || "PUMP_LAUNCH_FAILED";
      wrapped.stage = error.stage || error.cause?.stage || "";
      wrapped.launchAttemptId = error.launchAttemptId || launchAttemptId;
      wrapped.txSignature = error.txSignature || "";
      wrapped.providerStatus = error.providerStatus || error.status || error.statusCode || null;
      wrapped.providerResponseBody = sanitizeProviderBody(error.providerResponseBody || error.responseBody || "");
      throw wrapped;
    }
  }

  const payload = buildPumpLaunchPayload(basePayload);

  const timeoutMs = Number.isFinite(CONFIG.pumpLaunchTimeoutMs) && CONFIG.pumpLaunchTimeoutMs > 0
    ? CONFIG.pumpLaunchTimeoutMs
    : 30000;
  let providerResult;
  try {
    providerResult = await fetchJson(CONFIG.pumpLaunchApiUrl, buildPumpLaunchRequestOptions(basePayload, payload, timeoutMs));
  } catch (error) {
    const status = Number(error.status || error.statusCode || 502);
    const detail = launchProviderErrorDetail(error);
    const message = status === 413
      ? `Pump launch provider rejected the upload because the image/payload is too large. Compress the image or switch to multipart upload.${pumpLaunchProviderHint(status)}`
      : `Pump launch provider rejected the request${detail ? `: ${detail}` : `: ${friendlyError(error)}`}${pumpLaunchProviderHint(status)}`;
    const wrapped = new Error(message);
    wrapped.statusCode = status >= 400 && status < 500 ? status : 502;
    wrapped.code = "PUMP_LAUNCH_PROVIDER_FAILED";
    wrapped.stage = PUMP_LAUNCH_STAGE.PUMPPORTAL_LOCAL;
    wrapped.launchAttemptId = launchAttemptId;
    wrapped.providerStatus = status;
    wrapped.providerResponseBody = sanitizeProviderBody(error.responseBody || "");
    await recordPumpLaunchEarlyFailure({ launchAttemptId, userId, body, name, symbol, error: wrapped });
    throw wrapped;
  }
  const tokenMint = normalizeLaunchResponseMint(providerResult);
  const status = firstString(providerResult.status, providerResult.state, tokenMint ? "launched" : "submitted");

  await audit("web_launch_pump_coin", {
    userId,
    symbol,
    status,
    tokenMint: tokenMint ? shortMint(tokenMint) : "",
    hasImage: Boolean(imageDataUrl)
  });

  return {
    status,
    tokenMint,
    signature: firstString(
      providerResult.signature,
      providerResult.txSignature,
      providerResult.transactionSignature,
      providerResult.txid,
      providerResult.result?.signature
    ),
    requestId: firstString(providerResult.requestId, providerResult.id, providerResult.result?.requestId, payload.clientRequestId),
    launchAttemptId,
    pumpUrl: tokenMint ? pumpFunUrl(tokenMint) : "",
    dexUrl: tokenMint ? dexScreenerUrl(tokenMint) : "",
    message: tokenMint ? `Pump launch returned ${shortMint(tokenMint)}.` : "Pump launch submitted. Waiting for token CA."
  };
}

async function webCreateLaunchWatch(userId, body = {}) {
  const store = await readWalletStore();
  const wallets = webSelectedWallets(store, userId, body.walletIndexes, body.walletGroup);
  const ticker = cleanTickerSymbol(String(body.ticker || ""));
  const amountSol = parsePositiveNumber(String(body.amountSol || ""));
  const sellDelayInput = firstString(body.sellDelay, body.sellDelaySeconds);
  const sellDelaySeconds = sellDelayInput
    ? parseOptionalSellDelaySeconds(sellDelayInput)
    : PUMPSNIPE_SELL_DELAY_SECONDS;
  const takeProfitPct = parseTakeProfitPercent(String(body.takeProfitPct || PUMPSNIPE_TAKE_PROFIT_PCT));
  const stopLossPct = parseOptionalTriggerPercent(String(body.stopLossPct || PUMPSNIPE_STOP_LOSS_PCT));
  const loopCount = parseLoopCount(String(body.loopCount || "1"));
  const loopDelaySeconds = parseLoopDelaySeconds(String(body.loopDelay || body.loopDelaySeconds || "0"));
  const slippageBps = parseWebSlippage(body.slippageBps || PUMPSNIPE_SLIPPAGE_BPS);
  const walletIndexes = wallets.map((wallet, index) => Number(wallet.webIndex || index + 1));
  const walletTakeProfitTargets = parseWebWalletTakeProfitTargets(body, walletIndexes);
  const walletStopLossTargets = parseWebWalletStopLossTargets(body, walletIndexes);
  ensureTimedPlanHasExit({
    sellDelaySeconds,
    takeProfitPct,
    stopLossPct,
    walletTakeProfitTargets,
    walletStopLossTargets
  });
  const plan = {
    id: crypto.randomUUID(),
    status: "launch_watch",
    userId,
    chatId: null,
    source: "manual_launch_snipe",
    launchTicker: ticker,
    walletSelector: wallets.map((wallet) => wallet.label).join(", "),
    amountSol,
    sellDelayMinutes: sellDelaySeconds / 60,
    sellDelaySeconds,
    sellPercent: 100,
    triggerSellPercent: 100,
    loopCount,
    loopDelaySeconds,
    takeProfitPct,
    stopLossPct,
    takeProfitMode: walletTakeProfitTargets ? "wallets" : "single",
    stopLossMode: walletStopLossTargets ? "wallets" : "single",
    takeProfitLadder: [],
    autoBundle: false,
    manualLaunch: true,
    slippageBps,
    createdAt: new Date().toISOString(),
    lastScanAt: null,
    wallets: wallets.map((wallet, index) => {
      const walletIndex = walletIndexes[index];
      return {
        label: wallet.label,
        publicKey: wallet.publicKey,
        walletIndex,
        takeProfitPct: walletTakeProfitTargets ? walletTakeProfitTargets[String(walletIndex)] || null : null,
        stopLossPct: walletStopLossTargets ? walletStopLossTargets[String(walletIndex)] || null : null,
        status: "pending",
        results: []
      };
    }),
    results: [`Watching for ticker $${ticker}`]
  };

  const plans = await readTradePlans();
  plans.plans.push(plan);
  await writeTradePlans(plans);
  await audit("web_create_manual_launch_snipe", {
    userId,
    planId: plan.id,
    ticker,
    wallets: wallets.map(publicWallet),
    amountSol,
    sellDelaySeconds,
    loopCount,
    loopDelaySeconds,
    takeProfitPct,
    stopLossPct,
    walletTakeProfitTargets,
    walletStopLossTargets,
    slippageBps
  });
  void refreshSnipeWatchTickers(); // arm the real-time onCreation sniper instantly
  setTimeout(() => void processTradePlans().catch((error) => {
    console.error("Web manual launch immediate scan failed:", error.message);
  }), 250);

  return webLaunchWatchRow(plan);
}

async function webLaunchWatches(userId) {
  const plans = await readTradePlans();
  return plans.plans
    .filter((plan) => String(plan.userId) === String(userId) && ["launch_watch", "watching"].includes(plan.status) && plan.manualLaunch)
    .sort((a, b) => Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .slice(0, 20)
    .map(webLaunchWatchRow);
}

async function webCancelLaunchWatch(userId, planId) {
  const store = await readTradePlans();
  const plan = store.plans.find((item) => item.id === String(planId || "") && String(item.userId) === String(userId));
  if (!plan) {
    throw new Error("Launch watch not found.");
  }
  if (plan.status !== "launch_watch") {
    throw new Error("This launch watch is no longer scanning.");
  }

  plan.status = "canceled";
  plan.canceledAt = new Date().toISOString();
  plan.results = appendLimited([...(plan.results || []), "Canceled from web panel."]);
  await writeTradePlans(store);
  void refreshSnipeWatchTickers(); // drop it from the real-time sniper set
  await audit("web_cancel_manual_launch_snipe", { userId, planId: plan.id, ticker: plan.launchTicker });
  return webLaunchWatchRow(plan);
}

function webLaunchWatchRow(plan) {
  return {
    id: plan.id,
    status: plan.status,
    ticker: plan.launchTicker,
    tokenMint: plan.tokenMint || null,
    shortMint: plan.tokenMint ? shortMint(plan.tokenMint) : null,
    walletCount: plan.wallets?.length || 0,
    amountSol: plan.amountSol,
    takeProfitPct: plan.takeProfitPct,
    stopLossPct: plan.stopLossPct,
    takeProfitSummary: formatPlanTakeProfitSummary(plan),
    stopLossSummary: formatPlanStopLossSummary(plan),
    sellDelaySeconds: plan.sellDelaySeconds,
    loopCount: plan.loopCount || 1,
    loopDelaySeconds: plan.loopDelaySeconds || 0,
    slippageBps: plan.slippageBps,
    scanIntervalMs: CONFIG.manualLaunchScanIntervalMs,
    createdAt: plan.createdAt,
    lastScanAt: plan.lastScanAt || null,
    results: (plan.results || []).slice(-6),
    dexUrl: plan.tokenMint ? dexScreenerUrl(plan.tokenMint) : null,
    message: plan.status === "launch_watch"
      ? `Watching $${plan.launchTicker} every ${(CONFIG.manualLaunchScanIntervalMs / 1000).toFixed(CONFIG.manualLaunchScanIntervalMs % 1000 === 0 ? 0 : 1)}s while the bot is online.`
      : `Launch watch ${plan.status}.`
  };
}

function webSelectedWallets(store, userId, walletIndexes, walletGroup = "") {
  const ownerWallets = walletsForOwner(store, userId);
  const group = String(walletGroup || "").trim().toLowerCase();
  const indexes = group
    ? ownerWallets
      .map((wallet, index) => ({ wallet, index: index + 1 }))
      .filter(({ wallet }) => {
        const label = String(wallet.label || "").toLowerCase();
        return label === group || label.startsWith(`${group} `);
      })
      .map(({ index }) => index)
    : Array.isArray(walletIndexes)
      ? walletIndexes.map((value) => Number.parseInt(value, 10))
      : String(walletIndexes || "").toLowerCase() === "all"
        ? ownerWallets.map((_, index) => index + 1)
        : [];

  const uniqueIndexes = [...new Set(indexes)].filter((index) => Number.isInteger(index) && index >= 1);
  if (uniqueIndexes.length === 0) {
    throw new Error(group ? `No wallets found for group "${walletGroup}".` : "Choose at least one wallet.");
  }
  if (uniqueIndexes.length > 20) {
    throw new Error("Choose 20 wallets or fewer.");
  }

  return uniqueIndexes.map((index) => ({
    ...assertServerTradeWalletReady(getWalletAt(store, index, userId), "server trading"),
    webIndex: index
  }));
}

function webWalletRef(wallet) {
  return {
    walletIndex: wallet.webIndex,
    walletLabel: wallet.label,
    walletPublicKey: wallet.publicKey,
    shortPublicKey: shortMint(wallet.publicKey)
  };
}

function parseWebDestination(value, label = "destination wallet") {
  const text = String(value || "").trim();
  if (!text) {
    throw new Error(`Enter a ${label}.`);
  }
  try {
    return new PublicKey(text);
  } catch {
    throw new Error(`Invalid ${label}.`);
  }
}

function parseOptionalWebMint(value) {
  const text = String(value || "").trim();
  if (!text || text.toLowerCase() === "all") return "";
  try {
    return new PublicKey(text).toBase58();
  } catch {
    throw new Error("Invalid token mint. Leave blank for all tokens.");
  }
}

function splitWebDestinationList(value) {
  const rows = Array.isArray(value)
    ? value
    : String(value || "").split(/[\s,]+/);
  const destinations = rows.map((item) => String(item || "").trim()).filter(Boolean);
  const unique = [...new Set(destinations)];
  if (unique.length === 0) {
    throw new Error("Enter at least one destination wallet.");
  }
  if (unique.length > 20) {
    throw new Error("Use 20 destination wallets or fewer.");
  }
  return unique.map((address) => parseWebDestination(address, "destination wallet"));
}

function selectedWebSweepWallets(store, userId, body = {}) {
  return webSelectedWallets(
    store,
    userId,
    body.walletIndexes || body.wallets || "all",
    body.walletGroup || body.group || ""
  );
}

function solTransferResultRow(wallet, result) {
  return {
    ...webWalletRef(wallet),
    ok: Boolean(result.signature),
    signature: result.signature || null,
    sentSol: result.sentLamports ? lamportsToSol(result.sentLamports) : "0",
    feeSol: result.feeLamports ? lamportsToSol(result.feeLamports) : "0",
    message: result.message || (result.signature ? "SOL sent." : "No sweepable SOL.")
  };
}

async function webSweepSol(userId, body = {}) {
  const store = await readWalletStore();
  const destination = parseWebDestination(body.destination || body.destinationWallet);
  const wallets = selectedWebSweepWallets(store, userId, body);
  const rows = [];

  for (const wallet of wallets) {
    try {
      const keypair = decryptWallet(wallet);
      const result = await drainSolFromWallet(keypair, destination);
      invalidateWalletReadCache(wallet.publicKey);
      rows.push(solTransferResultRow(wallet, result));
    } catch (error) {
      rows.push({
        ...webWalletRef(wallet),
        ok: false,
        signature: null,
        sentSol: "0",
        feeSol: "0",
        message: friendlyError(error)
      });
    }
  }

  invalidateWalletReadCache(destination.toBase58());
  await audit("web_sweep_sol", { userId, destination: destination.toBase58(), walletCount: wallets.length, successCount: rows.filter((row) => row.ok).length });
  return {
    action: "sweep-sol",
    destination: destination.toBase58(),
    rows,
    summary: `${rows.filter((row) => row.ok).length}/${rows.length} wallet(s) swept SOL.`
  };
}

async function webSweepTokens(userId, body = {}) {
  const store = await readWalletStore();
  const destination = parseWebDestination(body.destination || body.destinationWallet);
  const tokenMint = parseOptionalWebMint(body.tokenMint || body.mint);
  const wallets = selectedWebSweepWallets(store, userId, body);
  const rows = [];

  for (const wallet of wallets) {
    const walletRow = {
      ...webWalletRef(wallet),
      ok: false,
      transfers: [],
      message: ""
    };

    try {
      const keypair = decryptWallet(wallet);
      const lookup = await getOwnedTokenAccountsWithWarningsCached(keypair.publicKey, { force: true });
      const accounts = (lookup.accounts || []).filter((account) => account.rawAmount > 0n && (!tokenMint || account.mint === tokenMint));

      if (!accounts.length) {
        walletRow.message = tokenMint ? "No balance for that token." : "No sweepable tokens.";
        rows.push(walletRow);
        continue;
      }

      for (const account of accounts) {
        const mint = new PublicKey(account.mint);
        const decimals = Number.isInteger(account.decimals) ? account.decimals : await getMintDecimals(mint);
        const sourceAta = new PublicKey(account.pubkey);
        const tokenProgramId = new PublicKey(account.tokenProgramId || TOKEN_PROGRAM_ID);
        const destinationAta = getAssociatedTokenAddress(mint, destination, tokenProgramId);
        const tx = new Transaction();
        const destinationInfo = await rpcWithRetry("check destination token account", () => connection.getAccountInfo(destinationAta, "confirmed"));

        if (!destinationInfo) {
          tx.add(createAssociatedTokenAccountInstruction(keypair.publicKey, destinationAta, destination, mint, tokenProgramId));
        }

        tx.add(createTransferCheckedInstruction(
          sourceAta,
          mint,
          destinationAta,
          keypair.publicKey,
          account.rawAmount,
          decimals,
          [],
          tokenProgramId
        ));

        const signature = await sendLegacyTransaction(tx, [keypair]);
        walletRow.transfers.push({
          mint: account.mint,
          uiAmount: rawTokenAmountToUi(account.rawAmount, decimals),
          rawAmount: account.rawAmount.toString(),
          signature
        });
      }

      walletRow.ok = walletRow.transfers.length > 0;
      walletRow.message = `Transferred ${walletRow.transfers.length} token account(s).`;
      invalidateWalletReadCache(wallet.publicKey);
      rows.push(walletRow);
    } catch (error) {
      walletRow.message = friendlyError(error);
      rows.push(walletRow);
    }
  }

  invalidateWalletReadCache(destination.toBase58());
  await audit("web_sweep_tokens", { userId, destination: destination.toBase58(), tokenMint: tokenMint || "all", walletCount: wallets.length, successCount: rows.filter((row) => row.ok).length });
  return {
    action: "sweep-tokens",
    destination: destination.toBase58(),
    tokenMint: tokenMint || "all",
    rows,
    summary: `${rows.filter((row) => row.ok).length}/${rows.length} wallet(s) transferred tokens.`
  };
}

async function webSellAllTokens(userId, body = {}) {
  const store = await readWalletStore();
  const tokenMint = parseOptionalWebMint(body.tokenMint || body.mint);
  const destination = String(body.destination || body.destinationWallet || "").trim()
    ? parseWebDestination(body.destination || body.destinationWallet)
    : null;
  const slippageBps = parseWebSlippage(body.slippageBps || body.slippage || CONFIG.stopLossExitSlippageBps);
  const wallets = selectedWebSweepWallets(store, userId, body);
  const rows = Array.from({ length: wallets.length });
  const tradeEvents = [];

  await runWithConcurrency(wallets, Math.max(1, Math.min(CONFIG.bundleConcurrency || 3, wallets.length)), async (wallet, index) => {
    const walletRow = {
      ...webWalletRef(wallet),
      ok: false,
      sells: [],
      solSweep: null,
      message: ""
    };

    try {
      const keypair = decryptWallet(wallet);
      const lookup = await getOwnedTokenAccountsWithWarningsCached(keypair.publicKey, { force: true });
      const tokens = sellableTokensFromAccounts(lookup.accounts || []).filter((token) => !tokenMint || token.mint === tokenMint);

      if (!tokens.length) {
        walletRow.message = tokenMint ? "No sellable balance for that token." : "No sellable token balances.";
      }

      for (const token of tokens) {
        try {
          const sell = await sellTokenAmountFromWallet(wallet, token.mint, token.rawAmount, slippageBps, { userId });
          walletRow.sells.push({
            ok: true,
            mint: token.mint,
            uiAmount: rawTokenAmountToUi(token.rawAmount, token.decimals),
            outputSol: lamportsToSol(sell.outputLamports),
            signature: sell.signature,
            feeSol: lamportsToSol(sell.feeLamports || "0")
          });
          tradeEvents.push({
            userId,
            type: "sell",
            source: "web_sell_all_tokens",
            tokenMint: token.mint,
            walletLabel: wallet.label,
            walletPublicKey: wallet.publicKey,
            tokenAmount: sell.tokenAmount,
            solLamportsReceived: sell.outputLamports,
            signature: sell.signature
          });
        } catch (sellError) {
          walletRow.sells.push({
            ok: false,
            mint: token.mint,
            uiAmount: rawTokenAmountToUi(token.rawAmount, token.decimals),
            message: friendlyError(sellError)
          });
        }
      }

      if (destination && walletRow.sells.some((sell) => sell.ok)) {
        const sweep = await drainSolFromWallet(keypair, destination);
        walletRow.solSweep = solTransferResultRow(wallet, sweep);
      }

      walletRow.ok = walletRow.sells.some((sell) => sell.ok) || Boolean(walletRow.solSweep?.ok);
      walletRow.message = walletRow.message || `Sold ${walletRow.sells.filter((sell) => sell.ok).length}/${walletRow.sells.length} token(s).`;
      invalidateWalletReadCache(wallet.publicKey);
      rows[index] = walletRow;
    } catch (error) {
      walletRow.message = friendlyError(error);
      rows[index] = walletRow;
    }
  });

  if (tradeEvents.length) {
    await recordTradeEvents(tradeEvents);
  }
  if (destination) {
    invalidateWalletReadCache(destination.toBase58());
  }
  await audit("web_sell_all_tokens", { userId, tokenMint: tokenMint || "all", destination: destination?.toBase58?.() || null, walletCount: wallets.length, successCount: rows.filter((row) => row.ok).length });
  return {
    action: destination ? "sell-all-and-sweep-sol" : "sell-all-tokens",
    destination: destination?.toBase58?.() || null,
    tokenMint: tokenMint || "all",
    rows,
    summary: `${rows.filter((row) => row.ok).length}/${rows.length} wallet(s) sold token balances.`
  };
}

// One-tap "return funds to my wallet": sell all tokens to SOL, then send all
// tokens' proceeds AND remaining SOL from the selected (session) wallets back
// to the user's connected wallet. User-initiated; composes tested sweeps.
async function webReturnFundsToConnected(userId, body = {}) {
  const destination = parseWebDestination(body.destination || body.destinationWallet);
  const slippageBps = parseWebSlippage(body.slippageBps || CONFIG.stopLossExitSlippageBps);
  const selector = {
    walletIndexes: body.walletIndexes || body.wallets || "all",
    walletGroup: body.walletGroup || body.group || "",
    destination: destination.toBase58(),
    slippageBps
  };

  // 1) Sell every token to SOL and sweep the proceeds back.
  const sell = await webSellAllTokens(userId, selector).catch((error) => ({
    rows: [],
    summary: `Token sell-off skipped: ${friendlyError(error)}`
  }));
  // 2) Sweep any remaining SOL (covers wallets that held only SOL).
  const sweep = await webSweepSol(userId, selector).catch((error) => ({
    rows: [],
    summary: `SOL sweep skipped: ${friendlyError(error)}`
  }));

  const sweptSol = (sweep.rows || []).reduce((sum, row) => sum + (Number(row.sentSol) || 0), 0);
  await audit("web_return_funds_to_connected", {
    userId,
    destination: destination.toBase58(),
    walletCount: (sweep.rows || []).length,
    sweptSol
  });
  return {
    action: "return-funds-to-connected",
    destination: destination.toBase58(),
    shortDestination: shortMint(destination.toBase58()),
    sell,
    sweep,
    sweptSol: Number(sweptSol.toFixed(6)),
    summary: `Returned tokens + ${sweptSol.toFixed(4)} SOL to ${shortMint(destination.toBase58())}.`
  };
}

// Safety recovery: drain every background volume-bot wallet (tokens + SOL) back to
// its stamped origin (volumeSource), or a fallback destination, then prune the ones
// that end empty. Guarantees funds can never be stranded in hidden wallets.
async function webSweepBackgroundWallets(userId, body = {}) {
  const store = await readWalletStore();
  const owned = walletsForOwner(store, userId);
  const volumeWallets = owned.filter((wallet) => wallet.volumeBot || wallet.ephemeral);
  if (!volumeWallets.length) {
    return { action: "sweep-background", walletCount: 0, cleared: 0, sweptSol: 0, summary: "No background wallets to sweep." };
  }
  const slippageBps = parseWebSlippage(body.slippageBps || CONFIG.stopLossExitSlippageBps);
  const explicitDest = String(body.destination || "").trim() ? parseWebDestination(body.destination) : null;
  const firstReal = owned.find((wallet) => !wallet.volumeBot && !wallet.ephemeral);
  const fallbackDest = explicitDest || (firstReal ? new PublicKey(firstReal.publicKey) : null);
  const toPublicKey = (value) => { try { return value ? new PublicKey(value) : null; } catch { return null; } };
  const emptied = [];
  let sweptSol = 0;
  const rows = [];

  await runWithConcurrency(volumeWallets, Math.max(1, Math.min(CONFIG.bundleConcurrency || 3, volumeWallets.length)), async (wallet) => {
    const row = { wallet: shortMint(wallet.publicKey), sells: 0, sentSol: 0, message: "" };
    let destination = toPublicKey(wallet.volumeSource) || fallbackDest;
    try {
      const keypair = decryptWallet(wallet);
      if (destination && keypair.publicKey.equals(destination)) destination = fallbackDest;
      if (!destination) { row.message = "No destination wallet to return to."; return; }
      const lookup = await getOwnedTokenAccountsWithWarningsCached(keypair.publicKey, { force: true }).catch(() => ({ accounts: [] }));
      const tokens = sellableTokensFromAccounts(lookup.accounts || []);
      for (const token of tokens) {
        try { await sellTokenAmountFromWallet(wallet, token.mint, token.rawAmount, slippageBps, { userId }); row.sells += 1; }
        catch { /* leave token if it cannot route; SOL drain still runs */ }
      }
      try {
        const drain = await drainSolFromWallet(keypair, destination);
        const sent = Number(lamportsToSol(drain.sentLamports || 0)) || 0;
        sweptSol += sent;
        row.sentSol = Number(sent.toFixed(6));
      } catch (error) { row.message = friendlyError(error); }
      const remaining = await getSolBalanceCached(keypair.publicKey, { force: true }).catch(() => 0);
      const remainingTokens = await getOwnedTokenAccountsWithWarningsCached(keypair.publicKey, { force: true }).then((l) => sellableTokensFromAccounts(l.accounts || []).length).catch(() => 1);
      if (remaining <= 20_000 && !remainingTokens) emptied.push(wallet.publicKey); // <= ~unsweepable dust + no tokens
    } catch (error) { row.message = friendlyError(error); }
    finally { rows.push(row); }
  });

  let cleared = 0;
  if (emptied.length) {
    const fresh = await readWalletStore();
    const emptiedSet = new Set(emptied);
    const before = fresh.wallets.length;
    fresh.wallets = fresh.wallets.filter((wallet) => !(emptiedSet.has(wallet.publicKey) && (wallet.volumeBot || wallet.ephemeral)));
    if (fresh.wallets.length !== before) { await writeWalletStore(fresh); cleared = before - fresh.wallets.length; }
  }
  await audit("web_sweep_background_wallets", { userId, walletCount: volumeWallets.length, sweptSol, cleared });
  return {
    action: "sweep-background",
    walletCount: volumeWallets.length,
    cleared,
    sweptSol: Number(sweptSol.toFixed(6)),
    rows,
    summary: `Swept ${volumeWallets.length} background wallet(s) and returned ${sweptSol.toFixed(4)} SOL.${cleared ? ` Cleared ${cleared} empty wallet(s).` : ""}`
  };
}

async function webSendSolMany(userId, body = {}) {
  const store = await readWalletStore();
  const walletIndex = parseWebWalletIndex(body.fromWalletIndex || body.walletIndex);
  const wallet = {
    ...getWalletAt(store, walletIndex, userId),
    webIndex: walletIndex
  };
  const destinations = splitWebDestinationList(body.destinations || body.destinationWallets || body.destination);
  const keypair = decryptWallet(wallet);
  const splitAll = Boolean(body.splitAll || body.amountMode === "splitAll");
  let amountLamports;

  if (splitAll) {
    const balance = await getSolBalanceCached(keypair.publicKey, { force: true });
    const estimatedFeeLamports = 5000 * Math.max(1, destinations.length);
    const reserveLamports = CONFIG.buyReserveLamports + estimatedFeeLamports;
    const sendableLamports = balance - reserveLamports;
    if (sendableLamports <= 0) {
      throw new Error(`Not enough SOL after keeping ${lamportsToSol(reserveLamports)} SOL for reserve and fees.`);
    }
    amountLamports = Math.floor(sendableLamports / destinations.length);
  } else {
    amountLamports = solToLamports(parsePositiveNumber(String(body.amountSol || "")));
  }

  if (amountLamports <= 0) {
    throw new Error("Enter a SOL amount greater than zero.");
  }

  const tx = new Transaction();
  for (const destination of destinations) {
    if (keypair.publicKey.equals(destination)) {
      throw new Error("A destination matches the source wallet.");
    }
    await assertDestinationCanReceiveSol(destination, amountLamports);
    tx.add(SystemProgram.transfer({
      fromPubkey: keypair.publicKey,
      toPubkey: destination,
      lamports: amountLamports
    }));
  }

  const signature = await sendLegacyTransaction(tx, [keypair]);
  invalidateWalletReadCache(wallet.publicKey);
  destinations.forEach((destination) => invalidateWalletReadCache(destination.toBase58()));
  await audit("web_send_sol_many", { userId, walletIndex, destinationCount: destinations.length, amountSol: lamportsToSol(amountLamports), signature });
  return {
    action: "send-sol-many",
    source: webWalletRef(wallet),
    amountSol: lamportsToSol(amountLamports),
    destinationCount: destinations.length,
    destinations: destinations.map((destination) => destination.toBase58()),
    signature,
    summary: `Sent ${lamportsToSol(amountLamports)} SOL to ${destinations.length} wallet(s).`
  };
}

function parseWebWalletIndex(value) {
  const index = Number.parseInt(value || "1", 10);
  if (!Number.isInteger(index) || index < 1) {
    throw new Error("Choose a wallet first.");
  }
  return index;
}

function parseWebSlippage(value) {
  return parseSlippage(String(value || "default"), CONFIG.defaultSlippageBps);
}

async function webBuyAmountLamports(wallet, body = {}) {
  if (String(body.amountMode || "").trim().toLowerCase() === "max") {
    const balance = await getSolBalanceCached(new PublicKey(wallet.publicKey), { force: true });
    const amountLamports = balance - CONFIG.buyReserveLamports;
    if (amountLamports <= 0) {
      throw new Error(`Not enough SOL after keeping ${CONFIG.buyReserveSol} SOL safety reserve.`);
    }
    return amountLamports;
  }

  return solToLamports(parsePositiveNumber(String(body.amountSol || "")));
}

async function webBalanceRows(userId, options = {}) {
  const store = await readWalletStore();
  const wallets = walletsForOwner(store, userId);
  const rows = [];

  // One batched RPC primes every wallet's SOL balance; the per-wallet reads
  // below then hit warm cache instead of issuing N round trips.
  await primeSolBalancesBatch(wallets.map((wallet) => wallet.publicKey)).catch(() => 0);

  await runWithConcurrency(wallets, CONFIG.balanceConcurrency, async (wallet, index) => {
    const row = {
      index: index + 1,
      label: wallet.label,
      publicKey: wallet.publicKey,
      shortPublicKey: shortMint(wallet.publicKey),
      sol: null,
      tokens: [],
      warnings: [],
      error: null
    };

    try {
      const keypair = decryptWallet(wallet);
      const balance = await getSolBalanceCached(keypair.publicKey, { force: false });
      row.sol = lamportsToSol(balance);
      row.lamports = String(balance);

      const { accounts, warnings } = await getOwnedTokenAccountsWithWarningsCached(keypair.publicKey, { force: Boolean(options.force) });
      row.warnings = warnings || [];
      row.tokens = accounts
        .filter((account) => account.rawAmount > 0n)
        .slice(0, 12)
        .map((account) => ({
          mint: account.mint,
          shortMint: shortMint(account.mint),
          uiAmount: account.uiAmount,
          rawAmount: account.rawAmount.toString(),
          dexUrl: dexScreenerUrl(account.mint)
        }));
    } catch (error) {
      row.error = friendlyError(error);
    }

    rows[index] = row;
  });

  return rows;
}

async function webConnectedWalletBalance(userId, options = {}) {
  const profile = await webProfileForUser(userId);
  const connected = profile.connectedWallet || null;
  if (!connected?.publicKey) return null;

  const row = {
    label: connected.provider || "Connected Wallet",
    publicKey: connected.publicKey,
    shortPublicKey: connected.shortPublicKey || shortMint(connected.publicKey),
    provider: connected.provider || "Solana Wallet",
    connectedAt: connected.connectedAt || "",
    sol: null,
    lamports: null,
    tokens: [],
    warnings: [],
    error: null,
    viewOnly: true
  };

  try {
    const owner = new PublicKey(connected.publicKey);
    // User-initiated refreshes ride the priority RPC lane and the SOL + token
    // reads run in parallel - this is the "refresh wallet" button path.
    const refreshOpts = { force: Boolean(options.force), priority: Boolean(options.force) };
    const [balance, accountsRead] = await Promise.all([
      getSolBalanceCached(owner, refreshOpts),
      getOwnedTokenAccountsWithWarningsCached(owner, refreshOpts)
    ]);
    row.sol = lamportsToSol(balance);
    row.lamports = String(balance);
    const { accounts, warnings } = accountsRead;
    row.warnings = warnings || [];
    const tokens = accounts
      .filter((account) => account.rawAmount > 0n)
      .slice(0, 12)
      .map((account) => ({
        mint: account.mint,
        shortMint: shortMint(account.mint),
        uiAmount: account.uiAmount,
        rawAmount: account.rawAmount.toString(),
        dexUrl: dexScreenerUrl(account.mint)
      }));
    const metadataByMint = await tokenMetadataMapForMints(tokens.map((token) => token.mint), {
      timeoutMs: 1_800,
      pumpTimeoutMs: 900
    }).catch(() => new Map());
    row.tokens = tokens.map((token) => {
      const metadata = metadataByMint.get(token.mint) || {};
      return {
        ...token,
        symbol: metadata.symbol || token.shortMint,
        name: metadata.name || "",
        imageUrl: metadata.imageUrl || metadata.imageUri || "",
        imageUri: metadata.imageUri || metadata.imageUrl || "",
        metadataUri: metadata.metadataUri || "",
        metadataSourceUsed: metadata.metadataSourceUsed || metadata.source || "",
        metadataMissing: Boolean(metadata.metadataMissing)
      };
    });
  } catch (error) {
    row.error = friendlyError(error);
  }

  return row;
}

async function webPositionSummary(userId, options = {}) {
  const [positions, connectedWallet] = await Promise.all([
    webPositionRows(userId, options),
    webConnectedWalletBalance(userId, { force: Boolean(options.force) }).catch(() => null)
  ]);
  const connectedWalletPositionCount = Array.isArray(connectedWallet?.tokens)
    ? connectedWallet.tokens.filter((token) => token?.mint || token?.tokenMint).length
    : 0;
  return {
    positions,
    connectedWallet,
    connectedWalletPositionCount
  };
}

async function webPositionRows(userId, options = {}) {
  const positions = await buildPositionsOverview(userId, options);
  const limited = positions.slice(0, 25);
  const metadataByMint = await tokenMetadataMapForMints(limited.map((position) => position.tokenMint), {
    timeoutMs: options.fast ? 900 : 2_000,
    pumpTimeoutMs: options.fast ? 650 : 1_000
  }).catch(() => new Map());
  return limited.map((position) => {
    const metadata = metadataByMint.get(position.tokenMint) || {};
    const realized = position.received - position.spent;
    const hasCostBasis = position.spent > 0n || position.received > 0n;
    const openPnl = position.estimatedValueLamports !== null && hasCostBasis
      ? position.estimatedValueLamports + position.received - position.spent
      : null;
    return {
      tokenMint: position.tokenMint,
      shortMint: shortMint(position.tokenMint),
      symbol: metadata.symbol || shortMint(position.tokenMint),
      name: metadata.name || "",
      imageUrl: metadata.imageUrl || metadata.imageUri || "",
      imageUri: metadata.imageUri || metadata.imageUrl || "",
      metadataUri: metadata.metadataUri || "",
      metadataSourceUsed: metadata.metadataSourceUsed || metadata.source || "",
      metadataMissing: Boolean(metadata.metadataMissing),
      dexUrl: dexScreenerUrl(position.tokenMint),
      uiAmount: formatTokenAmount(position.uiAmount),
      uiAmountNum: Number(position.uiAmount) || 0,   // raw token count so the client can mark-to-market live
      walletCount: position.walletCount,
      buys: position.buys,
      sells: position.sells,
      spentSol: lamportsBigToSol(position.spent),
      receivedSol: lamportsBigToSol(position.received),
      realizedSol: formatSignedLamports(realized),
      estimatedValueSol: position.estimatedValueLamports !== null ? lamportsBigToSol(position.estimatedValueLamports) : null,
      openPnlSol: openPnl !== null ? formatSignedLamports(openPnl) : null,
      openPnlPercent: openPnl !== null && position.spent > 0n ? formatPercentMove(openPnl, position.spent) : null,
      viewOnly: Boolean(position.connectedWallet),
      source: position.connectedWallet ? "connected-wallet" : "managed-wallet",
      valuePending: Boolean(position.valuePending),
      valueError: position.valueError || null
    };
  });
}

async function webPnlSummary(userId) {
  const trades = await tradeHistoryRows(userId, null);
  const tokenRows = await pnlRows(userId, null, { groupByToken: true, sortBy: "recent", limit: 25 });
  const metadataByMint = await tokenMetadataMapForMints(tokenRows.map((row) => row.tokenMint), {
    timeoutMs: 2_000,
    pumpTimeoutMs: 1_000
  }).catch(() => new Map());
  const totals = trades.reduce((summary, trade) => {
    if (trade.type === "buy") {
      summary.buys += 1;
      summary.spent += positiveBigIntOrZero(trade.solLamportsSpent);
    } else if (trade.type === "sell") {
      summary.sells += 1;
      summary.received += positiveBigIntOrZero(trade.solLamportsReceived);
    }
    return summary;
  }, { buys: 0, sells: 0, spent: 0n, received: 0n });
  const realized = totals.received - totals.spent;

  return {
    totals: {
      tradeCount: trades.length,
      buys: totals.buys,
      sells: totals.sells,
      spentSol: lamportsBigToSol(totals.spent),
      receivedSol: lamportsBigToSol(totals.received),
      realizedSol: formatSignedLamports(realized)
    },
    tokens: tokenRows.map((row) => {
      const metadata = metadataByMint.get(row.tokenMint) || {};
      return {
        tokenMint: row.tokenMint,
        shortMint: shortMint(row.tokenMint),
        symbol: metadata.symbol || shortMint(row.tokenMint),
        name: metadata.name || "",
        imageUrl: metadata.imageUrl || metadata.imageUri || "",
        imageUri: metadata.imageUri || metadata.imageUrl || "",
        metadataUri: metadata.metadataUri || "",
        metadataSourceUsed: metadata.metadataSourceUsed || metadata.source || "",
        dexImagePresent: Boolean(metadata.dexImagePresent),
        pumpMetadataPresent: Boolean(metadata.pumpMetadataPresent),
        imageFetchStatus: metadata.imageFetchStatus || "",
        metadataMissing: Boolean(metadata.metadataMissing),
        metadataWarnings: Array.isArray(metadata.warnings) ? metadata.warnings.slice(0, 5) : [],
        walletLabel: row.walletLabel,
        buys: row.buys,
        sells: row.sells,
        spentSol: lamportsBigToSol(row.spent),
        receivedSol: lamportsBigToSol(row.received),
        realizedSol: formatSignedLamports(row.received - row.spent),
        firstBuyAt: row.firstBuyAt,
        lastSellAt: row.lastSellAt,
        lastTradeAt: row.lastTradeAt,
        holdTime: formatPnlHoldDuration(row),
        dexUrl: dexScreenerUrl(row.tokenMint)
      };
    }),
    trades: trades.slice(0, 50).map((trade) => ({
      id: trade.id,
      timestamp: trade.timestamp,
      type: trade.type,
      walletLabel: trade.walletLabel || shortMint(trade.walletPublicKey || ""),
      walletPublicKey: trade.walletPublicKey || null,
      tokenMint: trade.tokenMint,
      shortMint: shortMint(trade.tokenMint || ""),
      solAmount: trade.type === "buy"
        ? lamportsBigToSol(positiveBigIntOrZero(trade.solLamportsSpent))
        : lamportsBigToSol(positiveBigIntOrZero(trade.solLamportsReceived)),
      tokenAmount: trade.tokenAmount || null,
      source: trade.source ? formatTradeSource(trade.source) : null,
      signature: trade.signature || null,
      dexUrl: trade.tokenMint ? dexScreenerUrl(trade.tokenMint) : null
    }))
  };
}

async function webPnlCard(userId, tokenMintText) {
  const tokenMint = parsePublicKey(String(tokenMintText || "")).toBase58();
  const rows = await pnlRows(userId, tokenMint, { groupByToken: true, limit: 1 });
  if (rows.length === 0) {
    const error = new Error("No PnL data found for that token. Cards only work for buys/sells made from this account.");
    error.statusCode = 404;
    throw error;
  }

  const row = rows[0];
  const metadata = await getDexTokenMetadata(row.tokenMint);
  // Use the SAME Higgs win/loss flex card as the TG /flex (photoreal slime art — green for wins,
  // blood-red for losses); fall back to the classic gradient card only if the slime renderer throws.
  let png = null;
  try { png = await renderSlimeCard(slimeDataFromPnlRow(row, metadata)); } catch {}
  if (!png) png = await renderPnlCard(row, metadata);
  return {
    png,
    filename: `pnl-card-${sanitizeFilenamePart(metadata.symbol || row.tokenMint)}.png`
  };
}

async function webTxAudit(signatureText) {
  const signature = String(signatureText || "").trim();
  if (!/^[1-9A-HJ-NP-Za-km-z]{40,100}$/.test(signature)) {
    throw new Error("Paste a valid Solana transaction signature.");
  }

  const tx = await rpcRead("get transaction audit", (c) => c.getParsedTransaction(signature, {
    commitment: "finalized",
    maxSupportedTransactionVersion: 0
  }));
  if (!tx) {
    return {
      signature,
      status: "not_found",
      message: "Finalized transaction was not found by the configured RPC. Try again later or check the signature on Solscan.",
      explorerUrl: `https://solscan.io/tx/${signature}`
    };
  }

  const solDeltas = parseSolBalanceDeltas(tx);
  const tokenDeltas = parseTokenBalanceDeltas(tx);
  const createdAtas = detectCreatedAssociatedTokenAccounts(tx);
  const swapActivity = detectSwapActivity(tx);
  const feePayer = solDeltas[0]?.account || "";

  return {
    signature,
    status: tx.meta?.err ? "failed" : "finalized",
    error: tx.meta?.err || null,
    slot: tx.slot,
    blockTime: tx.blockTime || null,
    blockTimeLabel: tx.blockTime ? new Date(tx.blockTime * 1000).toISOString() : "",
    feeLamports: tx.meta?.fee || 0,
    feeSol: lamportsToSol(tx.meta?.fee || 0),
    feePayer,
    signer: feePayer,
    programs: swapActivity.programs,
    swapActivity,
    solDeltas,
    tokenDeltas,
    createdAssociatedTokenAccounts: createdAtas,
    logs: tx.meta?.logMessages || [],
    explorerUrl: `https://solscan.io/tx/${signature}`,
    shouldRefreshBalances: !tx.meta?.err && (solDeltas.length > 0 || tokenDeltas.length > 0 || createdAtas.length > 0)
  };
}

function parseSolBalanceDeltas(tx) {
  const accountKeys = tx.transaction?.message?.accountKeys || [];
  const pre = tx.meta?.preBalances || [];
  const post = tx.meta?.postBalances || [];
  return accountKeys.map((key, index) => {
    const pubkey = key.pubkey?.toBase58?.() || key.pubkey?.toString?.() || key.toString?.() || String(key);
    const before = Number(pre[index] || 0);
    const after = Number(post[index] || 0);
    const delta = after - before;
    if (delta === 0) return null;
    return {
      account: pubkey,
      shortAccount: shortMint(pubkey),
      beforeSol: lamportsToSol(before),
      afterSol: lamportsToSol(after),
      deltaSol: formatSignedLamports(BigInt(delta))
    };
  }).filter(Boolean);
}

function parseTokenBalanceDeltas(tx) {
  const byKey = new Map();
  const collect = (balance, side) => {
    if (!balance?.mint) return;
    const owner = balance.owner || "";
    const key = `${balance.accountIndex}:${owner}:${balance.mint}`;
    const current = byKey.get(key) || {
      accountIndex: balance.accountIndex,
      owner,
      shortOwner: owner ? shortMint(owner) : "",
      mint: balance.mint,
      shortMint: shortMint(balance.mint),
      decimals: balance.uiTokenAmount?.decimals ?? null,
      preRaw: 0n,
      postRaw: 0n
    };
    const amount = BigInt(balance.uiTokenAmount?.amount || 0);
    if (side === "pre") current.preRaw = amount;
    else current.postRaw = amount;
    byKey.set(key, current);
  };

  for (const balance of tx.meta?.preTokenBalances || []) collect(balance, "pre");
  for (const balance of tx.meta?.postTokenBalances || []) collect(balance, "post");

  return [...byKey.values()].map((row) => {
    const delta = row.postRaw - row.preRaw;
    const decimals = Number.isInteger(row.decimals) ? row.decimals : 0;
    return {
      ...row,
      preAmount: rawTokenAmountToUi(row.preRaw, decimals),
      postAmount: rawTokenAmountToUi(row.postRaw, decimals),
      deltaAmount: `${delta < 0n ? "-" : ""}${rawTokenAmountToUi(delta < 0n ? -delta : delta, decimals)}`
    };
  }).filter((row) => row.preRaw !== row.postRaw);
}

function detectCreatedAssociatedTokenAccounts(tx) {
  return flattenParsedInstructions(tx)
    .filter((instruction) => {
      const type = String(instruction.parsed?.type || "").toLowerCase();
      const program = String(instruction.program || instruction.programId || "").toLowerCase();
      return type.includes("create") && (type.includes("associated") || program.includes("associated"));
    })
    .map((instruction) => ({
      type: instruction.parsed?.type || "create",
      account: instruction.parsed?.info?.account || instruction.parsed?.info?.associatedAccount || "",
      mint: instruction.parsed?.info?.mint || "",
      wallet: instruction.parsed?.info?.wallet || instruction.parsed?.info?.owner || "",
      program: instruction.program || String(instruction.programId || "")
    }));
}

function detectSwapActivity(tx) {
  const instructions = flattenParsedInstructions(tx);
  const logs = tx.meta?.logMessages || [];
  const programs = uniqueStrings(instructions.map((instruction) => (
    instruction.programId?.toBase58?.() || instruction.programId?.toString?.() || instruction.program || ""
  )).filter(Boolean)).slice(0, 20);
  const lowerLogs = logs.join("\n").toLowerCase();
  const swapLike = /jupiter|raydium|orca|meteora|pump|swap|route/.test(lowerLogs)
    || instructions.some((instruction) => /swap|route/i.test(String(instruction.parsed?.type || instruction.program || "")));
  return {
    detected: swapLike,
    programs,
    summary: swapLike ? "Swap/route activity detected from parsed instructions or logs." : "No obvious swap activity detected in parsed logs."
  };
}

function flattenParsedInstructions(tx) {
  const top = tx.transaction?.message?.instructions || [];
  const inner = (tx.meta?.innerInstructions || []).flatMap((group) => group.instructions || []);
  return [...top, ...inner].filter(Boolean);
}

async function webKolScan(userId, mode = "hot", wallet = "") {
  let result;
  if (String(mode || "").trim().toLowerCase() === "slimewire") {
    const traders = await webSlimewireTraders();
    result = {
      configured: true,
      label: "Top SlimeWire Traders",
      message: traders.length
        ? "Top opt-in SlimeWire traders by saved web trade history."
        : "No opt-in SlimeWire traders yet. Turn on the leaderboard option in Profile after you have trade history.",
      kolCount: traders.length,
      kols: traders,
      rows: [],
      source: "slimewire"
    };
  } else {
    result = await buildKolScan(userId, mode, wallet);
  }
  rememberKolScanResult(mode, wallet, result);
  return result;
}

function rememberKolScanResult(mode = "hot", wallet = "", scan = {}) {
  const key = `${String(mode || "hot").toLowerCase()}:${String(wallet || "").trim().toLowerCase() || "global"}`;
  kolScanSharedCache.set(key, { cachedAt: Date.now(), value: scan });
  if (kolScanSharedCache.size > 20) {
    const oldest = [...kolScanSharedCache.entries()].sort((a, b) => Number(a[1]?.cachedAt || 0) - Number(b[1]?.cachedAt || 0))[0]?.[0];
    if (oldest) kolScanSharedCache.delete(oldest);
  }
  void persistKolProfilesFromScan(mode, wallet, scan).catch(() => {});
}

function kolDumpStatsExternalKey(kolId = "all") {
  return externalCacheKey(`kol:dumpstats:${String(kolId || "all").trim().toLowerCase()}`, "global");
}

function kolProfilesExternalKey() {
  return externalCacheKey("kol:profiles:history", "global");
}

function kolProfileId(kol = {}) {
  return firstString(kol.id, kol.kolId, kol.wallet, kol.twitter, kol.handle, kol.name, kol.shortWallet).replace(/\s+/g, "_").toLowerCase();
}

function kolProfilesFromScan(scan = {}, source = "kol_scan") {
  const profiles = [];
  if (Array.isArray(scan?.kols)) {
    profiles.push(...scan.kols.map((kol) => ({ ...kol, source: kol.source || source, lastSeenAt: new Date().toISOString() })));
  }
  if (Array.isArray(scan?.rows)) {
      const byWallet = new Map();
      for (const row of scan.rows) {
        const wallet = firstString(row.wallet, row.kolWallet, row.owner, row.traderWallet);
        if (!wallet || byWallet.has(wallet)) continue;
        byWallet.set(wallet, {
          wallet,
          name: firstString(row.kolName, row.name, row.twitter, shortMint(wallet)),
          twitter: stripAt(firstString(row.twitter, row.handle)),
          profileUrl: firstString(row.profileUrl, row.kolscanUrl, row.kolScanUrl, row.links?.kolscan),
          xUrl: firstString(row.xUrl, row.twitterUrl, row.links?.x, row.twitter ? `https://x.com/${stripAt(row.twitter)}` : ""),
          websiteUrl: firstString(row.websiteUrl, row.website, row.links?.website),
          tokenMint: firstString(row.tokenMint, row.mint, row.address),
          symbol: firstString(row.symbol, row.baseSymbol),
          currentPositionCount: Number(firstMeaningfulNumber(row.currentPositionCount, row.positionsCount, row.positionCount) || 0),
          trades: firstMeaningfulNumber(row.callsTracked, row.trades, row.tradeCount, row.kolCount, row.kol_count, row.buyCount, row.buy_count) || 0,
          callsTracked: firstMeaningfulNumber(row.callsTracked, row.trades, row.tradeCount, row.kolCount, row.kol_count, row.buyCount, row.buy_count) || 0,
          dumpRiskPercent: row.dumpRiskPercent,
          soldWithin15mPercent: row.soldWithin15mPercent,
          soldWithin60mPercent: row.soldWithin60mPercent,
          medianHoldMinutes: row.medianHoldMinutes,
          medianPostSignalDrawdownPercent: row.medianPostSignalDrawdownPercent,
          followerSurvival30mPercent: row.followerSurvival30mPercent,
          followerSurvival60mPercent: row.followerSurvival60mPercent,
          source: row.source || "kol_signal_row",
          lastSeenAt: new Date().toISOString()
        });
      }
      profiles.push(...byWallet.values());
  }
  return profiles;
}

function mergeKolProfiles(...profileGroups) {
  const byId = new Map();
  for (const profile of profileGroups.flat().filter(Boolean)) {
    const id = kolProfileId(profile);
    if (!id) continue;
    const existing = byId.get(id);
    const nextTrades = Number(profile.callsTracked || profile.trades || profile.tradeCount || 0);
    const existingTrades = Number(existing?.callsTracked || existing?.trades || existing?.tradeCount || 0);
    const merged = existing ? {
      ...existing,
      ...profile,
      walletAddresses: uniqueStrings([
        ...(Array.isArray(existing.walletAddresses) ? existing.walletAddresses : []),
        ...(Array.isArray(profile.walletAddresses) ? profile.walletAddresses : []),
        existing.wallet,
        profile.wallet,
        existing.address,
        profile.address,
        existing.publicKey,
        profile.publicKey
      ].filter(Boolean)),
      callsTracked: Math.max(Number(existing.callsTracked || existing.trades || 0), Number(profile.callsTracked || profile.trades || 0)),
      trades: Math.max(existingTrades, nextTrades),
      firstSeenAt: existing.firstSeenAt || profile.firstSeenAt || profile.lastSeenAt || new Date().toISOString(),
      lastSeenAt: profile.lastSeenAt || existing.lastSeenAt || new Date().toISOString()
    } : {
      ...profile,
      walletAddresses: uniqueStrings([profile.wallet, profile.address, profile.publicKey, ...(Array.isArray(profile.walletAddresses) ? profile.walletAddresses : [])].filter(Boolean)),
      firstSeenAt: profile.firstSeenAt || profile.lastSeenAt || new Date().toISOString(),
      lastSeenAt: profile.lastSeenAt || new Date().toISOString()
    };
    byId.set(id, merged);
  }
  return [...byId.values()];
}

function cachedKolProfiles() {
  const profiles = [];
  for (const cached of kolScanSharedCache.values()) {
    profiles.push(...kolProfilesFromScan(cached?.value, cached?.value?.source || "kol_scan"));
  }
  if (Array.isArray(kolProfileHistoryCache.value)) profiles.push(...kolProfileHistoryCache.value);
  return mergeKolProfiles(profiles);
}

async function storedKolProfiles() {
  const current = cachedKolProfiles();
  const external = await cacheGetJson(kolProfilesExternalKey()).catch(() => null);
  const externalRows = Array.isArray(external?.value?.profiles) ? external.value.profiles : Array.isArray(external?.profiles) ? external.profiles : [];
  const postgresRows = await readPostgresKolProfiles().catch(() => []);
  const merged = mergeKolProfiles(postgresRows, externalRows, current).slice(0, 500);
  if (merged.length) kolProfileHistoryCache = { cachedAt: Date.now(), value: merged };
  return merged;
}

async function persistKolProfilesFromScan(mode = "hot", wallet = "", scan = {}) {
  const incoming = kolProfilesFromScan(scan, scan?.source || `kol_${mode || "scan"}`);
  if (!incoming.length) return false;
  const external = await cacheGetJson(kolProfilesExternalKey()).catch(() => null);
  const externalRows = Array.isArray(external?.value?.profiles) ? external.value.profiles : Array.isArray(external?.profiles) ? external.profiles : [];
  const merged = mergeKolProfiles(externalRows, kolProfileHistoryCache.value || [], incoming).slice(0, 250);
  kolProfileHistoryCache = { cachedAt: Date.now(), value: merged };
  kolDumpStatsCache.clear();
  await cacheSetJson(kolProfilesExternalKey(), displayCacheEnvelope({
    profiles: merged,
    count: merged.length,
    updatedAt: new Date().toISOString(),
    source: "cached-kol-api-profile-rows"
  }), KOL_PROFILE_HISTORY_TTL_MS).catch(() => false);
  void persistPostgresKolProfiles(merged).catch(() => {});
  void persistPostgresKolSignalRows(scan?.rows || []).catch(() => {});
  return true;
}

function kolDumpRiskLabel(dumpRiskPercent, callsTracked) {
  if (Number(callsTracked || 0) < 5) return "Mixed";
  const risk = Number(dumpRiskPercent || 0);
  if (risk >= 50) return "High Dump Risk";
  if (risk >= 30) return "Dump Risk";
  if (risk <= 15) return "Trusted Flow";
  return "Mixed";
}

function computeKolDumpStatsFromProfile(kol = {}) {
  const kolId = kolProfileId(kol);
  const callsTracked = Number(firstMeaningfulNumber(kol.callsTracked, kol.trades, kol.tradeCount, kol.buyCount, kol.buy_count) || 0);
  const explicitDumpRisk = firstMeaningfulNumber(kol.dumpRiskPercent, kol.soldWithin60mPercent, kol.sold_within_60m_percent);
  const hasExplicitDumpRisk = explicitDumpRisk !== null && Number.isFinite(Number(explicitDumpRisk));
  const dumpRiskPercent = hasExplicitDumpRisk ? Math.max(0, Math.min(100, Math.round(Number(explicitDumpRisk)))) : 0;
  const lowData = !hasExplicitDumpRisk || callsTracked < 5;
  const riskLabel = lowData ? "Mixed" : kolDumpRiskLabel(dumpRiskPercent, callsTracked);
  const sourceNote = kol.source ? `Source: ${String(kol.source).replace(/_/g, " ")}.` : "Source: cached KOL profile row.";
  const reasons = lowData
    ? ["Low local sell-window history. Wallet-based until social signal data is available."]
    : dumpRiskPercent >= 30
      ? ["Fast sell-window history is elevated for tracked calls."]
      : ["Tracked sell-window history is not showing high dump pressure."];
  const walletAddresses = uniqueStrings([kol.wallet, kol.owner, kol.address, kol.publicKey, ...(Array.isArray(kol.walletAddresses) ? kol.walletAddresses : [])].filter(Boolean));
  const externalLinks = [
    { label: "KOLscan", url: firstString(kol.kolscanUrl, kol.kolScanUrl, kol.profileUrl, kol.links?.kolscan) },
    { label: "X", url: firstString(kol.xUrl, kol.twitterUrl, kol.links?.x, kol.twitter ? `https://x.com/${stripAt(kol.twitter)}` : "") },
    { label: "Website", url: firstString(kol.websiteUrl, kol.website, kol.links?.website) }
  ].filter((link) => /^https?:\/\//i.test(String(link.url || "")));
  const currentPositionCount = Number(firstMeaningfulNumber(kol.currentPositionCount, kol.positionsCount, kol.positionCount) || 0);
  const primaryWallet = walletAddresses[0] || firstString(kol.wallet, kol.owner, kol.address, kol.publicKey);
  return {
    kolId,
    displayName: firstString(kol.displayName, kol.name, kol.twitter ? `@${stripAt(kol.twitter)}` : "", kol.shortWallet, kol.wallet ? shortMint(kol.wallet) : "KOL Wallet"),
    handle: stripAt(firstString(kol.handle, kol.twitter, kol.x)),
    walletAddresses,
    callsTracked,
    currentPositionCount,
    lastTokenMint: firstString(kol.tokenMint, kol.mint),
    lastTokenSymbol: firstString(kol.symbol, kol.baseSymbol),
    dumpRiskPercent,
    medianHoldMinutes: Number(firstMeaningfulNumber(kol.medianHoldMinutes, kol.median_hold_minutes) || 0) || null,
    soldWithin15mPercent: Number(firstMeaningfulNumber(kol.soldWithin15mPercent, kol.sold_within_15m_percent) || 0) || null,
    soldWithin60mPercent: hasExplicitDumpRisk ? dumpRiskPercent : null,
    medianPostSignalDrawdownPercent: Number(firstMeaningfulNumber(kol.medianPostSignalDrawdownPercent, kol.median_drawdown_percent) || 0) || null,
    followerSurvival30mPercent: Number(firstMeaningfulNumber(kol.followerSurvival30mPercent, kol.survival30mPercent) || 0) || null,
    followerSurvival60mPercent: Number(firstMeaningfulNumber(kol.followerSurvival60mPercent, kol.survival60mPercent) || 0) || null,
    riskLabel,
    confidence: lowData ? "low" : callsTracked >= 12 ? "high" : "medium",
    lowData,
    historySource: String(kol.source || "cached-kol-profile").slice(0, 80),
    firstSeenAt: kol.firstSeenAt || "",
    lastSeenAt: kol.lastSeenAt || "",
    externalLinks: [
      ...externalLinks,
      { label: "Solscan", url: primaryWallet ? `https://solscan.io/account/${encodeURIComponent(primaryWallet)}` : "" },
      { label: "KOLscan", url: primaryWallet ? kolscanAccountUrl(primaryWallet) : "" }
    ].filter((link, index, links) => /^https?:\/\//i.test(String(link.url || ""))
      && links.findIndex((candidate) => String(candidate.url || "") === String(link.url || "")) === index).slice(0, 6),
    reasons: [...reasons, sourceNote],
    updatedAt: new Date().toISOString()
  };
}

async function webKolDumpStats(kolId = "", options = {}) {
  const id = String(kolId || "all").trim().toLowerCase() || "all";
  const force = Boolean(options.force);
  if (force) {
    const mode = normalizeKolMode(options.mode || "hot");
    const wallet = String(options.wallet || "").trim();
    await Promise.race([
      webKolScan(options.userId || "guest", mode, wallet),
      new Promise((resolve) => setTimeout(() => resolve(null), 3_800))
    ]).catch(() => null);
  }
  const cached = force ? null : kolDumpStatsCache.get(id);
  if (!force && cached?.value && Date.now() - Number(cached.cachedAt || 0) < KOL_DUMP_STATS_TTL_MS) {
    return { ...cached.value, cacheHit: true, cacheSource: "memory" };
  }
  const external = force ? null : await cacheGetJson(kolDumpStatsExternalKey(id)).catch(() => null);
  if (!force && external?.value && Number.isFinite(Number(external.cachedAt)) && Date.now() - Number(external.cachedAt) < KOL_DUMP_STATS_TTL_MS) {
    kolDumpStatsCache.set(id, { cachedAt: Number(external.cachedAt), value: external.value });
    return { ...external.value, cacheHit: true, cacheSource: kvProviderName() };
  }
  const [profiles, persistedStats] = await Promise.all([
    storedKolProfiles(),
    readPostgresKolDumpStats().catch(() => [])
  ]);
  const persistedById = new Map((Array.isArray(persistedStats) ? persistedStats : [])
    .filter((row) => row?.kolId)
    .map((row) => [String(row.kolId).toLowerCase(), row]));
  const seenStats = new Set();
  const stats = profiles.map((profile) => {
    const computed = computeKolDumpStatsFromProfile(profile);
    const key = String(computed.kolId || "").toLowerCase();
    const persisted = persistedById.get(key);
    if (!persisted) {
      if (key) seenStats.add(key);
      return computed;
    }
    if (key) seenStats.add(key);
    const mergedLinks = [...(Array.isArray(computed.externalLinks) ? computed.externalLinks : []), ...(Array.isArray(persisted.externalLinks) ? persisted.externalLinks : [])]
      .filter((link, index, links) => /^https?:\/\//i.test(String(link?.url || ""))
        && links.findIndex((candidate) => String(candidate?.url || "") === String(link?.url || "")) === index)
      .slice(0, 6);
    return {
      ...computed,
      ...persisted,
      displayName: firstString(computed.displayName, persisted.displayName),
      handle: firstString(computed.handle, persisted.handle),
      walletAddresses: uniqueStrings([...(Array.isArray(computed.walletAddresses) ? computed.walletAddresses : []), ...(Array.isArray(persisted.walletAddresses) ? persisted.walletAddresses : [])]).slice(0, 6),
      externalLinks: mergedLinks,
      reasons: uniqueStrings([...(Array.isArray(persisted.reasons) ? persisted.reasons : []), ...(Array.isArray(computed.reasons) ? computed.reasons : [])]).slice(0, 6),
      cacheSource: "postgres-history"
    };
  });
  for (const persisted of persistedById.values()) {
    const key = String(persisted.kolId || "").toLowerCase();
    if (!key || seenStats.has(key)) continue;
    seenStats.add(key);
    stats.push({
      ...persisted,
      externalLinks: Array.isArray(persisted.externalLinks) ? persisted.externalLinks.slice(0, 6) : [],
      reasons: Array.isArray(persisted.reasons) && persisted.reasons.length
        ? persisted.reasons.slice(0, 6)
        : ["Loaded from saved KOL dump history. Refresh KOL Tracker for the newest wallet-position rows."],
      cacheSource: "postgres-history"
    });
  }
  const filtered = id === "all" ? stats : stats.filter((item) => String(item.kolId || "").toLowerCase() === id);
  const value = {
    stats: filtered,
    count: filtered.length,
    updatedAt: new Date().toISOString(),
    cacheHit: false,
    cacheSource: force ? "forced-kol-refresh" : "local-cache",
    message: filtered.length
      ? "KOL Dump Detector uses cached KOL API/profile rows and local wallet-position signals only."
      : "No cached KOL profiles yet. Refresh KOL Tracker to warm the detector."
  };
  kolDumpStatsCache.set(id, { cachedAt: Date.now(), value });
  await cacheSetJson(kolDumpStatsExternalKey(id), displayCacheEnvelope(value), KOL_DUMP_STATS_TTL_MS).catch(() => false);
  void persistPostgresKolDumpStats(filtered).catch(() => {});
  return value;
}

async function webCreateKolEntry(userId, body = {}) {
  const store = await readWalletStore();
  const wallets = webSelectedWallets(store, userId, body.walletIndexes, body.walletGroup);
  return webCreateManagedBuyPlan(userId, wallets, body, {
    source: "kol_tracker",
    label: "KOL copy plan",
    auditType: "web_create_kol_copy_plan",
    defaultSellDelay: "5",
    defaultTakeProfitPct: "25",
    defaultStopLossPct: "8",
    defaultSlippageBps: 400
  });
}

async function webCreateKolCopyWallet(userId, body = {}) {
  if (!CONFIG.solanaTrackerApiKey) {
    throw new Error("Live copy-wallet watches need SOLANA_TRACKER_API_KEY. You can still paste a wallet, scan its current positions, and use Copy Plan on any token without this.");
  }

  const copyWallet = parsePublicKey(String(body.copyWallet || body.wallet || "")).toBase58();
  const store = await readWalletStore();
  const wallets = webSelectedWallets(store, userId, body.walletIndexes, body.walletGroup);
  const amountSol = parsePositiveNumber(String(body.amountSol || ""));
  const sellDelaySeconds = parseOptionalSellDelaySeconds(firstString(body.sellDelay, body.sellDelaySeconds, "5"));
  const takeProfitPct = parseTakeProfitPercent(String(body.takeProfitPct || "25"));
  const stopLossPct = parseOptionalTriggerPercent(String(body.stopLossPct || "8"));
  const loopCount = parseLoopCount(String(body.loopCount || "1"));
  const loopDelaySeconds = parseLoopDelaySeconds(String(body.loopDelay || body.loopDelaySeconds || "0"));
  const slippageBps = parseWebSlippage(body.slippageBps || 400);
  const walletIndexes = wallets.map((wallet, index) => Number(wallet.webIndex || index + 1));
  const walletTakeProfitTargets = parseWebWalletTakeProfitTargets(body, walletIndexes);
  const walletStopLossTargets = parseWebWalletStopLossTargets(body, walletIndexes);
  ensureTimedPlanHasExit({
    sellDelaySeconds,
    takeProfitPct,
    stopLossPct,
    walletTakeProfitTargets,
    walletStopLossTargets
  });
  const initialSignals = await fetchKolWalletTradeSignals(copyWallet, "fresh", {
    limit: 12,
    cacheTtlMs: Math.max(0, Math.min(CONFIG.kolCopyScanIntervalMs - 500, CONFIG.solanaTrackerKolCacheTtlMs))
  }).catch(() => []);

  const plan = {
    id: crypto.randomUUID(),
    status: "copy_wallet_watch",
    userId,
    chatId: null,
    source: "kol_copy_wallet",
    copyWallet,
    walletSelector: String(body.walletGroup || "").trim()
      ? `group:${String(body.walletGroup).trim()}`
      : Array.isArray(body.walletIndexes)
        ? body.walletIndexes.join(",")
        : "selected",
    amountSol,
    sellDelayMinutes: sellDelaySeconds / 60,
    sellDelaySeconds,
    sellPercent: 100,
    triggerSellPercent: 100,
    loopCount,
    loopDelaySeconds,
    takeProfitPct,
    stopLossPct,
    takeProfitMode: walletTakeProfitTargets ? "wallets" : "single",
    stopLossMode: walletStopLossTargets ? "wallets" : "single",
    takeProfitLadder: [],
    autoBundle: false,
    slippageBps,
    seenTokenMints: uniqueStrings(initialSignals.map((row) => row.tokenMint).filter(Boolean)).slice(-80),
    createdAt: new Date().toISOString(),
    lastScanAt: null,
    wallets: wallets.map((wallet, index) => {
      const walletIndex = walletIndexes[index];
      return {
        label: wallet.label,
        publicKey: wallet.publicKey,
        walletIndex,
        takeProfitPct: walletTakeProfitTargets ? walletTakeProfitTargets[String(walletIndex)] || null : null,
        stopLossPct: walletStopLossTargets ? walletStopLossTargets[String(walletIndex)] || null : null,
        status: "pending",
        results: []
      };
    }),
    results: [
      `Watching ${shortMint(copyWallet)} for the next new buy.`,
      `Initial recent buys ignored: ${initialSignals.length}`
    ]
  };

  const plans = await readTradePlans();
  plans.plans.push(plan);
  await writeTradePlans(plans);
  await audit("web_create_kol_copy_wallet_watch", {
    userId,
    planId: plan.id,
    copyWallet,
    wallets: wallets.map(publicWallet),
    amountSol,
    sellDelaySeconds,
    takeProfitPct,
    stopLossPct,
    walletTakeProfitTargets,
    walletStopLossTargets,
    loopCount,
    loopDelaySeconds,
    slippageBps
  });
  setTimeout(() => void processTradePlans().catch((error) => {
    console.error("Web KOL copy-wallet watch failed:", error.message);
  }), 1_000);

  return {
    id: plan.id,
    type: "kol_copy_wallet",
    copyWallet,
    shortWallet: shortMint(copyWallet),
    walletCount: wallets.length,
    amountSol,
    takeProfitPct,
    stopLossPct,
    takeProfitSummary: formatPlanTakeProfitSummary(plan),
    stopLossSummary: formatPlanStopLossSummary(plan),
    sellDelaySeconds,
    loopCount,
    loopDelaySeconds,
    slippageBps,
    scanIntervalMs: CONFIG.kolCopyScanIntervalMs,
    results: plan.results,
    message: `Copy Wallet armed for ${shortMint(copyWallet)}. It ignores already-seen buys and watches for the next new buy.`
  };
}

// FREE KOL leaderboard from kolscan.io — no API key, no rate cap. kolscan SSRs its KOL PnL board into
// streamed Next.js RSC chunks (self.__next_f.push([1,"…"])); we concatenate every chunk's JSON-unescaped
// string, then bracket-match the `initLeaderboard` array → ~150 KOLs with name, wallet, X handle, SOL
// profit and win/loss. This gives ROI + win-rate + pfps (via the X handle) for free, so the Copy tab is
// never starved by MadeOnSol's 200/day cap and we lean far less on paid Solana Tracker for KOL data.
const kolscanLeaderboardCache = { at: 0, rows: [] };
const KOLSCAN_TTL_MS = 10 * 60 * 1000;
function extractKolscanLeaderboard(html) {
  const NEEDLE = 'push([1,"';
  let clean = "", from = 0;
  while (true) {
    const open = html.indexOf(NEEDLE, from);
    if (open < 0) break;
    const strStart = open + "push([1,".length;
    let inStr = false, esc = false, strEnd = -1;
    for (let j = strStart; j < html.length; j++) {
      const c = html[j];
      if (!inStr) { if (c === '"') inStr = true; continue; }
      if (esc) { esc = false; continue; }
      if (c === "\\") { esc = true; continue; }
      if (c === '"') { strEnd = j + 1; break; }
    }
    if (strEnd < 0) break;
    try { clean += JSON.parse(html.slice(strStart, strEnd)); } catch {}
    from = strEnd;
  }
  const a = clean.indexOf('"initLeaderboard"');
  if (a < 0) return [];
  const lb = clean.indexOf("[", a);
  if (lb < 0) return [];
  let depth = 0, s2 = false, e2 = false, end = -1;
  for (let j = lb; j < clean.length; j++) {
    const c = clean[j];
    if (s2) { if (e2) e2 = false; else if (c === "\\") e2 = true; else if (c === '"') s2 = false; continue; }
    if (c === '"') s2 = true;
    else if (c === "[") depth++;
    else if (c === "]") { depth--; if (depth === 0) { end = j + 1; break; } }
  }
  if (end < 0) return [];
  try { return JSON.parse(clean.slice(lb, end)); } catch { return []; }
}
async function fetchKolscanLeaderboard() {
  if (kolscanLeaderboardCache.rows.length && Date.now() - kolscanLeaderboardCache.at < KOLSCAN_TTL_MS) {
    return kolscanLeaderboardCache.rows;
  }
  try {
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 9000);
    const res = await fetch("https://kolscan.io/leaderboard", {
      headers: { "User-Agent": "Mozilla/5.0 (compatible; SlimeWire/1.0)", Accept: "text/html" },
      signal: ctrl.signal
    }).catch(() => null);
    clearTimeout(timer);
    if (!res || !res.ok) return kolscanLeaderboardCache.rows;
    const arr = extractKolscanLeaderboard(await res.text());
    const rows = arr.map((e) => {
      const wins = Number(e.wins || 0), losses = Number(e.losses || 0), trades = wins + losses;
      const profit = Number(e.profit || 0);
      return webKolSummaryRow({
        wallet: e.wallet_address,
        name: e.name || (e.twitter ? stripAt(twitterHandleFromUrl(e.twitter)) : ""),
        twitter: e.twitter,
        telegram: e.telegram,
        avatar: firstString(e.pfp, e.avatar),
        realizedSol: profit,
        roiLabel: `${profit >= 0 ? "+" : ""}${profit.toFixed(profit >= 100 ? 0 : 1)} SOL`,
        winRatePct: trades ? Math.round(1000 * wins / trades) / 10 : null,
        trades,
        source: "kolscan"
      });
    }).filter((k) => k.wallet);
    if (rows.length) { kolscanLeaderboardCache.at = Date.now(); kolscanLeaderboardCache.rows = rows; }
    return kolscanLeaderboardCache.rows;
  } catch { return kolscanLeaderboardCache.rows; }
}
async function buildKolScan(userId, mode = "hot", wallet = "") {
  const safeMode = normalizeKolMode(mode);
  const customWallet = String(wallet || "").trim();
  const scanState = nextSniperScanState(`web:${userId}`, `kol:${safeMode}:${customWallet || "global"}`);
  const hasMadeOnSol = Boolean(CONFIG.madeOnSolApiKey);
  const hasSolanaTracker = Boolean(CONFIG.solanaTrackerApiKey);
  const base = {
    mode: safeMode,
    label: kolModeLabel(safeMode),
    description: kolModeDescription(safeMode),
    configured: hasMadeOnSol || hasSolanaTracker,
    source: hasMadeOnSol && hasSolanaTracker ? "mixed" : hasMadeOnSol ? "made_on_sol" : "solana_tracker",
    apiBase: hasMadeOnSol ? CONFIG.madeOnSolApiBase : CONFIG.solanaTrackerApiBase,
    sources: {
      madeOnSol: hasMadeOnSol,
      solanaTracker: hasSolanaTracker,
      localWallet: Boolean(customWallet),
      solanaTrackerFallback: CONFIG.kolUseSolanaTrackerFallback,
      solanaTrackerPeriodEndpoint: CONFIG.solanaTrackerKolUsePeriodEndpoint
    },
    kolCount: 0,
    kols: [],
    rows: [],
    message: ""
  };

  try {
    if (customWallet) {
      const owner = parsePublicKey(customWallet).toBase58();
      const localPart = await fetchPublicWalletPositionSignals(owner, safeMode).catch((error) => ({
        rows: [],
        warnings: [friendlyError(error)]
      }));
      const madeRows = hasMadeOnSol
        ? await fetchMadeOnSolKolFeedSignals(safeMode, { kol: owner }).catch(() => [])
        : [];
      const solanaPositionRows = hasSolanaTracker
        ? await fetchKolWalletPositions(owner, safeMode)
          .then((positions) => positions
            .map((position) => normalizeKolPositionSignal(position, { wallet: owner, name: shortMint(owner) }, safeMode))
            .filter(Boolean))
          .catch(() => [])
        : [];
      const solanaRows = hasSolanaTracker && (!madeRows.length || CONFIG.kolUseSolanaTrackerFallback)
        ? await fetchKolWalletTradeSignals(owner, safeMode).catch(() => [])
        : [];
      const customCandidates = diversifyKolSignals(uniqueKolSignals([
        ...madeRows,
        ...solanaPositionRows,
        ...solanaRows,
        ...(localPart.rows || [])
      ]).sort(compareKolSignals), 72);
      const hydratedRows = diversifyKolSignals((await hydrateKolSignalMetadata(customCandidates)).sort(compareKolSignals), 48);
      const rows = rotateRowsForRefresh(hydratedRows, 36, scanState.refreshCount, { stickyCount: 2 });
      return {
        ...base,
        configured: true,
        source: hasMadeOnSol || hasSolanaTracker ? base.source : "wallet_scan",
        label: `Custom Wallet ${shortMint(owner)}`,
        description: "Current positions and recent buy-style trades from the wallet you entered.",
        wallet: owner,
        kolCount: 1,
        kols: [webKolSummaryRow({
          wallet: owner,
          name: shortMint(owner),
          trades: rows.length,
          volumeLabel: `${localPart.rows?.length || 0} current holding(s)`
        })],
        rows,
        localRows: localPart.rows?.length || 0,
        warnings: localPart.warnings || [],
        madeOnSolRows: madeRows.length,
        solanaTrackerRows: solanaRows.length + solanaPositionRows.length,
        refreshCount: scanState.refreshCount,
        copyWalletEnabled: hasSolanaTracker,
        copyScanIntervalMs: CONFIG.kolCopyScanIntervalMs,
        message: rows.length
          ? `Custom wallet loaded: ${localPart.rows?.length || 0} current holding(s), ${madeRows.length + solanaRows.length + solanaPositionRows.length} API signal(s).`
          : "No current token positions or recent buy-style trades found for this wallet."
      };
    }

    if (!base.configured) {
      // No paid KOL key set — fall back to the FREE kolscan.io leaderboard (ROI + win-rate + pfps). This
      // is what lets the Copy tab work fully even if Solana Tracker / MadeOnSol are dropped.
      const free = await fetchKolscanLeaderboard().catch(() => []);
      const freeKols = rotateRowsForRefresh(uniqueKolSummaries(free), 12, scanState.refreshCount, { stickyCount: 2 });
      if (freeKols.length) {
        return {
          ...base, configured: true, source: "kolscan", kolFallback: "kolscan_free",
          kolCount: freeKols.length, kols: freeKols, rows: [], refreshCount: scanState.refreshCount,
          notes: [`kolscan: ${free.length} KOLs (free)`],
          message: `KOL leaderboard via kolscan.io — ${freeKols.length} traders by realized SOL.`
        };
      }
      return {
        ...base,
        message: "Live KOL lists are not connected yet. Use Scan Wallet to inspect a public wallet, or try again later."
      };
    }

    const madePart = hasMadeOnSol
      ? await buildMadeOnSolKolPart(safeMode).catch((error) => ({ rows: [], kols: [], error: formatError(error), calls: 1 }))
      : { rows: [], kols: [], calls: 0 };
    const shouldUseSolanaTracker = hasSolanaTracker && (!hasMadeOnSol || (CONFIG.kolUseSolanaTrackerFallback && madePart.rows.length < 4));
    const solanaPart = shouldUseSolanaTracker
      ? await buildSolanaTrackerKolPart(safeMode).catch((error) => ({ rows: [], kols: [], error: formatError(error), calls: 1, signalWalletsChecked: 0 }))
      : { rows: [], kols: [], calls: 0, signalWalletsChecked: 0 };

    const signalCandidates = diversifyKolSignals(uniqueKolSignals([
      ...(madePart.rows || []),
      ...(solanaPart.rows || [])
    ]).sort(compareKolSignals), 72);
    const sortedPool = diversifyKolSignals((await hydrateKolSignalMetadata(signalCandidates)).sort(compareKolSignals), 48);
    const sorted = rotateRowsForRefresh(sortedPool, 36, scanState.refreshCount, { stickyCount: 2 });
    // kolscan.io (FREE) leads the roster — it carries ROI (SOL profit) + win-rate + X handle (→ pfp) for
    // ~150 KOLs, so the list is rich and populated even when MadeOnSol is rate-limited. Sorted by mode.
    const kolscanKols = customWallet ? [] : await fetchKolscanLeaderboard().catch(() => []);
    const kolscanSorted = safeMode === "consistent"
      ? [...kolscanKols].filter((k) => Number(k.trades) >= 6).sort((a, b) => Number(b.winRatePct || 0) - Number(a.winRatePct || 0))
      : kolscanKols; // already profit-desc from the leaderboard
    const kolPool = uniqueKolSummaries([
      ...kolscanSorted,
      ...(madePart.kols || []),
      ...(solanaPart.kols || [])
    ]);
    const stickyKols = safeMode === "top" ? 4 : safeMode === "consistent" ? 3 : 2;
    let kols = rotateRowsForRefresh(kolPool, 12, scanState.refreshCount, { stickyCount: stickyKols });
    const notes = [madePart.error ? `MadeOnSol: ${madePart.error}` : "", solanaPart.error ? `Solana Tracker: ${solanaPart.error}` : ""].filter(Boolean);
    if (kolscanKols.length) notes.push(`kolscan: ${kolscanKols.length} KOLs (free)`);

    // Live KOL sources can go dark mid-day (e.g. MadeOnSol's 200/day BASIC rate limit). When the
    // live pool comes back empty, fall back to the persisted KOL roster from earlier successful
    // scans (Postgres + external cache) so the "Known KOL wallets" list is NEVER empty — rotated by
    // refresh count so it still feels alive. This is what the user means by "a solid list that rotates".
    let kolFallback = "";
    if (!kols.length) {
      const stored = await storedKolProfiles().catch(() => []);
      const summaries = uniqueKolSummaries((stored || []).map(webKolSummaryRow).filter((k) => k.wallet && (k.name || k.twitter)));
      if (summaries.length) {
        kols = rotateRowsForRefresh(summaries, 12, scanState.refreshCount, { stickyCount: stickyKols });
        kolFallback = "cached_roster";
        if (madePart.error) notes.push("Showing cached KOL roster while the live feed cools down.");
      }
    }

    return {
      ...base,
      kolCount: kols.length,
      kols,
      kolFallback,
      rows: sorted,
      madeOnSolRows: madePart.rows?.length || 0,
      solanaTrackerRows: solanaPart.rows?.length || 0,
      madeOnSolCalls: madePart.calls || 0,
      solanaTrackerCalls: solanaPart.calls || 0,
      signalWalletsChecked: solanaPart.signalWalletsChecked || 0,
      refreshCount: scanState.refreshCount,
      cacheTtlMs: Math.max(CONFIG.madeOnSolCacheTtlMs, CONFIG.solanaTrackerKolCacheTtlMs),
      periodEndpoint: CONFIG.solanaTrackerKolUsePeriodEndpoint,
      creditHint: kolCreditHint(solanaPart.signalWalletsChecked || 0, madePart.calls || 0, solanaPart.calls || 0),
      notes,
      message: sorted.length
        ? `KOL tracker refreshed with ${sorted.length} token signal(s).`
        : `KOL tracker refreshed. Try another mode or refresh again for new signals.`
    };
  } catch (error) {
    return {
      ...base,
      error: formatError(error),
      message: `KOL Tracker could not load ${kolModeLabel(safeMode)}: ${formatError(error)}`
    };
  }
}

function kolCreditHint(signalWalletsChecked, madeOnSolCalls = 0, solanaTrackerCalls = null) {
  const trackerCalls = solanaTrackerCalls === null
    ? 1 + Math.max(0, Number(signalWalletsChecked || 0))
    : Number(solanaTrackerCalls || 0);
  const parts = [];
  if (madeOnSolCalls) parts.push(`${madeOnSolCalls} MadeOnSol call(s), cache ${Math.round(CONFIG.madeOnSolCacheTtlMs / 1000)}s`);
  if (trackerCalls) parts.push(`${trackerCalls} Solana Tracker call(s), cache ${Math.round(CONFIG.solanaTrackerKolCacheTtlMs / 1000)}s`);
  if (!parts.length) return "KOL refresh complete.";
  return "KOL refresh complete.";
}

function uniqueKolSummaries(kols) {
  const seen = new Set();
  const rows = [];
  for (const kol of kols || []) {
    const key = kolSummaryIdentityKey(kol);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    rows.push(kol);
  }
  return rows;
}

function kolSummaryIdentityKey(kol = {}) {
  const wallet = firstString(kol.wallet, kol.owner, kol.address, kol.publicKey);
  if (wallet) return `wallet:${wallet}`;
  const twitter = stripAt(firstString(kol.twitter, kol.x, kol.username, deepFindKolTwitter(kol))).toLowerCase();
  if (twitter) return `x:${twitter}`;
  const name = String(firstString(kol.name, kol.kolName, kol.kol_name)).trim().toLowerCase();
  if (name && !/^(unknown kol|kol wallet|kol cluster|\d+\s+kols?)$/i.test(name)) return `name:${name}`;
  return "";
}

async function buildMadeOnSolKolPart(mode) {
  const safeMode = normalizeKolMode(mode);
  if (safeMode === "top" || safeMode === "consistent") {
    const kols = await fetchMadeOnSolKolLeaderboard(safeMode);
    return { rows: [], kols, calls: 1 };
  }

  const rows = safeMode === "hot"
    ? await fetchMadeOnSolHotKolTokens(safeMode)
    : await fetchMadeOnSolKolFeedSignals(safeMode);
  return {
    rows: rows.slice(0, 24),
    kols: uniqueKolSummaries(rows
      .filter((row) => row.kolWallet || row.twitter)
      .map((row) => webKolSummaryRow({
        wallet: row.kolWallet,
        name: row.kolName,
        twitter: row.twitter,
        avatar: row.avatar,
        lastTradeAt: row.lastTradeAt,
        trades: row.kolCount || null
      }))).slice(0, 24),
    calls: 1
  };
}

async function buildSolanaTrackerKolPart(mode) {
  const safeMode = normalizeKolMode(mode);
  const kols = await fetchKolLeaderboard(safeMode);
  const signals = [];
  const topKols = kols.slice(0, Math.min(CONFIG.solanaTrackerKolLimit, 24));
  const signalKols = topKols.slice(0, Math.min(CONFIG.solanaTrackerKolSignalLookups, topKols.length));

  await runWithConcurrency(signalKols, CONFIG.solanaTrackerKolPositionConcurrency, async (kol) => {
    const positions = await fetchKolWalletPositions(kol.wallet, safeMode).catch(() => []);
    for (const position of positions.slice(0, CONFIG.solanaTrackerKolPositionLimit)) {
      const signal = normalizeKolPositionSignal(position, kol, safeMode);
      if (signal) signals.push(signal);
    }
  });

  return {
    rows: uniqueKolSignals(signals).sort(compareKolSignals).slice(0, 24),
    kols: topKols.map((kol) => webKolSummaryRow(kol)),
    calls: 1 + signalKols.length,
    signalWalletsChecked: signalKols.length
  };
}

async function fetchPublicWalletPositionSignals(wallet, mode) {
  const owner = parsePublicKey(wallet).toBase58();
  const { accounts, warnings } = await getOwnedTokenAccountsWithWarningsCached(new PublicKey(owner), {
    ttlMs: Math.max(CONFIG.balanceCacheTtlMs, 15_000)
  });
  const tokens = sellableTokensFromAccounts(accounts)
    .filter((account) => account.mint && account.rawAmount > 0n && account.mint !== SOL_MINT)
    .slice(0, 20);
  const rows = tokens.map((token, index) => normalizePublicWalletPositionSignal(token, owner, mode, index));
  return { rows, warnings };
}

function normalizePublicWalletPositionSignal(token, wallet, mode, index = 0) {
  const numericAmount = Number(token.uiAmount || 0);
  const amountText = Number.isFinite(numericAmount) ? formatTokenAmount(numericAmount) : String(token.uiAmount || "0");
  const amountLabel = `${amountText} token${amountText === "1" ? "" : "s"}`;
  const score = Math.max(38, Math.min(78, 58 - Math.min(index, 10) + Math.min(10, Number(token.accountCount || 1))));
  return {
    tokenMint: token.mint,
    symbol: shortMint(token.mint),
    name: "Current wallet holding",
    score,
    signalType: "Wallet holding",
    kolWallet: wallet,
    kolName: shortMint(wallet),
    twitter: "",
    valueUsd: 0,
    valueLabel: amountLabel,
    amount: token.uiAmount,
    amountLabel,
    roiPct: null,
    roiLabel: "chart check",
    winRatePct: null,
    winRateLabel: "wallet scan",
    kolRoiPct: null,
    realizedLabel: `${token.accountCount || 1} account(s)`,
    lastTradeAt: null,
    dexUrl: dexScreenerUrl(token.mint),
    kolscanUrl: kolscanAccountUrl(wallet),
    source: "wallet_holding",
    sourceLabel: "On-chain wallet scan",
    mode: normalizeKolMode(mode)
  };
}

async function hydrateKolSignalMetadata(rows) {
  const signals = Array.isArray(rows) ? rows : [];
  const mints = [...new Set(signals
    .filter((row) => row?.tokenMint)
    .map((row) => row.tokenMint))]
    .slice(0, 30);
  const metadataByMint = mints.length
    ? await tokenMetadataMapForMints(mints, { timeoutMs: 2_500, pumpTimeoutMs: 1_200 }).catch(() => new Map())
    : new Map();

  return signals.map((row) => {
    const metadata = metadataByMint.get(row.tokenMint) || {};
    const symbol = meaningfulTokenText(row.symbol, row.tokenMint) || metadata.symbol || shortMint(row.tokenMint);
    const name = meaningfulTokenText(row.name, row.tokenMint) || metadata.name || (symbol !== shortMint(row.tokenMint) ? symbol : "Unknown Token");
    const volume = metadata.volume || {};
    const rowVolume = row.volume || {};
    const rowLiquidity = row.liquidity || {};
    const rowDex = row.dex || row.dexScreener || row.pair || row.dexPair || {};
    const rowPump = row.pump || row.pumpFun || row.pumpfun || {};
    const rowBaseToken = row.baseToken || row.base || {};
    const txns5m = metadata.txns?.m5 || {};
    const txnsH1 = metadata.txns?.h1 || {};
    const priceChange = metadata.priceChange || {};
    const marketCap = firstMeaningfulNumber(
      row.marketCap,
      row.marketCapUsd,
      row.market_cap,
      row.usdMarketCap,
      row.usd_market_cap,
      row.mc,
      row.mcap,
      metadata.marketCap,
      metadata.marketCapUsd,
      metadata.usdMarketCap,
      rowDex.marketCap,
      rowDex.marketCapUsd,
      rowDex.fdv,
      rowPump.marketCap,
      rowPump.marketCapUsd,
      rowPump.usdMarketCap,
      rowPump.usd_market_cap,
      rowBaseToken.marketCap,
      row.fdv,
      metadata.fdv
    ) || 0;
    const fdv = firstMeaningfulNumber(row.fdv, metadata.fdv, marketCap) || 0;
    const liquidityUsd = firstMeaningfulNumber(
      row.liquidityUsd,
      row.liquidity_usd,
      row.currentLiquidityUsd,
      rowLiquidity.usd,
      metadata.liquidityUsd,
      metadata.liquidity_usd,
      metadata.liquidity?.usd,
      rowDex.liquidityUsd,
      rowDex.liquidity?.usd,
      rowPump.liquidityUsd,
      rowPump.liquidity_usd,
      rowPump.liquidity?.usd
    ) || 0;
    const volume5m = firstMeaningfulNumber(row.volume5m, row.volumeM5, row.volumeUsd, rowVolume.m5, volume.m5, rowDex.volume?.m5, rowPump.volume5m) || 0;
    const volumeM15 = firstMeaningfulNumber(row.volumeM15, row.volume15m, rowVolume.m15, rowVolume.m5, volume.m15, volume.m15m, volume.m5, rowDex.volume?.m15, rowDex.volume?.m5, rowPump.volumeM15, rowPump.volume15m, rowPump.volume5m) || 0;
    const volumeM30 = firstMeaningfulNumber(row.volumeM30, row.volume30m, rowVolume.m30, volume.m30, volume.m30m, rowDex.volume?.m30, rowPump.volumeM30) || 0;
    const volumeH1 = firstMeaningfulNumber(row.volumeH1, row.volume1h, row.volume_h1, rowVolume.h1, rowVolume.m30, volume.h1, rowDex.volume?.h1, rowDex.volume?.m30, rowPump.volumeH1, rowPump.volume1h) || 0;
    const volumeH24 = firstMeaningfulNumber(row.volumeH24, row.volume24h, row.volume_h24, rowVolume.h24, rowVolume.d1, volume.h24, volume.d1, rowDex.volume?.h24, rowPump.volumeH24, rowPump.volume24h) || 0;
    const primaryVolume = firstMeaningfulNumber(volumeM15, volumeM30, volumeH1, volume5m, volumeH24) || 0;
    const primaryVolumeLabel = formatUsdCompact(primaryVolume);
    const m5 = firstMeaningfulNumber(row.m5, priceChange.m5) || 0;
    const h1 = firstMeaningfulNumber(row.h1, priceChange.h1) || 0;
    const h6 = firstMeaningfulNumber(row.h6, priceChange.h6) || 0;
    const h24 = firstMeaningfulNumber(row.h24, priceChange.h24) || 0;
    const buys5m = firstMeaningfulNumber(row.buys5m, txns5m.buys) || 0;
    const sells5m = firstMeaningfulNumber(row.sells5m, txns5m.sells) || 0;
    const buysH1 = firstMeaningfulNumber(row.buysH1, txnsH1.buys) || 0;
    const sellsH1 = firstMeaningfulNumber(row.sellsH1, txnsH1.sells) || 0;
    const pairCreatedAt = firstMeaningfulNumber(normalizePairCreatedAt(row.pairCreatedAt), normalizePairCreatedAt(metadata.pairCreatedAt)) || null;
    const trustedSourceAge = ["source-age", "trusted-source-age"].includes(String(row.pairAgeSource || "").toLowerCase());
    const pairAgeSeconds = pairCreatedAt
      ? Math.max(0, Math.floor((Date.now() - pairCreatedAt) / 1000))
      : trustedSourceAge && Number.isFinite(Number(row.pairAgeSeconds)) ? Number(row.pairAgeSeconds) : null;
    const pairAgeMinutes = Number.isFinite(Number(pairAgeSeconds))
      ? Math.floor(Number(pairAgeSeconds) / 60)
      : null;
    const isPump = Boolean(row.isPump) || isPumpStyleToken({
      tokenMint: row.tokenMint,
      symbol,
      name,
      source: row.source || metadata.source
    });
    const enriched = {
      ...row,
      symbol,
      name,
      imageUrl: firstString(
        row.imageUrl,
        row.imageUri,
        row.image,
        row.iconUrl,
        row.icon,
        row.logoURI,
        row.logo,
        row.logoUrl,
        row.tokenImageUrl,
        row.token_image_url,
        row.pfp,
        row.avatar,
        rowPump.imageUrl,
        rowPump.imageUri,
        rowPump.image_uri,
        rowPump.image,
        rowDex.imageUrl,
        rowDex.image,
        rowDex.logoURI,
        rowDex.logo,
        rowDex.info?.imageUrl,
        rowDex.baseToken?.imageUrl,
        rowDex.baseToken?.logoURI,
        rowBaseToken.imageUrl,
        rowBaseToken.image,
        rowBaseToken.logoURI,
        metadata.imageUrl,
        metadata.imageUri,
        metadata.image_uri,
        metadata.image,
        metadata.logoURI,
        metadata.logo
      ),
      websiteUrl: firstString(row.websiteUrl, metadata.websiteUrl),
      twitterUrl: firstString(row.twitterUrl, metadata.twitterUrl),
      telegramUrl: firstString(row.telegramUrl, metadata.telegramUrl),
      marketCap,
      fdv,
      marketCapLabel: formatUsdCompact(marketCap) || row.marketCapLabel || "checking",
      fdvLabel: formatUsdCompact(fdv) || row.fdvLabel || "checking",
      liquidityUsd,
      liquidityLabel: formatUsdCompact(liquidityUsd) || row.liquidityLabel || "checking",
      volume5m,
      volume5mLabel: formatUsdCompact(volume5m) || row.volume5mLabel || "checking",
      volumeM15,
      volumeM15Label: formatUsdCompact(volumeM15) || row.volumeM15Label || "",
      volumeM30,
      volumeM30Label: formatUsdCompact(volumeM30) || row.volumeM30Label || "",
      volumeH1,
      volumeH1Label: formatUsdCompact(volumeH1) || row.volumeH1Label || row.volumeLabel || "checking",
      volumeH24,
      volumeH24Label: formatUsdCompact(volumeH24) || row.volumeH24Label || "",
      volumeLabel: row.volumeLabel && row.volumeLabel !== "n/a"
        ? row.volumeLabel
        : primaryVolumeLabel ? `${primaryVolumeLabel} vol` : "checking",
      m5,
      h1,
      h6,
      h24,
      buys5m,
      sells5m,
      buysH1,
      sellsH1,
      txnsLabel: `${buys5m + buysH1}/${sells5m + sellsH1}`,
      pairCreatedAt,
      pairAgeSeconds,
      pairAgeMinutes,
      pairAgeLabel: Number.isFinite(Number(pairAgeSeconds)) ? formatLivePairAgeLabel(pairAgeSeconds, pairAgeMinutes) : "age unknown",
      pairAgeSource: pairCreatedAt ? "pair-created-at" : trustedSourceAge ? row.pairAgeSource : "unknown",
      isPump,
      pumpUrl: row.pumpUrl || (isPump ? pumpFunUrl(row.tokenMint) : ""),
      valueLabel: row.valueLabel && row.valueLabel !== "n/a" ? row.valueLabel : primaryVolumeLabel ? `${primaryVolumeLabel} vol` : row.valueLabel,
      roiLabel: row.roiLabel && row.roiLabel !== "n/a" ? row.roiLabel : marketCap ? `MC ${formatUsdCompact(marketCap)}` : row.roiLabel,
      dexUrl: row.dexUrl || dexScreenerUrl(row.tokenMint),
      kolscanUrl: row.kolscanUrl || kolscanAccountUrl(row.kolWallet)
    };
    const bestPick = computeBestPickScore(enriched);
    return {
      ...enriched,
      bestPickScore: firstMeaningfulNumber(enriched.bestPickScore, bestPick.score) || bestPick.score,
      bestPickLabel: enriched.bestPickLabel || bestPick.label,
      bestPickInputs: enriched.bestPickInputs || bestPick.inputs,
      bestPickWarnings: enriched.bestPickWarnings || bestPick.warnings,
      scoreBreakdown: enriched.scoreBreakdown || bestPick.inputs,
      scoreWarnings: enriched.scoreWarnings || bestPick.warnings
    };
  }).filter((row) => !isPumpMayhemToken(row));
}

function needsKolMetadataHydration(row) {
  return !meaningfulTokenText(row.symbol, row.tokenMint)
    || !meaningfulTokenText(row.name, row.tokenMint)
    || row.name === "Unknown Token"
    || !row.imageUrl;
}

function parseNumericValue(value) {
  if (value === null || value === undefined || value === "") return null;
  if (typeof value === "number") return Number.isFinite(value) ? value : null;
  const raw = String(value).trim();
  if (!raw) return null;
  const compact = raw.replace(/[$,%_\s,]/g, "");
  const match = compact.match(/^([-+]?\d*\.?\d+)([kmb])?$/i);
  if (!match) return null;
  const number = Number(match[1]);
  if (!Number.isFinite(number)) return null;
  const suffix = String(match[2] || "").toLowerCase();
  if (suffix === "k") return number * 1_000;
  if (suffix === "m") return number * 1_000_000;
  if (suffix === "b") return number * 1_000_000_000;
  return number;
}

function firstMeaningfulNumber(...values) {
  const finite = [];
  for (const value of values) {
    const number = parseNumericValue(value);
    if (Number.isFinite(number)) finite.push(number);
  }
  return finite.find((number) => number !== 0) ?? finite[0] ?? null;
}

function meaningfulTokenText(value, tokenMint = "") {
  const text = String(value || "").trim();
  if (!text || /^unknown token$/i.test(text)) return "";
  if (tokenMint && text === shortMint(tokenMint)) return "";
  return text;
}

async function fetchMadeOnSolKolFeedSignals(mode, filters = {}) {
  const search = new URLSearchParams({
    limit: String(CONFIG.madeOnSolKolLimit),
    action: "buy"
  });
  if (filters.kol) {
    search.set("kol", filters.kol);
    search.set("wallet", filters.kol);
  }
  const data = await madeOnSolJson(`/kol/feed?${search.toString()}`, { cacheTtlMs: CONFIG.madeOnSolCacheTtlMs });
  return arrayFromApiData(data)
    .map((trade) => normalizeMadeOnSolKolTradeSignal(trade, mode))
    .filter(Boolean)
    .sort(compareKolSignals);
}

async function fetchMadeOnSolHotKolTokens(mode) {
  const search = new URLSearchParams({
    period: normalizeKolMode(mode) === "fresh" ? "1h" : "6h",
    min_kols: "1",
    limit: String(Math.min(CONFIG.madeOnSolKolLimit, 20))
  });
  const data = await madeOnSolJson(`/kol/tokens/hot?${search.toString()}`, { cacheTtlMs: CONFIG.madeOnSolCacheTtlMs });
  const rows = arrayFromApiData(data)
    .map((token) => normalizeMadeOnSolHotTokenSignal(token, mode))
    .filter(Boolean)
    .sort(compareKolSignals);
  return rows.length ? rows : fetchMadeOnSolKolFeedSignals(mode);
}

async function fetchMadeOnSolKolLeaderboard(mode) {
  const safeMode = normalizeKolMode(mode);
  const search = new URLSearchParams({
    period: safeMode === "consistent" ? "30d" : "7d",
    limit: String(Math.min(CONFIG.madeOnSolKolLimit, 20))
  });
  const data = await madeOnSolJson(`/kol/leaderboard?${search.toString()}`, { cacheTtlMs: CONFIG.madeOnSolCacheTtlMs });
  return arrayFromApiData(data)
    .map((row) => normalizeMadeOnSolLeaderboardKol(row))
    .filter((kol) => kol.wallet || kol.twitter)
    .map((kol) => webKolSummaryRow(kol));
}

async function madeOnSolJson(pathName, options = {}) {
  const url = `${CONFIG.madeOnSolApiBase}${pathName.startsWith("/") ? pathName : `/${pathName}`}`;
  const cacheTtlMs = Number(options.cacheTtlMs ?? CONFIG.madeOnSolCacheTtlMs);
  const cached = madeOnSolCache.get(url);
  if (cached && cacheTtlMs > 0 && Date.now() - cached.cachedAt < cacheTtlMs) {
    return cached.value;
  }

  const data = await fetchJson(url, {
    headers: {
      "Accept": "application/json",
      "User-Agent": "solana-telegram-wallet-ops-bot",
      "Authorization": `Bearer ${CONFIG.madeOnSolApiKey}`,
      "x-api-key": CONFIG.madeOnSolApiKey
    },
    timeoutMs: options.timeoutMs || 6_500
  });
  madeOnSolCache.set(url, { cachedAt: Date.now(), value: data });
  return data;
}

function normalizeMadeOnSolKolTradeSignal(trade, mode) {
  const token = trade.token || trade.tokenInfo || trade.token_info || trade.metadata || {};
  const kol = trade.kol || trade.trader || trade.walletInfo || trade.wallet_info || {};
  const action = String(firstString(trade.action, trade.side, trade.type, "buy")).toLowerCase();
  if (action.includes("sell")) return null;
  const tokenMint = firstString(
    trade.tokenMint,
    trade.token_mint,
    trade.mint,
    trade.tokenAddress,
    trade.token_address,
    trade.address,
    token.mint,
    token.address,
    token.tokenAddress,
    token.token_address
  );
  if (!tokenMint || tokenMint === SOL_MINT) return null;
  const solAmount = firstNumber(trade.solAmount, trade.sol_amount, trade.amountSol, trade.amount_sol, trade.sizeSol, trade.size_sol);
  const usdValue = firstNumber(trade.valueUsd, trade.value_usd, trade.usdValue, trade.usd_value, trade.amountUsd, trade.amount_usd, trade.volumeUsd);
  const marketCap = firstNumber(trade.marketCapUsdAtTrade, trade.market_cap_usd_at_trade, trade.marketCap, trade.market_cap, trade.mc);
  const winRate = normalizePercentLike(firstNumber(
    trade.winRate,
    trade.win_rate,
    trade.winrate_7d,
    trade.kolWinRate,
    trade.kol_win_rate,
    kol.winRate,
    kol.win_rate
  ));
  const roiPct = normalizePercentLike(firstNumber(trade.roi, trade.roiPct, trade.roi_pct, kol.roi, kol.roiPct));
  const lastTradeAt = normalizeTimestamp(firstString(
    trade.tradedAt,
    trade.traded_at,
    trade.timestamp,
    trade.time,
    trade.createdAt,
    trade.created_at
  ));
  const score = scoreMadeOnSolSignal({
    solAmount,
    usdValue,
    winRate,
    roiPct,
    ageHours: hoursSince(lastTradeAt),
    mode
  });
  if (score < 35 && normalizeKolMode(mode) !== "fresh") return null;

  const kolWallet = firstString(trade.wallet, trade.walletAddress, trade.wallet_address, trade.kolWallet, trade.kol_wallet, kol.wallet, kol.wallet_address, kol.address);
  const kolTwitter = stripAt(firstString(trade.kolTwitter, trade.kol_twitter, trade.twitter, trade.x, trade.username, kol.twitter, kol.kol_twitter, kol.x, kol.username, twitterHandleFromUrl(kol.twitterUrl || kol.twitter_url || kol.xUrl || kol.x_url), deepFindKolTwitter(kol, trade)));
  const kolAvatar = firstString(
    trade.kolAvatar, trade.kol_avatar,
    deepFindKolAvatar(kol, trade.kol, trade.trader, trade.walletInfo, trade.wallet_info),
    trade.avatar, trade.avatarUrl, trade.avatar_url, trade.image, trade.imageUrl, trade.image_url,
    trade.profileImage, trade.profile_image, trade.profileImageUrl, trade.profile_image_url,
    trade.profilePic, trade.profile_pic, trade.pfp, trade.pfpUrl, trade.pfp_url
  );
  return {
    tokenMint,
    symbol: firstString(token.symbol, token.token_symbol, trade.tokenSymbol, trade.token_symbol, trade.symbol, trade.ticker, shortMint(tokenMint)),
    name: firstString(token.name, token.token_name, trade.tokenName, trade.token_name, trade.token_name_display, "Unknown Token"),
    imageUrl: firstString(token.image_uri, token.image, token.imageUrl, token.image_url, token.logoURI, token.logo, token.metadata?.image, trade.tokenImage, trade.token_image, trade.tokenImageUrl, trade.token_image_url),
    score,
    signalType: "MadeOnSol KOL buy",
    kolWallet,
    kolName: firstString(trade.kolName, trade.kol_name, trade.traderName, trade.trader_name, kol.name, kol.kol_name, kol.username, "KOL Wallet"),
    twitter: kolTwitter,
    avatar: kolAvatar,
    valueUsd: Number(usdValue || solAmount || 0),
    valueLabel: usdValue ? (formatUsdCompact(usdValue) || "$0") : solAmount ? `${formatCompactNumber(solAmount)} SOL` : "n/a",
    roiPct,
    roiLabel: roiPct !== null ? formatPercentNumber(roiPct) : marketCap ? `MC ${formatUsdCompact(marketCap)}` : "n/a",
    winRatePct: winRate,
    winRateLabel: formatPercentNumber(winRate),
    kolRoiPct: roiPct,
    realizedLabel: "n/a",
    callsTracked: 1,
    currentPositionCount: 1,
    lastTradeAt,
    dexUrl: dexScreenerUrl(tokenMint),
    kolscanUrl: kolscanAccountUrl(kolWallet),
    source: "made_on_sol_feed",
    sourceLabel: "MadeOnSol",
    mode: normalizeKolMode(mode)
  };
}

function normalizeMadeOnSolHotTokenSignal(tokenRow, mode) {
  const token = tokenRow.token || tokenRow.tokenInfo || tokenRow.token_info || tokenRow.metadata || {};
  const kolList = firstArray(
    tokenRow.kolsList,
    tokenRow.kols_list,
    tokenRow.kolWallets,
    tokenRow.kol_wallets,
    tokenRow.kols,
    tokenRow.wallets,
    tokenRow.buyers
  );
  const topKol = kolList[0];
  const topKolObject = topKol && typeof topKol === "object" ? topKol : {};
  const tokenMint = firstString(
    tokenRow.tokenMint,
    tokenRow.token_mint,
    tokenRow.mint,
    tokenRow.address,
    tokenRow.tokenAddress,
    tokenRow.token_address,
    token.mint,
    token.address,
    token.tokenAddress,
    token.token_address
  );
  if (!tokenMint || tokenMint === SOL_MINT) return null;
  const kolCount = firstNumber(
    tokenRow.kolCount,
    tokenRow.kol_count,
    tokenRow.kols_total,
    tokenRow.kolsRecent,
    tokenRow.kols_recent,
    Array.isArray(tokenRow.kols) ? tokenRow.kols.length : tokenRow.kols,
    kolList.length || null
  );
  const buySol = firstNumber(tokenRow.buySol, tokenRow.buy_sol, tokenRow.totalBuySol, tokenRow.total_buy_sol, tokenRow.netFlowSol, tokenRow.net_flow_sol);
  const volumeUsd = firstNumber(tokenRow.volumeUsd, tokenRow.volume_usd, tokenRow.volume, tokenRow.totalVolumeUsd, tokenRow.total_volume_usd);
  const marketCap = firstNumber(tokenRow.marketCap, tokenRow.market_cap, tokenRow.mc, token.marketCap, token.market_cap);
  const lastTradeAt = normalizeTimestamp(firstString(tokenRow.lastTradeAt, tokenRow.last_trade_at, tokenRow.updatedAt, tokenRow.updated_at, tokenRow.createdAt, tokenRow.created_at));
  const score = scoreMadeOnSolHotToken({ kolCount, buySol, volumeUsd, marketCap, ageHours: hoursSince(lastTradeAt), mode });
  if (score < 35 && normalizeKolMode(mode) !== "fresh") return null;
  const kolWallet = firstString(
    typeof topKol === "string" ? topKol : "",
    topKolObject.wallet,
    topKolObject.walletAddress,
    topKolObject.wallet_address,
    topKolObject.address,
    tokenRow.topKolWallet,
    tokenRow.top_kol_wallet
  );
  const kolName = kolWallet
    ? firstString(topKolObject.name, topKolObject.username, topKolObject.twitter, tokenRow.topKolName, tokenRow.top_kol_name, shortMint(kolWallet))
    : kolCount ? `${kolCount} KOL${Number(kolCount) === 1 ? "" : "s"}` : "KOL cluster";
  const topKolTwitter = stripAt(firstString(topKolObject.twitter, topKolObject.x, topKolObject.username, twitterHandleFromUrl(topKolObject.twitterUrl || topKolObject.twitter_url || topKolObject.xUrl || topKolObject.x_url), tokenRow.topKolTwitter, deepFindKolTwitter(topKolObject)));
  const topKolAvatar = firstString(
    deepFindKolAvatar(topKolObject),
    topKolObject.avatar, topKolObject.avatarUrl, topKolObject.avatar_url,
    topKolObject.image, topKolObject.imageUrl, topKolObject.image_url,
    topKolObject.profileImage, topKolObject.profile_image, topKolObject.profileImageUrl, topKolObject.profile_image_url,
    topKolObject.profilePic, topKolObject.profile_pic, topKolObject.pfp, topKolObject.pfpUrl, topKolObject.pfp_url,
    tokenRow.topKolAvatar, tokenRow.top_kol_avatar, tokenRow.topKolAvatarUrl, tokenRow.top_kol_avatar_url
  );
  return {
    tokenMint,
    symbol: firstString(token.symbol, token.token_symbol, tokenRow.tokenSymbol, tokenRow.token_symbol, tokenRow.symbol, tokenRow.ticker, shortMint(tokenMint)),
    name: firstString(token.name, token.token_name, tokenRow.tokenName, tokenRow.token_name, tokenRow.name, "Unknown Token"),
    imageUrl: firstString(token.image_uri, token.image, token.imageUrl, token.image_url, token.logoURI, token.logo, token.metadata?.image, tokenRow.tokenImage, tokenRow.token_image, tokenRow.tokenImageUrl, tokenRow.token_image_url),
    score,
    signalType: kolWallet ? "Hot KOL buy" : "Hot KOL cluster",
    kolWallet,
    kolName,
    kolCount,
    callsTracked: kolCount || null,
    currentPositionCount: kolCount ? 1 : null,
    twitter: topKolTwitter,
    avatar: topKolAvatar,
    valueUsd: Number(volumeUsd || buySol || 0),
    valueLabel: volumeUsd ? (formatUsdCompact(volumeUsd) || "$0") : buySol ? `${formatCompactNumber(buySol)} SOL` : "n/a",
    roiPct: null,
    roiLabel: marketCap ? `MC ${formatUsdCompact(marketCap)}` : "n/a",
    winRatePct: null,
    winRateLabel: kolCount ? `${kolCount} KOL${Number(kolCount) === 1 ? "" : "s"}` : "n/a",
    kolRoiPct: null,
    realizedLabel: buySol ? `${formatCompactNumber(buySol)} SOL buys` : "n/a",
    lastTradeAt,
    dexUrl: dexScreenerUrl(tokenMint),
    kolscanUrl: kolscanAccountUrl(kolWallet),
    source: "made_on_sol_hot",
    sourceLabel: "MadeOnSol",
    mode: normalizeKolMode(mode)
  };
}

function normalizeMadeOnSolLeaderboardKol(row) {
  const profile = row.profile || row.identity || row.kol || row.walletInfo || row.wallet_info || {};
  const stats = row.stats || row.summary || row.performance || {};
  const wallet = firstString(row.wallet, row.walletAddress, row.wallet_address, row.address, profile.wallet, profile.address);
  const socials = row.socials || row.social || {};
  const profileSocials = profile.socials || profile.social || {};
  const twitter = stripAt(firstString(row.twitter, row.x, row.username, socials.twitter, socials.x, profile.twitter, profile.x, profile.username, profileSocials.twitter, profileSocials.x, twitterHandleFromUrl(row.twitterUrl || row.twitter_url || row.xUrl || row.x_url || profile.twitterUrl || profile.twitter_url || profile.xUrl || profile.x_url), deepFindKolTwitter(profile, row)));
  const buyCount = firstNumber(row.buyCount, row.buy_count, stats.buyCount, stats.buy_count);
  const sellCount = firstNumber(row.sellCount, row.sell_count, stats.sellCount, stats.sell_count);
  const pnlSol = firstNumber(row.pnl, row.realizedSol, row.realized_sol, stats.pnl, stats.realizedSol, stats.realized_sol);
  const volumeSol = firstNumber(row.volume, row.volumeSol, row.volume_sol, stats.volume, stats.volumeSol, stats.volume_sol);
  const trades = firstNumber(row.trades, row.tradeCount, row.trade_count, stats.trades, stats.tradeCount)
    ?? (Number.isFinite(Number(buyCount)) || Number.isFinite(Number(sellCount)) ? Number(buyCount || 0) + Number(sellCount || 0) : null);
  return {
    wallet,
    name: firstString(row.name, row.kolName, row.kol_name, profile.name, twitter, wallet ? shortMint(wallet) : "Unknown KOL"),
    twitter,
    avatar: firstString(deepFindKolAvatar(profile, row), row.avatar, row.avatarUrl, row.avatar_url, row.image, row.imageUrl, row.image_url, row.profileImage, row.profile_image, row.profileImageUrl, row.profile_image_url, row.profilePic, row.profile_pic, row.profilePicture, row.profile_picture, row.pfp, row.pfpUrl, row.pfp_url, profile.avatar, profile.avatarUrl, profile.avatar_url, profile.image, profile.imageUrl, profile.image_url, profile.profileImage, profile.profile_image, profile.profileImageUrl, profile.profile_image_url, profile.profilePic, profile.profile_pic, profile.profilePicture, profile.profile_picture, profile.pfp, profile.pfpUrl, profile.pfp_url),
    realizedUsd: firstNumber(row.realizedUsd, row.realized_usd, row.realized, row.pnlUsd, row.pnl_usd, stats.realizedUsd, stats.realized_usd, stats.realized),
    realizedLabel: pnlSol !== null ? `${formatCompactNumber(pnlSol)} SOL` : "",
    roiPct: normalizePercentLike(firstNumber(row.roi, row.roiPct, row.roi_pct, stats.roi, stats.roiPct, stats.roi_pct)),
    winRatePct: normalizePercentLike(firstNumber(row.winRate, row.win_rate, row.winrate, row.winPercentage, row.win_percentage, stats.winRate, stats.win_rate, stats.winPercentage)),
    trades,
    buyCount,
    sellCount,
    callsTracked: trades ?? (Number.isFinite(Number(buyCount)) || Number.isFinite(Number(sellCount)) ? Number(buyCount || 0) + Number(sellCount || 0) : null),
    currentPositionCount: firstNumber(row.currentPositionCount, row.positionsCount, row.positionCount, stats.currentPositionCount, stats.positionsCount),
    dumpRiskPercent: firstNumber(row.dumpRiskPercent, row.dump_risk_percent, stats.dumpRiskPercent, stats.dump_risk_percent),
    soldWithin15mPercent: firstNumber(row.soldWithin15mPercent, row.sold_within_15m_percent, stats.soldWithin15mPercent, stats.sold_within_15m_percent),
    soldWithin60mPercent: firstNumber(row.soldWithin60mPercent, row.sold_within_60m_percent, stats.soldWithin60mPercent, stats.sold_within_60m_percent),
    medianHoldMinutes: firstNumber(row.medianHoldMinutes, row.median_hold_minutes, stats.medianHoldMinutes, stats.median_hold_minutes),
    medianPostSignalDrawdownPercent: firstNumber(row.medianPostSignalDrawdownPercent, row.median_drawdown_percent, stats.medianPostSignalDrawdownPercent, stats.median_drawdown_percent),
    followerSurvival30mPercent: firstNumber(row.followerSurvival30mPercent, row.survival30mPercent, stats.followerSurvival30mPercent, stats.survival30mPercent),
    followerSurvival60mPercent: firstNumber(row.followerSurvival60mPercent, row.survival60mPercent, stats.followerSurvival60mPercent, stats.survival60mPercent),
    profileUrl: firstString(row.profileUrl, row.profile_url, row.kolscanUrl, row.kolscan_url, profile.profileUrl, profile.profile_url),
    xUrl: firstString(row.xUrl, row.x_url, row.twitterUrl, row.twitter_url, profile.xUrl, profile.x_url, profile.twitterUrl, profile.twitter_url),
    websiteUrl: firstString(row.websiteUrl, row.website_url, row.website, profile.websiteUrl, profile.website_url, profile.website),
    volumeLabel: volumeSol !== null ? `${formatCompactNumber(volumeSol)} SOL volume` : "",
    lastTradeAt: normalizeTimestamp(firstString(row.lastTradeAt, row.last_trade_at, row.lastTrade, stats.lastTradeAt, stats.last_trade_at))
  };
}

function scoreMadeOnSolSignal({ solAmount, usdValue, winRate, roiPct, ageHours, mode }) {
  const safeMode = normalizeKolMode(mode);
  let score = 52;
  const numericSol = Number(solAmount || 0);
  const numericUsd = Number(usdValue || 0);
  if (numericSol > 0) score += Math.min(18, Math.log10(Math.max(1, numericSol * 10)) * 8);
  if (numericUsd > 0) score += Math.min(18, Math.log10(Math.max(1, numericUsd)) * 3);
  if (Number.isFinite(Number(winRate))) score += Math.min(12, Math.max(0, Number(winRate)) / 7);
  if (Number.isFinite(Number(roiPct))) score += Math.min(10, Math.max(0, Number(roiPct)) / 30);
  if (Number.isFinite(ageHours)) {
    if (ageHours <= 1) score += 13;
    else if (ageHours <= 6) score += 8;
    else if (ageHours <= 24) score += 4;
  }
  if (safeMode === "fresh" && Number.isFinite(ageHours) && ageHours <= 6) score += 8;
  if (safeMode === "consistent" && Number(winRate || 0) >= 55) score += 7;
  return Math.round(Math.max(0, Math.min(100, score)));
}

function scoreMadeOnSolHotToken({ kolCount, buySol, volumeUsd, marketCap, ageHours, mode }) {
  const safeMode = normalizeKolMode(mode);
  let score = 50;
  score += Math.min(18, Math.max(0, Number(kolCount || 0)) * 5);
  if (Number(buySol || 0) > 0) score += Math.min(15, Math.log10(Math.max(1, Number(buySol) * 10)) * 6);
  if (Number(volumeUsd || 0) > 0) score += Math.min(14, Math.log10(Math.max(1, Number(volumeUsd))) * 2.5);
  if (Number.isFinite(Number(marketCap)) && Number(marketCap) > 0) {
    if (Number(marketCap) >= 5_000 && Number(marketCap) <= 500_000) score += 8;
    else if (Number(marketCap) <= 2_000_000) score += 4;
  }
  if (Number.isFinite(ageHours)) {
    if (ageHours <= 1) score += 12;
    else if (ageHours <= 6) score += 7;
    else if (ageHours <= 24) score += 3;
  }
  if (safeMode === "hot" && Number(kolCount || 0) >= 2) score += 6;
  if (safeMode === "fresh" && Number.isFinite(ageHours) && ageHours <= 3) score += 8;
  return Math.round(Math.max(0, Math.min(100, score)));
}

function twitterHandleFromUrl(value) {
  const text = String(value || "").trim();
  if (!text) return "";
  const match = text.match(/(?:x\.com|twitter\.com)\/([^/?#]+)/i);
  return match ? stripAt(match[1]) : stripAt(text);
}

function deepFindKolAvatar(...values) {
  const keyPattern = /(avatar|pfp|profile.*(image|pic|photo|picture)|image.*url|photo.*url|picture.*url|avatar.*url)/i;
  for (const value of values) {
    const found = deepFindStringByKey(value, keyPattern, { preferUrl: true });
    const normalized = normalizeAvatarUrlCandidate(found);
    if (normalized) return normalized;
  }
  return "";
}

function deepFindKolTwitter(...values) {
  const keyPattern = /(^|_)(twitter|x|username|handle|screenname|screen_name)($|_)|twitter.*url|x.*url/i;
  for (const value of values) {
    const found = deepFindStringByKey(value, keyPattern, { preferUrl: false });
    const handle = twitterHandleFromUrl(found);
    if (handle && !/^https?$/i.test(handle)) return handle;
  }
  return "";
}

function deepFindStringByKey(value, keyPattern, options = {}, seen = new Set(), depth = 0) {
  if (!value || depth > 5) return "";
  if (typeof value !== "object") return "";
  if (seen.has(value)) return "";
  seen.add(value);

  const entries = Array.isArray(value)
    ? value.map((item, index) => [String(index), item])
    : Object.entries(value);

  for (const [key, child] of entries) {
    if (keyPattern.test(key) && child !== null && child !== undefined && typeof child !== "object") {
      const text = String(child).trim();
      if (text && (!options.preferUrl || /^(https?:)?\/\//i.test(text) || text.startsWith("data:image/"))) {
        return text;
      }
    }
  }

  for (const [, child] of entries) {
    const nested = deepFindStringByKey(child, keyPattern, options, seen, depth + 1);
    if (nested) return nested;
  }

  return "";
}

function normalizeAvatarUrlCandidate(value) {
  const text = String(value || "").trim();
  if (!text) return "";
  if (/^data:image\//i.test(text)) return text;
  if (/^\/\//.test(text)) return `https:${text}`;
  if (/^https:\/\//i.test(text)) return text;
  if (/^http:\/\//i.test(text)) return text.replace(/^http:/i, "https:");
  return "";
}

function formatCompactNumber(value) {
  const number = Number(value);
  if (!Number.isFinite(number)) return "0";
  if (Math.abs(number) >= 1_000_000_000) return `${(number / 1_000_000_000).toFixed(2).replace(/0+$/, "").replace(/\.$/, "")}B`;
  if (Math.abs(number) >= 1_000_000) return `${(number / 1_000_000).toFixed(2).replace(/0+$/, "").replace(/\.$/, "")}M`;
  if (Math.abs(number) >= 1_000) return `${(number / 1_000).toFixed(2).replace(/0+$/, "").replace(/\.$/, "")}K`;
  return number.toFixed(number >= 10 ? 2 : 4).replace(/0+$/, "").replace(/\.$/, "");
}

